PRINT N'Creating Table [Alert].[ActiveAlerts]...';


GO
CREATE TABLE [Alert].[ActiveAlerts] (
    [AlertID]                 BIGINT         IDENTITY (1, 1) NOT NULL,
    [InstanceID]              INT            NOT NULL,
    [Priority]                TINYINT        NOT NULL,
    [AlertType]               VARCHAR (50)   NOT NULL,
    [AlertKey]                NVARCHAR (256) NOT NULL,
    [FirstMessage]            NVARCHAR (MAX) NOT NULL,
    [LastMessage]             NVARCHAR (MAX) NOT NULL,
    [TriggerDate]             DATETIME2 (7)  NOT NULL,
    [UpdatedDate]             DATETIME2 (7)  NOT NULL,
    [FirstNotification]       DATETIME2 (7)  NULL,
    [LastNotification]        DATETIME2 (7)  NULL,
    [UpdateCount]             INT            NOT NULL,
    [ResolvedCount]           INT            NOT NULL,
    [NotificationCount]       INT            NOT NULL,
    [FailedNotificationCount] INT            NOT NULL,
    [IsAcknowledged]          BIT            NOT NULL,
    [IsResolved]              BIT            NOT NULL,
    [ResolvedDate]            DATETIME2 (7)  NULL,
    [IsBlackout]              BIT            NOT NULL,
    [Escalated]               DATETIME2 (7)  NULL,
    [DeEscalated]             DATETIME2 (7)  NULL,
    [Notes]                   NVARCHAR (MAX) NULL,
    [RuleID]                  INT            NULL,
    [GroupID]                 INT            NOT NULL,
    [AcknowledgedDate]        DATETIME2 (7)  NULL,
    CONSTRAINT [PK_ActiveAlerts] PRIMARY KEY CLUSTERED ([AlertID] ASC)
);


