    [database_name]                NVARCHAR (512)   NULL,
    [event_description_keyword]    NVARCHAR (100)   NULL,
    [occurrence_count]             INT              NULL,
    [count_reset]                  DATETIME2 (3)    NULL,
    [job_id]                       UNIQUEIDENTIFIER NULL,
    [has_notification]             INT              NULL,
    [category_id]                  INT              NULL,
    [performance_condition]        NVARCHAR (512)   NULL,
    [AcknowledgeDate]              DATETIME2 (3)    NULL,
    [AlertLevel]                   TINYINT          NULL,
    [NotificationPeriodHrs]        SMALLINT         NULL,
    [DefaultAlertLevel]            AS               CASE WHEN message_id = 823
                                                              OR message_id = 824
                                                              OR message_id = 825
                                                              OR severity > 20 THEN CONVERT (TINYINT, 1) ELSE CONVERT (TINYINT, 2) END,
    [DefaultNotificationPeriodHrs] AS               CASE WHEN message_id = 823
                                                              OR message_id = 824
                                                              OR message_id = 825
                                                              OR severity > 20 THEN 168 ELSE 72 END,
    CONSTRAINT [PK_Alerts] PRIMARY KEY CLUSTERED ([InstanceID] ASC, [id] ASC)
);


