    CONSTRAINT [PK_CPU_60MIN] PRIMARY KEY CLUSTERED ([InstanceID] ASC, [EventTime] ASC) WITH (DATA_COMPRESSION = PAGE ON PARTITIONS (1)) ON [PS_CPU_60MIN] ([EventTime])
) ON [PS_CPU_60MIN] ([EventTime]);


