PRINT N'Creating View [dbo].[AgentJob7Day]...';


GO
CREATE VIEW dbo.AgentJob7Day
AS
WITH agg AS ( 
	SELECT JS.InstanceID,
		job_id,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-7,GETUTCDATE()) AND JS.step_id = 0 THEN JS.FailedCount ELSE 0 END) AS FailCount7Days,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-7,GETUTCDATE()) AND JS.step_id = 0 THEN JS.SucceededCount ELSE 0 END) AS SucceededCount7Days,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-1,GETUTCDATE()) AND JS.step_id = 0 THEN JS.FailedCount ELSE 0 END) AS FailCount24Hrs,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-1,GETUTCDATE()) AND JS.step_id = 0 THEN JS.SucceededCount ELSE 0 END) AS SucceededCount24Hrs,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-7,GETUTCDATE()) AND JS.step_id > 0 THEN JS.FailedCount ELSE 0 END) AS JobStepFails7Days,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-7,GETUTCDATE()) AND JS.step_id > 0 THEN JS.FailedCount ELSE 0 END) AS JobStepFails24Hrs,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-7,GETUTCDATE()) THEN JS.RetryCount ELSE 0 END) AS RetryCount7Days,
		SUM(CASE WHEN JS.RunDateTime >= DATEADD(d,-7,GETUTCDATE()) THEN JS.RetryCount ELSE 0 END) AS RetryCount24Hrs,
		MAX(CASE WHEN JS.step_id=0 THEN JS.MaxRunDurationSec ELSE NULL END) AS MaxDurationSec,
		AVG(CASE WHEN JS.step_id=0 THEN JS.RunDurationSec / NULLIF((JS.FailedCount+JS.SucceededCount),0) ELSE NULL END) AS AvgDurationSec
	FROM dbo.JobStats_60MIN JS 
	WHERE JS.RunDateTime >= CAST(DATEADD(d,-7,GETUTCDATE()) AS DATETIME2(2))
	GROUP BY JS.InstanceID,job_id
)
SELECT I.InstanceID,
	I.Instance,
	I.InstanceDisplayName,
	J.job_id,
	J.name,
	J.description,
	J.LastSucceeded,
	J.LastFailed,
	DATEDIFF(mi,J.LastSucceeded,GETUTCDATE()) AS TimeSinceLastSucceeded,
	DATEDIFF(mi,J.LastFailed,GETUTCDATE()) AS TimeSinceLastFailed,
    ISNULL(agg.FailCount7Days,0) AS FailCount7Days,
    ISNULL(agg.SucceededCount7Days,0) AS SucceededCount7Days,
    ISNULL(agg.FailCount24Hrs,0) AS FailCount24Hrs,
    ISNULL(agg.SucceededCount24Hrs,0) AS SucceededCount24Hrs,
    ISNULL(agg.JobStepFails7Days,0) AS JobStepFails7Days,
    ISNULL(agg.JobStepFails24Hrs,0) AS  JobStepFails24Hrs,
    ISNULL(agg.RetryCount7Days,0) AS RetryCount7Days,
    ISNULL(agg.RetryCount24Hrs,0) AS RetryCount24Hrs,
	CASE WHEN J.LastFailed > ISNULL(J.LastSucceeded,'19000101') THEN 1 ELSE 0 END AS IsLastFail,
	agg.MaxDurationSec,
	agg.AvgDurationSec,
	J.enabled,
	I.ShowInSummary,
	J.AckDate,
	J.StepLastFailed,
	DATEDIFF(mi,J.LastFailed,GETUTCDATE()) AS TimeSinceLastFailedMin,
	DATEDIFF(mi,J.LastSucceeded,GETUTCDATE()) AS TimeSinceLastSucceededMin
FROM dbo.Instances I 
JOIN  dbo.Jobs J ON I.InstanceID = J.InstanceID
LEFT JOIN agg ON J.job_id = agg.job_id AND J.InstanceID = agg.InstanceID
WHERE I.IsActive=1
AND J.IsActive=1
GO
PRINT N'Creating View [dbo].[AzureDBElasticPoolResourceStats_Current]...';


GO
CREATE VIEW dbo.AzureDBElasticPoolResourceStats_Current
AS
SELECT P.PoolID,
       P.InstanceID,
       P.elastic_pool_name,
       LastRS.start_time,
       LastRS.end_time,
       LastRS.avg_cpu_percent,
       LastRS.avg_data_io_percent,
       LastRS.avg_log_write_percent,
       LastRS.avg_storage_percent,
       LastRS.max_worker_percent,
       LastRS.max_session_percent,
       LastRS.elastic_pool_dtu_limit,
       LastRS.elastic_pool_storage_limit_mb,
       LastRS.avg_allocated_storage_percent,
       LastRS.elastic_pool_cpu_limit
FROM dbo.AzureDBElasticPool P 
CROSS APPLY(SELECT TOP(1) * FROM dbo.AzureDBElasticPoolResourceStats RS WHERE P.PoolID = RS.PoolID ORDER BY RS.end_time DESC) LastRS
GO
PRINT N'Creating View [dbo].[AzureDBElasticPoolResourceStatsCounters]...';


GO
CREATE VIEW dbo.AzureDBElasticPoolResourceStatsCounters
AS
/*
	Replicates dbo.PerformanceCounters table for use in dbo.PerformanceCountersBetweenDates function
*/
SELECT unpvt.InstanceID,
	C.CounterID,
	unpvt.end_time AS SnapshotDate,
	unpvt.value,
	1 AS SampleCount
FROM (
	SELECT	InstanceID,
			EP.elastic_pool_name,
			EPRS.end_time,
			CAST(EPRS.avg_allocated_storage_percent AS DECIMAL(28,9)) AS avg_allocated_storage_percent,
			CAST(EPRS.avg_cpu_percent AS DECIMAL(28,9)) AS avg_cpu_percent,
			CAST(EPRS.avg_data_io_percent AS DECIMAL(28,9)) AS avg_data_io_percent,
			CAST(EPRS.avg_log_write_percent AS DECIMAL(28,9)) AS avg_log_write_percent,
			CAST(EPRS.avg_storage_percent AS DECIMAL(28,9)) AS avg_storage_percent,
			CAST(EPRS.max_worker_percent AS DECIMAL(28,9)) AS max_worker_percent ,
			CAST(EPRS.max_session_percent AS DECIMAL(28,9)) AS max_session_percent,
			CAST(EPRS.elastic_pool_dtu_limit AS DECIMAL(28,9)) AS elastic_pool_dtu_limit,
			CAST(EPRS.elastic_pool_storage_limit_mb AS DECIMAL(28,9)) AS elastic_pool_storage_limit_mb,
			CAST(EPRS.elastic_pool_cpu_limit AS DECIMAL(28,9)) AS elastic_pool_cpu_limit
	FROM dbo.AzureDBElasticPool EP
	JOIN dbo.AzureDBElasticPoolResourceStats EPRS ON EP.PoolID = EPRS.PoolID
) PoolStats
UNPIVOT(
	value FOR CounterName IN(
	avg_allocated_storage_percent,
	avg_cpu_percent,
	avg_data_io_percent,
	avg_log_write_percent,
	avg_storage_percent,
	max_worker_percent,
	max_session_percent,
	elastic_pool_dtu_limit,
	elastic_pool_storage_limit_mb,
	elastic_pool_cpu_limit
	)
) unpvt
JOIN dbo.Counters C ON C.counter_name = unpvt.CounterName AND C.CounterType = 3 AND C.instance_name = elastic_pool_name AND C.object_name = 'sys.elastic_pool_resource_stats'
GO
PRINT N'Creating View [dbo].[AzureDBElasticPoolResourceStatsCounters_60MIN]...';


GO
CREATE VIEW dbo.AzureDBElasticPoolResourceStatsCounters_60MIN
AS
/*
	Replicates dbo.PerformanceCounters_60MIN table for use in dbo.PerformanceCountersBetweenDates_60MIN function
*/
SELECT unpvt.InstanceID,
	C.CounterID,
	calc.CounterName,
	unpvt.end_time AS SnapshotDate,
    MAX(CASE WHEN Calc.IsMaxCounter=1 THEN unpvt.value ELSE NULL END) AS max_value,
    MAX(CASE WHEN Calc.IsMaxCounter=0 THEN unpvt.value ELSE NULL  END) AS value,
    MAX(unpvt.SampleCount) AS SampleCount
FROM (
	SELECT	InstanceID,
			EP.elastic_pool_name,
			EPRS.end_time,
			CAST(EPRS.avg_allocated_storage_percent AS DECIMAL(28,9)) AS avg_allocated_storage_percent,
			CAST(EPRS.avg_cpu_percent AS DECIMAL(28,9)) AS avg_cpu_percent,
			CAST(EPRS.max_cpu_percent AS DECIMAL(28,9)) AS max_cpu_percent,
			CAST(EPRS.avg_data_io_percent AS DECIMAL(28,9)) AS avg_data_io_percent,
			CAST(EPRS.max_data_io_percent AS DECIMAL(28,9)) AS max_data_io_percent,
			CAST(EPRS.avg_log_write_percent AS DECIMAL(28,9)) AS avg_log_write_percent,
			CAST(EPRS.max_log_write_percent AS DECIMAL(28,9)) AS max_log_write_percent,
			CAST(EPRS.avg_storage_percent AS DECIMAL(28,9)) AS avg_storage_percent,
			CAST(EPRS.max_storage_percent AS DECIMAL(28,9)) AS max_storage_percent,
			CAST(EPRS.max_worker_percent AS DECIMAL(28,9)) AS max_worker_percent ,
			CAST(EPRS.max_session_percent AS DECIMAL(28,9)) AS max_session_percent,
			CAST(EPRS.elastic_pool_dtu_limit AS DECIMAL(28,9)) AS elastic_pool_dtu_limit,
			CAST(EPRS.elastic_pool_storage_limit_mb AS DECIMAL(28,9)) AS elastic_pool_storage_limit_mb,
			CAST(EPRS.elastic_pool_cpu_limit AS DECIMAL(28,9)) AS elastic_pool_cpu_limit,
			EPRS.CPU10+EPRS.CPU20+EPRS.CPU30+EPRS.CPU40+EPRS.CPU50+EPRS.CPU60+EPRS.CPU70+EPRS.CPU80+EPRS.CPU90+EPRS.CPU100  AS SampleCount
	FROM dbo.AzureDBElasticPool EP
	JOIN dbo.AzureDBElasticPoolResourceStats_60MIN EPRS ON EP.PoolID = EPRS.PoolID
) PoolStats
UNPIVOT(
	value FOR CounterName IN(
	avg_allocated_storage_percent,
	avg_cpu_percent,
	max_cpu_percent,
	avg_data_io_percent,
	max_data_io_percent,
	avg_log_write_percent,
	max_log_write_percent,
	avg_storage_percent,
	max_storage_percent,
	max_worker_percent,
	max_session_percent,
	elastic_pool_dtu_limit,
	elastic_pool_storage_limit_mb,
	elastic_pool_cpu_limit
	)
) unpvt
OUTER APPLY(SELECT CASE WHEN CounterName = 'max_cpu_percent' THEN 'avg_cpu_percent' 
                   WHEN CounterName = 'max_data_io_percent' THEN 'avg_data_io_percent'
                   WHEN CounterName = 'max_log_write_percent' THEN 'avg_log_write_percent'
				   WHEN CounterName = 'max_storage_percent' THEN 'avg_storage_percent'
                    ELSE CounterName END AS CounterName,
                CASE WHEN unpvt.CounterName IN('max_cpu_percent','max_data_io_percent','max_log_write_percent','max_storage_percent','max_worker_percent','max_session_percent')
                    THEN 1 ELSE 0 END AS IsMaxCounter
            ) AS calc
JOIN dbo.Counters C ON C.counter_name = calc.CounterName AND C.CounterType = 3 AND C.instance_name = elastic_pool_name AND C.object_name = 'sys.elastic_pool_resource_stats'
GROUP BY  unpvt.InstanceID,
        unpvt.end_time,
        C.CounterID,
        calc.CounterName
GO
PRINT N'Creating View [dbo].[AzureDBElasticPoolStorageStatus]...';


GO
CREATE VIEW dbo.AzureDBElasticPoolStorageStatus
AS
SELECT P.PoolID,
	P.InstanceID,
	P.avg_allocated_storage_percent,
	P.elastic_pool_storage_limit_mb,
	P.elastic_pool_storage_limit_mb*(avg_allocated_storage_percent/100.0) AS elastic_pool_storage_used_mb,
	P.elastic_pool_storage_limit_mb*(1-avg_allocated_storage_percent/100.0) AS elastic_pool_storage_free_mb,
	CASE WHEN P.avg_allocated_storage_percent> (PT.CriticalThreshold*100) THEN 1  WHEN P.avg_allocated_storage_percent>(PT.WarningThreshold*100) THEN 2  WHEN PT.WarningThreshold IS NULL THEN 3 ELSE 4 END AS ElasticPoolStorageStatus
FROM dbo.AzureDBElasticPoolResourceStats_Current P 
OUTER APPLY(SELECT TOP(1) WarningThreshold,CriticalThreshold FROM dbo.AzureDBElasticPoolStorageThresholds T 
		WHERE (T.PoolID = P.PoolID OR T.PoolID=-1)
		ORDER BY T.PoolID DESC) PT
GO
