GO
CREATE VIEW dbo.FileStatus
AS
WITH FG AS (
	SELECT	F.data_space_id, 
			F.DatabaseID, 
			F.InstanceID,
			SUM(F.size)  /128.0 AS FilegroupSizeMB,
			SUM(F.space_used) /128.0 AS FilegroupUsedMB,
			SUM(F.size-F.space_used) / 128.0 AS FilegroupFreeMB,
			1.0-(SUM(f.space_used) /SUM(NULLIF(f.size,0)*1.0)) AS FilegroupPctFree,
			COUNT(*) AS FilegroupNumberOfFiles,
			CASE WHEN MIN(f.max_size) <0 THEN NULL ELSE SUM(F.max_size) /128.0 END AS FilegroupMaxSizeMB,
			CASE WHEN MIN(f.max_size) <0 THEN NULL ELSE SUM(F.size) /NULLIF(SUM(F.max_size) *1.0,0) END AS FilegroupPctOfMaxSize,
			CASE WHEN MIN(f.max_size) <0 THEN NULL ELSE SUM(F.space_used) /NULLIF(SUM(F.max_size) *1.0,0) END AS FilegroupUsedPctOfMaxSize,
			SUM(CASE WHEN f.growth>0 THEN 1 WHEN f.type=2 THEN NULL ELSE 0 END) AS FilegroupAutogrowFileCount
	FROM dbo.DBFiles F
	WHERE F.IsActive=1
	GROUP BY F.data_space_id, F.DatabaseID, F.InstanceID
)
SELECT	F.FileID,
		F.InstanceID,
		F.DatabaseID,
		F.data_space_id,
		I.Instance,
		I.InstanceDisplayName,
		I.InstanceGroupName,
		I.ConnectionID,
		D.name,
		F.name AS file_name,
		F.filegroup_name,
		F.physical_name,
		f.size/128.0 AS FileSizeMB,
		f.space_used /128.0 AS FileUsedMB,
		(f.size-f.space_used) / 128.0 AS FileFreeMB,
		1.0 - (f.space_used/(NULLIF(f.size,0)*1.0)) AS FilePctFree,
		FG.FilegroupSizeMB,
		FG.FilegroupUsedMB,
		FG.FilegroupFreeMB,
		FG.FilegroupPctFree,
		FG.FilegroupNumberOfFiles,
		FG.FilegroupMaxSizeMB,
		FG.FilegroupPctOfMaxSize,
		FG.FilegroupUsedPctOfMaxSize,
		FG.FilegroupAutogrowFileCount,
		CASE	WHEN D.is_in_standby=1 OR F.is_read_only=1 OR D.is_read_only=1 OR D.state<>0 OR F.type=2 THEN 3 
				WHEN FG.FilegroupPctOfMaxSize > cfg.PctMaxSizeCriticalThreshold THEN 1 
				WHEN FG.FilegroupPctOfMaxSize > cfg.PctMaxSizeWarningThreshold THEN 2 
				WHEN F.max_size >= 268435456 AND F.data_space_id=0 THEN 3 
				WHEN cfg.PctMaxSizeWarningThreshold IS NOT NULL AND cfg.PctMaxSizeCriticalThreshold IS NOT NULL AND FG.FilegroupMaxSizeMB IS NOT NULL THEN 4 ELSE 3 END AS PctMaxSizeStatus,
		CASE	WHEN FG.FilegroupMaxSizeMB IS NULL THEN 'Max size not capped'
				WHEN F.max_size >= 268435456 AND F.data_space_id=0 THEN 'Log file max size'
				WHEN D.is_in_standby=1 THEN 'Standby' 
				WHEN F.is_read_only=1 THEN 'Filegroup Readonly' 
				WHEN D.is_read_only=1 THEN 'Database Readonly' 
				WHEN D.state<>0 THEN 'Database State:' + D.state_desc 
				WHEN F.type=2 THEN 'Filestream' 
				WHEN cfg.PctMaxSizeWarningThreshold IS NULL AND cfg.PctMaxSizeCriticalThreshold IS NULL THEN 'No Threshold'
				ELSE NULL END AS MaxSizeExcludedReason,
		CASE WHEN D.is_read_only=0 AND D.state=0 AND F.is_read_only=0 AND D.is_in_standby=0 AND FG.FilegroupAutogrowFileCount=0 THEN 2 WHEN FG.FilegroupAutogrowFileCount=0 THEN 3 ELSE 4 END AS FilegroupAutogrowStatus,
		f.is_read_only,
		D.is_read_only AS is_db_read_only,
		D.is_in_standby,
		D.state,
		D.state_desc,
		CASE	WHEN D.is_in_standby=1 THEN 'Standby' 
				WHEN F.is_read_only=1 THEN 'Filegroup Readonly' 
				WHEN D.is_read_only=1 THEN 'Database Readonly' 
				WHEN D.state<>0 THEN 'Database State:' + D.state_desc 
				WHEN F.type=2 THEN 'Filestream' 
				WHEN cfg.FreeSpaceWarningThreshold IS NULL AND cfg.FreeSpaceCriticalThreshold IS NULL THEN 'No Threshold'
				WHEN FG.FilegroupUsedMB IS NULL THEN 'UsedMB is NULL'
				WHEN cfg.FreeSpaceCheckZeroAutogrowthOnly=1 AND FG.FilegroupAutogrowFileCount>0 THEN 'Autogrow enabled'
				WHEN Calc.IsAzureDB = 1 THEN 'AzureDB'
				ELSE NULL END AS ExcludedReason, 
	   CASE		WHEN D.is_in_standby=1 OR F.is_read_only=1 OR D.is_read_only=1 OR D.state<>0 OR F.type=2 OR Calc.IsAzureDB=1 THEN 3 
				WHEN FG.FilegroupUsedMB IS NULL THEN 3
				WHEN cfg.FreeSpaceCheckZeroAutogrowthOnly=1 AND FG.FilegroupAutogrowFileCount>0 THEN 3
				WHEN cfg.FreeSpaceCheckType='%' AND FG.FilegroupPctFree<= cfg.FreeSpaceCriticalThreshold THEN 1 
				WHEN cfg.FreeSpaceCheckType='M' AND FG.FilegroupFreeMB<cfg.FreeSpaceCriticalThreshold THEN 1
				WHEN cfg.FreeSpaceCheckType='%' AND FG.FilegroupPctFree<=cfg.FreeSpaceWarningThreshold THEN 2
				WHEN cfg.FreeSpaceCheckType='M' AND FG.FilegroupFreeMB <=cfg.FreeSpaceWarningThreshold THEN 2
				WHEN cfg.FreeSpaceWarningThreshold IS NULL AND cfg.FreeSpaceCriticalThreshold IS NULL THEN 3
				ELSE 4 END AS FreeSpaceStatus,
		cfg.FreeSpaceWarningThreshold,
		cfg.FreeSpaceCriticalThreshold,
		cfg.FreeSpaceCheckType,
		cfg.ConfiguredLevel,
		F.type,
		CASE WHEN F.type =0 THEN N'ROWS' WHEN F.type = 1 THEN N'LOG' WHEN F.type=2 THEN N'FILESTREAM' WHEN F.type = 4 THEN N'FULLTEXT' ELSE CAST(f.type as NVARCHAR(60)) END as type_desc,
		SSD.SnapshotDate AS FileSnapshotDate,
		Calc.FileSnapshotAge,
		CASE WHEN CDT.WarningThreshold IS NULL AND CDT.CriticalThreshold IS NULL THEN 3 WHEN Calc.FileSnapshotAge > CDT.CriticalThreshold THEN 1 WHEN Calc.FileSnapshotAge>CDT.WarningThreshold THEN 2 ELSE 4 END AS FileSnapshotAgeStatus,
		F.max_size,
		NULLIF(f.max_size,-1)/128.0 AS MaxSizeMB,
		CASE WHEN F.is_percent_growth=1 THEN (F.growth*0.01*F.size)/128.0 ELSE F.growth/128.0 END AS GrowthMB,
		F.growth,
		CASE WHEN F.is_percent_growth=1 THEN F.growth ELSE NULL END AS GrowthPct,
		F.is_percent_growth,
		Calc.IsAzureDB,
		I.ShowInSummary
FROM dbo.DBFiles F
JOIN FG ON F.DatabaseID = FG.DatabaseID AND F.InstanceID = FG.InstanceID AND F.data_space_id = FG.data_space_id
JOIN dbo.Databases D ON D.DatabaseID = F.DatabaseID AND D.InstanceID = F.InstanceID
JOIN dbo.Instances I ON I.InstanceID = F.InstanceID
LEFT JOIN dbo.CollectionDates SSD ON I.InstanceID = SSD.InstanceID AND SSD.Reference='DBFiles'
OUTER APPLY(SELECT CASE WHEN I.EngineEdition=5 THEN CAST(1 as BIT) ELSE CAST(0 as BIT) END as IsAzureDB,
					DATEDIFF(mi,SSD.SnapshotDate,GETUTCDATE()) AS FileSnapshotAge) AS Calc
/* Filegroup level threshold */
LEFT OUTER JOIN dbo.DBFileThresholds T_FG ON T_FG.InstanceID = F.InstanceID 
									AND T_FG.DatabaseID = F.DatabaseID 
									AND T_FG.data_space_id = F.data_space_id 
									AND T_FG.data_space_id <> 0 /* Exclude log as this is considered a DB threshold */
/* DB level threshold */
LEFT OUTER JOIN dbo.DBFileThresholds T_DB ON T_DB.InstanceID = F.InstanceID 
									AND T_DB.DatabaseID = F.DatabaseID 
									AND (
											(T_DB.data_space_id = -1 AND F.type=0) /* Row threshold */
											OR 
											(T_DB.data_space_id=0 AND F.type=1) /* Log Threshold */
										)
									AND T_FG.InstanceID IS NULL /* Only JOIN if we don't have a Filegroup level threshold (so COALESCE works with NULL thresholds) */
/* Instance level threshold */
LEFT OUTER JOIN dbo.DBFileThresholds T_Inst ON T_Inst.InstanceID = F.InstanceID 
									AND T_Inst.DatabaseID = -1 
									AND (
											(T_Inst.data_space_id = -1 AND F.type=0) /* Row threshold */
											OR 
											(T_Inst.data_space_id=0 AND F.type=1) /* Log Threshold */
										) 
									AND T_FG.InstanceID IS NULL /* Only JOIN if we don't have a Filegroup level threshold (so COALESCE works with NULL thresholds) */
									AND T_DB.InstanceID IS NULL /* Only JOIN if we don't have a DB level threshold (so COALESCE works with NULL thresholds) */
/* Root level threshold */
LEFT OUTER JOIN dbo.DBFileThresholds T_Root ON T_Root.InstanceID = -1 
									AND T_Root.DatabaseID = -1 
									AND (
											(T_Root.data_space_id = -1 AND F.type=0) /* Row threshold */
											OR 
											(T_Root.data_space_id=0 AND F.type=1) /* Log Threshold */
										)
									AND T_FG.InstanceID IS NULL /* Only JOIN if we don't have a Filegroup level threshold (so COALESCE works with NULL thresholds) */
									AND T_DB.InstanceID IS NULL /* Only JOIN if we don't have a DB level threshold (so COALESCE works with NULL thresholds) */
									AND T_Inst.InstanceID IS NULL /* Only JOIN if we don't have an instance threshold (so COALESCE works with NULL thresholds) */
/* Calculate the threshold we need to apply. */
OUTER APPLY(
			SELECT	COALESCE(T_FG.FreeSpaceWarningThreshold, T_DB.FreeSpaceWarningThreshold, T_Inst.FreeSpaceWarningThreshold, T_Root.FreeSpaceWarningThreshold) AS FreeSpaceWarningThreshold,
					COALESCE(T_FG.FreeSpaceCriticalThreshold, T_DB.FreeSpaceCriticalThreshold, T_Inst.FreeSpaceCriticalThreshold, T_Root.FreeSpaceCriticalThreshold) AS FreeSpaceCriticalThreshold,
					COALESCE(T_FG.FreeSpaceCheckType, T_DB.FreeSpaceCheckType, T_Inst.FreeSpaceCheckType, T_Root.FreeSpaceCheckType) AS FreeSpaceCheckType,
					COALESCE(T_FG.PctMaxSizeWarningThreshold, T_DB.PctMaxSizeWarningThreshold, T_Inst.PctMaxSizeWarningThreshold, T_Root.PctMaxSizeWarningThreshold) AS PctMaxSizeWarningThreshold,
					COALESCE(T_FG.PctMaxSizeCriticalThreshold, T_DB.PctMaxSizeCriticalThreshold, T_Inst.PctMaxSizeCriticalThreshold, T_Root.PctMaxSizeCriticalThreshold) AS PctMaxSizeCriticalThreshold,
					COALESCE(T_FG.FreeSpaceCheckZeroAutogrowthOnly, T_DB.FreeSpaceCheckZeroAutogrowthOnly, T_Inst.FreeSpaceCheckZeroAutogrowthOnly, T_Root.FreeSpaceCheckZeroAutogrowthOnly) AS FreeSpaceCheckZeroAutogrowthOnly,
					CASE 
						WHEN T_FG.InstanceID IS NOT NULL THEN 'FG'
						WHEN T_DB.InstanceID IS NOT NULL THEN 'DB'
						WHEN T_Inst.InstanceID IS NOT NULL THEN 'Instance'
						WHEN T_Root.InstanceID IS NOT NULL THEN 'Root'
						ELSE 'N/A' 
					END AS ConfiguredLevel
			) cfg
-- Join for Collection Date Thresholds (Instance Specific)
LEFT JOIN dbo.CollectionDatesThresholds CDT_Inst ON CDT_Inst.InstanceID = F.InstanceID AND CDT_Inst.Reference = 'DBFiles'
-- Join for Collection Date Thresholds (Global)
LEFT JOIN dbo.CollectionDatesThresholds CDT_Root ON CDT_Root.InstanceID = -1 AND CDT_Root.Reference = 'DBFiles'
											AND CDT_Inst.InstanceID IS NULL /* Only JOIN if we don't have an instance level threshold. (so COALESCE works with NULL thresholds) */ 
-- Calculate Effective Date Thresholds
CROSS APPLY (
    SELECT 	COALESCE(CDT_Inst.WarningThreshold, CDT_Root.WarningThreshold) AS WarningThreshold,
			COALESCE(CDT_Inst.CriticalThreshold, CDT_Root.CriticalThreshold) AS CriticalThreshold
	) AS CDT
WHERE F.IsActive=1
AND I.IsActive=1
AND D.IsActive=1;
GO
PRINT N'Creating View [dbo].[IdentityColumnsInfo]...';


GO
CREATE VIEW dbo.IdentityColumnsInfo
AS
SELECT	IC.InstanceID,
		IC.DatabaseID,
		I.InstanceDisplayName,
		D.name AS DB, 
		IC.SnapshotDate,
		CASE WHEN cdt.WarningThreshold IS NULL AND cdt.CriticalThreshold IS NULL THEN 3 WHEN DATEDIFF(mi,IC.SnapshotDate,GETUTCDATE()) > cdt.CriticalThreshold THEN 1 WHEN DATEDIFF(mi,IC.SnapshotDate,GETUTCDATE()) > cdt.WarningThreshold THEN 2 ELSE 4 END AS SnapshotStatus,
		IC.object_id,
		IC.schema_name,
		IC.object_name,
		IC.column_name,
		TYPE_NAME(IC.system_type_id) AS type,
		IC.increment_value,
		IC.seed_value, 
		IC.row_count,
		IC.last_value,
		IC.min_ident,
		IC.max_ident,
		IC.max_rows,
		calc2.pct_used,
		calc2.pct_free,
		CASE	WHEN calc2.pct_used>THRES.PctUsedCriticalThreshold OR calc3.estimated_days <= THRES.DaysCriticalThreshold THEN 1 
				WHEN calc2.pct_used > THRES.PctUsedWarningThreshold OR calc3.estimated_days <= THRES.DaysWarningThreshold THEN 2 
				WHEN THRES.PctUsedWarningThreshold IS NOT NULL OR THRES.PctUsedCriticalThreshold IS NOT NULL
					OR THRES.DaysCriticalThreshold IS NOT NULL OR THRES.DaysWarningThreshold IS NOT NULL THEN 4 
				ELSE 3 END AS IdentityStatus,
		CASE	WHEN calc2.pct_used>THRES.PctUsedCriticalThreshold THEN 1 
				WHEN calc2.pct_used > THRES.PctUsedWarningThreshold THEN 2 
				WHEN THRES.PctUsedWarningThreshold IS NOT NULL OR THRES.PctUsedCriticalThreshold IS NOT NULL THEN 4 
				ELSE 3 END AS IdentityPctStatus,
		CASE	WHEN calc3.estimated_days <= THRES.DaysCriticalThreshold THEN 1 
				WHEN calc3.estimated_days <= THRES.DaysWarningThreshold THEN 2 
				WHEN THRES.DaysCriticalThreshold IS NOT NULL OR THRES.DaysWarningThreshold IS NOT NULL THEN 4 
				ELSE 3 END AS IdentityDaysStatus,
		calc.pct_ident_used,
        calc.pct_rows_used,
		calc.remaining_ident_count,
		calc.remaining_row_count,
		PerDay.avg_ident_per_day,
        PerDay.avg_rows_per_day,
		PerDay.avg_calc_days,
		calc2.ident_estimated_days,
		calc2.row_estimated_days,
		CASE WHEN calc3.estimated_days >= 9223372036854775807 THEN 9223372036854775807 ELSE calc3.estimated_days END AS estimated_days,
		CAST(DATEADD(d,CASE WHEN calc3.estimated_days > 36500 THEN NULL ELSE calc3.estimated_days END,IC.SnapshotDate) AS DATE) AS estimated_date,
		THRES.PctUsedWarningThreshold,
		THRES.PctUsedCriticalThreshold,
		THRES.DaysWarningThreshold,
		THRES.DaysCriticalThreshold,
		I.ShowInSummary,
		THRES.ThresholdConfigurationLevel
FROM dbo.IdentityColumns IC
JOIN dbo.Instances I ON I.InstanceID = IC.InstanceID
JOIN dbo.Databases D ON D.DatabaseID = IC.DatabaseID
OUTER APPLY (SELECT CASE WHEN IC.last_value <0 THEN (ABS(IC.min_ident)-ABS(CONVERT(decimal(38,0), IC.last_value))) / IC.max_rows ELSE IC.last_value/IC.max_ident END AS pct_ident_used,
					IC.row_count/IC.max_rows AS pct_rows_used,
					CASE WHEN IC.last_value < 0 THEN ABS(CONVERT(decimal(38,0), IC.last_value))+IC.max_ident ELSE IC.max_ident - IC.last_value END AS remaining_ident_count,
					IC.max_rows-IC.row_count AS remaining_row_count
	
		) AS calc
OUTER APPLY(SELECT TOP(1) (IC.last_value-ICH.last_value) / (DATEDIFF(s,ICH.SnapshotDate,IC.SnapshotDate)/86400.) avg_ident_per_day,
				(IC.row_count-ICH.row_count) / (DATEDIFF(s,ICH.SnapshotDate,IC.SnapshotDate)/86400.) AS avg_rows_per_day,
				(DATEDIFF(s,ICH.SnapshotDate,IC.SnapshotDate)/86400.) AS avg_calc_days
			FROM dbo.IdentityColumnsHistory ICH
			WHERE ICH.InstanceID = IC.InstanceID 
			AND ICH.DatabaseID = IC.DatabaseID
			AND ICH.object_id = IC.object_id
			AND ICH.SnapshotDate < DATEADD(d,-1,IC.SnapshotDate) /* At least 1 day of history */
			AND ICH.SnapshotDate > CAST(DATEADD(d,-31,GETUTCDATE()) AS DATETIME2(2))
			ORDER BY ICH.SnapshotDate
			) AS PerDay
OUTER APPLY(SELECT	calc.remaining_ident_count / CASE WHEN calc.remaining_ident_count =0 THEN 1  WHEN PerDay.avg_ident_per_day <=0 THEN NULL ELSE PerDay.avg_ident_per_day END AS ident_estimated_days,
					calc.remaining_row_count / CASE WHEN calc.remaining_row_count = 0 THEN 1 WHEN PerDay.avg_rows_per_day <=0 THEN NULL ELSE PerDay.avg_rows_per_day END AS row_estimated_days,
					(SELECT MAX(PCT.pct_used) FROM (VALUES (calc.pct_ident_used),(calc.pct_rows_used)) PCT(pct_used)) AS pct_used,
					(SELECT 1.-MAX(PCT.pct_used) FROM (VALUES (calc.pct_ident_used),(calc.pct_rows_used)) PCT(pct_used)) AS pct_free
			) AS calc2
OUTER APPLY(SELECT MIN(Est.estimated_days) AS estimated_days
			FROM (VALUES(calc2.ident_estimated_days),(calc2.row_estimated_days)) AS Est(estimated_days)
			) AS calc3
OUTER APPLY(SELECT TOP(1)	T.WarningThreshold, 
							T.CriticalThreshold
			FROM dbo.CollectionDatesThresholds T
			WHERE T.InstanceID = D.InstanceID OR T.InstanceID=-1
			AND T.Reference = 'IdentityColumns'
			ORDER BY T.InstanceID DESC) cdt
OUTER APPLY(SELECT TOP(1)	ICT.PctUsedWarningThreshold,
							ICT.PctUsedCriticalThreshold,
							ICT.DaysWarningThreshold,
							ICT.DaysCriticalThreshold,
							CASE WHEN ICT.object_name <>'' THEN 'Table' WHEN ICT.DatabaseID <> -1 THEN 'Database' WHEN ICT.InstanceID <> -1 THEN 'Instance' ELSE 'Root' END AS ThresholdConfigurationLevel
		FROM dbo.IdentityColumnThresholds ICT
		WHERE (ICT.InstanceID = IC.InstanceID OR ICT.InstanceID=-1)
		AND (ICT.DatabaseID = IC.DatabaseID OR ICT.DatabaseID =-1)
		AND (ICT.object_name = IC.object_name OR ICT.object_name = '')
		ORDER BY ICT.InstanceID DESC,ICT.DatabaseID DESC, ICT.object_name DESC
		)  AS THRES
WHERE I.IsActive=1
AND D.IsActive=1
GO
PRINT N'Creating View [dbo].[JobStats_RAW]...';


GO
CREATE VIEW dbo.JobStats_RAW
AS
SELECT jh.InstanceID,
	jh.job_id,
	jh.step_id,
	RunDateTime,
	SUM(CASE WHEN run_status IN(0,3) THEN 1 ELSE 0 END) as FailedCount,
	SUM(CASE WHEN run_status=1 THEN 1 ELSE 0 END) as SucceededCount,
	ISNULL(SUM(retries_attempted),0) as RetryCount,
	ISNULL(SUM(RunDurationSec),0) as RunDurationSec,
	ISNULL(MAX(RunDurationSec),0) as MaxRunDurationSec,
	ISNULL(MIN(RunDurationSec),0) as MinRunDurationSec
FROM dbo.JobHistory jh
GROUP BY InstanceID,
		job_id,
		step_id,
		jh.RunDateTime
GO
PRINT N'Creating View [dbo].[LastGoodCheckDB]...';


GO
CREATE VIEW dbo.LastGoodCheckDB
AS
SELECT I.InstanceID,
	D.DatabaseID,
	I.Instance,
	I.InstanceDisplayName,
	D.name,
	D.state,
	D.state_desc,
	D.is_in_standby,
	D.LastGoodCheckDbTime,
	DATEADD(mi,CASE WHEN D.LastGoodCheckDbTime = '19000101' THEN 0 ELSE I.UTCOffset END,D.LastGoodCheckDbTime) AS LastGoodCheckDbTimeUTC,
	DATEDIFF(hh,NULLIF(D.LastGoodCheckDbTime,'19000101'),GETUTCDATE()) AS HrsSinceLastGoodCheckDB,
	DATEDIFF(d,NULLIF(D.LastGoodCheckDbTime,'19000101'),GETUTCDATE()) AS DaysSinceLastGoodCheckDB,
	S.Status,
	CASE S.Status WHEN 1 THEN 'Critical' WHEN 2 THEN 'Warning' WHEN 3 THEN 'N/A' WHEN 4 THEN 'OK' ELSE NULL END AS StatusDescription,
	CASE WHEN cfg.InstanceID IS NULL THEN 'None'
	WHEN cfg.DatabaseID = -1 AND cfg.InstanceID =-1 THEN 'Root' 
	WHEN cfg.DatabaseID = -1 THEN 'Instance'
	ELSE 'Database' END AS ConfiguredLevel,
	cfg.WarningThresholdHrs,
	cfg.CriticalThresholdHrs,
	excl.LastGoodCheckDBExcludedReason,
	D.create_date,
	DATEADD(mi,I.UTCOffset,D.create_date)  AS create_date_utc,
	I.ShowInSummary
FROM dbo.Databases D 
JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
OUTER APPLY(SELECT TOP(1) T.*
			FROM dbo.LastGoodCheckDBThresholds T
			WHERE (D.InstanceID = T.InstanceID OR T.InstanceID = -1)
				AND (D.DatabaseID = T.DatabaseID  OR T.DatabaseID = -1)
				ORDER BY T.InstanceID DESC,T.DatabaseID DESC
			) cfg
OUTER APPLY(SELECT STUFF(CONCAT(CASE WHEN D.state<>0 THEN ', ' + state_desc ELSE NULL END,
					CASE WHEN D.is_in_standby=1 THEN ', STANDBY' WHEN D.is_read_only=1 THEN ', READ ONLY'  ELSE NULL END,
					CASE WHEN EXISTS(SELECT * FROM STRING_SPLIT(cfg.ExcludedDatabases,',') SS WHERE d.name LIKE RTRIM(LTRIM(SS.value))) THEN ', name' ELSE NULL END,
					CASE WHEN D.LastGoodCheckDbTime IS NULL THEN ', Not captured' ELSE NULL END,
					CASE WHEN DATEADD(mi,I.UTCOffset,D.create_date) > DATEADD(mi,-cfg.MinimumAge,GETUTCDATE())  THEN ', create_date' ELSE NULL END,
					CASE WHEN cfg.WarningThresholdHrs IS NULL AND cfg.CriticalThresholdHrs IS NULL THEN ', No threshold' ELSE NULL END
					),1,2,'') as LastGoodCheckDBExcludedReason
			) excl	
OUTER APPLY(SELECT	CASE WHEN excl.LastGoodCheckDBExcludedReason IS NOT NULL THEN 3
					WHEN DATEADD(mi,I.UTCOffset,D.LastGoodCheckDbTime) < DATEADD(hh,-cfg.CriticalThresholdHrs,GETUTCDATE()) THEN 1 
					WHEN DATEADD(mi,I.UTCOffset,D.LastGoodCheckDbTime) < DATEADD(hh,-cfg.WarningThresholdHrs,GETUTCDATE()) THEN 2
					ELSE 4 END AS Status
			) S
WHERE D.IsActive=1
AND I.IsActive=1
GO
PRINT N'Creating View [dbo].[NonDefaultDBConfig]...';


GO
CREATE VIEW NonDefaultDBConfig
AS
SELECT i.Instance, d.name,cfgo.name AS configuration_name,value
FROM dbo.DBConfig cfg
JOIN dbo.Databases d ON d.DatabaseID = cfg.DatabaseID
JOIN dbo.Instances i ON i.InstanceID = d.InstanceID
JOIN dbo.DBConfigOptions cfgo ON cfgo.configuration_id = cfg.configuration_id
WHERE NOT (cfg.configuration_id=1 AND value=0) --MAXDOP
AND NOT (cfg.configuration_id=2 AND cfg.value=0) --LEGACY_CARDINALITY_ESTIMATION
AND NOT (cfg.configuration_id=3 AND cfg.value=1) -- PARAMETER_SNIFFING
AND NOT (cfg.configuration_id=4 AND cfg.value=0) -- QUERY_OPTIMIZER_HOTFIXES
AND NOT (cfg.configuration_id=6 AND cfg.value=1) -- IDENTITY_CACHE
