PRINT N'Creating View [dbo].[RunningQueriesPerformanceCounters]...';


GO
CREATE VIEW dbo.RunningQueriesPerformanceCounters
AS
SELECT	unpvt.InstanceID,
		C.CounterID,
		unpvt.SnapshotDateUTC AS SnapshotDate,	
		unpvt.Value
FROM (
	SELECT	InstanceID,
			SnapshotDateUTC,
			CAST(RunningQueries AS DECIMAL(28,9)) AS [Running Query Count],
			CAST(BlockedQueries AS DECIMAL(28,9)) AS [Blocked Query Count],
			CAST(BlockedQueriesWaitMs AS DECIMAL(28,9)) AS [Blocked Queries Wait (ms)],
			CAST(MaxMemoryGrant*8 AS DECIMAL(28,9)) AS [Max Memory Grant KB],
			CAST(SumMemoryGrant*8 AS DECIMAL(28,9)) AS [Sum Memory Grant KB],
			CAST(LongestRunningQueryMs AS DECIMAL(28,9)) AS [Longest Running Query (ms)],
			CAST(CriticalWaitCount AS DECIMAL(28,9)) AS [Critical Wait Count],
			CAST(CriticalWaitTime AS DECIMAL(28,9)) AS [Critical Wait Time (ms)],
			CAST(TempDBWaitCount AS DECIMAL(28,9)) AS [TempDB Wait Count],
			CAST(TempDBWaitTimeMs AS DECIMAL(28,9)) AS [TempDB Wait Time (ms)],
			CAST(SleepingSessionsCount AS DECIMAL(28,9)) AS [Sleeping Sessions Count],
			CAST(SleepingSessionsMaxIdleTimeMs AS DECIMAL(28,9)) AS [Sleeping Sessions Max Idle Time (ms)],
			CAST(ISNULL(OldestTransactionMs,0) AS DECIMAL(28,9)) AS [Oldest Transaction (ms)]
	FROM dbo.RunningQueriesSummary
	) RQS
UNPIVOT( 
	Value FOR CounterName IN([Running Query Count],
							[Blocked Query Count], 
							[Blocked Queries Wait (ms)], 
							[Max Memory Grant KB], 
							[Sum Memory Grant KB], 
							[Longest Running Query (ms)], 
							[Critical Wait Count], 
							[Critical Wait Time (ms)], 
							[TempDB Wait Count], 
							[TempDB Wait Time (ms)], 
							[Sleeping Sessions Count], 
							[Sleeping Sessions Max Idle Time (ms)],
							[Oldest Transaction (ms)]
							)
) unpvt
JOIN dbo.Counters C ON C.counter_name = unpvt.CounterName AND C.object_name = 'Running Queries' AND C.instance_name = '' 
WHERE C.CounterType = 2
GO
PRINT N'Creating View [dbo].[SysAlerts]...';


GO
CREATE VIEW dbo.SysAlerts
AS
SELECT I.InstanceID,
		I.Instance,
		I.ConnectionID,
        I.InstanceDisplayName,
        A.id,
        A.name,
        A.message_id,
        A.severity,
        A.enabled,
        A.delay_between_responses,
		A.last_occurrence,
		calc.last_occurrence_utc,
        A.last_response,
		DATEADD(mi,I.UTCOffset,A.last_response) last_response_utc,
        A.notification_message,
        A.include_event_description,
        A.database_name,
        A.event_description_keyword,
        A.occurrence_count,
        A.count_reset,
		DATEADD(mi,I.UTCOffset,A.count_reset) count_reset_utc,
        A.job_id,
		J.name AS JobName,
        A.has_notification,
		CASE WHEN A.include_event_description & 1 = 1 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS Email,
		CASE WHEN A.include_event_description & 2 = 2 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS Pager,
		CASE WHEN A.include_event_description & 4 = 4 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS NetSend,
        A.category_id,
		A.performance_condition,
		calc.IsCriticalAlert,
		I.UTCOffset,
        I.ShowInSummary,
        A.AlertLevel,
        A.DefaultAlertLevel,
        calc.ActualAlertLevel,
        A.NotificationPeriodHrs,
        A.DefaultNotificationPeriodHrs,
        calc.ActualNotificationPeriodHrs,
        CASE    WHEN calc.ActualAlertLevel = 3 THEN 3
                WHEN calc.last_occurrence_utc >= DATEADD(HOUR,-calc.ActualNotificationPeriodHrs,GETUTCDATE()) AND calc.last_occurrence_utc < A.AcknowledgeDate THEN 5
                WHEN calc.last_occurrence_utc >= DATEADD(HOUR,-calc.ActualNotificationPeriodHrs,GETUTCDATE()) THEN calc.ActualAlertLevel
                ELSE 4 END AS AlertStatus,
        A.AcknowledgeDate
FROM dbo.Alerts A 
JOIN dbo.Instances I ON A.InstanceID = I.InstanceID
LEFT JOIN dbo.Jobs J ON J.InstanceID = I.InstanceID AND J.job_id = A.job_id
OUTER APPLY(SELECT  CASE WHEN ISNULL(A.AlertLevel,A.DefaultAlertLevel)=1 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsCriticalAlert,
                    DATEADD(mi,I.UTCOffset,A.last_occurrence) AS last_occurrence_utc,
                     ISNULL(A.AlertLevel,A.DefaultAlertLevel) AS ActualAlertLevel,
                     ISNULL(A.NotificationPeriodHrs,A.DefaultNotificationPeriodHrs) AS ActualNotificationPeriodHrs
            ) calc
GO
