CREATE VIEW dbo.FilegroupStatus
AS
SELECT NULL AS FileID,
	   F.InstanceID,
       F.DatabaseID,
       F.data_space_id,
       F.Instance,
       F.InstanceDisplayName,
       F.InstanceGroupName,
       F.ConnectionID,
       F.name,
       NULL AS file_name,
       F.filegroup_name,
       NULL AS physical_name,
       F.FilegroupSizeMB AS FileSizeMB,
       F.FilegroupUsedMB AS FileUsedMB,
       F.FilegroupFreeMB AS FileFreeMB,
       F.FilegroupPctFree AS FilePctFree,
       F.FilegroupSizeMB,
       F.FilegroupUsedMB,
       F.FilegroupFreeMB,
       F.FilegroupPctFree,
       F.FilegroupNumberOfFiles,
       F.is_read_only,
       F.is_db_read_only,
       F.is_in_standby,
       F.state,
       F.state_desc,
