CREATE FUNCTION dbo.Histogram_CPU(@CPU INT)
RETURNS TABLE
AS
RETURN 
SELECT CASE WHEN @CPU<10 THEN 1 ELSE 0 END AS CPU10,
	   CASE WHEN @CPU >=10 AND @CPU <20 THEN 1 ELSE 0 END AS CPU20,
	   CASE WHEN @CPU >=20 AND @CPU <30 THEN 1 ELSE 0 END AS CPU30,
	   CASE WHEN @CPU >=30 AND @CPU <40 THEN 1 ELSE 0 END AS CPU40,
	   CASE WHEN @CPU >=40 AND @CPU <50 THEN 1 ELSE 0 END AS CPU50,
	   CASE WHEN @CPU >=50 AND @CPU <60 THEN 1 ELSE 0 END AS CPU60,
	   CASE WHEN @CPU >=60 AND @CPU <70 THEN 1 ELSE 0 END AS CPU70,
	   CASE WHEN @CPU >=70 AND @CPU <80 THEN 1 ELSE 0 END AS CPU80,
	   CASE WHEN @CPU >=80 AND @CPU <90 THEN 1 ELSE 0 END AS CPU90,
	   CASE WHEN @CPU>= 90 THEN 1 ELSE 0 END AS CPU100
GO
PRINT N'Creating Function [dbo].[InstancesMatchingTags]...';


GO
CREATE FUNCTION dbo.InstancesMatchingTags(
	@TagIDs VARCHAR(MAX)
)
RETURNS TABLE
AS
RETURN
WITH T AS (
	SELECT * 
	FROM dbo.Tags T
	JOIN STRING_SPLIT(@TagIDs,',') ss ON ss.value = T.TagID
)
SELECT * 
FROM dbo.Instances I
WHERE EXISTS(SELECT 1
			FROM T
			JOIN dbo.InstanceTags IT ON IT.TagID = T.TagID
			WHERE IT.Instance = I.Instance
			GROUP BY IT.Instance
			HAVING COUNT(DISTINCT T.TagName) = (SELECT COUNT(DISTINCT TagName) FROM T)
			UNION ALL
			SELECT 1
			FROM T
			JOIN dbo.InstanceIDsTags IT ON IT.TagID = T.TagID
			WHERE IT.InstanceID = I.InstanceID
			GROUP BY IT.InstanceID
			HAVING COUNT(DISTINCT T.TagName) = (SELECT COUNT(DISTINCT TagName) FROM T)
			)
AND @TagIDs IS NOT NULL AND @TagIDs <> '' AND @TagIDs<>'-1'
UNION ALL
SELECT * 
FROM dbo.Instances
WHERE @TagIDs IS NULL OR @TagIDs='' OR @TagIDs='-1'
GO
PRINT N'Creating Function [dbo].[MillisecondsToHumanDuration]...';


GO
CREATE FUNCTION dbo.MillisecondsToHumanDuration (
    @ms BIGINT
)
RETURNS TABLE
AS
RETURN SELECT CASE WHEN @ms IS NULL THEN '' WHEN ABS(@ms)>=8640000000 THEN CONCAT(@ms/86400000,' Days') ELSE
				CONCAT(
						CASE WHEN @ms<0 THEN '-' ELSE '' END,
                        RIGHT('00' + CAST(ISNULL((ABS(@ms) / 3600000 / 24), 0) AS VARCHAR(2)), 2), ' ',
                        RIGHT('00' + CAST(ISNULL(ABS(@ms) / 3600000 % 24, 0) AS VARCHAR(2)), 2), ':',
                        RIGHT('00' + CAST(ISNULL(ABS(@ms) / 60000 % 60, 0) AS VARCHAR(2)), 2), ':',
                        RIGHT('00' + CAST(ISNULL(ABS(@ms) / 1000 % 3600 % 60, 0) AS VARCHAR(2)), 2) + '.',
						RIGHT('000' + CAST(ISNULL(ABS(@ms) % 1000, 0) AS VARCHAR(3)), 3) 
                    )
				END AS HumanDuration;
GO
