CREATE FUNCTION ParseFileName(@FileName AS NVARCHAR(1024))
RETURNS TABLE
AS
RETURN
SELECT  RIGHT(@FileName,ISNULL(NULLIF(CHARINDEX('\',REVERSE(@FileName))-1,-1),LEN(@FileName))) AS FileName
