PRINT N'Creating Function [dbo].[ParseInstanceMetadata]...';


GO
CREATE FUNCTION dbo.ParseInstanceMetadata(
	@Metadata NVARCHAR(MAX)
)
RETURNS TABLE
AS
RETURN 
SELECT 	JSON_VALUE(@Metadata,'$.compute.name') AS Name,
		ISNULL(JSON_VALUE(@Metadata,'$.compute.vmSize'),JSON_VALUE(@Metadata,'$.instanceType')) AS VMSize,
		JSON_VALUE(@Metadata,'$.compute.sku') AS SKU,
		JSON_VALUE(@Metadata,'$.compute.resourceGroupName') AS ResourceGroup,
		ISNULL(JSON_VALUE(@Metadata,'$.privateIp'), STUFF((SELECT ',' + NULLIF(JSON_VALUE(ipConfig.value, '$.privateIpAddress'),'') 
			FROM OPENJSON(@Metadata, '$.network.interface') AS networkInterface 
			CROSS APPLY OPENJSON(networkInterface.value, '$.ipv4.ipAddress') AS ipConfig
			FOR XML PATH(''),TYPE
   			).value('.','NVARCHAR(MAX)'),1,1,'')) AS PrivateIPs,
		STUFF((SELECT ',' + NULLIF(JSON_VALUE(ipConfig.value, '$.publicIpAddress'),'') 
			FROM OPENJSON(@Metadata, '$.network.interface') AS networkInterface 
			CROSS APPLY OPENJSON(networkInterface.value, '$.ipv4.ipAddress') AS ipConfig
			FOR XML PATH(''),TYPE
   			).value('.','NVARCHAR(MAX)'),1,1,'') AS PublicIPs,
		STUFF((SELECT  ', ' + IPs.value
			FROM OPENJSON(@Metadata,'$.IPAddresses') AS IPs
			FOR XML PATH(''),TYPE
			).value('.','NVARCHAR(MAX)'),1,2,'') IPAddresses,
		ISNULL(JSON_VALUE(@Metadata,'$.compute.tags'),
			STUFF((SELECT ', ' +  [key] +':' + value
			FROM OPENJSON(@Metadata,'$.Tags') tags
			FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,2,'')
		) AS Tags,
		JSON_VALUE(@Metadata,'$.accountId') AS AccountID,
		JSON_VALUE(@Metadata,'$.compute.subscriptionId') AS SubscriptionID,
		ISNULL(JSON_VALUE(@Metadata,'$.compute.location'),JSON_VALUE(@Metadata,'$.region')) AS Location,
		JSON_VALUE(@Metadata,'$.availabilityZone') AS AvailabilityZone,
		JSON_VALUE(@Metadata,'$.imageId') AS ImageID,
		JSON_VALUE(@Metadata,'$.instanceId') AS AWSInstanceID,
		JSON_VALUE(@Metadata,'$.VMHostName') AS VMHostName,
		JSON_VALUE(@Metadata,'$.IamRole') AS IAMRole,
		STUFF((SELECT  ', ' + G.value
			FROM OPENJSON(@Metadata,'$.SecurityGroups') AS G
			FOR XML PATH(''),TYPE
			).value('.','NVARCHAR(MAX)'),1,2,'') SecurityGroups,
		JSON_VALUE(@Metadata,'$.LocalHostname') AS LocalHostname,
				STUFF((SELECT  ', ' + BP.value
			FROM OPENJSON(@Metadata,'$.billingProducts') AS BP
			FOR XML PATH(''),TYPE
			).value('.','NVARCHAR(MAX)'),1,2,'') BillingProducts,
		JSON_VALUE(@Metadata,'$.ClusterIP') AS ClusterIP,
		JSON_VALUE(@Metadata,'$.ClusterName') AS ClusterName
GO
PRINT N'Creating Function [dbo].[PerformanceCountersBetweenDates]...';


GO
CREATE FUNCTION dbo.PerformanceCountersBetweenDates(
	@FromDate DATETIME2(7),
	@ToDate DATETIME2(7),
	@InstanceID INT,
	@CounterID INT,
	@CounterType TINYINT
)
RETURNS TABLE
AS
RETURN
SELECT	PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate,
		PC.Value
FROM dbo.PerformanceCounters PC
WHERE @CounterType = 1
AND PC.SnapshotDate >= CAST(@FromDate AS DATETIME2(2)) /* Important that date type matches for performance */
AND PC.SnapshotDate < CAST(@ToDate AS DATETIME2(2)) /* Important that date type matches for performance */
AND PC.InstanceID = @InstanceID
AND PC.CounterID = @CounterID
UNION ALL
/* Running Queries performance counters. No 60 MIN aggregation available so fake schema. */
SELECT	RQPC.InstanceID,
		RQPC.CounterID,
		RQPC.SnapshotDate,
		RQPC.Value
FROM dbo.RunningQueriesPerformanceCounters RQPC
WHERE @CounterType = 2
AND RQPC.SnapshotDate >= @FromDate 
AND RQPC.SnapshotDate < @ToDate
AND RQPC.InstanceID = @InstanceID
AND RQPC.CounterID = @CounterID
UNION ALL
/* Azure DB Elastic Pool Resource Stats performance counters. */
SELECT	PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate,
		PC.value
FROM dbo.AzureDBElasticPoolResourceStatsCounters PC
WHERE @CounterType = 3
AND PC.SnapshotDate >= @FromDate
AND PC.SnapshotDate < @ToDate
AND PC.InstanceID = @InstanceID
AND PC.CounterID = @CounterID
UNION ALL
/* Azure DB Resource Stats performance counters. */
SELECT	PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate,
		PC.value
FROM dbo.AzureDBResourceStatsCounters PC
WHERE @CounterType = 4
AND PC.SnapshotDate >= CAST(@FromDate AS DATETIME2(3))
AND PC.SnapshotDate < CAST(@ToDate AS DATETIME2(3))
AND PC.InstanceID = @InstanceID
AND PC.CounterID = @CounterID
GO
PRINT N'Creating Function [dbo].[PerformanceCountersBetweenDates_60MIN]...';


GO
CREATE FUNCTION dbo.PerformanceCountersBetweenDates_60MIN(
	@FromDate DATETIME2(7),
	@ToDate DATETIME2(7),
	@InstanceID INT,
	@CounterID INT,
	@CounterType TINYINT
)
RETURNS TABLE
AS
RETURN
/* Standard performance counters*/
SELECT	PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate,
		PC.Value_Total,
		PC.Value_Min,
		PC.Value_Max,
		PC.SampleCount
FROM dbo.PerformanceCounters_60MIN PC
WHERE @CounterType = 1
AND PC.SnapshotDate >= CAST(@FromDate AS DATETIME2(2))
AND PC.SnapshotDate < CAST(@ToDate AS DATETIME2(2))
AND PC.InstanceID = @InstanceID
AND PC.CounterID = @CounterID
UNION ALL
/* Running Queries performance counters. No 60 MIN aggregation available so fake schema. */
SELECT	RQPC.InstanceID,
		RQPC.CounterID,
		RQPC.SnapshotDate,
		RQPC.Value AS Value_Total,
		RQPC.Value AS Value_Min,
		RQPC.Value AS Value_Max,
		1 AS SampleCount
FROM dbo.RunningQueriesPerformanceCounters RQPC
WHERE @CounterType = 2
AND RQPC.SnapshotDate >= @FromDate 
AND RQPC.SnapshotDate < @ToDate
AND RQPC.InstanceID = @InstanceID
AND RQPC.CounterID = @CounterID
UNION ALL
/* Azure DB Elastic Pool Resource Stats performance counters. */
SELECT	PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate,
		PC.value*SampleCount AS Value_Total,
		NULL AS Value_Min,
		PC.max_value AS Value_Max,
		PC.SampleCount
FROM dbo.AzureDBElasticPoolResourceStatsCounters_60MIN PC
WHERE @CounterType = 3
AND PC.SnapshotDate >= CAST(@FromDate AS DATETIME2(3))
AND PC.SnapshotDate < CAST(@ToDate AS DATETIME2(3))
AND PC.InstanceID = @InstanceID
AND PC.CounterID = @CounterID
UNION ALL
/* Azure DB Resource Stats performance counters. */
SELECT	PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate,
		PC.value*SampleCount AS Value_Total,
		NULL AS Value_Min,
		PC.max_value AS Value_Max,
		PC.SampleCount
FROM dbo.AzureDBResourceStatsCounters_60MIN PC
WHERE @CounterType = 4
AND PC.SnapshotDate >= CAST(@FromDate AS DATETIME2(3))
AND PC.SnapshotDate < CAST(@ToDate AS DATETIME2(3))
AND PC.InstanceID = @InstanceID
AND PC.CounterID = @CounterID
GO
PRINT N'Creating Function [dbo].[RunningQueriesBlockingHierarchy]...';


GO
CREATE FUNCTION dbo.RunningQueriesBlockingHierarchy(
	@InstanceID INT,
	@SnapshotDateUTC DATETIME2(7),
	@BlockingSessionID SMALLINT
)
RETURNS TABLE
AS
RETURN
/* 
	Get the blocking hierarchy for a blocked session starting with the current blocking session  
	For example session 123 might be blocked by session 64.  Session 64 is blocked by session 72.  Session 72 is blocked by session 96 (root blocker)
	We pass in 64 as the current blocking session and get: 96 \ 72 \ 64.  
*/
WITH  H AS(
	SELECT	@BlockingSessionID as blocking_session_id,
			0 as Sort,
			' \ ' + CAST(@BlockingSessionID AS VARCHAR(MAX)) AS BlockingHierarchy,
			0 AS IsDeadlock
	WHERE @BlockingSessionID<>0
	UNION ALL
	SELECT	Q.blocking_session_id,
			H.Sort+1,
			CASE WHEN calc.IsDeadlock =1 THEN ' \ {!Deadlock!}' ELSE '' END + ' \ ' + CAST(Q.blocking_session_id AS VARCHAR(MAX)) + H.BlockingHierarchy,
			calc.IsDeadlock
	FROM H 
	JOIN dbo.RunningQueries Q ON H.blocking_session_id = Q.session_id
	-- Check for a loop (deadlock).  Break execution on the next iteration when a deadlock is detected
	OUTER APPLY(SELECT CASE WHEN Q.blocking_session_id = @BlockingSessionID OR H.BlockingHierarchy LIKE '%\ ' + CAST(Q.blocking_session_id AS VARCHAR(MAX)) + ' \%' THEN 1 ELSE 0 END AS IsDeadlock) calc
	WHERE Q.InstanceID = @InstanceID
	AND Q.SnapshotDateUTC = @SnapshotDateUTC
	AND Q.blocking_session_id <> 0
	AND H.IsDeadlock=0 -- Stop if a deadlock was detected on the previous loop
	AND H.Sort < 100 -- Stop before we break max recursion
	)
SELECT TOP(1) ISNULL(STUFF(BlockingHierarchy,1,3,''),'')  as BlockingHierarchy
FROM H
ORDER BY Sort DESC
GO
PRINT N'Creating Function [dbo].[RunningQueriesBlockingRecursiveStats]...';


GO
CREATE FUNCTION dbo.RunningQueriesBlockingRecursiveStats(
	@InstanceID INT,
	@SnapshotDateUTC DATETIME2,
	@session_id SMALLINT
)
RETURNS TABLE 
AS
RETURN
WITH R AS (
	SELECT Q.session_id, Q.wait_time,1 AS IsDirect
	FROM dbo.RunningQueries Q
	WHERE Q.InstanceID = @InstanceID
	AND Q.blocking_session_id=@session_id 
	AND Q.SnapshotDateUTC = @SnapshotDateUTC
	UNION ALL
	SELECT RQ.session_id, RQ.wait_time,0 AS IsDirect
	FROM R 
	JOIN dbo.RunningQueries RQ ON RQ.blocking_session_id = R.session_id
	WHERE RQ.session_id<>@session_id
	AND RQ.InstanceID = @InstanceID
	AND RQ.SnapshotDateUTC = @SnapshotDateUTC
)
SELECT COUNT(*) BlockCountRecursive, 
	ISNULL(SUM(CAST(R.wait_time AS BIGINT)),0) BlockWaitTimeRecursiveMs,
	ISNULL(SUM(R.IsDirect),0) AS BlockCount,
	ISNULL(SUM(CASE WHEN R.IsDirect=1 THEN CAST(R.wait_time AS BIGINT) ELSE 0 END),0) AS BlockWaitTimeMs
FROM R
GO
PRINT N'Creating Function [dbo].[SecondsToHumanDuration]...';


GO
CREATE FUNCTION dbo.SecondsToHumanDuration (
    @Seconds BIGINT
)
RETURNS TABLE
AS
RETURN SELECT CASE WHEN @Seconds IS NULL THEN '' WHEN ABS(@Seconds)>=8640000 THEN CONCAT(@Seconds/86400,' Days') ELSE
				CONCAT(
						CASE WHEN @Seconds<0 THEN '-' ELSE '' END,
                        RIGHT('00' + CAST(ISNULL((ABS(@Seconds) / 3600 / 24), 0) AS VARCHAR(2)), 2), ' ',
                        RIGHT('00' + CAST(ISNULL(ABS(@Seconds) / 3600 % 24, 0) AS VARCHAR(2)), 2), ':',
                        RIGHT('00' + CAST(ISNULL(ABS(@Seconds) / 60 % 60, 0) AS VARCHAR(2)), 2), ':',
                        RIGHT('00' + CAST(ISNULL(ABS(@Seconds) % 3600 % 60, 0) AS VARCHAR(2)), 2)
                    )
				END AS HumanDuration;
GO
