		CASE WHEN DTU.avg_dtu_percent>=30 AND DTU.avg_dtu_percent<40 THEN 1 ELSE 0 END AS DTU40,
		CASE WHEN DTU.avg_dtu_percent>=40 AND DTU.avg_dtu_percent<50 THEN 1 ELSE 0 END AS DTU50,
