		CASE WHEN RS.avg_log_write_percent >=70 AND RS.avg_log_write_percent <80 THEN 1 ELSE 0 END AS Log80,
		CASE WHEN RS.avg_log_write_percent >=80 AND RS.avg_log_write_percent <90 THEN 1 ELSE 0 END AS Log90,
		CASE WHEN RS.avg_log_write_percent >= 90 THEN 1 ELSE 0 END AS Log100
FROM dbo.AzureDBResourceStats RS
CROSS APPLY dbo.DateGroupingMins(RS.end_time,60) DG
OUTER APPLY(SELECT 	CASE WHEN dtu_limit>0 THEN (SELECT Max(value.v) FROM (VALUES (avg_cpu_percent), (avg_data_io_percent), (avg_log_write_percent)) AS value(v)) ELSE NULL END AS [avg_dtu_percent],
					CASE WHEN dtu_limit>0 THEN ((dtu_limit)*((SELECT Max(value.v) FROM (VALUES (avg_cpu_percent), (avg_data_io_percent), (avg_log_write_percent)) AS value(v))/100.00)) ELSE NULL END AS [avg_dtu]
			) AS DTU
