CREATE VIEW dbo.InstanceInfo
AS
SELECT I.InstanceID,
	I.Instance,
	I.ConnectionID,
    I.MachineName,
	I.ComputerNamePhysicalNetBIOS,
	I.ServerName,
	I.InstanceName,
	I.ActivePowerPlanGUID,
    I.ActivePowerPlan,
    I.ProcessorNameString,
    I.SystemManufacturer,
    I.SystemProductName,
	I.physical_memory_kb,
	I.physical_memory_kb/POWER(1024.0,2) PhysicalMemoryGB,
	CAST(maxmem.value AS BIGINT) BufferPoolMB, 
	CASE WHEN CAST(maxmem.value AS BIGINT)*1024 > I.physical_memory_kb THEN 1.0 ELSE CAST(maxmem.value AS BIGINT) / (I.physical_memory_kb/1024.0) END AS  PctMemoryAllocatedToBufferPool,
	CASE WHEN CAST(maxmem.value AS BIGINT)*1024 > I.physical_memory_kb THEN 0.0 ELSE ((I.physical_memory_kb/1024)-CAST(maxmem.value AS BIGINT)) / 1024.0 END AS MemoryNotAllocatedToBufferPoolGB,
    I.sql_memory_model,	  
   	CASE I.sql_memory_model WHEN 1 THEN 'CONVENTIONAL' WHEN 2 THEN 'LOCK_PAGES' WHEN 3 THEN 'LARGE_PAGES' ELSE NULL END AS sql_memory_model_desc,
	I.OfflineSchedulers,
    I.affinity_type,
	CASE I.affinity_type WHEN 1 THEN 'MANUAL' WHEN 2 THEN 'AUTO' ELSE NULL END AS affinity_type_desc,
    I.cores_per_socket,
	I.socket_count,
	I.cores_per_socket*I.socket_count AS cpu_core_count,
	I.cpu_count/I.hyperthread_ratio AS physical_cpu_count,
    I.cpu_count,
    I.hyperthread_ratio,
	I.numa_node_count,
    I.softnuma_configuration,
	CASE I.softnuma_configuration WHEN 0 THEN 'OFF' WHEN 1 THEN 'ON' WHEN 2 THEN 'MANUAL' ELSE NULL END AS softnuma_configuration_desc,
    I.ms_ticks,
	I.ms_ticks/60000 host_up_time_mins,
	DATEADD(s,-I.ms_ticks/1000,os.SnapshotDate) AS host_start_time,
	I.sqlserver_start_time,
    I.os_priority_class,
	CASE I.os_priority_class WHEN 32 THEN 'NORMAL' WHEN 128 THEN 'HIGH' ELSE NULL END AS os_priority_class_desc,
    I.max_workers_count,
    I.scheduler_count,
    I.BuildClrVersion,
	I.LicenseType,
    I.NumLicenses,
    I.ProductBuild,
    I.ProductBuildType,
    I.ProductLevel,
    I.ProductMajorVersion,
    I.ProductUpdateLevel,
    I.ProductUpdateReference,
    I.ProductVersion,
	I.Edition,
    I.EditionID,
    I.EngineEdition,
	I.ResourceLastUpdateDateTime,
    I.ResourceVersion,
	v.SQLVersionName + ' ' + ISNULL(I.Edition + ' ','') + 
						ISNULL(I.ProductLevel + ' ','') + ISNULL(I.ProductUpdateLevel,'') AS SQLVersion,
    I.Collation,
    I.CollationID,
    I.ComparisonStyle,
	I.LCID,
    I.SqlCharSet,
    I.SqlCharSetName,
    I.SqlSortOrder,
    I.SqlSortOrderName,
    I.FileStreamConfiguredLevel,
    I.FileStreamEffectiveLevel,
    I.FileStreamShareName,
    I.HadrManagerStatus,
    I.InstanceDefaultDataPath,
    I.InstanceDefaultLogPath,
    I.IsAdvancedAnalyticsInstalled,
    I.IsClustered,
    I.IsFullTextInstalled,
    I.IsHadrEnabled,
    I.IsIntegratedSecurityOnly,
    I.IsLocalDB,
    I.IsPolybaseInstalled,
    I.IsXTPSupported,
    I.IsAgentRunning,
    I.InstantFileInitializationEnabled,
    A.AgentHostName,
	I.WindowsCaption,
	I.host_platform,
	I.host_distribution,
	I.host_release,
	I.host_service_pack_level,
	I.host_sku,
    I.os_language_version,
	I.host_sku as WindowsSKU,
    I.host_service_pack_level as WindowsSP,
    I.host_release as WindowsRelease,
	I.IsActive,
	DATEDIFF(mi,DATEADD(mi,I.UTCOffset,I.sqlserver_start_time),os.SnapshotDate) AS sqlserver_uptime,
	CASE WHEN tDB.value_in_use=1 AND tDB.value=1 THEN CAST(1 AS BIT) WHEN tDB.configuration_id=1589 THEN CAST(0 AS BIT) ELSE NULL END AS IsTempDBMetadataMemoryOptimized,
	CASE WHEN I.EditionID=1674378470 -- AzureDB or Azure Managed Instance
            THEN 170 ELSE TRY_CAST(I.ProductMajorVersion AS INT)*10 END AS MaxSupportedCompatibilityLevel,
    I.InstanceDisplayName,
    I.ShowInSummary,
    I.InstanceGroupName,
    I.ProductMinorVersion,
    I.ProductRevision,
    CASE    /* 2008-2014 advice.  Note: We will only know the NUMA node count on SQL 2014 and later.  */
			WHEN I.ProductMajorVersion<=12 AND ISNULL(I.numa_node_count,1)=1 AND I.cpu_count <=8 THEN I.cpu_count /* Server with single NUMA node.  Less than or equal to eight logical processors	Keep MAXDOP at or below # of logical processors */
			WHEN I.ProductMajorVersion<=12 AND ISNULL(I.numa_node_count,1)=1 AND I.cpu_count>8 THEN 8 /* Server with single NUMA node	Greater than eight logical processors	Keep MAXDOP at 8 */
			WHEN I.ProductMajorVersion<=12 AND I.numa_node_count>1 AND I.cpu_count/I.numa_node_count <=8 THEN I.cpu_count/I.numa_node_count /* Server with multiple NUMA nodes. Less than or equal to eight logical processors per NUMA node	Keep MAXDOP at or below # of logical processors per NUMA node*/
			WHEN I.ProductMajorVersion<=12 AND I.numa_node_count>1 AND I.cpu_count/I.numa_node_count > 8 THEN 8 /* Server with multiple NUMA nodes. Greater than eight logical processors per NUMA node	Keep MAXDOP at 8*/
                      
			/* 2016 + advice */
			WHEN I.ProductMajorVersion>12 AND I.numa_node_count=1 AND I.cpu_count <=8 THEN I.cpu_count /* Server with single NUMA node.  Less than or equal to eight logical processors	Keep MAXDOP at or below # of logical processors */
			WHEN I.ProductMajorVersion>12 AND I.numa_node_count=1 AND I.cpu_count>8 THEN 8 /* Server with single NUMA node	Greater than eight logical processors	Keep MAXDOP at 8 */
			WHEN I.ProductMajorVersion>12 AND I.numa_node_count>1 AND I.cpu_count/I.numa_node_count <=16 THEN I.cpu_count/I.numa_node_count /* Server with multiple NUMA nodes	Less than or equal to 16 logical processors per NUMA node	Keep MAXDOP at or below # of logical processors per NUMA node */
			WHEN I.ProductMajorVersion>12 AND I.numa_node_count>1 AND I.cpu_count/I.numa_node_count > 16 AND I.cpu_count/I.numa_node_count * 0.5 > 16 THEN 16 /* Server with multiple NUMA nodes	Greater than 16 logical processors per NUMA node	Keep MAXDOP at half the number of logical processors per NUMA node with a MAX value of 16 */
			WHEN I.ProductMajorVersion>12 AND I.numa_node_count>1 AND I.cpu_count/I.numa_node_count > 16 AND I.cpu_count/I.numa_node_count * 0.5 <= 16 THEN CAST(I.cpu_count/I.numa_node_count*0.5 AS INT) /* Server with multiple NUMA nodes	Greater than 16 logical processors per NUMA node	Keep MAXDOP at half the number of logical processors per NUMA node with a MAX value of 16 */
		ELSE NULL END AS MaxRecommendedMaxDOP,
	1 AS MinRecommendedMaxDOP,
    I.IsWindowsUpdate
FROM dbo.Instances I
LEFT JOIN dbo.DBADashAgent A ON I.CollectAgentID = A.DBADashAgentID
CROSS APPLY dbo.SQLVersionName(I.EditionID,I.ProductVersion) v
LEFT JOIN dbo.SysConfig maxmem ON maxmem.InstanceID = I.InstanceID AND maxmem.configuration_id=1544 
LEFT JOIN dbo.CollectionDates os ON os.InstanceID = I.InstanceID AND os.Reference='OSInfo'
LEFT JOIN dbo.SysConfig tDB ON tDB.InstanceID = i.InstanceID AND tDB.configuration_id=1589
GO
PRINT N'Creating View [dbo].[LastBackup]...';


GO
CREATE VIEW dbo.LastBackup
AS
/*
	App currently only collects the last backup of each type.  This view is to take availability groups into consideration
*/
WITH hadr AS (
	SELECT D.DatabaseID,
		partnr.DatabaseID BackupDatabaseID,
		partnr.DatabaseID PartnerDatabaseID,
        D.InstanceID
	FROM dbo.Databases D
	JOIN dbo.DatabasesHADR hadr ON D.DatabaseID = hadr.DatabaseID
	JOIN dbo.DatabasesHADR partnr ON hadr.group_database_id = partnr.group_database_id AND D.DatabaseID <> partnr.DatabaseID 
	WHERE hadr.is_local=1
	AND partnr.is_local=1
	UNION ALL
	SELECT D.DatabaseID,
		D.DatabaseID,
		NULL as PartnerDatabaseID,
        D.InstanceID
	FROM dbo.Databases D
),
LastBackup AS (
	SELECT  hadr.InstanceID,
            hadr.DatabaseID,
            B.type,
            B.backup_type_desc,
            B.backup_start_date,
            B.backup_finish_date,
            B.backup_set_id,
            B.time_zone,
            B.backup_size,
            B.is_password_protected,
            B.recovery_model,
            B.has_bulk_logged_data,
            B.is_snapshot,
            B.is_readonly,
            B.is_single_user,
            B.has_backup_checksums,
            B.is_damaged,
            B.has_incomplete_metadata,
            B.is_force_offline,
            B.is_copy_only,
            B.database_guid,
            B.family_guid,
            B.compressed_backup_size,
            B.key_algorithm,
            B.encryptor_type,
            B.backup_start_date_utc,
            B.backup_finish_date_utc,
            B.BackupDurationSec,
            B.BackupDuration,
            B.BackupMBsec,
            B.BackupWriteMBsec,
            B.IsCompressed,
            B.BackupSizeGB,
            B.BackupSizeCompressedGB,
            B.CompressionSavingPct,
			B.IsEncrypted,
			CASE WHEN hadr.PartnerDatabaseID IS NULL THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS IsPartnerBackup,
			hadr.PartnerDatabaseID,
            B.compression_algorithm,
			ROW_NUMBER() OVER(PARTITION BY hadr.DatabaseID,B.type ORDER BY B.backup_start_date_utc DESC) rnum
	FROM dbo.BackupStats B
	JOIN hadr ON hadr.BackupDatabaseID = B.DatabaseID
    OUTER APPLY(SELECT TOP(1) T.ConsiderCopyOnlyBackups,
                              T.ConsiderSnapshotBackups
			FROM dbo.BackupThresholds T 
			WHERE (hadr.InstanceID = T.InstanceID OR T.InstanceID = -1)
			AND (hadr.DatabaseID = T.DatabaseID  OR T.DatabaseID = -1)
			ORDER BY T.InstanceID DESC,T.DatabaseID DESC
			) AS TH
    WHERE NOT(TH.ConsiderCopyOnlyBackups=0 AND B.is_copy_only=1)
    AND NOT(TH.ConsiderSnapshotBackups=0 AND B.is_snapshot=1)
)
SELECT B.DatabaseID,
       B.type,
       B.backup_type_desc,
       B.backup_start_date,
       B.backup_finish_date,
       B.backup_set_id,
       B.time_zone,
       B.backup_size,
       B.is_password_protected,
       B.recovery_model,
       B.has_bulk_logged_data,
       B.is_snapshot,
       B.is_readonly,
       B.is_single_user,
       B.has_backup_checksums,
       B.is_damaged,
       B.has_incomplete_metadata,
       B.is_force_offline,
       B.is_copy_only,
       B.database_guid,
       B.family_guid,
       B.compressed_backup_size,
       B.key_algorithm,
       B.encryptor_type,
       B.backup_start_date_utc,
       B.backup_finish_date_utc,
       B.BackupDurationSec,
       B.BackupDuration,
       B.BackupMBsec,
       B.BackupWriteMBsec,
       B.IsCompressed,
       B.BackupSizeGB,
       B.BackupSizeCompressedGB,
       B.CompressionSavingPct,
	   B.IsEncrypted,
	   B.IsPartnerBackup,
	   B.PartnerDatabaseID,
       B.compression_algorithm
FROM LastBackup B
WHERE rnum=1
GO
PRINT N'Creating View [dbo].[LogShippingStatus]...';


GO
CREATE VIEW dbo.LogShippingStatus
AS
SELECT I.InstanceID,
	D.DatabaseID,
	I.Instance,
	I.InstanceDisplayName,
	D.name,
	LR.restore_date,
	utc.restore_date_utc,
	LR.backup_start_date,
	utc.backup_start_date_utc,
	l.TimeSinceLast,
	TimeSinceLastHD.HumanDuration AS TimeSinceLastDuration,
	l.LatencyOfLast,
	LatencyOfLastHD.HumanDuration as LatencyOfLastDuration,
	l.TotalTimeBehind,
	TotalTimeBehindHD.HumanDuration AS TotalTimeBehindDuration,
	l.SnapshotAge,
	SnapshotAgeHD.HumanDuration AS SnapshotAgeDuration,
	SSD.SnapshotDate,
	SSD.Status AS SnapshotAgeStatus,
	chk.Status,
	CASE WHEN utc.create_date_utc > DATEADD(mi,-cfg.NewDatabaseExcludePeriodMin,GETUTCDATE()) THEN 'N/A (New Database)' WHEN chk.Status = 1 THEN 'Critical' WHEN chk.Status = 2 THEN 'Warning' WHEN chk.Status = 3 THEN 'N/A' WHEN chk.Status = 4 THEN 'OK' ELSE 'N/A' END AS StatusDescription,
	LR.last_file,
	D.state_desc,
	CASE WHEN cfg.InstanceID=D.InstanceID AND cfg.DatabaseID=D.DatabaseID THEN 'Database' WHEN cfg.InstanceID = D.InstanceID THEN 'Instance' ELSE 'Root' END AS ThresholdConfiguredLevel,
	I.ShowInSummary
FROM dbo.Instances I 
JOIN dbo.Databases D ON I.InstanceID = D.InstanceID
JOIN dbo.CollectionDatesStatus SSD ON SSD.InstanceID = I.InstanceID AND SSD.Reference='LogRestores'
LEFT JOIN dbo.LogRestores LR ON LR.DatabaseID = D.DatabaseID AND LR.InstanceID = D.InstanceID
OUTER APPLY(SELECT TOP(1) T.* 
			FROM dbo.LogRestoreThresholds T 
			WHERE (D.InstanceID = T.InstanceID OR T.InstanceID = -1)
			AND (D.DatabaseID = T.DatabaseID  OR T.DatabaseID = -1)
			ORDER BY InstanceID DESC,DatabaseID DESC
			) cfg
OUTER APPLY(SELECT DATEADD(mi,ISNULL(NULLIF(-LR.backup_time_zone,127)*15,I.UTCOffset),LR.backup_start_date) AS backup_start_date_utc,
				DATEADD(mi,I.UTCOffset,LR.restore_date) AS restore_date_utc,
				DATEADD(mi,I.UTCOffset,D.create_date) AS create_date_utc
				) AS utc
OUTER APPLY(SELECT DATEDIFF_BIG(s,utc.restore_date_utc,GETUTCDATE())/60.0 AS TimeSinceLast,
					DATEDIFF_BIG(s,utc.backup_start_date_utc,restore_date_utc)/60.0 AS LatencyOfLast,
					DATEDIFF_BIG(s,utc.backup_start_date_utc,GETUTCDATE())/60.0 AS TotalTimeBehind,
					DATEDIFF_BIG(s,SSD.SnapshotDate,GETUTCDATE())/60.0 AS SnapshotAge) l
OUTER APPLY dbo.SecondsToHumanDuration(l.TimeSinceLast*60.0) AS TimeSinceLastHD
OUTER APPLY dbo.SecondsToHumanDuration(l.LatencyOfLast*60.0) AS LatencyOfLastHD
OUTER APPLY dbo.SecondsToHumanDuration(l.TotalTimeBehind*60.0) AS TotalTimeBehindHD
OUTER APPLY dbo.SecondsToHumanDuration(l.SnapshotAge*60.0) AS SnapshotAgeHD
OUTER APPLY(SELECT CASE WHEN utc.create_date_utc > DATEADD(mi,-cfg.NewDatabaseExcludePeriodMin,GETUTCDATE()) THEN 3
	WHEN l.TimeSinceLast >cfg.TimeSinceLastCriticalThreshold THEN 1
	WHEN l.TimeSinceLast IS NULL AND cfg.TimeSinceLastCriticalThreshold IS NOT NULL THEN 1
	WHEN l.LatencyOfLast IS NULL AND cfg.LatencyCriticalThreshold IS NOT NULL THEN 1
	WHEN l.LatencyOfLast > cfg.LatencyCriticalThreshold THEN 1
	WHEN l.TimeSinceLast >cfg.TimeSinceLastWarningThreshold THEN 2
	WHEN l.LatencyOfLast > cfg.LatencyWarningThreshold THEN 2
	WHEN cfg.LatencyCriticalThreshold IS NULL AND cfg.TimeSinceLastCriticalThreshold IS NULL AND cfg.LatencyWarningThreshold IS NULL AND cfg.TimeSinceLastWarningThreshold IS NULL  THEN 3
	ELSE 4 END AS Status) chk
WHERE (D.state =1 OR D.is_in_standby=1)
AND D.IsActive=1
AND I.IsActive=1
AND D.recovery_model<>3
AND NOT EXISTS(SELECT 1 FROM dbo.DatabaseMirroring DM WHERE DM.DatabaseID = D.DatabaseID AND DM.InstanceID = D.InstanceID)
GO
PRINT N'Creating View [dbo].[LogShippingStatusSummary]...';


GO
CREATE VIEW dbo.LogShippingStatusSummary 
AS
WITH Summary AS (
	SELECT LSS.InstanceID,
		   LSS.InstanceDisplayName,
		   MIN(LSS.Status) AS Status,
		   CASE MIN(LSS.Status) WHEN 1 THEN 'Critical' WHEN 2 THEN 'Warning' WHEN 3 THEN 'N/A' WHEN 4 THEN 'OK' ELSE 'N/A' END AS StatusDescription,
		   COUNT(*) AS LogShippedDBCount,
		   SUM(CASE WHEN LSS.Status=2 THEN 1 ELSE 0 END) AS WarningCount,
		   SUM(CASE WHEN LSS.Status=1 THEN 1 ELSE 0 END) AS CriticalCount,
		   MAX(LSS.TotalTimeBehind) MaxTotalTimeBehind,
		   MIN(LSS.TotalTimeBehind) MinTotalTimeBehind,
		   AVG(LSS.TotalTimeBehind) AvgTotalTimeBehind,
		   MAX(LSS.LatencyOfLast) MaxLatencyOfLast,
		   MIN(LSS.LatencyOfLast) MinLatencyOfLast,
		   AVG(LSS.LatencyOfLast) AvgLatencyOfLast,
		   MAX(LSS.TimeSinceLast) AS MaxTimeSinceLast,
		   MIN(LSS.TimeSinceLast) AS MinTimeSinceLast,
		   AVG(LSS.TimeSinceLast) AS AvgTimeSinceLast,
		   MAX(LSS.SnapshotAge) AS SnapshotAge,
		   ISNULL(MIN(NULLIF(LSS.SnapshotAgeStatus,3)),3) AS SnapshotAgeStatus,
		   MIN(LSS.backup_start_date_utc) MinDateOfLastBackupRestored,
		   MAX(LSS.backup_start_date_utc) MaxDateOfLastBackupRestored,
		   MIN(LSS.restore_date_utc) MinLastRestoreCompleted,
		   MAX(LSS.restore_date_utc) MaxLastRestoreCompleted,
		   CASE WHEN T.InstanceID IS NULL THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS InstanceLevelThreshold,
		   SUM(CASE WHEN LSS.ThresholdConfiguredLevel='Database' THEN 1 ELSE 0 END) AS DatabaseLevelThresholds,
		   LSS.ShowInSummary
	FROM dbo.LogShippingStatus LSS
	LEFT JOIN dbo.LogRestoreThresholds T ON LSS.InstanceID = T.InstanceID AND T.DatabaseID=-1
	WHERE LSS.Status<> 3
	GROUP BY LSS.InstanceID,
			 LSS.InstanceDisplayName,
			 T.InstanceID,
			 LSS.ShowInSummary
)
SELECT	InstanceID,
		InstanceDisplayName,
		Status,
		StatusDescription,
		LogShippedDBCount,
		WarningCount,
		CriticalCount,
		MaxTotalTimeBehind,
		MaxTotalTimeBehindHD.HumanDuration AS MaxTotalTimeBehindDuration,
		MinTotalTimeBehind,
		MinTotalTimeBehindHD.HumanDuration AS MinTotalTimeBehindDuration,
		AvgTotalTimeBehind,
		AvgTotalTimeBehindHD.HumanDuration AS AvgTotalTimeBehindDuration,
		MaxLatencyOfLast,
		MaxLatencyOfLastHD.HumanDuration AS MaxLatencyOfLastDuration,
		MinLatencyOfLast,
		MinLatencyOfLastHD.HumanDuration AS MinLatencyOfLastDuration,
		AvgLatencyOfLast,
		AvgLatencyOfLastHD.HumanDuration AS AvgLatencyOfLastDuration,
		MaxTimeSinceLast,
		MaxTimeSinceLastHD.HumanDuration AS MaxTimeSinceLastDuration,
		MinTimeSinceLast,
		MinTimeSinceLastHD.HumanDuration AS MinTimeSinceLastDuration,
		AvgTimeSinceLast,
		AvgTimeSinceLastHD.HumanDuration AS AvgTimeSinceLastDuration,
		SnapshotAge,
		SnapshotAgeHD.HumanDuration AS SnapshotAgeDuration,
		SnapshotAgeStatus,
		MinDateOfLastBackupRestored,
		MaxDateOfLastBackupRestored,
		MinLastRestoreCompleted,
		MaxLastRestoreCompleted,
		InstanceLevelThreshold,
		DatabaseLevelThresholds,
		ShowInSummary
FROM Summary
OUTER APPLY dbo.SecondsToHumanDuration(MaxTimeSinceLast*60.0) AS MaxTimeSinceLastHD
OUTER APPLY dbo.SecondsToHumanDuration(MinTimeSinceLast*60.0) AS MinTimeSinceLastHD
OUTER APPLY dbo.SecondsToHumanDuration(AvgTimeSinceLast*60.0) AS AvgTimeSinceLastHD
OUTER APPLY dbo.SecondsToHumanDuration(MaxLatencyOfLast*60.0) AS MaxLatencyOfLastHD
OUTER APPLY dbo.SecondsToHumanDuration(MinLatencyOfLast*60.0) AS MinLatencyOfLastHD
OUTER APPLY dbo.SecondsToHumanDuration(AvgLatencyOfLast*60.0) AS AvgLatencyOfLastHD
OUTER APPLY dbo.SecondsToHumanDuration(MaxTotalTimeBehind*60.0) AS MaxTotalTimeBehindHD
OUTER APPLY dbo.SecondsToHumanDuration(MinTotalTimeBehind*60.0) AS MinTotalTimeBehindHD
OUTER APPLY dbo.SecondsToHumanDuration(AvgTotalTimeBehind*60.0) AS AvgTotalTimeBehindHD
OUTER APPLY dbo.SecondsToHumanDuration(SnapshotAge*60.0) AS SnapshotAgeHD
GO
PRINT N'Creating View [dbo].[RunningJobsInfo]...';


GO
CREATE VIEW dbo.RunningJobsInfo
AS
SELECT RJ.InstanceID,
		I.InstanceDisplayName,
		RJ.job_id,
		J.name AS job_name,
		RJ.current_execution_status,
		CASE	WHEN RJ.current_execution_status = 1 THEN '1. Executing'
				WHEN RJ.current_execution_status = 2 THEN '2. Waiting For Thread'
				WHEN RJ.current_execution_status = 3 THEN '3. Between Retries'
				WHEN RJ.current_execution_status = 4 THEN '4. Idle'
				WHEN RJ.current_execution_status = 5 THEN '5. Suspended'
				WHEN RJ.current_execution_status = 6 THEN '6. Obsolete'
				WHEN RJ.current_execution_status = 7 THEN '7. Performing Completion Actions'
				ELSE CONCAT(RJ.current_execution_status, '. Unknown') END AS current_execution_status_description,

		HD.HumanDuration AS RunningTime, /* How long has the job been running */
		HDAvg.HumanDuration AS AvgDuration, /* How long does the job usually take to run (Avg over 30 days) */
		JStats.AvgRunDurationSec, /* How long does the job usually take to run (Avg over 30 days) */
		HDMax.HumanDuration AS MaxDuration,	/* What's the max time the job took to run (over 30 days) */
		JStats.MaxRunDurationSec, /* What's the max time the job took to run (over 30 days) */
		DATEADD(s,JStats.AvgRunDurationSec,RJ.start_execution_date_utc) AS EstimatedCompletionTime, /* Estimated completion date based on average duration for this job */
		RJ.start_execution_date_utc, /* Job started */
		DATEDIFF(s,RJ.start_execution_date_utc,RJ.SnapshotDate) AS RunningTimeSec, /* How long job was running at time of data collection */
		
		/* Current Step */

		CASE WHEN RJ.current_execution_step_id IS NULL THEN '' ELSE CONCAT('(',RJ.current_execution_step_id,')  ',RJ.current_execution_step_name) END AS current_execution_step,
		RJ.current_execution_step_id,
		RJ.current_execution_step_name,
		RJ.current_retry_attempt,
		HDCurrentStep.HumanDuration AS CurrentStepDuration,
		H.CurrentStepRunDurationSec,

		/* Previous Step */
		CASE WHEN RJ.last_executed_step_id IS NULL THEN '' ELSE CONCAT('(',RJ.last_executed_step_id,')  ',JS.step_name) END AS last_executed_step,
		RJ.last_executed_step_id,
		JS.step_name AS last_executed_step_name,
		RJ.last_executed_step_date_utc AS LastStepStartDateUtc,
		H.LastStepFinishDateUtc,
		HDLastStep.HumanDuration AS LastStepDuration,
		H.LastStepRunDurationSec,
		
		/* Running Jobs collection info */
		HDSnapshot.HumanDuration AS TimeSinceSnapshot, 
		RJ.SnapshotDate,
		CDS.Status AS SnapshotAgeStatus

FROM dbo.RunningJobs RJ
JOIN dbo.Instances I ON RJ.InstanceID = I.InstanceID
LEFT JOIN dbo.Jobs J ON RJ.InstanceID = J.InstanceID AND J.job_id = RJ.job_id
LEFT JOIN dbo.JobSteps JS ON JS.InstanceID = RJ.InstanceID AND RJ.job_id = JS.job_id AND RJ.last_executed_step_id = JS.step_id
/* Get Avg and Max run times for this job over last 30 days */
OUTER APPLY(SELECT	SUM(JS.RunDurationSec)/NULLIF(SUM(JS.SucceededCount+JS.FailedCount),0) AvgRunDurationSec,
					MAX(JS.MaxRunDurationSec) MaxRunDurationSec
			FROM dbo.JobStats_60MIN JS
			WHERE JS.RunDateTime >= DATEADD(d,-30,GETUTCDATE())
			AND JS.InstanceID = RJ.InstanceID
			AND JS.job_id = RJ.job_id
			AND JS.step_id =0 /* result */
			) JStats

LEFT JOIN dbo.CollectionDatesStatus CDS ON CDS.InstanceID = RJ.InstanceID AND CDS.Reference = 'RunningJobs'
/* Find the last step in JobHistory table so we know it's finish time and we can calculate how long the current step has been running */
OUTER APPLY(SELECT TOP(1)	JH.FinishDateTime AS LastStepFinishDateUtc, 
							JH.RunDurationSec AS LastStepRunDurationSec,
							DATEDIFF_BIG(s,CASE WHEN RJ.last_executed_step_id IS NULL THEN RJ.start_execution_date_utc ELSE JH.FinishDateTime END,RJ.SnapshotDate) AS CurrentStepRunDurationSec
			FROM dbo.JobHistory JH 
			WHERE JH.InstanceID = RJ.InstanceID
			AND JH.job_id = RJ.job_id
			AND JH.FinishDateTime >= CAST(RJ.start_execution_date_utc AS DATETIME2(2))
			AND JH.FinishDateTime <= CAST(GETUTCDATE() AS DATETIME2(2))
			AND JH.RunDateTime >= CAST(RJ.start_execution_date_utc AS DATETIME2(2))
			AND JH.RunDateTime < CAST(GETUTCDATE() AS DATETIME2(2))
			AND JH.step_id = RJ.last_executed_step_id
			ORDER BY JH.RunDateTime DESC
			) AS H
CROSS APPLY dbo.SecondsToHumanDuration(H.CurrentStepRunDurationSec) HDCurrentStep
CROSS APPLY dbo.SecondsToHumanDuration(H.LastStepRunDurationSec) HDLastStep
CROSS APPLY dbo.SecondsToHumanDuration(JStats.AvgRunDurationSec) HDAvg
CROSS APPLY dbo.SecondsToHumanDuration(JStats.MaxRunDurationSec) HDMax
CROSS APPLY dbo.MillisecondsToHumanDuration(DATEDIFF_BIG(ms,RJ.start_execution_date_utc,RJ.SnapshotDate)) HD
CROSS APPLY dbo.MillisecondsToHumanDuration(DATEDIFF_BIG(ms,RJ.SnapshotDate,GETUTCDATE())) HDSnapshot
GO
PRINT N'Creating View [dbo].[RunningQueriesInfo]...';


GO
CREATE VIEW dbo.RunningQueriesInfo
AS
SELECT Q.InstanceID,
    I.InstanceDisplayName,
    HD.HumanDuration AS [Duration],
    QT.text AS batch_text,
	SUBSTRING(QT.text,ISNULL((NULLIF(Q.statement_start_offset,-1)/2)+1,0),ISNULL((NULLIF(NULLIF(Q.statement_end_offset,-1),0) - NULLIF(Q.statement_start_offset,-1))/2+1,2147483647)) AS text,
	CAST(DECOMPRESS(QP.query_plan_compresed) AS NVARCHAR(MAX)) query_plan,
	ISNULL(QT.object_id,QP.object_id) AS object_id,
	O.SchemaName + '.' +  O.ObjectName AS object_name,
    O.ObjectID AS DBADashObjectID,
    O.SchemaName,
    O.ObjectName,
    Q.SnapshotDateUTC,
    Q.session_id,
    Q.command,
    Q.status,
    Q.wait_time,
    Q.wait_type,
    sessionW.TopSessionWaits,
    Q.blocking_session_id,
    H.BlockingHierarchy,
    RQBRS.BlockCountRecursive, 
	RQBRS.BlockWaitTimeRecursiveMs,
    BlockWaitTimeRecursive.HumanDuration AS BlockWaitTimeRecursive,
	RQBRS.BlockCount,
    CASE WHEN RQBRS.BlockCount>0 AND Q.blocking_session_id=0 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsRootBlocker,
	RQBRS.BlockWaitTimeMs,
    BlockWaitTime.HumanDuration AS BlockWaitTime,
    Q.cpu_time,
    Q.logical_reads,
    Q.reads,
    Q.writes,
    Q.granted_query_memory*8 granted_query_memory_kb,
    Q.percent_complete,
    Q.open_transaction_count,
    CASE Q.transaction_isolation_level WHEN 0 THEN 'Unspecified'
        WHEN 1 THEN 'ReadUncomitted'
        WHEN 2 THEN 'ReadCommitted'
        WHEN 3 THEN 'Repeatable'
        WHEN 4 THEN 'Serializable'
        WHEN 5 THEN 'Snapshot'
        ELSE CAST(Q.transaction_isolation_level AS VARCHAR(30)) END AS transaction_isolation_level,
    Q.login_name,
    Q.host_name,
    Q.database_id,
    ISNULL(objD.name,D.name) AS database_name,
	CONCAT(D.name,', ' + NULLIF(objD.name,D.name))  AS database_names,
    Q.program_name,
    jid.job_id,
	J.name AS job_name,
    Q.client_interface_name,
    Q.start_time_utc,
    Q.last_request_start_time_utc,
    Q.last_request_end_time_utc,
    LastRequestDuration.HumanDuration as last_request_duration,
    CASE WHEN status = 'sleeping' THEN DATEDIFF_BIG(ms,Q.last_request_end_time_utc,Q.SnapshotDateUTC)/1000.0 ELSE NULL END AS sleeping_session_idle_time_sec,
    CASE WHEN status = 'sleeping' THEN TimeSinceLastRequestEnd.HumanDuration ELSE NULL END AS sleeping_session_idle_time,
    CONVERT(CHAR(90),Q.sql_handle,1) AS sql_handle,
    CONVERT(CHAR(90),Q.plan_handle,1) AS plan_handle,
    CONVERT(CHAR(18),Q.query_hash,1) AS query_hash,
    CONVERT(CHAR(18),Q.query_plan_hash,1) AS query_plan_hash,
    Q.sql_handle AS sql_handle_bin,
    Q.plan_handle AS plan_handle_bin,
    Q.query_hash AS query_hash_bin,
    Q.query_plan_hash AS query_plan_hash_bin,
    calc.Duration AS [Duration (ms)],
    Q.wait_resource,
    waitR.wait_resource_type,
    waitR.wait_database_id,
    waitR.wait_file_id,
    waitR.wait_page_id,
    waitR.wait_object_id,
    waitR.wait_index_id,
    waitR.wait_hobt,
    waitR.wait_hash,
    waitR.wait_slot,
    waitR.wait_is_compile,
    waitR.page_type,
	CASE WHEN waitR.wait_database_id=2 THEN 'tempdb' ELSE waitD.name END AS wait_db,
	waitO.SchemaName + '.' + waitO.ObjectName AS wait_object,
	waitF.filegroup_name + ' | ' + waitF.name AS wait_file,
    Q.login_time_utc,
    CASE WHEN QP.query_plan_compresed IS NULL THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS has_plan,
    Q.statement_start_offset,
    Q.statement_end_offset,
    Q.context_info,
    Q.transaction_begin_time_utc,
    calc.transaction_duration_ms,
    TranHD.HumanDuration AS transaction_duration,
    Q.is_implicit_transaction,
    D.is_query_store_on,
    CASE WHEN Q.tempdb_alloc_page_count < Q.tempdb_dealloc_page_count THEN 0 ELSE (Q.tempdb_alloc_page_count - Q.tempdb_dealloc_page_count) / 128.0 END AS tempdb_current_mb,
    Q.tempdb_alloc_page_count /128.0 AS tempdb_allocations_mb,
    Q.total_elapsed_time,
    CONCAT(Q.task_wait_type_1 + ' (' + CAST(Q.task_wait_time_1 AS NVARCHAR(260)) + 'ms)',
            ', ' + Q.task_wait_type_2 + ' (' + CAST(Q.task_wait_time_2 AS NVARCHAR(260)) + 'ms)',
            ', ' + Q.task_wait_type_3 + ' (' + CAST(Q.task_wait_time_3 AS NVARCHAR(260)) + 'ms)') AS TaskWaits,
    Q.task_wait_type_1,
    Q.task_wait_time_1,
    Q.task_wait_type_2,
    Q.task_wait_time_2,
    Q.task_wait_type_3,
    Q.task_wait_time_3,
    Q.dop,
    ISNULL(SUBSTRING(QTC.text,ISNULL((NULLIF(C.statement_start_offset,-1)/2)+1,0),ISNULL((NULLIF(NULLIF(C.statement_end_offset,-1),0) - NULLIF(C.statement_start_offset,-1))/2+1,2147483647)),C.properties) AS cursor_text,
    WG.name AS workload_group,
    RP.name AS resource_pool
FROM dbo.RunningQueries Q
JOIN dbo.Instances I ON Q.InstanceID = I.InstanceID
CROSS APPLY(SELECT 	/* 
						If the total_elapsed_time and calculated duration are within 500ms or the calculated duration is negative and total_elapsed_time is less than 30 seconds, use total_elapsed_time.  
						total_elapsed_time might offer better precision, but if it differs too much from the calculated duration, it might contain an error. #1491.  
						For sleeping sessions, start_time will be NULL and the calculated duration will be based on last request start time
					*/
				   CASE WHEN (Q.start_time_utc > Q.SnapshotDateUTC AND Q.total_elapsed_time < 30000) 
								OR ABS(DATEDIFF_BIG(ms,Q.start_time_utc,Q.SnapshotDateUTC)-CAST(Q.total_elapsed_time AS BIGINT)) < CAST(500 AS BIGINT) THEN CAST(Q.total_elapsed_time AS BIGINT) 
						WHEN Q.start_time_utc < Q.SnapshotDateUTC OR Q.start_time_utc IS NULL  THEN DATEDIFF_BIG(ms,ISNULL(Q.start_time_utc,Q.last_request_start_time_utc),Q.SnapshotDateUTC) 
						ELSE 0 END AS Duration,
                   CASE WHEN Q.transaction_begin_time_utc<Q.SnapshotDateUTC OR Q.transaction_begin_time_utc IS NULL THEN DATEDIFF_BIG(ms,Q.transaction_begin_time_utc,Q.SnapshotDateUTC) ELSE 0 END AS transaction_duration_ms) calc
CROSS APPLY dbo.MillisecondsToHumanDuration (calc.Duration) HD
CROSS APPLY dbo.SplitWaitResource(Q.wait_resource) waitR
LEFT JOIN dbo.QueryText QT ON QT.sql_handle = Q.sql_handle
LEFT JOIN dbo.QueryPlans QP ON QP.plan_handle = Q.plan_handle AND QP.query_plan_hash = Q.query_plan_hash AND QP.statement_start_offset = Q.statement_start_offset AND QP.statement_end_offset = Q.statement_end_offset
LEFT JOIN dbo.Databases D ON Q.database_id =D.database_id AND D.IsActive=1 AND D.InstanceID = Q.InstanceID
LEFT JOIN dbo.Databases objD ON ISNULL(QT.dbid,QP.dbid) =objD.database_id AND objD.IsActive=1 AND objD.InstanceID = Q.InstanceID
OUTER APPLY(SELECT TOP(1) * 
			FROM dbo.DBObjects O 
			WHERE objD.DatabaseID = O.DatabaseID 
			AND O.object_id = ISNULL(QT.object_id,QP.object_id)
			ORDER  BY O.IsActive DESC,O.ObjectName DESC) O 
LEFT JOIN dbo.Databases waitD ON waitD.InstanceID = Q.InstanceID AND waitR.wait_database_id = waitD.database_id AND waitD.IsActive=1
OUTER APPLY(SELECT TOP(1) *
			FROM dbo.DBObjects waitO
			WHERE waitR.wait_object_id = waitO.object_id 
			AND waitO.DatabaseID = waitD.DatabaseID 
			ORDER  BY O.IsActive DESC,O.ObjectName DESC
			) waitO
LEFT JOIN dbo.DBFiles waitF ON waitF.DatabaseID = waitD.DatabaseID AND waitF.file_id = waitR.wait_file_id
OUTER APPLY (SELECT CASE WHEN program_name LIKE 'SQLAgent - TSQL JobStep (Job 0x%' THEN TRY_CAST(TRY_CONVERT(BINARY(16),SUBSTRING(program_name, 30,34),1) AS UNIQUEIDENTIFIER)  ELSE NULL END AS job_id) jid
LEFT JOIN dbo.Jobs J ON J.job_id = jid.job_id AND J.InstanceID = Q.InstanceID
OUTER APPLY(SELECT STUFF((SELECT TOP(3) ', ' + WT.WaitType + ' (' + CAST(SW.wait_time_ms AS VARCHAR(MAX)) +'ms)'
		FROM dbo.SessionWaits SW 
		JOIN dbo.WaitType WT ON SW.WaitTypeID = WT.WaitTypeID
		WHERE SW.InstanceID = Q.InstanceID 
		AND SW.SnapshotDateUTC = Q.SnapshotDateUTC 
		AND SW.session_id = Q.session_id 
		AND SW.login_time_utc = Q.login_time_utc
		ORDER BY SW.wait_time_ms DESC
		FOR XML PATH('')),1,1,'') AS TopSessionWaits
		) sessionW
OUTER APPLY dbo.RunningQueriesBlockingRecursiveStats(Q.InstanceID,Q.SnapshotDateUTC,Q.session_id) AS RQBRS
OUTER APPLY dbo.RunningQueriesBlockingHierarchy(Q.InstanceID,Q.SnapshotDateUTC,Q.blocking_session_id) AS H
CROSS APPLY dbo.MillisecondsToHumanDuration (RQBRS.BlockWaitTimeMs) AS BlockWaitTime
CROSS APPLY dbo.MillisecondsToHumanDuration (RQBRS.BlockWaitTimeRecursiveMs) AS BlockWaitTimeRecursive
CROSS APPLY dbo.MillisecondsToHumanDuration (DATEDIFF_BIG(ms,Q.last_request_end_time_utc,Q.SnapshotDateUTC)) AS TimeSinceLastRequestEnd
CROSS APPLY dbo.MillisecondsToHumanDuration (DATEDIFF_BIG(ms,Q.last_request_start_time_utc,Q.last_request_end_time_utc)) AS LastRequestDuration
CROSS APPLY dbo.MillisecondsToHumanDuration (calc.transaction_duration_ms) TranHD
LEFT JOIN dbo.RunningQueriesCursors C ON C.InstanceID = Q.InstanceID 
                                    AND C.SnapshotDateUTC = Q.SnapshotDateUTC 
                                    AND C.session_id = Q.session_id 
                                    AND C.uniqueifier=1 /* Get only the first cursor if multiple exist */
                                    AND C.creation_time_utc <= Q.SnapshotDateUTC /* Ensure cursor was created before or at the same time as the snapshot.  If it was created after it might not be related to this request */
LEFT JOIN dbo.QueryText QTC ON QTC.sql_handle = C.sql_handle 
LEFT JOIN dbo.ResourceGovernorWorkloadGroups WG ON WG.WorkloadGroupID = Q.WorkloadGroupID AND WG.InstanceID = Q.InstanceID
LEFT JOIN dbo.ResourceGovernorResourcePools RP ON RP.ResourcePoolID = Q.ResourcePoolID AND RP.InstanceID = Q.InstanceID
GO
PRINT N'Creating View [dbo].[TempDBConfiguration]...';


GO
CREATE VIEW dbo.TempDBConfiguration
AS
SELECT i.InstanceID,
		i.Instance,
		i.InstanceDisplayName,
		SUM(CASE WHEN f.type=0 THEN 1 ELSE 0 END) NumberOfDataFiles,
	    calc.MinimumRecommendedFiles,
		CASE WHEN SUM(CASE WHEN f.type=0 THEN 1 ELSE 0 END) < calc.MinimumRecommendedFiles THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS InsufficientFiles,
		SUM(CASE WHEN f.type=1 THEN 1 ELSE 0 END) NumberOfLogFiles,
		CASE WHEN COUNT(DISTINCT CASE WHEN type= 0 THEN f.size ELSE NULL END) =1 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsEvenlySized,
		CASE WHEN COUNT(DISTINCT CASE WHEN type= 0 THEN f.growth ELSE NULL END)=1 
					AND COUNT(DISTINCT CASE WHEN type= 0 THEN f.is_percent_growth ELSE NULL END)=1 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsEvenGrowth,
		SUM(CASE WHEN f.type=0 THEN f.size ELSE NULL END)/128 AS TotalSizeMB,
		SUM(CASE WHEN f.type=1 THEN f.size ELSE NULL END)/128 AS LogMB,
		MAX(CASE WHEN f.type=0 THEN f.size ELSE NULL END)/128 AS FileSizeMB,
		MAX(CASE WHEN f.type=0 AND f.is_percent_growth=0 THEN f.growth/128 ELSE NULL END) AS MaxGrowthMB,
		MAX(CASE WHEN f.type=1 AND f.is_percent_growth=0 THEN f.growth/128 ELSE NULL END) AS MaxLogGrowthMB,
		MAX(CASE WHEN f.type=0 AND f.is_percent_growth=1 THEN f.growth ELSE NULL END) AS MaxGrowthPct,
		MAX(CASE WHEN f.type=1 AND f.is_percent_growth=1 THEN f.growth ELSE NULL END) AS MaxLogGrowthPct,
		STUFF((SELECT DISTINCT ', ' + LEFT(f2.physical_name,3) FROM dbo.DBFiles f2 WHERE f2.DatabaseID =d.DatabaseID AND f2.physical_name LIKE '_:\%' FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,2,'') AS TempDBVolumes,
		ISNULL(i.cpu_core_count,i.cpu_count) AS cpu_core_count,
		CAST(ISNULL(T.T1117,0) AS BIT) AS T1117,
		CAST(ISNULL(T.T1118,0) AS BIT) AS T1118,
		CASE WHEN I.ProductMajorVersion<13 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsTraceFlagRequired,
		i.IsTempDBMetadataMemoryOptimized,
		i.ShowInSummary
FROM dbo.InstanceInfo i 
JOIN dbo.Databases d ON d.InstanceID = i.InstanceID
JOIN dbo.DBFiles f ON d.DatabaseID = f.DatabaseID
OUTER APPLY(SELECT CASE WHEN ISNULL(i.cpu_core_count,i.cpu_count) >8 THEN 8 ELSE COALESCE(i.cpu_core_count,i.cpu_count,8) END AS MinimumRecommendedFiles) calc
OUTER APPLY(SELECT	MAX(CASE WHEN TF.TraceFlag=1117 THEN 1 ELSE 0 END) AS T1117, 
					MAX(CASE WHEN TF.TraceFlag=1118 THEN 1 ELSE 0 END) T1118
			FROM dbo.TraceFlags TF 
			WHERE TF.InstanceID = i.InstanceID 
			AND TF.TraceFlag IN(1118,1117)
			) T
WHERE d.name = 'tempdb'
AND i.IsActive=1
AND d.IsActive=1
AND f.IsActive=1
GROUP BY	i.Instance,
			i.InstanceID,
			i.InstanceDisplayName,
			i.cpu_core_count,
			d.DatabaseID, 
			T.T1118,
			T.T1117,
			i.ProductMajorVersion,
			calc.MinimumRecommendedFiles,
			i.IsTempDBMetadataMemoryOptimized,
			i.cpu_count,
			i.ShowInSummary
GO
PRINT N'Creating Function [dbo].[GetInstanceMetadataTags]...';


GO
CREATE FUNCTION dbo.GetInstanceMetadataTags(
	@InstanceID INT
)
RETURNS TABLE
AS
RETURN
WITH T AS (
SELECT	1 AS Type,
		UNPVT.TagName,
		UNPVT.TagValue
FROM (
	SELECT	CAST(M.Provider AS NVARCHAR(MAX)) AS Provider,
			CAST(VMSize AS NVARCHAR(MAX)) AS VMSize,
			CAST(Name AS NVARCHAR(MAX)) AS Name,
			CAST(SKU AS NVARCHAR(MAX)) AS SKU,
			CAST(ResourceGroup AS NVARCHAR(MAX)) AS ResourceGroup,
			CAST(AccountID AS NVARCHAR(MAX)) AS AccountID,
			CAST(SubscriptionID AS NVARCHAR(MAX)) AS SubscriptionID,
			CAST(Location AS NVARCHAR(MAX)) AS Location,
			CAST(AvailabilityZone AS NVARCHAR(MAX)) AS AvailabilityZone,
			CAST(ImageID AS NVARCHAR(MAX)) AS ImageID,
			CAST(AWSInstanceID AS NVARCHAR(MAX)) AS AWSInstanceID,
			CAST(IAMRole AS NVARCHAR(MAX)) AS IAMRole,
			CAST(VMHostName AS NVARCHAR(MAX)) AS VMHostName,
			CAST(BillingProducts AS NVARCHAR(MAX)) AS BillingProducts,
			CAST(ClusterName AS NVARCHAR(MAX)) AS ClusterName
	FROM dbo.InstanceMetadata M
	OUTER APPLY dbo.ParseInstanceMetadata(M.Metadata) P
	WHERE M.InstanceID = @InstanceID
	) MD
UNPIVOT(TagValue 
		FOR TagName IN(	[VMSize],
						[Name],
						[SKU],
						[ResourceGroup],
						[AccountID],
						[SubscriptionID],
						[Location],
						[AvailabilityZone],
						[ImageID],
						[AWSInstanceID],
						[Provider],
						[IAMRole],
						[VMHostName],
						[BillingProducts],
						[ClusterName]
		)
		) AS UNPVT

UNION ALL
SELECT	2 AS Type,
		JSON_VALUE(tags.value, '$.name') COLLATE DATABASE_DEFAULT AS TagName,
		JSON_VALUE(tags.value, '$.value') COLLATE DATABASE_DEFAULT AS TagValue
FROM dbo.InstanceMetadata M
OUTER APPLY OPENJSON(M.Metadata, '$.compute.tagsList') AS tags 
WHERE M.InstanceID = @InstanceID
UNION ALL
SELECT	2 AS Type,
		tags.[key] AS TagName,
		tags.value AS TagValue
FROM dbo.InstanceMetadata M
OUTER APPLY OPENJSON(M.Metadata,'$.Tags') tags
WHERE M.InstanceID = @InstanceID
)
SELECT	Type,
		TagName,
		TagValue
FROM T 
WHERE TagName IS NOT NULL
AND TagValue IS NOT NULL
GO
PRINT N'Creating View [dbo].[AzureDBInfo]...';


GO
CREATE VIEW dbo.AzureDBInfo
AS
SELECT	I.InstanceID,
		D.DatabaseID,
		I.ConnectionID,
		I.Instance,
		D.name AS DB,
		O.edition,
		O.service_objective,
		O.elastic_pool_name,
		Size.AllocatedSpaceMB,
		Size.UsedSpaceMB,
		Size.MaxStorageSizeMB,
		Size.AllocatedPctOfMaxSize,
		Size.UsedPctOfMaxSize,
		cfg.ConfiguredLevel,
		cfg.PctMaxSizeWarningThreshold,
		cfg.PctMaxSizeCriticalThreshold,
		CASE WHEN Size.AllocatedPctOfMaxSize > cfg.PctMaxSizeCriticalThreshold THEN 1 WHEN Size.AllocatedPctOfMaxSize > cfg.PctMaxSizeWarningThreshold THEN 2 ELSE 4 END PctMaxSizeStatus,
		CD.SnapshotDate AS FileSnapshotDate,
		CD.HumanSnapshotAge AS FileSnapshotAge,
		ISNULL(CD.Status,3) AS FileSnapshotStatus
FROM dbo.Instances I 
JOIN dbo.Databases D ON I.InstanceID = D.InstanceID
LEFT JOIN dbo.AzureDBServiceObjectives O ON O.InstanceID = I.InstanceID
OUTER APPLY(SELECT	 SUM(F.size)/128.0 AS AllocatedSpaceMB,
					 SUM(F.space_used)/128.0 AS UsedSpaceMB,
					 CASE WHEN MIN(F.max_size)<0 THEN NULL ELSE SUM(F.max_size)/128.0 END AS MaxStorageSizeMB,
					 CASE WHEN MIN(F.max_size)<0 THEN NULL ELSE SUM(F.size)*1.0/SUM(F.max_size) END AllocatedPctOfMaxSize,
					 CASE WHEN MIN(F.max_size)<0 THEN NULL ELSE SUM(F.space_used)*1.0/SUM(F.max_size) END UsedPctOfMaxSize
			FROM dbo.DBFiles F
			WHERE F.DatabaseID = D.DatabaseID 
			AND F.type=0
			AND F.IsActive=1
			AND F.data_space_id=1
			) Size
OUTER APPLY(SELECT TOP(1)	CASE WHEN T.data_space_id NOT IN(0,-1) THEN 'FG'
									WHEN T.DatabaseID <>-1 THEN 'DB'
									WHEN T.InstanceID<>-1 THEN 'Instance'
									WHEN T.InstanceID=-1 THEN 'Root'
									ELSE 'N/A' END AS ConfiguredLevel,
							T.PctMaxSizeWarningThreshold,
							T.PctMaxSizeCriticalThreshold
			FROM dbo.DBFileThresholds T 
			WHERE (T.InstanceID = I.InstanceID OR T.InstanceID=-1)
			AND (T.DatabaseID = D.DatabaseID OR T.DatabaseID=-1)
			AND (T.data_space_id = 1 OR T.data_space_id=-1)
			ORDER BY T.InstanceID DESC,T.DatabaseID DESC,T.data_space_id DESC
			) cfg
LEFT JOIN dbo.CollectionDatesStatus CD ON CD.InstanceID = D.InstanceID AND CD.Reference='DBFiles'
WHERE I.EditionID=1674378470
AND D.IsActive=1
AND I.IsActive=1
GO
PRINT N'Creating View [dbo].[BackupStatus]...';


GO
CREATE VIEW dbo.BackupStatus
AS
WITH B AS(
	SELECT B.DatabaseID,
			MAX(CASE WHEN B.type='D' THEN B.backup_start_date_utc ELSE NULL END) AS LastFull,
			MAX(CASE WHEN B.type='I' THEN B.backup_start_date_utc ELSE NULL END) AS LastDiff,
			MAX(CASE WHEN B.type='L' THEN B.backup_start_date_utc ELSE NULL END) AS LastLog,
			MAX(CASE WHEN B.type='F' THEN B.backup_start_date_utc ELSE NULL END) AS LastFG,
			MAX(CASE WHEN B.type='G' THEN B.backup_start_date_utc ELSE NULL END) AS LastFGDiff,
			MAX(CASE WHEN B.type='P' THEN B.backup_start_date_utc ELSE NULL END) AS LastPartial,
			MAX(CASE WHEN B.type='Q' THEN B.backup_start_date_utc ELSE NULL END) AS LastPartialDiff,
			MAX(CASE WHEN B.type='D' THEN B.BackupDuration ELSE NULL END) AS LastFullDuration,
			MAX(CASE WHEN B.type='D' THEN B.BackupDurationSec ELSE NULL END) AS LastFullDurationSec,
			MAX(CASE WHEN B.type='D' THEN B.BackupMBsec ELSE NULL END) AS FullBackupMBsec,
			MAX(CASE WHEN B.type='D' THEN B.BackupWriteMBsec ELSE NULL END) AS FullBackupWriteMBsec,
			MAX(CASE WHEN B.type='D' THEN B.BackupSizeGB ELSE NULL END) AS FullBackupSizeGB,
			MAX(CASE WHEN B.type='D' THEN B.BackupSizeCompressedGB ELSE NULL END) AS FullBackupSizeCompressedGB,
			MAX(CASE WHEN B.type='D' THEN B.CompressionSavingPct ELSE NULL END) AS FullCompressionSavingPct,
			MAX(CASE WHEN B.type='I' THEN B.BackupDuration ELSE NULL END) AS LastDiffDuration,
			MAX(CASE WHEN B.type='I' THEN B.BackupDurationSec ELSE NULL END) AS LastDiffDurationSec,
			MAX(CASE WHEN B.type='I' THEN B.BackupMBsec ELSE NULL END) AS DiffBackupMBsec,
			MAX(CASE WHEN B.type='I' THEN B.BackupWriteMBsec ELSE NULL END) AS DiffBackupWriteMBsec,
			MAX(CASE WHEN B.type='I' THEN B.BackupSizeGB ELSE NULL END) AS DiffBackupSizeGB,
			MAX(CASE WHEN B.type='I' THEN B.BackupSizeCompressedGB ELSE NULL END) AS DiffBackupSizeCompressedGB,
			MAX(CASE WHEN B.type='I' THEN B.CompressionSavingPct ELSE NULL END) AS DiffCompressionSavingPct,
			MAX(CASE WHEN B.type IN('D','F','P') THEN CAST(B.is_damaged AS INT) ELSE 0 END) IsFullDamaged,
			MAX(CASE WHEN B.type IN('I','G','Q') THEN CAST(B.is_damaged AS INT) ELSE 0 END) IsDiffDamaged,
			MAX(CASE WHEN B.type IN('L') THEN CAST(B.is_damaged AS INT) ELSE 0 END) IsLogDamaged,
			CAST(MAX(CASE WHEN B.type ='D' THEN CAST(B.has_backup_checksums AS INT) ELSE NULL END) AS BIT) as IsFullChecksum,
			CAST(MAX(CASE WHEN B.type ='I' THEN CAST(B.has_backup_checksums AS INT) ELSE NULL END) AS BIT) as IsDiffChecksum,
			CAST(MAX(CASE WHEN B.type ='L' THEN CAST(B.has_backup_checksums AS INT) ELSE NULL END) AS BIT) as IsLogChecksum,		
			CAST(MAX(CASE WHEN B.type ='D' THEN CAST(B.is_password_protected AS INT) ELSE NULL END) AS BIT) as IsFullPasswordProtected,
			CAST(MAX(CASE WHEN B.type ='I' THEN CAST(B.is_password_protected AS INT) ELSE NULL END) AS BIT) as IsDiffPasswordProtected,
			CAST(MAX(CASE WHEN B.type ='L' THEN CAST(B.is_password_protected AS INT) ELSE NULL END) AS BIT) as IsLogPasswordProtected,
			CAST(MAX(CASE WHEN B.type ='D' THEN CAST(B.IsEncrypted AS INT) ELSE NULL END) AS BIT) as IsFullEncrypted,
			CAST(MAX(CASE WHEN B.type ='I' THEN CAST(B.IsEncrypted AS INT) ELSE NULL END) AS BIT) as IsDiffEncrypted,
			CAST(MAX(CASE WHEN B.type ='L' THEN CAST(B.IsEncrypted AS INT) ELSE NULL END) AS BIT) as IsLogEncrypted,			
			CAST(MAX(CASE WHEN B.type ='D' THEN CAST(B.IsCompressed AS INT) ELSE NULL END) AS BIT) as IsFullCompressed,
			CAST(MAX(CASE WHEN B.type ='I' THEN CAST(B.IsCompressed AS INT) ELSE NULL END) AS BIT) as IsDiffCompressed,
			CAST(MAX(CASE WHEN B.type ='L' THEN CAST(B.IsCompressed AS INT) ELSE NULL END) AS BIT) as IsLogCompressed,	
			CASE WHEN MIN(CAST(B.is_snapshot AS INT))=1 THEN 'Y' WHEN MAX(CAST(B.is_snapshot AS INT))=1 THEN '(Y)' ELSE 'N' END AS SnapshotBackups,
			CAST(MAX(CAST(B.IsPartnerBackup AS INT)) AS BIT) AS IsPartnerBackup,
			MAX(CASE WHEN B.type ='D' THEN B.compression_algorithm ELSE NULL END) as FullCompressionAlgorithm,
			MAX(CASE WHEN B.type ='I' THEN B.compression_algorithm ELSE NULL END) as DiffCompressionAlgorithm,
			MAX(CASE WHEN B.type ='L' THEN B.compression_algorithm ELSE NULL END) as LogCompressionAlgorithm	
	FROM dbo.LastBackup B
	GROUP BY B.DatabaseID
)
SELECT I.InstanceID,
	d.DatabaseID,
	I.Instance,
	I.InstanceDisplayName,
	d.name,
	D.recovery_model,
	CASE D.recovery_model WHEN 1 THEN 'FULL' WHEN 2 THEN 'BULK_LOGGED' WHEN 3 THEN 'SIMPLE' ELSE '???' END AS recovery_model_desc,
	B.LastFull,
	B.LastDiff,
	B.LastLog,
	B.LastFG,
	B.LastFGDiff,
	B.LastPartial,
	B.LastPartialDiff,
	chk.FullBackupStatus,
	chk.LogBackupStatus,
	chk.DiffBackupStatus,
	CASE WHEN chk.FullBackupStatus=1 OR chk.DiffBackupStatus=1 OR chk.LogBackupStatus=1 THEN 1
		WHEN chk.FullBackupStatus=2 OR chk.DiffBackupStatus=2 OR chk.LogBackupStatus=2 THEN 2
		WHEN chk.FullBackupStatus=4 OR chk.DiffBackupStatus=4 OR chk.LogBackupStatus=4 THEN 4
		ELSE 3 END AS BackupStatus,
	cfg.LogBackupWarningThreshold,
    cfg.LogBackupCriticalThreshold,
    cfg.FullBackupWarningThreshold,
    cfg.FullBackupCriticalThreshold,
    cfg.DiffBackupWarningThreshold,
    cfg.DiffBackupCriticalThreshold,
    cfg.ConsiderPartialBackups,
    cfg.ConsiderFGBackups,
	cfg.ConsiderCopyOnlyBackups,
	cfg.ConsiderSnapshotBackups,
	cfg.ConsiderFullBackupWithDiffThreshold,
	CASE WHEN cfg.InstanceID = D.InstanceID AND cfg.DatabaseID = D.DatabaseID THEN 'Database' WHEN cfg.InstanceID=D.InstanceID THEN 'Instance' ELSE 'Root' END AS ThresholdsConfiguredLevel,
	SSD.SnapshotDate,
	HD.HumanDuration AS SnapshotAge,
	SSD.Status as SnapshotAgeStatus,
 	d.create_date,
	DATEADD(mi,I.UTCOffset,d.create_date) AS create_date_utc,
	I.UTCOffset,
    B.LastFullDuration,
    B.LastFullDurationSec,
    B.[FullBackupMBsec],
    B.FullBackupWriteMBsec,
    B.FullBackupSizeGB,
    B.FullBackupSizeCompressedGB,
	B.FullCompressionSavingPct,
    B.LastDiffDuration,
    B.LastDiffDurationSec,
    B.DiffBackupMBsec,
    B.DiffBackupWriteMBsec,
    B.DiffBackupSizeGB,
    B.DiffBackupSizeCompressedGB,
	B.DiffCompressionSavingPct,
	B.IsFullDamaged,
	B.IsDiffDamaged,
	B.IsLogDamaged,
	B.IsFullChecksum,
	B.IsDiffChecksum,
	B.IsLogChecksum,
	B.IsFullPasswordProtected,
	B.IsDiffPasswordProtected,
	B.IsLogPasswordProtected,
	B.IsFullCompressed,
	B.IsDiffCompressed,
	B.IsLogCompressed,
	B.IsFullEncrypted,
	B.IsDiffEncrypted,
	B.IsLogEncrypted,
	B.SnapshotBackups,
	B.IsPartnerBackup,
	f.FullBackupExcludedReason,
	f.DiffBackupExcludedReason,
	f.LogBackupExcludedReason,
	B.FullCompressionAlgorithm,
	B.DiffCompressionAlgorithm,
	B.LogCompressionAlgorithm,
	I.ShowInSummary
FROM dbo.Databases d 
JOIN dbo.Instances I ON d.InstanceID = I.InstanceID
JOIN dbo.CollectionDatesStatus SSD ON SSD.InstanceID = I.InstanceID AND SSD.Reference='Backups'
LEFT JOIN B ON d.DatabaseID = B.DatabaseID
OUTER APPLY dbo.SecondsToHumanDuration(DATEDIFF(s,SSD.SnapshotDate,GETUTCDATE())) HD
OUTER APPLY(SELECT TOP(1) T.*,
				CASE WHEN EXISTS(SELECT * FROM STRING_SPLIT(T.ExcludedDatabases,',') SS WHERE d.name LIKE SS.value) THEN CAST(1 AS BIT) ELSE CAST(0 as BIT) END as IsExcludedByName,
				CASE WHEN T.MinimumAge > DATEDIFF(mi,0,GETUTCDATE()) THEN CAST(1 AS BIT) WHEN DATEADD(mi,I.UTCOffset,d.create_date) > DATEADD(mi,-T.MinimumAge,GETUTCDATE()) THEN CAST(1 AS BIT) ELSE CAST(0 as BIT) END IsExcludedByDate
			FROM dbo.BackupThresholds T 
			WHERE (D.InstanceID = T.InstanceID OR T.InstanceID = -1)
			AND (D.DatabaseID = T.DatabaseID  OR T.DatabaseID = -1)
			ORDER BY InstanceID DESC,DatabaseID DESC
			) cfg
OUTER APPLY(SELECT	DATEDIFF(mi,
								CASE WHEN cfg.ConsiderFGBackups=1 AND (LastFG> LastFull OR LastFull IS NULL) AND (cfg.ConsiderPartialBackups=0 OR LastPartial<LastFG OR LastPartial IS NULL) THEN LastFG
									WHEN cfg.ConsiderPartialBackups=1 AND (LastPartial>LastFull OR LastFull IS NULL) THEN LastPartial
								ELSE LastFull END,
							GETUTCDATE()) AS FullBackupAge,
					DATEDIFF(mi,
								CASE WHEN cfg.ConsiderFGBackups=1 AND (LastFGDiff> LastDiff OR LastDiff IS NULL) AND (cfg.ConsiderPartialBackups=0 OR LastPartialDiff<LastFGDiff OR LastPartialDiff IS NULL) THEN LastFGDiff
									WHEN cfg.ConsiderPartialBackups=1 AND (LastPartialDiff>LastDiff OR LastDiff IS NULL) THEN LastPartialDiff
								ELSE LastDiff END,
							GETUTCDATE()) DiffBackupAge,
					DATEDIFF(mi,LastLog,GETUTCDATE()) LogBackupAge
		) AS calc
OUTER APPLY(SELECT STUFF(CONCAT(CASE WHEN d.source_database_id IS NOT NULL THEN ', Snapshot' ELSE NULL END,
								CASE WHEN d.state NOT IN(0,4,5) THEN ', ' + d.state_desc ELSE NULL END,
								CASE WHEN d.is_in_standby=1 THEN ', Standby' ELSE NULL END,
								CASE WHEN d.name = 'tempdb' THEN ', tempdb' ELSE NULL END,
								CASE WHEN cfg.IsExcludedByName=1 THEN ', name' ELSE NULL END,
								CASE WHEN cfg.IsExcludedByDate=1 THEN ', created_date' ELSE NULL END,
								CASE WHEN cfg.FullBackupWarningThreshold IS NULL AND cfg.FullBackupCriticalThreshold IS NULL THEN ', No Threshold' END
								),1,2,'') as FullBackupExcludedReason,
					STUFF(CONCAT(CASE WHEN d.source_database_id IS NOT NULL THEN ', Snapshot' ELSE NULL END,
								CASE WHEN d.state NOT IN(0,4,5) THEN ', ' + d.state_desc ELSE NULL END,
								CASE WHEN d.is_in_standby=1 THEN ', Standby' ELSE NULL END,
								CASE WHEN d.name = 'tempdb' THEN ', tempdb' ELSE NULL END,
								CASE WHEN cfg.IsExcludedByName=1 THEN ', name' ELSE NULL END,
								CASE WHEN cfg.IsExcludedByDate=1 THEN ', created_date' ELSE NULL END,
								CASE WHEN d.name = 'master' THEN ', master' ELSE NULL END,
								CASE WHEN cfg.DiffBackupWarningThreshold IS NULL AND cfg.DiffBackupCriticalThreshold IS NULL THEN ', No Threshold' END,
								CASE WHEN cfg.ConsiderFullBackupWithDiffThreshold =1 
									AND  calc.FullBackupAge < ISNULL(calc.DiffBackupAge,214748364)
									AND calc.FullBackupAge < (SELECT MIN(dt) FROM (VALUES (cfg.DiffBackupCriticalThreshold),(cfg.DiffBackupWarningThreshold)) AS T(dt))
									AND ISNULL(calc.DiffBackupAge,214748364) > (SELECT MIN(dt) FROM (VALUES (cfg.DiffBackupCriticalThreshold),(cfg.DiffBackupWarningThreshold)) AS T(dt))
									THEN ', Full Backup' ELSE NULL END /* Diff backup doesn't meet thresholds, but we have a full backup that does. */
								),1,2,'') as DiffBackupExcludedReason,
					STUFF(CONCAT(CASE WHEN d.source_database_id IS NOT NULL THEN ', Snapshot' ELSE NULL END,
								CASE WHEN d.state NOT IN(0,4,5) THEN ', ' + d.state_desc ELSE NULL END,
								CASE WHEN d.is_in_standby=1 THEN ', Standby' ELSE NULL END,
								CASE WHEN d.name = 'tempdb' THEN ', tempdb' ELSE NULL END,
								CASE WHEN cfg.IsExcludedByName=1 THEN ', name' ELSE NULL END,
								CASE WHEN cfg.IsExcludedByDate=1 THEN ', created_date' ELSE NULL END,
								CASE WHEN d.recovery_model=3 THEN ', SIMPLE' ELSE NULL END,
								CASE WHEN cfg.LogBackupWarningThreshold IS NULL AND cfg.LogBackupCriticalThreshold IS NULL THEN ', No Threshold' END
								),1,2,'') as LogBackupExcludedReason
	
			) f
OUTER APPLY(SELECT CASE WHEN f.FullBackupExcludedReason IS NOT NULL THEN 3
						WHEN B.IsFullDamaged=1 THEN 1
						WHEN ISNULL(calc.FullBackupAge,cfg.FullBackupCriticalThreshold) >= cfg.FullBackupCriticalThreshold THEN 1
						WHEN calc.FullBackupAge>=cfg.FullBackupWarningThreshold THEN 2
						ELSE 4 END AS FullBackupStatus,
					CASE WHEN f.DiffBackupExcludedReason IS NOT NULL THEN 3
						WHEN B.IsDiffDamaged=1 THEN 1
						WHEN ISNULL(calc.DiffBackupAge,cfg.DiffBackupCriticalThreshold) >= cfg.DiffBackupCriticalThreshold THEN 1
						WHEN calc.DiffBackupAge>=cfg.DiffBackupWarningThreshold THEN 2
					ELSE 4 END AS DiffBackupStatus,
					CASE WHEN LogBackupExcludedReason IS NOT NULL THEN 3
						WHEN B.IsLogDamaged=1 THEN 1
						WHEN ISNULL(calc.LogBackupAge,cfg.LogBackupCriticalThreshold) >= cfg.LogBackupCriticalThreshold THEN 1
						WHEN calc.LogBackupAge>=cfg.LogBackupWarningThreshold THEN 2
					ELSE 4 END AS LogBackupStatus
			) AS chk
WHERE d.IsActive=1
AND I.IsActive=1
AND I.EngineEdition NOT IN(5,8) -- Exclude AzureDB and Azure MI
GO
PRINT N'Creating View [dbo].[BackupSummary]...';


GO
CREATE VIEW dbo.BackupSummary
AS
SELECT BS.InstanceID, 
	BS.Instance,
	BS.InstanceDisplayName,
	COUNT(*) AS DatabaseCount,
	SUM(CASE WHEN BS.recovery_model=1 THEN 1 ELSE 0 END) AS FullRecoveryCount,
	SUM(CASE WHEN BS.recovery_model=2 THEN 1 ELSE 0 END) AS BulkLoggedCount,
	SUM(CASE WHEN BS.recovery_model=3 THEN 1 ELSE 0 END) AS SimpleCount,
	SUM(CASE WHEN BS.FullBackupStatus=4 THEN 1 ELSE 0 END) AS FullOK,
	SUM(CASE WHEN BS.FullBackupStatus=3 THEN 1 ELSE 0 END) AS FullNA,
	SUM(CASE WHEN BS.FullBackupStatus=2 THEN 1 ELSE 0 END) AS FullWarning,
	SUM(CASE WHEN BS.FullBackupStatus=1 THEN 1 ELSE 0 END) AS FullCritical,
	SUM(CASE WHEN BS.DiffBackupStatus=4 THEN 1 ELSE 0 END) AS DiffOK,
	SUM(CASE WHEN BS.DiffBackupStatus=3 THEN 1 ELSE 0 END) AS DiffNA,
	SUM(CASE WHEN BS.DiffBackupStatus=2 THEN 1 ELSE 0 END) AS DiffWarning,
	SUM(CASE WHEN BS.DiffBackupStatus=1 THEN 1 ELSE 0 END) AS DiffCritical,
	SUM(CASE WHEN BS.LogBackupStatus=4 THEN 1 ELSE 0 END) AS LogOK,
	SUM(CASE WHEN BS.LogBackupStatus=3 THEN 1 ELSE 0 END) AS LogNA,
	SUM(CASE WHEN BS.LogBackupStatus=2 THEN 1 ELSE 0 END) AS LogWarning,
	SUM(CASE WHEN BS.LogBackupStatus=1 THEN 1 ELSE 0 END) AS LogCritical,
	MIN(BS.SnapshotDate) AS SnapshotDate,
	MIN(BS.SnapshotAge) AS SnapshotAge,
	MIN(SnapshotAgeStatus) as SnapshotAgeStatus,
	SUM(BS.FullBackupSizeGB) AS FullBackupSizeGB,
	SUM(BS.FullBackupSizeGB)*1024.0 /NULLIF(SUM(BS.LastFullDurationSec),0) AS FullBackupMBsec,
	SUM(BS.FullBackupSizeCompressedGB) AS FullBackupSizeCompressedGB,
	1.0-(SUM(BS.FullBackupSizeCompressedGB)/SUM(BS.FullBackupSizeGB)) AS FullCompressionSavingPct,
	SUM(BS.FullBackupSizeCompressedGB)*1024.0 /NULLIF(SUM(BS.LastFullDurationSec),0) AS FullBackupWriteMBsec,
	SUM(BS.DiffBackupSizeGB) AS DiffBackupSizeGB,
	SUM(BS.DiffBackupSizeGB)*1024.0 /NULLIF(SUM(BS.LastDiffDurationSec),0) AS DiffBackupMBsec,
	SUM(BS.DiffBackupSizeCompressedGB) AS DiffBackupSizeCompressedGB,
	1.0-(SUM(BS.DiffBackupSizeCompressedGB)/SUM(BS.DiffBackupSizeGB)) AS DiffCompressionSavingPct,
	SUM(BS.DiffBackupSizeCompressedGB)*1024.0 /NULLIF(SUM(BS.LastDiffDurationSec),0) AS DiffBackupWriteMBsec,	
	CONCAT(SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN CAST(BS.IsFullEncrypted AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As FullEncrypted,
	CONCAT(SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN CAST(BS.IsDiffEncrypted AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As DiffEncrypted,
	CONCAT(SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN CAST(BS.IsLogEncrypted AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As LogEncrypted,	
	CONCAT(SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN CAST(BS.IsFullChecksum AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As FullChecksum,
	CONCAT(SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN CAST(BS.IsDiffChecksum AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As DiffChecksum,
	CONCAT(SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN CAST(BS.IsLogChecksum AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As LogChecksum,
	CONCAT(SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN CAST(BS.IsFullCompressed AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As FullCompressed,
	CONCAT(SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN CAST(BS.IsDiffCompressed AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As DiffCompressed,
	CONCAT(SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN CAST(BS.IsLogCompressed AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As LogCompressed,	
	CONCAT(SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN CAST(BS.IsFullPasswordProtected AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As FullPasswordProtected,
	CONCAT(SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN CAST(BS.IsFullPasswordProtected AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As DiffPasswordProtected,
	CONCAT(SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN CAST(BS.IsFullPasswordProtected AS INT) ELSE 0 END),'/',SUM(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN 1 ELSE 0 END))  As LogPasswordProtected,
	CASE WHEN MIN(CASE WHEN BS.SnapshotBackups ='Y' THEN 1 WHEN BS.SnapshotBackups IS NULL THEN 2 ELSE 0 END) = 1 THEN 'ALL'
		 WHEN MAX(CASE WHEN BS.SnapshotBackups IN('Y','(Y)') THEN 1 ELSE 0 END) = 1 THEN 'SOME'
		 ELSE 'NONE' END AS SnapshotBackups,
	SUM(CASE WHEN BS.ThresholdsConfiguredLevel='DATABASE' THEN 1 ELSE 0 END) AS DBThresholdConfiguration,
	CASE WHEN T.InstanceID IS NULL THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS InstanceThresholdConfiguration,
	CAST(MAX(CAST(BS.IsPartnerBackup AS INT)) AS BIT) as IsPartnerBackup,
	MIN(CASE WHEN BS.FullBackupExcludedReason IS NULL THEN BS.LastFull ELSE NULL END) as OldestFull,
	MIN(CASE WHEN BS.DiffBackupExcludedReason IS NULL THEN BS.LastDiff ELSE NULL END) as OldestDiff,
	MIN(CASE WHEN BS.LogBackupExcludedReason IS NULL THEN BS.LastLog ELSE NULL END) as OldestLog,
	STUFF(
			(SELECT ', ' + ISNULL(BSA.FullCompressionAlgorithm,'NULL') + '(' + CAST(COUNT(*) AS NVARCHAR(MAX)) + ')' 
			FROM dbo.BackupStatus BSA
			WHERE BSA.InstanceID=BS.InstanceID
			AND BSA.FullBackupExcludedReason IS NULL 
			GROUP BY BSA.FullCompressionAlgorithm
			FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,2,'') AS FullCompressionAlgorithms,
	STUFF(
			(SELECT ', ' + ISNULL(BSA.DiffCompressionAlgorithm,'NULL') + '(' + CAST(COUNT(*) AS NVARCHAR(MAX)) + ')' 
			FROM dbo.BackupStatus BSA
			WHERE BSA.InstanceID=BS.InstanceID
			AND BSA.DiffBackupExcludedReason IS NULL 
			GROUP BY BSA.DiffCompressionAlgorithm
			FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)')
		,1,2,'') AS DiffCompressionAlgorithms,
	STUFF(
			(SELECT ', ' + ISNULL(BSA.LogCompressionAlgorithm,'NULL') + '(' + CAST(COUNT(*) AS NVARCHAR(MAX)) + ')' 
			FROM dbo.BackupStatus BSA
			WHERE BSA.InstanceID=BS.InstanceID
			AND BSA.LogBackupExcludedReason IS NULL 
			GROUP BY BSA.LogCompressionAlgorithm
			FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)')
		,1,2,'') AS LogCompressionAlgorithms,
	BS.ShowInSummary
FROM dbo.BackupStatus BS
LEFT JOIN dbo.BackupThresholds T ON BS.InstanceID = T.InstanceID AND T.DatabaseID = -1
GROUP BY BS.InstanceID,
	BS.Instance,
	BS.InstanceDisplayName,
	T.InstanceID,
	BS.ShowInSummary
GO
PRINT N'Creating View [dbo].[ConfigurationCheck]...';


GO


CREATE VIEW [dbo].[ConfigurationCheck]
AS
SELECT U.InstanceID,
	   U.Instance,
       U.name,
       U.chk
FROM
(
    SELECT I.Instance,
		   D.InstanceID,
           D.name,
           D.is_auto_close_on AutoClose,
           D.is_auto_shrink_on AutoShrink,
           CASE
               WHEN D.page_verify_option = 2 THEN
                   CAST(0 AS BIT)
               ELSE
                   CAST(1 AS BIT)
           END AS PageVerify,
		   ~D.is_auto_create_stats_on AutoCreateStats,
		   ~D.is_auto_update_stats_on AutoUpdateStats,
		   D.is_auto_update_stats_async_on AutoUpdateStatsAsync,
		   D.is_date_correlation_on DateCorrelation,
		   D.is_encrypted IsEncrypted,
		   CASE WHEN D.owner_sid = 0x01 THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS DBOwner
    FROM dbo.Databases D
	JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
    WHERE D.IsActive = 1
    AND   D.state = 0
	AND D.is_in_standby=0
	AND I.IsActive=1
	AND NOT EXISTS(SELECT 1 FROM dbo.DatabasesHADR hadr WHERE D.DatabaseID = hadr.DatabaseID AND hadr.is_primary_replica=0)
) T
    UNPIVOT
    (
        chkValue
        FOR chk IN (AutoClose, AutoShrink, PageVerify,AutoCreateStats,AutoUpdateStats,AutoUpdateStatsAsync,DateCorrelation,IsEncrypted,DBOwner)
    ) U
WHERE U.chkValue = 1
UNION ALL
SELECT U.InstanceID,
		U.Instance,
       U.name,
       U.chk
FROM (
	SELECT I.Instance,
		I.InstanceID,
		D.name + ' - ' + ISNULL(F.filegroup_name,F.data_space_id) AS name,
		MAX(CASE WHEN F.is_percent_growth=1 AND F.size>131072 THEN 1 ELSE 0 END) PercentGrowth,
		CASE WHEN COUNT(DISTINCT F.growth)>1 OR COUNT(DISTINCT F.is_percent_growth)>1 THEN 1 ELSE 0 END AS UnevenGrowth,
		MAX(CASE WHEN F.growth=128 AND F.size>131072 THEN 1 ELSE 0 END) AS SmallGrowth,
		MIN(CASE WHEN F.max_size NOT IN(268435456,-1) AND F.type IN(0,1) AND F.growth>0 THEN 1 ELSE 0 END) AS MaxSizeSet
	FROM dbo.DBFiles F 
	JOIN dbo.Databases D ON D.DatabaseID = F.DatabaseID
	JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
	WHERE I.IsActive=1
	AND D.IsActive=1
	AND F.IsActive=1
	AND D.is_in_standby=0
	AND D.state=0
	AND NOT EXISTS(SELECT 1 FROM dbo.DatabasesHADR hadr WHERE D.DatabaseID = hadr.DatabaseID AND hadr.is_primary_replica=0)
	GROUP BY I.InstanceID,F.DatabaseID,F.data_space_id,F.filegroup_name,D.name,I.Instance
) T
UNPIVOT(chkValue FOR chk IN(PercentGrowth,UnevenGrowth,SmallGrowth,MaxSizeSet)) U 
WHERE U.chkValue=1
UNION ALL
SELECT InstanceID,Instance,'Buffer Pool:' + FORMAT(PctMemoryAllocatedToBufferPool,'0.0%'),CASE WHEN PctMemoryAllocatedToBufferPool<0.85 THEN 'BufferPoolLow' ELSE 'BufferPoolHigh' END
FROM dbo.InstanceInfo
WHERE PctMemoryAllocatedToBufferPool>=0.91 OR (PctMemoryAllocatedToBufferPool<0.85 AND MemoryNotAllocatedToBufferPoolGB>4.5)
GO
