CREATE PROC Alert.ActiveAlertsAck_Upd(
	@AlertIDs BigIDs READONLY,
	@AlertID BIGINT=NULL,
	@IsAcknowledged BIT
)
AS 
/* Toggle the acknowledged status for alerts specified */
UPDATE AA
    SET AA.IsAcknowledged = @IsAcknowledged,
    AA.AcknowledgedDate = CASE WHEN @IsAcknowledged = 1 THEN SYSUTCDATETIME() ELSE NULL END
FROM Alert.ActiveAlerts AA
WHERE EXISTS(
            SELECT 1 
            FROM @AlertIDs T
            WHERE T.ID = AA.AlertID
            AND @AlertID IS NULL
            UNION ALL
            SELECT 1
            WHERE AA.AlertID = @AlertID
            AND @AlertID IS NOT NULL
            )
GO
PRINT N'Creating Procedure [Alert].[CurrentAgent_Upd]...';


GO
CREATE PROC Alert.CurrentAgent_Upd(
	@DBADashAgentID INT
)
AS
/* 
	Ensure only a single instance of the DBA Dash service is processing alerts at one time
*/
IF NOT EXISTS(SELECT 1 
	FROM Alert.CurrentAgent
	WHERE ID = 1
	)
BEGIN
	INSERT INTO Alert.CurrentAgent(
		ID,
		DBADashAgentID,
		LockAcquired,
		LockUpdated
	)
	SELECT 
		1,
		@DBADashAgentID ,
		SYSUTCDATETIME(),
		SYSUTCDATETIME()
	WHERE NOT EXISTS(SELECT 1 
					FROM Alert.CurrentAgent WITH(UPDLOCK)
					WHERE ID = 1
					)
END

UPDATE Alert.CurrentAgent
	SET DBADashAgentID = @DBADashAgentID,
	LockAcquired = CASE WHEN DBADashAgentID = @DBADashAgentID THEN LockAcquired ELSE SYSUTCDATETIME() END,
	LockUpdated = SYSUTCDATETIME()
WHERE ID = 1
AND (LockUpdated < DATEADD(mi,-10,SYSUTCDATETIME()) /* Lock will expire after 10min allowing another DBA Dash service to take over alert processing */
	OR DBADashAgentID = @DBADashAgentID
	)

SELECT CAST(@@ROWCOUNT AS BIT) AS LockAcquired
GO
PRINT N'Creating Procedure [Alert].[ClosedAlerts_Get]...';


GO
CREATE PROC Alert.ClosedAlerts_Get(
	@InstanceIDs IDs READONLY,
	@InstanceID INT=NULL,
	@Top INT=1000
)
AS
DECLARE @AllInstances BIT
SELECT @AllInstances = CASE WHEN EXISTS(SELECT 1 FROM @InstanceIDs) THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END

SELECT  TOP(@Top)
		CA.AlertID,
		CA.InstanceID,
		I.InstanceDisplayName, 
		CA.Priority,
		CONCAT(CA.Priority,' - ',
			CASE WHEN CA.Priority =0 THEN 'Critical'
				WHEN CA.Priority>=1 AND CA.Priority<=10 THEN 'High'
				WHEN CA.Priority>=11 AND CA.Priority<=20 THEN 'Medium'
				WHEN CA.Priority>=21 AND CA.Priority<=30 THEN 'Low'
				WHEN CA.Priority>=31 AND CA.Priority<=254 THEN 'Informational'
				ELSE 'Success' END)
			+ CASE WHEN CA.IsResolved=1 THEN ' (Resolved)'
				WHEN CA.IsAcknowledged=1 THEN ' (Acknowledged)'
				ELSE '' END AS PriorityDescription,
		CA.Priority,
		CA.AlertType,
		CA.AlertKey,
		CA.FirstMessage,
		CA.LastMessage,
		CA.TriggerDate,
		AlertDuration.HumanDuration AS AlertDuration,
		CA.UpdatedDate,
		LastUpdate.HumanDuration AS TimeSinceLastUpdate,
		CA.FirstNotification,
		CA.LastNotification,
		LastNotification.HumanDuration AS TimeSinceLastNotification,
		CA.UpdateCount,
		CA.ResolvedCount,
		CA.NotificationCount,
		CA.FailedNotificationCount,
		CA.IsAcknowledged,
		CA.IsResolved,
		CA.ResolvedDate,
		CA.Notes,
		CA.ClosedDate,
		CA.RuleID,
		CA.GroupID,
		ISNULL(NCG.GroupName,CONCAT('Missing group: ',CA.GroupID)) AS GroupName,
		R.Notes AS RuleNotes
FROM Alert.ClosedAlerts CA
LEFT JOIN Alert.Rules R ON CA.RuleID = R.RuleID
JOIN dbo.Instances I ON I.InstanceID = CA.InstanceID
LEFT JOIN Alert.NotificationChannelGroup NCG ON NCG.GroupID = CA.GroupID
OUTER APPLY dbo.SecondsToHumanDuration(DATEDIFF(SECOND,CA.TriggerDate,CASE WHEN CA.IsResolved=1 THEN CA.ResolvedDate ELSE SYSUTCDATETIME() END)) AS AlertDuration
OUTER APPLY dbo.SecondsToHumanDuration(DATEDIFF(SECOND,CA.UpdatedDate,SYSUTCDATETIME())) AS LastUpdate
OUTER APPLY dbo.SecondsToHumanDuration(DATEDIFF(SECOND,CA.LastNotification,SYSUTCDATETIME())) AS LastNotification
WHERE (CA.InstanceID = @InstanceID OR @InstanceID IS NULL)
AND (EXISTS(SELECT 1 
			FROM @InstanceIDs T 
			WHERE I.InstanceID = T.ID
			) OR @AllInstances=1)
ORDER BY CA.ClosedDate DESC
OPTION(RECOMPILE)
GO
