	@AlertID BIGINT,
	@FailedOnly BIT=0
)
AS
SELECT	NL.NotificationDate,
		NCT.NotificationChannelType,
		NC.ChannelName,
		CASE WHEN NL.ErrorMessage IS NULL THEN 'OK' ELSE 'Error' END AS Status,
		NL.ErrorMessage,
		NL.NotificationMessage
