CREATE PROC [Report].[ProcedureInsights](@UTCOffset INT = 0, @Top INT=30,@Instance SYSNAME,@DatabaseID INT=NULL,@Types VARCHAR(200)='P,FN,TR,TA,PC,X')
WITH EXEC AS OWNER
AS
DECLARE @SQL NVARCHAR(MAX)=N'
WITH T AS (
SELECT CAST(DATEADD(mi, @UTCOffset, OES.SnapshotDate) AS DATE) DT,
       D.name,
       O.ObjectName,
	   O.SchemaName,
       O.object_id,
       D.DatabaseID,
	   O.ObjectID,
       SUM(OES.total_elapsed_time) TotalDuration,
	   SUM(OES.execution_count) ExecutionCount,
	   SUM(SUM(OES.total_elapsed_time)) OVER(PARTITION BY O.ObjectID) TotalDurationAllDays
FROM dbo.ObjectExecutionStats_60MIN OES
JOIN dbo.DBObjects O ON O.ObjectID = OES.ObjectID
    JOIN dbo.Databases D ON D.DatabaseID = O.DatabaseID
    JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
WHERE I.Instance = @Instance
AND OES.InstanceID = I.InstanceID
' + CASE WHEN @DatabaseID IS NULL THEN '' ELSE 'AND D.DatabaseID= @DatabaseID' END + '
AND OES.SnapshotDate>= DATEADD(d,-90,CAST(DATEADD(mi,-@UTCOffset,GETUTCDATE()) AS DATE))
AND EXISTS(SELECT 1 FROM STRING_SPLIT(@Types,'','') ss WHERE ss.Value =  O.ObjectType)
GROUP BY CAST(DATEADD(mi, @UTCOffset, OES.SnapshotDate) AS DATE),
         D.name,
         O.ObjectName,
		 O.SchemaName,
         O.object_id,
		 O.ObjectID,
         D.DatabaseID
)
, rankings AS (
	SELECT *,
		DENSE_RANK() OVER(ORDER BY TotalDurationAllDays DESC) Rank 
	FROM T
)
SELECT *
FROM rankings
WHERE rankings.Rank<=@Top
ORDER BY DT
OPTION(RECOMPILE)'

PRINT @SQL

IF @Instance IS NOT NULL
BEGIN
	EXEC sp_executesql @SQL,N'@Instance SYSNAME,@DatabaseID INT,@UTCOffset INT,@Top INT,@Types VARCHAR(200)',@Instance,@DatabaseID,@UTCOffset,@Top,@Types
END 
ELSE
BEGIN
	DECLARE @t TABLE
	(
		[DT] DATE,
		[name] NVARCHAR(128),
		[ObjectName] NVARCHAR(128),
		[SchemaName] NVARCHAR(128),
		[object_id] INT,
		[DatabaseID] INT,
		[ObjectID] BIGINT,
		[TotalDuration] BIGINT,
		[ExecutionCount] BIGINT,
		[TotalDurationAllDays] BIGINT,
		[Rank] BIGINT
	);
	SELECT * FROM @t
END
GO
PRINT N'Creating Procedure [Report].[PerformanceDashboard]...';


GO
CREATE PROC [Report].[PerformanceDashboard](@InstanceIDs VARCHAR(MAX)=NULL,@Mins INT=60)
AS
DECLARE @Instances TABLE(
	InstanceID INT PRIMARY KEY
)
IF @InstanceIDs IS NULL
BEGIN
	INSERT INTO @Instances
	(
	    InstanceID
	)
	SELECT InstanceID 
	FROM dbo.Instances 
	WHERE IsActive=1
END 
ELSE 
BEGIN
	INSERT INTO @Instances
	(
		InstanceID
	)
	SELECT Item
	FROM dbo.SplitStrings(@InstanceIDs,',')
END;

WITH cpuAgg AS (
	SELECT InstanceID,AVG(100-SystemIdleCPU) AvgCPU
	FROM dbo.CPU
	WHERE EventTime >=CAST(DATEADD(mi,-@Mins,GETUTCDATE()) AS DATETIME2(3))
	AND EventTime < CAST(DATEADD(mi,1,GETUTCDATE()) AS DATETIME2(3))
	GROUP BY InstanceID
),
i AS (
	SELECT I.InstanceID,
		I.Instance,
		I.ConnectionID,
		SUM(IOS.num_of_reads)/(SUM(IOS.sample_ms_diff)/1000.0) AS ReadIOPs,
		SUM(IOS.num_of_writes)/(SUM(IOS.sample_ms_diff)/1000.0) AS WriteIOPs,
		SUM(IOS.num_of_bytes_read)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) ReadMBsec,
		SUM(IOS.num_of_bytes_written)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) WriteMBsec,
		SUM(IOS.io_stall_read_ms)/(NULLIF(SUM(IOS.num_of_reads),0)*1.0) AS ReadLatency,
		SUM(IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes),0)*1.0) AS WriteLatency,
		SUM(IOS.io_stall_read_ms+IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes+IOS.num_of_reads),0)*1.0) AS Latency,
		MAX(IOS.MaxReadIOPs) AS MaxReadIOPs,
		MAX(IOS.MaxWriteIOPs) AS MaxWriteIOPs,
		MAX(IOS.MaxIOPs) AS MaxIOPs,
		MAX(IOS.MaxReadMBsec) AS MaxReadMBsec,
		MAX(IOS.MaxWriteMBsec) AS MaxWriteMBsec,
		MAX(MaxMBsec) AS MaxMBsec
	FROM dbo.Instances I
	LEFT JOIN dbo.DBIOStats IOS ON IOS.InstanceID = I.InstanceID
						AND IOS.SnapshotDate>=CAST(DATEADD(mi,-@Mins,GETUTCDATE()) AS DATETIME2(2))
						AND IOS.SnapshotDate< CAST(DATEADD(mi,1,GETUTCDATE()) AS DATETIME2(2))
						AND IOS.FileID=-1
						AND IOS.DatabaseID=-1
						AND IOS.Drive='*'
	WHERE I.IsActive=1
	AND EXISTS(SELECT 1 FROM @Instances t WHERE I.InstanceID = t.InstanceID)
	GROUP BY I.InstanceID,I.Instance,I.ConnectionID
)
, wait AS (
	SELECT W.InstanceID,
		WT.IsCriticalWait, 
		WT.WaitType,
		SUM(W.wait_time_ms) TotalWaitMs,
		SUM(W.wait_time_ms)*1.0/ SUM(SUM(W.wait_time_ms)) OVER(PARTITION BY W.InstanceID) Pct
	FROM dbo.Waits W 
	JOIN dbo.WaitType WT ON WT.WaitTypeID = W.WaitTypeID
	WHERE W.SnapshotDate>= CAST(DATEADD(mi,-@Mins,GETUTCDATE()) AS DATETIME2(2))
	AND W.SnapshotDate< CAST(DATEADD(mi,1,GETUTCDATE()) AS DATETIME2(2))
	AND WT.WaitType <>'REDO_THREAD_PENDING_WORK'
	AND EXISTS(SELECT 1 FROM @Instances t WHERE W.InstanceID = t.InstanceID)
	GROUP BY WT.WaitType,W.InstanceID,WT.IsCriticalWait
)
SELECT i.InstanceID,
		i.ConnectionID,
       i.Instance,
       i.ReadIOPs,
       i.WriteIOPs,
       i.ReadMBsec,
       i.WriteMBsec,
       i.ReadLatency,
       i.WriteLatency,
       i.Latency,
       cpuAgg.AvgCPU,
       i.MaxReadIOPs,
       i.MaxWriteIOPs,
       i.MaxIOPs,
       i.MaxReadMBsec,
       i.MaxWriteMBsec,
       i.MaxMBsec,
       ISNULL(w.WaitType,'') WaitType,
       ISNULL(w.TotalWaitMs,0) TotalWaitMs,
       ISNULL(w.Pct,0) Pct,
	   ISNULL(W.IsCriticalWait,CAST(0 AS BIT)) IsCriticalWait,
	   CASE WHEN w.WaitType LIKE 'LCK%' THEN w.TotalWaitMs ELSE 0 END AS LockWaitMs,
	   CASE WHEN w.WaitType LIKE 'LCK%' THEN w.Pct ELSE 0 END AS LockWaitPct,
	   CASE WHEN w.WaitType LIKE 'PAGEIO%' OR w.WaitType LIKE 'WRITELOG%' THEN w.TotalWaitMs ELSE 0 END AS IOWaitMs,
	   CASE WHEN w.WaitType LIKE 'PAGEIO%' OR w.WaitType LIKE 'WRITELOG%' THEN w.Pct ELSE 0 END AS IOWaitPct
FROM i 
LEFT JOIN cpuAgg ON i.InstanceID = cpuAgg.InstanceID
LEFT JOIN wait w ON i.InstanceID = w.InstanceID AND (w.Pct>=0.01 OR w.IsCriticalWait=1 OR w.WaitType LIKE 'PAGEIO%' OR w.WaitType LIKE 'WRITELOG%')
GO
PRINT N'Creating Procedure [Report].[ProcStats]...';


GO
CREATE  PROC Report.ProcStats(
	@Instance SYSNAME=NULL,
	@DatabaseID INT=NULL,
	@Proc SYSNAME=NULL,
	@FromDate DATETIME=NULL,
	@ToDate DATETIME=NULL,
	@Measure VARCHAR(30)='TotalDuration',
	@DateAgg VARCHAR(20)='NONE',
	@IsFunction BIT=0,
	@UTCOffset INT=0,
	@InstanceID INT=NULL
)
AS
SELECT @FromDate= DATEADD(mi, -@UTCOffset, @FromDate),
	@ToDate = DATEADD(mi, -@UTCOffset, @ToDate) 

IF @FromDate IS NULL
	SET @FromDate = CONVERT(DATETIME,STUFF(CONVERT(VARCHAR,DATEADD(mi,-120,GETUTCDATE()),120),16,4,'0:00'),120) 
IF @ToDate IS NULL
	SET @ToDate = GETUTCDATE()

DECLARE @DateAggString NVARCHAR(MAX)
DECLARE @MeasureString NVARCHAR(MAX) 
SELECT @MeasureString = CASE WHEN @Measure IN('TotalCPU','AvgCPU','TotalDuration','AvgDuration','ExecutionCount','ExecutionsPerMin','AvgLogicalReads','AvgPhysicalReads','AvgWrites','TotalWrites','TotalLogicalReads','TotalPhysicalReads') THEN @Measure ELSE NULL END
SELECT @DateAggString = CASE @DateAgg WHEN 'NONE' THEN 'DATEADD(mi, @UTCOffset, PS.SnapshotDate)'
		WHEN '1MIN' THEN 'DATEADD(mi, DATEDIFF(mi, 0, DATEADD(s, 30, DATEADD(mi, @UTCOffset, PS.SnapshotDate))), 0)'
		WHEN '10MIN' THEN 'CONVERT(DATETIME,STUFF(CONVERT(VARCHAR,DATEADD(mi, @UTCOffset, PS.SnapshotDate),120),16,4,''0:00''),120)'
		WHEN '60MIN' THEN 'DATEADD(mi, @UTCOffset, PS.SnapshotDate) '
		WHEN '1DAY' THEN 'CAST(DATEADD(mi, @UTCOffset, PS.SnapshotDate) AS DATE)' ELSE NULL END
DECLARE @SQL NVARCHAR(MAX)
SET @SQL = N'
WITH agg AS (
SELECT ' + @DateAggString + ' as SnapshotDate,
       D.name AS DatabaseName,
	   D.DatabaseID,
       O.SchemaName + ''.'' + O.objectname as object_name,
	   SUM(PS.total_worker_time)/1000000.0 as TotalCPU,
	   SUM(PS.total_worker_time)/NULLIF(SUM(PS.execution_count),0)/1000000.0 as AvgCPU,
	   SUM(PS.execution_count) as ExecutionCount,
	   SUM(PS.execution_count)/(NULLIF(SUM(PeriodTime),0)/60000000.0) as ExecutionsPerMin,
	   SUM(PS.total_elapsed_time)/1000000.0 AS TotalDuration,
	   SUM(PS.total_elapsed_time)/NULLIF(SUM(PS.execution_count),0)/1000000.0 AS AvgDuration,
	   SUM(PS.total_logical_reads) as TotalLogicalReads,
	   SUM(PS.total_logical_reads)/NULLIF(SUM(PS.execution_count),0) as AvgLogicalReads,
	   SUM(PS.total_physical_reads) as TotalPhysicalReads,
	   SUM(PS.total_physical_reads)/NULLIF(SUM(PS.execution_count),0) as AvgPhysicalReads,
	   SUM(PS.total_logical_writes) as TotalWrites,
	   SUM(PS.total_logical_writes)/NULLIF(SUM(PS.execution_count),0) as AvgWrites
FROM dbo.ObjectExecutionStats' + CASE WHEN @DateAgg IN('60MIN','1DAY') THEN '_60MIN' ELSE '' END + ' PS
    JOIN dbo.DBObjects O ON PS.ObjectID = O.ObjectID
    JOIN dbo.Databases D ON D.DatabaseID = O.DatabaseID
	JOIN dbo.Instances I ON D.InstanceID = I.InstanceID AND PS.InstanceID = I.InstanceID
WHERE D.IsActive=1
' + CASE WHEN @IsFunction=1 THEN 'AND O.ObjectType = ''FN''' ELSE 'AND O.ObjectType IN(''P'',''PC'',''X'')' END + '
' + CASE WHEN @Instance IS NOT NULL THEN 'AND I.Instance = @Instance' ELSE '' END + '
' + CASE WHEN @InstanceID IS NOT NULL THEN 'AND I.InstanceID = @InstanceID' ELSE '' END + '
AND PS.SnapshotDate >= @FromDate 
AND PS.SnapshotDate< @ToDate
' + CASE WHEN @DatabaseID IS NULL THEN '' ELSE 'AND D.DatabaseID=@DatabaseID' END + '
' + CASE WHEN @Proc IS NULL THEN '' ELSE 'AND O.objectname=@Proc' END + '
GROUP BY ' + @DateAggString + ',D.Name,O.objectname,D.DatabaseID,O.SchemaName
)
, T AS (
	SELECT agg.*,
		' + @MeasureString + ' as Measure,
		ROW_NUMBER() OVER (PARTITION BY SnapshotDate ORDER BY ' + @MeasureString + ' DESC) ProcRank
	FROM agg
)
SELECT T.*
FROM T
WHERE ProcRank <=50
ORDER BY DatabaseName, object_name'
PRINT @SQL
IF @SQL IS NOT NULL
BEGIN
	EXEC sp_executesql @SQL,N'@Instance SYSNAME,@DatabaseID INT,@FromDate DATETIME,@ToDate DATETIME,@Proc SYSNAME,@UTCOffset INT,@InstanceID INT',
		@Instance,@DatabaseID,@FromDate,@ToDate,@Proc,@UTCOffset,@InstanceID
END 
ELSE
BEGIN
	DECLARE  @results TABLE( [SnapshotDate] DATETIME, [DatabaseName] NVARCHAR(128),[DatabaseID] INT, [object_name] NVARCHAR(128), [TotalCPU] DECIMAL(29,9), [AvgCPU] DECIMAL(29,9), [ExecutionCount] BIGINT, [ExecutionsPerMin] DECIMAL(38,9), [TotalDuration] DECIMAL(29,9), [AvgDuration] DECIMAL(29,9), [TotalLogicalReads] BIGINT, [AvgLogicalReads] BIGINT, [TotalPhysicalReads] BIGINT, [AvgPhysicalReads] BIGINT, [TotalWrites] BIGINT, [AvgWrites] BIGINT, [Measure] DECIMAL(29,9), [ProcRank] BIGINT )
	SELECT * FROM @results
END
GO
PRINT N'Creating Procedure [Report].[AzureDBUtilization]...';


GO
CREATE PROC [Report].[AzureDBUtilization](@FromDate DATETIME2(3)=NULL,@ToDate DATETIME2(3)=NULL,@Instance SYSNAME=NULL,@DatabaseName SYSNAME=NULL)
AS
IF @FromDate IS NULL
	SET @FromDate = DATEADD(d,-1,GETUTCDATE())
IF @ToDate IS NULL 
	SET @ToDate = GETUTCDATE()
DECLARE @Instances TABLE(
	Instance SYSNAME PRIMARY KEY
)
IF @Instance IS NULL
BEGIN
	INSERT INTO @Instances
	(
	    Instance
	)
	SELECT DISTINCT Instance 
	FROM dbo.Instances 
	WHERE IsActive=1
END 
ELSE 
BEGIN
	INSERT INTO @Instances
	(
		Instance
	)
	SELECT Item
	FROM dbo.SplitStrings(@Instance,',')
END;

WITH T AS (
SELECT RS.InstanceID,
  	MAX(DTU.AvgDTUPercent) Max_DTUPercent,
	MAX(DTU.AvgDTUsUsed) AS Max_DTUsUsed,
	MAX(RS.dtu_limit)-MAX(DTU.AvgDTUsUsed) AS UnusedDTU,
	AVG(DTU.AvgDTUPercent) AS Avg_DTUPercent,
	AVG(DTU.AvgDTUsUsed) AS Avg_DTUsUsed,
	MIN(RS.dtu_limit) Min_DTULimit,
	MAX(RS.dtu_limit) MAX_DTULimit,
	MAX(RS.avg_cpu_percent) AS MaxCPUPercent,
	MAX(RS.avg_data_io_percent) AS MaxDataPercent,
	MAX(RS.avg_log_write_percent) MaxLogWritePercent,
	AVG(RS.avg_cpu_percent) AS AvgCPUPercent,
	AVG(RS.avg_data_io_percent) AS AvgDataPercent,
	AVG(RS.avg_log_write_percent) AvgLogWritePercent,
	DATEDIFF(mi,MIN(RS.end_time),MAX(RS.end_time)) AS Minutes
FROM dbo.AzureDBResourceStats RS
OUTER APPLY(SELECT 	CASE WHEN dtu_limit>0 THEN (SELECT Max(v) FROM (VALUES (avg_cpu_percent), (avg_data_io_percent), (avg_log_write_percent)) AS value(v)) ELSE NULL END AS [AvgDTUPercent],
					CASE WHEN dtu_limit>0 THEN ((dtu_limit)*((SELECT Max(v) FROM (VALUES (avg_cpu_percent), (avg_data_io_percent), (avg_log_write_percent)) AS value(v))/100.00)) ELSE NULL END AS [AvgDTUsUsed]
			) AS DTU
WHERE RS.end_time>=@FromDate
AND RS.end_time <@ToDate
GROUP BY RS.InstanceID
)
SELECT T.InstanceID,
	I.ConnectionID,
	I.Instance,
	D.name AS DB,
	O.edition,
	O.service_objective,
	O.elastic_pool_name,
	T.Max_DTUPercent,
	T.Max_DTUsUsed,
	T.UnusedDTU,
	T.Avg_DTUPercent,
	T.Avg_DTUsUsed,
	T.Min_DTULimit,
	T.MAX_DTULimit,
	T.MaxCPUPercent,
	T.MaxDataPercent,
	T.MaxLogWritePercent,
	T.AvgCPUPercent,
	T.AvgDataPercent,
	T.AvgLogWritePercent,
	T.Minutes
FROM T
JOIN dbo.Instances I ON I.InstanceID = T.InstanceID
JOIN dbo.Databases D ON I.InstanceID = D.InstanceID
LEFT JOIN dbo.AzureDBServiceObjectives O ON O.InstanceID = I.InstanceID
WHERE I.IsActive=1
AND D.IsActive=1
AND EXISTS(SELECT 1 FROM @Instances t WHERE I.Instance = t.Instance)
AND (D.name=@DatabaseName OR @DatabaseName IS NULL)
ORDER BY T.UnusedDTU DESC;
GO
