PRINT N'Creating Procedure [dbo].[AvailabilityGroup_Get]...';


GO
CREATE PROC dbo.AvailabilityGroup_Get(
    @InstanceID INT
)
AS
SELECT D.name AS [Database],
       AG.name AS [Availability Group],
       AR.replica_server_name AS [Replica Server],
       HADR.synchronization_state_desc AS [Sync State],
       HADR.synchronization_health_desc AS [Sync Health],
       HADR.suspend_reason_desc AS [Suspend Reason],
       HADR.database_state_desc AS [Database State],
       HADR.is_local AS [Is Local],
       AR.availability_mode_desc AS [Availability Mode],
       AR.failover_mode_desc AS [Failover Mode],
	   HADR.is_primary_replica [Is Primary],
	   AR.primary_role_allow_connections_desc [Primary Connections],
	   AR.secondary_role_allow_connections_desc [Secondary Connections],
       CD.SnapshotDate as [Snapshot Date],
       CD.Status as [Snapshot Status],
       CD.HumanSnapshotAge as [Snapshot Age],
       calc.[Estimated Data Loss (sec)],
       calc.[Estimated Recovery Time (sec)],
       HADR.secondary_lag_seconds AS [Secondary Lag (sec)],
       CASE WHEN HADR.is_primary_replica =1 THEN 'None (Primary)' WHEN HADR.is_local=1 THEN 'Reported on Primary' WHEN PrimaryHADR.is_suspended=1 THEN PrimaryHADR.suspend_reason_desc ELSE HDLag.HumanDuration END AS [Secondary Lag],
       CASE WHEN Calc.[Estimated Data Loss (sec)] =-1 THEN 'None (Primary)' WHEN Calc.[Estimated Data Loss (sec)]=-2 THEN 'Unknown' ELSE HDDataLoss.HumanDuration END AS [Estimated Data Loss],
       CASE WHEN calc.[Estimated Recovery Time (sec)]=-1 THEN 'None (Primary)' WHEN calc.[Estimated Recovery Time (sec)]=-2 THEN 'Unknown' ELSE HDRecovery.HumanDuration END AS [Estimated Recovery Time],
       HADR.redo_queue_size AS [Log Redo Queue Size (KB)],        
       HADR.redo_rate AS [Log Redo Rate (KB/s)],
       HADR.log_send_queue_size AS [Log Send Queue Size (KB)],
       HADR.log_send_rate AS [Log Send Rate (KB/s)],
       HADR.last_sent_time AS [Last Sent Time],
       HADR.last_received_time AS [Last Received Time],
       HADR.last_hardened_time AS [Last Hardened Time],
       HADR.last_redone_time AS [Last Redone Time],
       HADR.last_commit_time AS [Last Commit Time]     
FROM dbo.DatabasesHADR HADR
JOIN dbo.Databases D ON D.DatabaseID = HADR.DatabaseID
LEFT JOIN dbo.AvailabilityReplicas AR ON D.InstanceID = AR.InstanceID
                                         AND AR.replica_id = HADR.replica_id
LEFT JOIN dbo.AvailabilityGroups AG ON HADR.group_id = AG.group_id
                                       AND D.InstanceID = AG.InstanceID
LEFT JOIN dbo.CollectionDatesStatus CD ON D.InstanceID = CD.InstanceID AND CD.Reference='DatabaseHADR'
LEFT JOIN dbo.DatabasesHADR PrimaryHADR ON PrimaryHADR.InstanceID = HADR.InstanceID 
                                         AND PrimaryHADR.group_database_id = HADR.group_database_id 
                                         AND PrimaryHADR.is_primary_replica = 1
                                         AND PrimaryHADR.is_local = 1     
OUTER APPLY(SELECT  CASE WHEN HADR.is_primary_replica = 1 THEN -1 WHEN HADR.synchronization_state=2 THEN 0 ELSE DATEDIFF(ss, HADR.last_commit_time, PrimaryHADR.last_commit_time) END [Estimated Data Loss (sec)],
                    CASE WHEN HADR.is_primary_replica = 1 THEN -1 WHEN HADR.redo_queue_size IS NULL THEN -2 WHEN HADR.redo_queue_size = 0 THEN 0 WHEN HADR.redo_rate IS NULL OR HADR.redo_rate = 0 THEN -2 ELSE CAST(HADR.redo_queue_size AS FLOAT) / HADR.redo_rate END AS [Estimated Recovery Time (sec)]
            ) AS Calc
OUTER APPLY dbo.SecondsToHumanDuration(calc.[Estimated Data Loss (sec)]) AS HDDataLoss
OUTER APPLY dbo.SecondsToHumanDuration(calc.[Estimated Recovery Time (sec)]) AS HDRecovery
OUTER APPLY dbo.SecondsToHumanDuration(HADR.secondary_lag_seconds) AS HDLag
WHERE D.InstanceID = @InstanceID
AND HADR.InstanceID = @InstanceID
AND D.IsActive=1
ORDER BY HADR.is_local DESC,
         AG.name,
         D.name;
GO
PRINT N'Creating Procedure [dbo].[AvailabilityGroupSummary_Get]...';


GO
CREATE PROC dbo.AvailabilityGroupSummary_Get(
    @InstanceIDs IDs READONLY
)
AS
WITH T AS (
SELECT I.InstanceID,
       I.InstanceDisplayName AS Instance,
       SUM(CASE WHEN HADR.is_primary_replica = 1 AND HADR.is_local=1 THEN 1 ELSE 0 END) AS [Primary Replicas],
	   SUM(CASE WHEN HADR.is_primary_replica = 0 AND HADR.is_local=1 THEN 1 ELSE 0 END) AS [Secondary Replicas],
	   SUM(CASE WHEN AR.secondary_role_allow_connections>0 AND HADR.is_local=1 THEN 1 ELSE 0 END) AS [Readable Secondaries],
	   SUM(CASE WHEN AR.availability_mode=0 AND HADR.is_local=1 THEN 1 ELSE 0 END) AS [Async Commit],
	   SUM(CASE WHEN AR.availability_mode=1 AND HADR.is_local=1 THEN 1 ELSE 0 END) AS [Sync Commit],
       SUM(CASE WHEN HADR.synchronization_state = 0 AND HADR.is_local = 1 THEN 1 ELSE 0 END) AS [Not Synchronizing],
       SUM(CASE WHEN HADR.synchronization_state = 1 AND HADR.is_local = 1 THEN 1 ELSE 0 END) AS [Synchronizing],
       SUM(CASE WHEN HADR.synchronization_state = 2 AND HADR.is_local = 1 THEN 1 ELSE 0 END) AS [Synchronized],
       SUM(CASE WHEN HADR.synchronization_state = 3 AND HADR.is_local = 1 THEN 1 ELSE 0 END) AS [Reverting],
       SUM(CASE WHEN HADR.synchronization_state = 4 AND HADR.is_local = 1 THEN 1 ELSE 0 END) AS [Initializing],
       SUM(CASE WHEN HADR.synchronization_state = 0 AND HADR.is_local = 0 THEN 1 ELSE 0 END) AS [Remote Not Synchronizing],
       SUM(CASE WHEN HADR.synchronization_state = 1 AND HADR.is_local = 0 THEN 1 ELSE 0 END) AS [Remote Synchronizing],
       SUM(CASE WHEN HADR.synchronization_state = 2 AND HADR.is_local = 0 THEN 1 ELSE 0 END) AS [Remote Synchronized],
       SUM(CASE WHEN HADR.synchronization_state = 3 AND HADR.is_local = 0 THEN 1 ELSE 0 END) AS [Remote Reverting],
       SUM(CASE WHEN HADR.synchronization_state = 4 AND HADR.is_local = 0 THEN 1 ELSE 0 END) AS [Remote Initializing],
       CASE MIN(HADR.synchronization_health)WHEN 0 THEN 'NOT_HEALTHY' WHEN 1 THEN 'PARTIALLY_HEALTHY' WHEN 2 THEN 'HEALTHY' ELSE NULL END AS [Sync Health],
       MAX(HADR.secondary_lag_seconds) AS [Max Secondary Lag (sec)],
       MAX(CASE WHEN HADR.is_primary_replica = 1 THEN -1 WHEN HADR.synchronization_state=2 THEN 0 ELSE ISNULL(DATEDIFF(ss, HADR.last_commit_time, PrimaryHADR.last_commit_time), -2) END) [Max Estimated Data Loss (sec)],
       MAX(CASE WHEN HADR.is_primary_replica = 1 THEN -1 WHEN HADR.redo_queue_size IS NULL THEN -2 WHEN HADR.redo_queue_size = 0 THEN 0 WHEN HADR.redo_rate IS NULL OR HADR.redo_rate = 0 THEN -2 ELSE CAST(HADR.redo_queue_size AS FLOAT) / HADR.redo_rate END) AS [Max Estimated Recovery Time (sec)],
       SUM(HADR.redo_queue_size) AS [Total Redo Queue Size (KB)],
       SUM(HADR.log_send_queue_size) AS [Total Log Send Queue Size (KB)],
       AVG(HADR.redo_queue_size) AS [Avg Redo Queue Size (KB)],
       AVG(HADR.log_send_queue_size) AS [Avg Log Send Queue Size (KB)],
       MIN(CD.SnapshotDate) as [Snapshot Date],
       MIN(CD.Status) as [Snapshot Status],
       MAX(CD.HumanSnapshotAge) as [Snapshot Age],
       MAX(CASE WHEN ISNULL(HADR.synchronization_state,0) <> 2 AND HADR.is_local = 1 THEN 6 ELSE 4 END) AS [Synchronized Status]
FROM dbo.DatabasesHADR HADR
JOIN dbo.Databases D ON D.DatabaseID = HADR.DatabaseID AND HADR.InstanceID = D.InstanceID
JOIN dbo.Instances I ON D.InstanceID = I.InstanceID
LEFT JOIN dbo.AvailabilityReplicas AR ON D.InstanceID = AR.InstanceID
                                         AND AR.replica_id = HADR.replica_id
LEFT JOIN dbo.AvailabilityGroups AG ON HADR.group_id = AG.group_id
                                       AND D.InstanceID = AG.InstanceID
LEFT JOIN dbo.CollectionDatesStatus CD ON D.InstanceID = CD.InstanceID AND CD.Reference='DatabaseHADR'
LEFT JOIN dbo.DatabasesHADR PrimaryHADR ON PrimaryHADR.InstanceID = HADR.InstanceID 
                                         AND PrimaryHADR.group_database_id = HADR.group_database_id 
                                         AND PrimaryHADR.is_primary_replica = 1
                                         AND PrimaryHADR.is_local = 1     
WHERE EXISTS(
        SELECT 1 
        FROM @InstanceIDs T 
        WHERE T.ID= I.InstanceID
        )
AND D.IsActive=1
GROUP BY I.Instance,I.InstanceID,I.InstanceDisplayName
)
SELECT T.InstanceID,
       T.Instance,
       T.[Primary Replicas],
       T.[Secondary Replicas],
       T.[Readable Secondaries],
       T.[Async Commit],
       T.[Sync Commit],
       T.[Not Synchronizing],
       T.Synchronizing,
       T.Synchronized,
       T.Reverting,
       T.Initializing,
       T.[Remote Not Synchronizing],
       T.[Remote Synchronizing],
       T.[Remote Synchronized],
       T.[Remote Reverting],
       T.[Remote Initializing],
       T.[Sync Health],
       T.[Snapshot Date],
       T.[Snapshot Status],
       T.[Snapshot Age],
       T.[Synchronized Status],
       T.[Max Secondary Lag (sec)],
       T.[Max Estimated Data Loss (sec)],
       T.[Max Estimated Recovery Time (sec)],
       HDLag.HumanDuration AS [Max Secondary Lag],
       CASE WHEN T.[Max Estimated Data Loss (sec)] =-1 THEN 'None (Primary)' WHEN T.[Max Estimated Data Loss (sec)]=-2 THEN 'Unknown' ELSE HDDataLoss.HumanDuration END AS [Max Estimated Data Loss],
       CASE WHEN T.[Max Estimated Recovery Time (sec)]=-1 THEN 'None (Primary)' WHEN T.[Max Estimated Recovery Time (sec)]=-2 THEN 'Unknown' ELSE HDRecovery.HumanDuration END AS [Max Estimated Recovery Time],
       T.[Total Redo Queue Size (KB)],
       T.[Avg Redo Queue Size (KB)],
       T.[Total Log Send Queue Size (KB)],
       T.[Avg Log Send Queue Size (KB)]
FROM T
OUTER APPLY dbo.SecondsToHumanDuration(T.[Max Secondary Lag (sec)]) AS HDLag
OUTER APPLY dbo.SecondsToHumanDuration(T.[Max Estimated Data Loss (sec)]) AS HDDataLoss
OUTER APPLY dbo.SecondsToHumanDuration(T.[Max Estimated Recovery Time (sec)]) AS HDRecovery
GO
PRINT N'Creating Procedure [dbo].[AzureDBCounters_Upd]...';


GO
CREATE PROC dbo.AzureDBCounters_Upd(
	@InstanceID INT=NULL
)
AS
/*
	Create virtual counters for Azure SQL Database Elastic Pool resource stats & Azure SQL Database resource stats.
	dbo.AzureDBElasticPoolResourceStatsCounters, dbo.AzureDBElasticPoolResourceStatsCounters_60MIN, AzureDBResourceStatsCounters & AzureDBResourceStatsCounters_60MIN views replicate dbo.PerformanceCounters and dbo.PerformanceCounters_60MIN tables.
	dbo.PerformanceCountersBetweenDates & dbo.PerformanceCountersBetweenDates_60MIN functions incorporate these views when CounterType=3 (Elastic Pool) or CounterType=4 (Azure DB resource stats).
	
*/
INSERT INTO dbo.Counters(object_name,counter_name,instance_name,CounterType)
SELECT 'sys.elastic_pool_resource_stats',counter_name,elastic_pool_name,3
FROM (	SELECT DISTINCT elastic_pool_name 
		FROM dbo.AzureDBElasticPool
		WHERE (InstanceID = @InstanceID OR @InstanceID IS NULL)
		) pools
CROSS APPLY (
VALUES('avg_allocated_storage_percent'),
	('avg_cpu_percent'),
	('avg_data_io_percent'),
	('avg_log_write_percent'),
	('avg_storage_percent'),
	('max_worker_percent'),
	('max_session_percent'),
	('elastic_pool_dtu_limit'),
	('elastic_pool_storage_limit_mb'),
	('elastic_pool_cpu_limit')
	) T (counter_name)
WHERE NOT EXISTS(
		SELECT 1 
		FROM dbo.Counters C
		WHERE C.object_name='sys.elastic_pool_resource_stats'
		AND C.CounterType = 3
		AND C.instance_name = pools.elastic_pool_name
		AND C.counter_name = T.counter_name
		)
OPTION(RECOMPILE)
	
INSERT INTO dbo.InstanceCounters(InstanceID,CounterID)
SELECT P.InstanceID, C.CounterID
FROM dbo.Counters C
JOIN dbo.AzureDBElasticPool P ON C.instance_name = P.elastic_pool_name
WHERE C.CounterType = 3
AND C.object_name = 'sys.elastic_pool_resource_stats'
AND (P.InstanceID = @InstanceID OR @InstanceID IS NULL)
AND NOT EXISTS(	SELECT 1 
				FROM InstanceCounters IC
				WHERE IC.InstanceID = P.InstanceID
				AND IC.CounterID = C.CounterID
				)
OPTION(RECOMPILE)

INSERT INTO dbo.InstanceCounters(InstanceID,CounterID)
SELECT  I.InstanceID,C.CounterID
FROM dbo.Instances I
CROSS JOIN dbo.Counters C
WHERE EngineEdition = 5
AND C.CounterType = 4
AND NOT EXISTS(
			SELECT 1 
			FROM dbo.InstanceCounters IC 
			WHERE IC.CounterID = C.CounterID 
			AND IC.InstanceID = I.InstanceID
			)
AND (I.InstanceID = @InstanceID OR @InstanceID IS NULL)
OPTION(RECOMPILE)
GO
