       SnapshotAgeStatus,
       FullBackupSizeGB,
       FullBackupMBsec,
       FullBackupSizeCompressedGB,
       FullCompressionSavingPct,
       FullBackupWriteMBsec,
       DiffBackupSizeGB,
       DiffBackupMBsec,
       DiffBackupSizeCompressedGB,
       DiffCompressionSavingPct,
       DiffBackupWriteMBsec,
       FullEncrypted,
       DiffEncrypted,
       LogEncrypted,
       FullChecksum,
       DiffChecksum,
       LogChecksum,
       FullCompressed,
       DiffCompressed,
       LogCompressed,
       FullPasswordProtected,
