GO
CREATE PROC dbo.Blocking_Get(
	/* Supply @BlockingSnapshotID OR @InstanceID + @SnapshotDate */
	@BlockingSnapshotID INT=NULL,
	@blocking_session_id INT=0, /* Start with blocking_session_id 0 (root blocker) */
	@InstanceID INT=NULL,
	@SnapshotDate DATETIME2(7)=NULL
)
AS
IF @InstanceID IS NULL OR @SnapshotDate IS NULL
BEGIN
	SELECT @InstanceID = InstanceID,
			@SnapshotDate = SnapshotDateUTC
	FROM dbo.BlockingSnapshotSummary
	WHERE BlockingSnapshotID=@BlockingSnapshotID
END

SELECT Q.session_id,
	ISNULL(Q.blocking_session_id,0) AS blocking_session_id,
	SUBSTRING(QT.text,ISNULL((NULLIF(Q.statement_start_offset,-1)/2)+1,0),ISNULL((NULLIF(Q.statement_end_offset,-1) - NULLIF(Q.statement_start_offset,-1))/2+1,2147483647)) AS Txt,
	ISNULL(Q.start_time_utc,Q.last_request_start_time_utc) AS start_time_utc,
	Q.command,
	Q.database_id,
	D.name AS database_name,
	Q.host_name,
	Q.program_name,
	Q.wait_time,
	Q.login_name,
	Q.wait_resource,
	Q.status,
	stat.BlockCountRecursive,
	stat.BlockWaitTimeRecursiveMs AS WaitTimeRecursive,
	stat.BlockCount,
	stat.BlockWaitTimeMs as BlockWaitTime,
	Q.status AS session_status,
	CASE Q.transaction_isolation_level WHEN 0 THEN 'Unspecified'
		WHEN 1 THEN 'ReadUncomitted'
		WHEN 2 THEN 'ReadCommitted'
		WHEN 3 THEN 'Repeatable'
		WHEN 4 THEN 'Serializable'
		WHEN 5 THEN 'Snapshot'
		ELSE CAST(Q.transaction_isolation_level AS VARCHAR(30)) END as transaction_isolation_level
FROM dbo.RunningQueries Q 
LEFT JOIN dbo.QueryText QT ON QT.sql_handle = Q.sql_handle
LEFT JOIN dbo.Databases D ON Q.database_id = D.database_id AND D.InstanceID=@InstanceID AND D.IsActive=1
OUTER APPLY dbo.RunningQueriesBlockingRecursiveStats(@InstanceID,@SnapshotDate,Q.session_id) stat
WHERE Q.InstanceID = @InstanceID
AND Q.SnapshotDateUTC = @SnapshotDate
AND Q.blocking_session_id = @blocking_session_id
AND (stat.BlockCount >0 OR @blocking_session_id <> 0)
ORDER BY stat.BlockWaitTimeRecursiveMs DESC
GO
PRINT N'Creating Procedure [dbo].[BlockingSnapshots_Get]...';


GO
CREATE PROC dbo.BlockingSnapshots_Get(
	@InstanceID INT,
	@FromDate DATETIME2(3), /* UTC */
	@ToDate DATETIME2(3), /* UTC */
	@Top INT=500,
	@DatabaseID INT=NULL,
	@UTCOffset INT=0, /* Used for Hours filter */
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY/* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
)
AS
SET DATEFIRST 1 /* Start week on Monday */
SET NOCOUNT ON
-- DatabaseID filter isn't required for AzureDB
IF EXISTS(
	SELECT 1
	FROM dbo.InstanceInfo
	WHERE InstanceID=@InstanceID 
	AND EngineEdition=5
)
BEGIN
	SET @DatabaseID=NULL
END

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @SQL NVARCHAR(MAX) 
SET @SQL = N'
SELECT TOP(@Top) SS.BlockingSnapshotID,
				SS.SnapshotDateUTC,
				SS.BlockedSessionCount,
				SS.BlockedWaitTime 
FROM dbo.BlockingSnapshotSummary SS
WHERE SS.InstanceID = @InstanceID
AND SS.SnapshotDateUTC>=@FromDate
AND SS.SnapshotDateUTC<@ToDate
' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, SS.SnapshotDateUTC)) IN (' + @DaysOfWeekCsv + ')' END + '
' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, SS.SnapshotDateUTC)) IN(' + @HoursCsv + ')' END + '
' + CASE WHEN @DatabaseID IS NULL THEN '' 
	ELSE 'AND EXISTS(SELECT 1
					FROM dbo.RunningQueries Q
					JOIN dbo.Databases D ON Q.InstanceID = D.InstanceID AND D.database_id = Q.database_id
					WHERE Q.InstanceID = @InstanceID
					AND Q.SnapshotDateUTC = SS.SnapshotDateUTC
					AND D.DatabaseID = @DatabaseID
					AND Q.blocking_session_id <> 0
					)'	END + '
ORDER BY SS.BlockedWaitTime DESC'

EXEC sp_executesql @SQL,
					N'@InstanceID INT,
					@DatabaseID INT,
					@FromDate DATETIME2,
					@ToDate DATETIME2,
					@Top INT,
					@UTCOffset INT',
					@InstanceID,
					@DatabaseID,
					@FromDate,
					@ToDate,
					@Top,
					@UTCOffset
GO
PRINT N'Creating Procedure [dbo].[BlockingSnapshotSummary_Del]...';


GO
CREATE PROC dbo.BlockingSnapshotSummary_Del(
	@InstanceID INT,
	@DaysToKeep INT,
	@BatchSize INT = 500000
)
AS
/* 
	Partitioning switching is used to efficiently remove data from this table for all instances.  
	This proc provides an alternative way to remove data associated with a specific instance.
*/
SET NOCOUNT ON
DECLARE @MaxDate DATETIME2
SELECT @MaxDate = CASE WHEN @DaysToKeep  = 0 THEN '30000101' ELSE DATEADD(d,-@DaysToKeep,GETUTCDATE()) END

SELECT @MaxDate = DATEADD(d,-RetentionDays,GETUTCDATE())
FROM dbo.DataRetention
WHERE TableName = 'RunningQueries'

WHILE 1=1
BEGIN
	DELETE TOP(@BatchSize) 
	FROM dbo.BlockingSnapshotSummary
	WHERE SnapshotDateUTC < @MaxDate
	AND InstanceID  = @InstanceID

	IF @@ROWCOUNT<@BatchSize
		BREAK
END
GO
