PRINT N'Creating Procedure [dbo].[Corruption_Get]...';


GO
CREATE PROC dbo.Corruption_Get(
	@InstanceIDs dbo.IDs READONLY
)
AS
SELECT D.DatabaseID,
	I.InstanceID,
	I.InstanceGroupName,	
	D.name,
	C.UpdateDate,
	C.AckDate,
	CASE WHEN C.AckDate >= DATEADD(mi,I.UTCOffset,C.UpdateDate) THEN 5 ELSE 1 END AS CorruptionStatus,
	CASE WHEN C.SourceTable = 1 THEN 'msdb.dbo.suspect_pages'
		WHEN C.SourceTable=2 THEN 'sys.dm_db_mirroring_auto_page_repair'
		WHEN C.SourceTable=3 THEN 'sys.dm_hadr_auto_page_repair'
		ELSE NULL END as SourceTable,
	D.LastGoodCheckDbTime,
	LG.Status as LastGoodCheckDBStatus,
	DATEADD(mi,I.UTCOffset,C.UpdateDate) AS UpdateDateUtc,
	C.CountOfRows,
	CASE WHEN C.SourceTable <> 1 THEN 4 WHEN C.CountOfRows>=1000 THEN 1 WHEN C.CountOfRows > 800 THEN 2 ELSE 4 END AS CountOfRowsStatus
FROM dbo.Corruption C 
JOIN dbo.Databases D ON C.DatabaseID = D.DatabaseID
JOIN dbo.Instances I ON D.InstanceID = I.InstanceID
LEFT JOIN dbo.LastGoodCheckDB LG ON LG.DatabaseID = D.DatabaseID
WHERE EXISTS(	
				SELECT 1 
				FROM @InstanceIDs T 
				WHERE T.ID = I.InstanceID
			)
ORDER BY C.UpdateDate DESC
GO
PRINT N'Creating Procedure [dbo].[Corruption_Upd]...';


GO
CREATE PROC dbo.Corruption_Upd(
		@Corruption dbo.Corruption READONLY,
		@InstanceID INT,
		@SnapshotDate DATETIME2(2)
)
AS
DECLARE @Ref VARCHAR(30)='Corruption'
IF NOT EXISTS	(	
				SELECT 1 
				FROM dbo.CollectionDates 
				WHERE SnapshotDate>=@SnapshotDate 
				AND InstanceID = @InstanceID 
				AND Reference=@Ref				
				)
BEGIN
	CREATE TABLE #CorruptionTemp(
		DatabaseID INT NOT NULL,
		SourceTable TINYINT NOT NULL,
		UpdateDate DATETIME2(3) NOT NULL,
		CountOfRows INT NULL
	)
	INSERT INTO #CorruptionTemp
	(
	    DatabaseID,
	    SourceTable,
	    UpdateDate,
		CountOfRows
	)
	SELECT	D.DatabaseID, 
			C.SourceTable,
			C.last_update_date,
			C.CountOfRows
	FROM @Corruption C 
	JOIN dbo.Databases D ON C.database_id = D.database_id AND D.InstanceID  = @InstanceID
	WHERE D.IsActive=1

	UPDATE C
		SET C.UpdateDate = T.UpdateDate,
			C.CountOfRows = T.CountOfRows
	FROM dbo.Corruption C 
	JOIN #CorruptionTemp T ON C.DatabaseID = T.DatabaseID AND C.SourceTable = T.SourceTable
	WHERE	EXISTS(	SELECT T.DatabaseID,T.SourceTable, T.UpdateDate, T.CountOfRows
					EXCEPT
					SELECT T.DatabaseID,T.SourceTable, C.UpdateDate, C.CountOfRows
					)

	INSERT INTO dbo.Corruption
	(
		DatabaseID,
		SourceTable,
		UpdateDate,
		CountOfRows
	)
	SELECT DatabaseID,
		SourceTable,
		UpdateDate,
		CountOfRows
	FROM #CorruptionTemp T
	WHERE NOT EXISTS(
					SELECT 1 
					FROM dbo.Corruption C
					WHERE C.DatabaseID = T.DatabaseID
					AND C.SourceTable = T.SourceTable
					)

	DELETE  C 
	FROM dbo.Corruption C 
	JOIN dbo.Databases D ON C.DatabaseID = D.DatabaseID 
	WHERE D.InstanceID = @InstanceID
	AND NOT EXISTS(SELECT 1
					FROM #CorruptionTemp T 
					WHERE T.DatabaseID = D.DatabaseID 
					AND T.SourceTable = C.SourceTable)

	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
									 @Reference = @Ref,
									 @SnapshotDate = @SnapshotDate

END
GO
