CREATE PROCEDURE dbo.CounterThresholds_Get(
	@InstanceID INT=NULL,
	@object_name NVARCHAR (128),
    @counter_name NVARCHAR (128),
    @instance_name NVARCHAR (128)
)
AS
IF @InstanceID IS NULL
BEGIN
	SELECT C.CriticalFrom,
		C.CriticalTo,
		C.WarningFrom,
		C.WarningTo,
		C.GoodFrom,
		C.GoodTo,
		C.SystemCriticalFrom,
		C.SystemCriticalTo,
		C.SystemWarningFrom,
		C.SystemWarningTo,
		C.SystemGoodFrom,
		C.SystemGoodTo
	FROM dbo.Counters C
	WHERE C.object_name = @object_name
	AND C.counter_name = @counter_name
	AND C.instance_name = @instance_name
END
BEGIN
	SELECT IC.CriticalFrom,
		IC.CriticalTo,
		IC.WarningFrom,
		IC.WarningTo,
		IC.GoodFrom,
		IC.GoodTo,
		C.SystemCriticalFrom,
		C.SystemCriticalTo,
		C.SystemWarningFrom,
		C.SystemWarningTo,
		C.SystemGoodFrom,
		C.SystemGoodTo
	FROM dbo.Counters C
	JOIN dbo.InstanceCounters IC ON IC.CounterID = C.CounterID
	WHERE C.object_name = @object_name
	AND C.counter_name = @counter_name
	AND C.instance_name = @instance_name
	AND IC.InstanceID = @InstanceID
END
GO
PRINT N'Creating Procedure [dbo].[CounterThresholds_Upd]...';


GO
CREATE PROCEDURE dbo.CounterThresholds_Upd(
	@InstanceID INT=NULL,
	@object_name NVARCHAR (128),
    @counter_name NVARCHAR (128),
    @instance_name NVARCHAR (128)=NULL,
	@CriticalFrom DECIMAL (28, 9),
    @CriticalTo DECIMAL (28, 9),
	@WarningFrom DECIMAL (28, 9),
	@WarningTo DECIMAL (28, 9),
	@GoodFrom DECIMAL (28, 9),
	@GoodTo DECIMAL (28, 9)
)
AS
IF @InstanceID IS NULL
BEGIN
	UPDATE dbo.Counters
	SET CriticalFrom=@CriticalFrom,
		CriticalTo=@CriticalTo,
		WarningFrom=@WarningFrom,
		WarningTo=@WarningTo,
		GoodFrom=@GoodFrom,
		GoodTo=@GoodTo
	WHERE object_name = @object_name
	AND counter_name = @counter_name
	AND (instance_name = @instance_name OR @instance_name IS NULL)
END
BEGIN
	UPDATE IC
	SET IC.CriticalFrom=@CriticalFrom,
		IC.CriticalTo=@CriticalTo,
		IC.WarningFrom=@WarningFrom,
		IC.WarningTo=@WarningTo,
		IC.GoodFrom=@GoodFrom,
		IC.GoodTo=@GoodTo
	FROM dbo.Counters C
	JOIN dbo.InstanceCounters IC ON C.CounterID = IC.CounterID
	WHERE IC.InstanceID = @InstanceID
	AND C.object_name = @object_name
	AND C.counter_name = @counter_name
	AND (C.instance_name = @instance_name OR @instance_name IS NULL)
END
