GO
CREATE PROC dbo.CPU_Get(
	@InstanceID INT,
	@FromDate DATETIME2(3)=NULL, /* UTC */
	@ToDate DATETIME2(3)=NULL, /* UTC */
	@DateGroupingMin INT=NULL, /* How many minutes to group by.  */
	@UTCOffset INT=0, /* Used for Hours filter */
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY/* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
)
AS
SET DATEFIRST 1 /* Start week on Monday */
IF @FromDate IS NULL
	SET @FromDate = DATEADD(mi,-60,GETUTCDATE())
IF @ToDate IS NULL
	SET @ToDate = GETUTCDATE()
DECLARE @SQL NVARCHAR(MAX)
DECLARE @DateGroupingSQL NVARCHAR(MAX)
SELECT @DateGroupingSQL= CASE WHEN @DateGroupingMin = 0 OR @DateGroupingMin IS NULL THEN 'EventTime'
			ELSE 'DateGroup' END


/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

SET @SQL = N'
SELECT ' + @DateGroupingSQL + ' AS EventTime,
       SUM(SumSQLProcessCPU*1.0)/SUM(SampleCount*1.0) as SQLProcessCPU,
	   SUM(SumOtherCPU*1.0)/SUM(SampleCount*1.0) as OtherCPU,
	   MAX(MaxTotalCPU*1.0) as MaxCPU
FROM '+ CASE WHEN @DateGroupingMin >=60 THEN 'dbo.CPU_60MIN' ELSE 'dbo.CPU' END + '
' + CASE WHEN @DateGroupingMin IS NULL OR @DateGroupingMin= 0 THEN '' ELSE 'CROSS APPLY dbo.DateGroupingMins(EventTime,@DateGroupingMin)' END + '
WHERE InstanceID = @InstanceID
AND EventTime >= @FromDate
AND EventTime < @ToDate
' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, EventTime)) IN (' + @DaysOfWeekCsv + ')' END + '
' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, EventTime)) IN(' + @HoursCsv + ')' END + '
GROUP BY ' + @DateGroupingSQL + '
ORDER BY EventTime'

PRINT @SQL
EXEC sp_executesql @SQL,
				N'@InstanceID INT,
				@FromDate DATETIME2(3),
				@ToDate DATETIME2(3),
				@DateGroupingMin INT,
				@UTCOffset INT',
				@InstanceID,
				@FromDate,
				@ToDate,
				@DateGroupingMin,
				@UTCOffset
GO
PRINT N'Creating Procedure [dbo].[CPU_Upd]...';


GO
CREATE PROC [dbo].[CPU_Upd](
	@CPU dbo.CPU READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON
DECLARE @IsLinux BIT 
SELECT @IsLinux = CASE WHEN EXISTS(SELECT 1 
									FROM dbo.Instances
									WHERE InstanceID = @InstanceID
									AND host_platform = 'Linux') 
						THEN CAST(1 as BIT) ELSE CAST(0 as BIT) END
DECLARE @Ref VARCHAR(30)='CPU'

DECLARE @Inserted TABLE(
	[EventTime] [datetime2](3) NOT NULL PRIMARY KEY,
	[SQLProcessCPU] [tinyint] NOT NULL,
	[SystemIdleCPU] [tinyint] NOT NULL
)
DECLARE @60MIN TABLE(
	[EventTime] [datetime2](3) NOT NULL,
	[SumSQLProcessCPU] [int] NOT NULL,
	[SumSystemIdleCPU] [int] NOT NULL,
	[SampleCount] [smallint] NOT NULL,
	[MaxSQLProcessCPU] [tinyint] NOT NULL,
	[MaxOtherProcessCPU] [tinyint] NOT NULL,
	[MaxTotalCPU] [tinyint] NOT NULL,
	[CPU10] [smallint] NULL,
	[CPU20] [smallint] NULL,
	[CPU30] [smallint] NULL,
	[CPU40] [smallint] NULL,
	[CPU50] [smallint] NULL,
	[CPU60] [smallint] NULL,
	[CPU70] [smallint] NULL,
	[CPU80] [smallint] NULL,
	[CPU90] [smallint] NULL,
	[CPU100] [smallint] NULL
)

DECLARE @MaxEventTime DATETIME2(3)
DECLARE @MaxEventTimeHr DATETIME2(3)
SELECT TOP(1) @MaxEventTime= ISNULL(MAX(EventTime),'19000101') 
FROM dbo.CPU
WHERE InstanceID = @InstanceID

SELECT @MaxEventTime = DATEADD(mi,1,DG.DateGroup)
FROM dbo.DateGroupingMins(@MaxEventTime,1) DG

SELECT @MaxEventTimeHr = DG.DateGroup 
FROM dbo.DateGroupingMins(@MaxEventTime,60) DG

BEGIN TRAN
INSERT INTO dbo.CPU(InstanceID,EventTime,SQLProcessCPU,SystemIdleCPU)
OUTPUT INSERTED.EventTime,INSERTED.SQLProcessCPU,INSERTED.SystemIdleCPU INTO @Inserted(EventTime,SQLProcessCPU,SystemIdleCPU)
SELECT @InstanceID,EventTime,SQLProcessCPU,CASE WHEN @IsLinux=1 THEN 100-SQLProcessCPU ELSE SystemIdleCPU END
FROM @CPU t
WHERE t.EventTime>=@MaxEventTime
AND SQLProcessCPU>=0 AND SQLProcessCPU<=100
AND SystemIdleCPU>=0 AND SystemIdleCPU<=100
AND (SystemIdleCPU+SQLProcessCPU)<=100

IF @@ROWCOUNT>0
BEGIN
	INSERT INTO @60MIN(	
		EventTime,
		SumSQLProcessCPU,
		SumSystemIdleCPU,
		SampleCount,
		MaxSQLProcessCPU,
		MaxOtherProcessCPU,
		MaxTotalCPU,
		CPU10,
		CPU20,
		CPU30,
		CPU40,
		CPU50,
		CPU60,
		CPU70,
		CPU80,
		CPU90,
		CPU100
	)
	SELECT 	DG.DateGroup AS EventTime,
			SUM(SQLProcessCPU) AS SumSQLProcessCPU,
			SUM(SystemIdleCPU) AS SumSystemIdleCPU,
			COUNT(*) AS SampleCount,
			MAX(SQLProcessCPU) MaxSQLProcessCPU,
			MAX(100-(SQLProcessCPU+SystemIdleCPU)) MaxOtherProcessCPU,
			MAX(100-SystemIdleCPU) as MaxTotalCPU,
			SUM(HCPU.CPU10) AS CPU10,
			SUM(HCPU.CPU20) AS CPU20,
			SUM(HCPU.CPU30) AS CPU30,
			SUM(HCPU.CPU40) AS CPU40,
			SUM(HCPU.CPU50) AS CPU50,
			SUM(HCPU.CPU60) AS CPU60,
			SUM(HCPU.CPU70) AS CPU70,
			SUM(HCPU.CPU80) AS CPU80,
			SUM(HCPU.CPU90) AS CPU90,
			SUM(HCPU.CPU100) AS CPU100
	FROM @Inserted I 
	CROSS APPLY dbo.DateGroupingMins(I.EventTime,60) DG
	CROSS APPLY dbo.Histogram_CPU(100-SystemIdleCPU) HCPU
	GROUP BY DG.DateGroup

	UPDATE T
		SET T.SumSQLProcessCPU+=S.SumSQLProcessCPU,
			T.SumSystemIdleCPU+=S.SumSystemIdleCPU,
			T.SampleCount+=S.SampleCount,
			T.MaxSQLProcessCPU = (SELECT MAX(V) FROM (VALUES(S.MaxSQLProcessCPU),(T.MaxSQLProcessCPU)) M(V)),
			T.MaxOtherProcessCPU = (SELECT MAX(V) FROM (VALUES(S.MaxOtherProcessCPU ),(T.MaxOtherProcessCPU )) M(V)),
			T.MaxTotalCPU = (SELECT MAX(V) FROM (VALUES(S.MaxTotalCPU),(T.MaxTotalCPU )) M(V)),
			T.CPU10 += S.CPU10,
			T.CPU20 += S.CPU20,
			T.CPU30 += S.CPU30,
			T.CPU40 += S.CPU40,
			T.CPU50 += S.CPU50,
			T.CPU60 += S.CPU60,
			T.CPU70 += S.CPU70,
			T.CPU80 += S.CPU80,
			T.CPU90 += S.CPU90,
			T.CPU100 += S.CPU100
	FROM dbo.CPU_60MIN T 
	JOIN @60MIN S ON S.EventTime = T.EventTime
	WHERE T.InstanceID= @InstanceID

	INSERT INTO dbo.CPU_60MIN
	(
		InstanceID,
		EventTime,
		SumSQLProcessCPU,
		SumSystemIdleCPU,
		SampleCount,
		MaxSQLProcessCPU,
		MaxOtherProcessCPU,
		MaxTotalCPU,
		CPU10,
		CPU20,
		CPU30,
		CPU40,
		CPU50,
		CPU60,
		CPU70,
		CPU80,
		CPU90,
		CPU100
	)
	SELECT @InstanceID,
		EventTime,
		SumSQLProcessCPU,
		SumSystemIdleCPU,
		SampleCount,
		MaxSQLProcessCPU,
		MaxOtherProcessCPU,
		MaxTotalCPU,
		CPU10,
		CPU20,
		CPU30,
		CPU40,
		CPU50,
		CPU60,
		CPU70,
		CPU80,
		CPU90,
		CPU100
	FROM @60MIN T
	WHERE NOT EXISTS(SELECT 1 FROM dbo.CPU_60MIN CPU WHERE T.EventTime = CPU.EventTime AND CPU.InstanceID = @InstanceID)

END

EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
									 @Reference = @Ref,
									 @SnapshotDate = @SnapshotDate

COMMIT
GO
PRINT N'Creating Procedure [dbo].[CustomCheck_Get]...';


GO
CREATE PROC dbo.CustomCheck_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@IncludeCritical BIT=1,
	@IncludeWarning BIT=1,
	@IncludeNA BIT=1,
	@IncludeOK BIT=1,
	@Context NVARCHAR(128)=NULL,
	@Test NVARCHAR(128)=NULL,
	@ShowHidden BIT=1
)
AS
DECLARE @StatusSQL NVARCHAR(MAX)

SELECT @StatusSQL = CASE WHEN @IncludeCritical=1 THEN ',1' ELSE '' END
	+ CASE WHEN @IncludeWarning=1 THEN ',2' ELSE '' END
	+ CASE WHEN @IncludeNA=1 THEN ',3' ELSE '' END
	+ CASE WHEN @IncludeOK=1 THEN ',4' ELSE '' END

SELECT @StatusSQL = CASE WHEN @StatusSQL='' THEN '1=2'
		ELSE 'cc.Status IN(' + STUFF(@StatusSQL,1,1,'') + ')' END

DECLARE @SQL NVARCHAR(MAX) 
SET @SQL = N'
SELECT I.InstanceID,
		I.InstanceDisplayName,
        cc.Test,
        cc.Context,
        cc.Status,
        cc.Info,
        cc.SnapshotDate
FROM dbo.CustomChecks cc
JOIN dbo.Instances I ON	 I.InstanceID = cc.InstanceID
WHERE ' + @StatusSQL + '
' + CASE WHEN @Test IS NULL THEN '' ELSE 'AND cc.Test = @Test' END + '
' + CASE WHEN @Context IS NULL THEN '' ELSE 'AND cc.Context = @Context' END + '
' + CASE WHEN @InstanceIDs IS NULL THEN '' ELSE 'AND EXISTS(SELECT 1 FROM STRING_SPLIT(@InstanceIDs,'','') ss WHERE ss.Value = I.InstanceID)' END + '
' + CASE WHEN @ShowHidden=1 THEN '' ELSE 'AND I.ShowInSummary=1' END + '
ORDER BY cc.Status'

EXEC sp_executesql @SQL,N'@InstanceIDs VARCHAR(MAX),@Test NVARCHAR(128),@Context NVARCHAR(128)',@InstanceIDs,@Test,@Context
GO
