CREATE PROC dbo.DatabaseQueryStoreOptions_Get(
	@InstanceGroupName NVARCHAR(128),
	@DatabaseID INT=NULL
)
AS
SELECT D.DatabaseID,
	D.name,
	QS.desired_state_desc,
	QS.actual_state_desc,
	QS.readonly_reason_desc,
	CASE WHEN QS.actual_state = 1 AND QS.readonly_reason NOT IN(0,1,8) THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END IsReadOnlyErrorState,
	QS.query_capture_mode_desc,
	QS.size_based_cleanup_mode_desc,
	QS.wait_stats_capture_mode_desc,
	QS.stale_query_threshold_days,
	QS.max_plans_per_query,
	QS.interval_length_minutes,
	QS.current_storage_size_mb,
	QS.max_storage_size_mb,
	QS.actual_state_additional_info,
	QS.flush_interval_seconds,
	QS.capture_policy_execution_count,
	QS.capture_policy_stale_threshold_hours,
	QS.capture_policy_total_compile_cpu_time_ms,
	QS.capture_policy_total_execution_cpu_time_ms,
	CDS.SnapshotAge,
	CDS.SnapshotDate,
	ISNULL(CDS.Status,3) AS CollectionDateStatus
FROM dbo.DatabaseQueryStoreOptions QS
JOIN dbo.Databases D ON QS.DatabaseID = D.DatabaseID
JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
LEFT JOIN dbo.CollectionDatesStatus CDS ON CDS.InstanceID = I.InstanceID AND CDS.Reference = 'DatabaseQueryStoreOptions'
WHERE I.InstanceGroupName = @InstanceGroupName
AND (D.DatabaseID= @DatabaseID OR @DatabaseID IS NULL)
GO
PRINT N'Creating Procedure [dbo].[DatabaseQueryStoreOptions_Upd]...';


GO
CREATE PROCEDURE dbo.DatabaseQueryStoreOptions_Upd
	@DatabaseQueryStoreOptions dbo.DatabaseQueryStoreOptions READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(2)
AS
BEGIN TRAN
DELETE QSO 
FROM dbo.DatabaseQueryStoreOptions QSO
WHERE EXISTS(SELECT 1 
			FROM dbo.Databases D 
			WHERE D.DatabaseID = QSO.DatabaseID 
			AND D.InstanceID = @InstanceID)

 INSERT INTO dbo.DatabaseQueryStoreOptions(
    DatabaseID,
    desired_state,
    actual_state,
    readonly_reason,
    current_storage_size_mb,
    flush_interval_seconds,
    interval_length_minutes,
    max_storage_size_mb,
    stale_query_threshold_days,
    max_plans_per_query,
    query_capture_mode,
    size_based_cleanup_mode,
    actual_state_additional_info,
    wait_stats_capture_mode,
    capture_policy_execution_count,
    capture_policy_total_compile_cpu_time_ms,
    capture_policy_total_execution_cpu_time_ms,
    capture_policy_stale_threshold_hours
)
SELECT DatabaseID,
       desired_state,
       actual_state,
       readonly_reason,
       current_storage_size_mb,
       flush_interval_seconds,
       interval_length_minutes,
       max_storage_size_mb,
       stale_query_threshold_days,
       max_plans_per_query,
       query_capture_mode,
       size_based_cleanup_mode,
       actual_state_additional_info,
       wait_stats_capture_mode,
       capture_policy_execution_count,
       capture_policy_total_compile_cpu_time_ms,
       capture_policy_total_execution_cpu_time_ms,
       capture_policy_stale_threshold_hours
FROM @DatabaseQueryStoreOptions t 
JOIN dbo.Databases D ON t.database_id = D.database_id
WHERE D.InstanceID = @InstanceID

EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID, 
                             @Reference = 'DatabaseQueryStoreOptions', 
                             @SnapshotDate = @SnapshotDate

COMMIT
GO
PRINT N'Creating Procedure [dbo].[DatabaseQueryStoreOptionsSummary_Get]...';


GO
CREATE PROC dbo.DatabaseQueryStoreOptionsSummary_Get(
	@InstanceIDs VARCHAR(MAX),
	@ShowHidden BIT=1
)
AS
SELECT	I.InstanceGroupName,
		SUM(CASE WHEN QS.actual_state = 0 THEN 1 ELSE 0 END) as QS_OFF,
		SUM(CASE WHEN QS.actual_state = 1 THEN 1 ELSE 0 END) as QS_READ_ONLY,
		SUM(CASE WHEN QS.actual_state = 1 AND QS.readonly_reason NOT IN(0,1,8) THEN 1 ELSE 0 END) as QS_READ_ONLY_ATT,
		SUM(CASE WHEN QS.actual_state = 2 THEN 1 ELSE 0 END) as QS_READ_WRITE,
		SUM(CASE WHEN QS.actual_state = 3 THEN 1 ELSE 0 END) as QS_ERROR,
		SUM(QS.current_storage_size_mb) TotalCurrentStorageSizeMB,
		AVG(QS.current_storage_size_mb) AvgCurrentStorageSizeMB,
		MAX(QS.current_storage_size_mb) MaxCurrentStorageSizeMB,
		MAX(QS.max_storage_size_mb) MaxSizeLimitMB,
		MIN(QS.max_storage_size_mb) MinSizeLimitMB,
		MAX(CDS.SnapshotAge) AS SnapshotAge,
		MAX(CDS.SnapshotDate) AS SnapshotDate,
		ISNULL(MIN(CDS.Status),3) AS CollectionDateStatus
FROM dbo.DatabaseQueryStoreOptions QS
JOIN dbo.Databases D ON QS.DatabaseID = D.DatabaseID
JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
LEFT JOIN dbo.CollectionDatesStatus CDS ON CDS.InstanceID = I.InstanceID AND CDS.Reference = 'DatabaseQueryStoreOptions'
WHERE EXISTS	(
				SELECT 1 
				FROM STRING_SPLIT(@InstanceIDs,',') ss 
				WHERE ss.value = I.InstanceID
				)
AND (I.ShowInSummary=1 OR @ShowHidden=1)
GROUP BY I.InstanceGroupName
GO
