PRINT N'Creating Procedure [dbo].[DBADashAgent_Upd]...';


GO
CREATE PROC dbo.DBADashAgent_Upd(	
	@AgentHostName NVARCHAR(16),
	@AgentVersion VARCHAR(30),
	@AgentServiceName NVARCHAR(256),
	@AgentPath NVARCHAR(260),
	@ServiceSQSQueueUrl NVARCHAR(256)=NULL,
	@AgentIdentifier CHAR(22)=NULL,
	@S3Path NVARCHAR(256)=NULL,
	@MessagingEnabled BIT=0,
	@AllowedScripts VARCHAR(MAX)=NULL,
	@AllowedCustomProcs NVARCHAR(MAX)=NULL,
	@DBADashAgentID INT OUT
)
AS
DECLARE @UpdateAgent BIT = 0

SELECT @DBADashAgentID = DBADashAgentID,
	@UpdateAgent = CASE WHEN 
						EXISTS(
								SELECT @AgentPath, @AgentVersion, @ServiceSQSQueueUrl, @AgentIdentifier,@S3Path,@MessagingEnabled,@AllowedScripts, @AllowedCustomProcs
								EXCEPT
								SELECT AgentPath, AgentVersion, ServiceSQSQueueUrl, AgentIdentifier, S3Path, MessagingEnabled, AllowedScripts, AllowedCustomProcs
								)
					THEN 1 ELSE 0 END
FROM dbo.DBADashAgent
WHERE AgentHostName = @AgentHostName
AND AgentServiceName = @AgentServiceName

IF @DBADashAgentID IS NULL
BEGIN

	INSERT INTO dbo.DBADashAgent(AgentHostName,AgentServiceName,AgentVersion,AgentPath,ServiceSQSQueueUrl,AgentIdentifier,S3Path,MessagingEnabled,AllowedScripts, AllowedCustomProcs)
	SELECT @AgentHostName,@AgentServiceName,@AgentVersion,@AgentPath,@ServiceSQSQueueUrl,ISNULL(@AgentIdentifier,LEFT(CONCAT('Temp.',REPLACE(NEWID(),'-','')),22)), @S3Path, @MessagingEnabled,@AllowedScripts,@AllowedCustomProcs
	WHERE NOT EXISTS(SELECT 1 
				FROM dbo.DBADashAgent WITH(UPDLOCK,HOLDLOCK) 
				WHERE AgentHostName = @AgentHostName 
				AND AgentServiceName = @AgentServiceName
				)

	/* 
		Not using SCOPE_IDENTITY as there is potential for no rows to be inserted if two processes attempt the insert
	*/
	SELECT @DBADashAgentID = DBADashAgentID
	FROM dbo.DBADashAgent
	WHERE AgentHostName = @AgentHostName
	AND AgentServiceName = @AgentServiceName
END
IF @UpdateAgent=1
BEGIN
	UPDATE dbo.DBADashAgent
		SET AgentPath = @AgentPath,
			AgentVersion = @AgentVersion,
			ServiceSQSQueueUrl = @ServiceSQSQueueUrl,
			AgentIdentifier = ISNULL(@AgentIdentifier,LEFT(CONCAT('Temp.',REPLACE(NEWID(),'-','')),22)),
			S3Path = @S3Path,
			MessagingEnabled = @MessagingEnabled,
			AllowedScripts = @AllowedScripts,
			AllowedCustomProcs = @AllowedCustomProcs,
			ModifiedDate = SYSUTCDATETIME()
	WHERE DBADashAgentID = @DBADashAgentID;
END
GO
PRINT N'Creating Procedure [dbo].[DBConfig_Upd]...';


GO
CREATE PROC dbo.DBConfig_Upd(
	@DBConfig dbo.DBConfig READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(2)
)
AS
DECLARE @Ref VARCHAR(30)='DBConfig'
IF NOT EXISTS(SELECT 1 
				FROM dbo.CollectionDates 
				WHERE SnapshotDate>=@SnapshotDate 
				AND InstanceID = @InstanceID 
				AND Reference=@Ref
				)
BEGIN
	IF EXISTS(SELECT 1 
				FROM @DBConfig t
				WHERE NOT EXISTS(SELECT 1 
								FROM dbo.DBConfigOptions o 
								WHERE t.configuration_id = o.configuration_id
								)
	)
	BEGIN
		INSERT INTO dbo.DBConfigOptions(configuration_id,name)
		SELECT configuration_id,MAX(name)
		FROM @DBConfig t
		WHERE NOT EXISTS(SELECT 1 
						FROM dbo.DBConfigOptions o WITH(UPDLOCK,HOLDLOCK)
						WHERE t.configuration_id = o.configuration_id
						)
		GROUP BY t.configuration_id
	END;

	INSERT INTO dbo.DBConfig(DatabaseID,configuration_id,value,value_for_secondary,ValidFrom)
	SELECT d.DatabaseID,t.configuration_id,t.value,t.value_for_secondary,@SnapshotDate
	FROM @DBConfig t
	JOIN dbo.Databases d ON t.database_id = d.database_id
	WHERE d.InstanceID = @InstanceID
	AND NOT EXISTS(SELECT 1 
					FROM dbo.DBConfig c 
					WHERE c.DatabaseID = d.DatabaseID 
					AND c.configuration_id = t.configuration_id
					);

	UPDATE c
	SET C.value = cfg.value,
		C.value_for_secondary = cfg.value_for_secondary
	OUTPUT DELETED.DatabaseID,
			DELETED.configuration_id,
			DELETED.value,
			DELETED.value_for_secondary,
			INSERTED.value,
			INSERTED.value_for_secondary,
			DELETED.ValidFrom,
			@SnapshotDate 
	INTO dbo.DBConfigHistory(DatabaseID,
							configuration_id,
							value,
							value_for_secondary,
							new_value,
							new_value_for_secondary,
							ValidFrom,
							ValidTo
							)
	FROM dbo.DBConfig c
	JOIN dbo.Databases d ON d.DatabaseID = c.DatabaseID
	JOIN @DBConfig cfg ON c.configuration_id = cfg.configuration_id AND cfg.database_id = d.database_id
	WHERE d.InstanceID = @InstanceID
	AND d.IsActive=1
	AND (	EXISTS(SELECT c.value 
					EXCEPT SELECT cfg.value
					)
			OR EXISTS(SELECT c.value_for_secondary 
						EXCEPT 
						SELECT cfg.value_for_secondary
						)
		);


	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										 @Reference = @Ref,
										 @SnapshotDate = @SnapshotDate
END
GO
PRINT N'Creating Procedure [dbo].[DBConfiguration_Get]...';


GO
CREATE PROC dbo.DBConfiguration_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@ConfiguredOnly BIT=0,
	@DatabaseID INT=NULL,
	@ShowHidden BIT=1
)
AS
DECLARE @Instances TABLE(
	InstanceID INT PRIMARY KEY
)
IF @InstanceIDs IS NULL
BEGIN
	INSERT INTO @Instances
	(
	    InstanceID
	)
	SELECT InstanceID 
	FROM dbo.Instances 
	WHERE IsActive=1
END 
ELSE 
BEGIN
	INSERT INTO @Instances
	(
		InstanceID
	)
	SELECT value
	FROM STRING_SPLIT(@InstanceIDs,',')
END;

WITH T AS (
	SELECT I.InstanceGroupName,
		D.DatabaseID,
		D.name AS DB,
		C.configuration_id,
		CO.name, 
		C.value,
		C.value_for_secondary,
		CO.default_value,
		CASE WHEN c.value=CO.default_value THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsDefault,
		C.ValidFrom,
		MAX(CASE WHEN C.value<> CO.default_value THEN 1 ELSE 0 END) OVER(PARTITION BY D.DatabaseID) AS HasDBScopedConfiguration,
		MAX(CASE WHEN C.value<> CO.default_value THEN 1 ELSE 0 END) OVER(PARTITION BY C.configuration_id) AS IsConfiguredForAnyDB
	FROM dbo.DBConfig C 
	JOIN dbo.DBConfigOptions CO ON C.configuration_id = CO.configuration_id
	JOIN dbo.Databases D ON C.DatabaseID = D.DatabaseID
	JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
	WHERE EXISTS(SELECT 1 
				FROM @Instances t 
				WHERE t.InstanceID = I.InstanceID)
	AND (D.DatabaseID = @DatabaseID OR @DatabaseID IS NULL)
	AND (I.ShowInSummary=1 OR @ShowHidden=1)
)
SELECT T.InstanceGroupName,
       T.DB,
	   T.DatabaseID,
       T.configuration_id,
       T.name,
       T.value,
       T.value_for_secondary,
	   T.IsDefault,
       T.ValidFrom
FROM T 
WHERE (
		(T.HasDBScopedConfiguration=1 AND T.IsConfiguredForAnyDB=1) 
		OR @ConfiguredOnly=0
	  )
ORDER BY T.InstanceGroupName,
		T.DB,
		T.DatabaseID,
		T.name
GO
PRINT N'Creating Procedure [dbo].[DBConfigurationHistory_Get]...';


GO
CREATE PROC dbo.DBConfigurationHistory_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@ConfiguredOnly BIT=0,
	@DatabaseID INT=NULL,
	@ShowHidden BIT=1
)
AS
DECLARE @Instances TABLE(
	InstanceID INT PRIMARY KEY
)
IF @InstanceIDs IS NULL
BEGIN
	INSERT INTO @Instances
	(
	    InstanceID
	)
	SELECT InstanceID 
	FROM dbo.Instances 
	WHERE IsActive=1
END 
ELSE 
BEGIN
	INSERT INTO @Instances
	(
		InstanceID
	)
	SELECT value
	FROM STRING_SPLIT(@InstanceIDs,',')
END;
SELECT	I.InstanceGroupName,
		D.name AS DB, 
		H.configuration_id, 
		CO.name,H.value,
		H.new_value,
		H.value_for_secondary,
		H.new_value_for_secondary,
		H.ValidFrom,
		H.ValidTo
FROM dbo.DBConfigHistory H 
JOIN dbo.DBConfigOptions CO ON H.configuration_id = CO.configuration_id
JOIN dbo.Databases D ON D.DatabaseID = H.DatabaseID
JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
WHERE EXISTS(
			SELECT 1 
			FROM @Instances t 
			WHERE I.InstanceID = t.InstanceID
			)
AND I.IsActive=1
AND D.IsActive=1
AND (D.DatabaseID = @DatabaseID OR @DatabaseID IS NULL)
AND (I.ShowInSummary=1 OR @ShowHidden=1)
ORDER BY H.ValidTo DESC
GO
PRINT N'Creating Procedure [dbo].[DBFiles_Get]...';


GO
CREATE PROC dbo.DBFiles_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@DatabaseID INT=NULL,
	@IncludeCritical BIT=1,
	@IncludeWarning BIT=1,
	@IncludeNA BIT=0,
	@IncludeOK BIT=0,
	@FilegroupLevel BIT=1,
    @Types VARCHAR(50)=NULL,
    @ShowHidden BIT=1,
    @DriveName NVARCHAR(256)=NULL
)
AS
DECLARE @StatusSQL NVARCHAR(MAX)

SELECT @StatusSQL = STUFF(CASE WHEN @IncludeCritical=1 THEN ',1' ELSE '' END
	+ CASE WHEN @IncludeWarning=1 THEN ',2' ELSE '' END
	+ CASE WHEN @IncludeNA=1 THEN ',3' ELSE '' END
	+ CASE WHEN @IncludeOK=1 THEN ',4' ELSE '' END,1,1,'')

SELECT @StatusSQL = CASE WHEN @StatusSQL='' THEN 'AND 1=2'
		ELSE 'AND (F.FreeSpaceStatus IN(' + @StatusSQL + ') OR F.PctMaxSizeStatus IN(' + @StatusSQL + ') OR FilegroupAutogrowStatus IN(' + @StatusSQL + '))' END

DECLARE @SQL NVARCHAR(MAX)

SET @SQL = CAST('' AS NVARCHAR(MAX)) + N'
SELECT FileID,
       InstanceID,
       DatabaseID,
       data_space_id,
       Instance,
       InstanceDisplayName,
       InstanceGroupName,
       ConnectionID,
       name,
       file_name,
       Filegroup_name,
       physical_name,
       FileSizeMB,
       FileUsedMB,
       FileFreeMB,
       FilePctFree,
       FilegroupSizeMB,
       FilegroupUsedMB,
       FilegroupFreeMB,
       FilegroupPctFree,
       FilegroupNumberOfFiles,
       is_read_only,
       is_db_read_only,
       is_in_standby,
       state,
       state_desc,
       ExcludedReason,
       FreeSpaceStatus,
       FreeSpaceWarningThreshold,
       FreeSpaceCriticalThreshold,
       FreeSpaceCheckType,
       ConfiguredLevel,
       FileSnapshotDate,
       FileSnapshotAge,
       FileSnapshotAgeStatus,
	   FilegroupMaxSizeMB,
	   FilegroupPctOfMaxSize,
	   FilegroupUsedPctOfMaxSize,
	   PctMaxSizeStatus,
	   MaxSizeExcludedReason,
	   FilegroupAutogrowFileCount,
	   FilegroupAutogrowStatus,
       type,
       type_desc' 
	   + CASE WHEN @FilegroupLevel=0 THEN ',
	   max_size,
	   MaxSizeMB,
	   GrowthMB,
	   GrowthPct,
	   growth,
	   is_percent_growth' ELSE '' END + '
FROM ' + CASE WHEN @FilegroupLevel = 1 THEN 'dbo.FilegroupStatus' ELSE 'dbo.FileStatus' END + ' AS F
WHERE 1=1
' + CASE WHEN @InstanceIDs IS NULL THEN '' ELSE 'AND EXISTS (SELECT 1
			FROM STRING_SPLIT(@InstanceIDs,'','') ss
			WHERE ss.value = F.InstanceID
			)' END + '
' + CASE WHEN @Types IS NULL THEN '' ELSE 'AND EXISTS (SELECT 1
			FROM STRING_SPLIT(@Types,'','') ss
			WHERE CAST(ss.value as TINYINT) = F.type
			)' END + '
' + @StatusSQL + '
' + CASE WHEN @DatabaseID IS NULL THEN '' ELSE 'AND F.DatabaseID = @DatabaseID' END + '
' + CASE WHEN @ShowHidden=1 THEN '' ELSE 'AND F.ShowInSummary=1' END + '
' + CASE WHEN @DriveName IS NULL THEN '' ELSE 'AND F.physical_name LIKE @DriveName + ''%''' END

PRINT @SQL
EXEC sp_executesql @SQL,N'@InstanceIDs VARCHAR(MAX), @DatabaseID INT, @Types VARCHAR(50),@DriveName NVARCHAR(256)', @InstanceIDs, @DatabaseID, @Types, @DriveName
GO
