GO
CREATE PROC dbo.DBFiles_Upd(
	@DBFiles DBFiles READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON
SET NOCOUNT ON
DECLARE @Ref VARCHAR(30)='DBFiles'
IF NOT EXISTS(SELECT 1 FROM dbo.CollectionDates WHERE SnapshotDate>=@SnapshotDate AND InstanceID = @InstanceID AND Reference=@Ref)
BEGIN
	DECLARE @DBFileCount INT
	DECLARE @UpdateCount INT

	CREATE TABLE #DBFiles(
		DatabaseID INT NOT NULL,
		file_id INT NOT NULL,
		data_space_id INT NULL,
		name sysname NOT NULL,
		filegroup_name sysname NULL,
		physical_name NVARCHAR(260) NULL,
		type TINYINT NULL,
		size BIGINT NULL,
		space_used BIGINT NULL,
		max_size BIGINT NULL,
		growth BIGINT NULL,
		is_percent_growth BIT NULL,
		is_read_only BIT NULL,
		state TINYINT NULL,
		PRIMARY KEY (DatabaseID,file_id)
	);
	INSERT INTO #DBFiles(DatabaseID,
		   file_id,
		   data_space_id,
		   name,
		   filegroup_name,
		   physical_name,
		   type,
		   size,
		   space_used,
		   max_size,
		   growth,
		   is_percent_growth,
		   is_read_only,
		   state
	)
	SELECT D.DatabaseID
		  ,F.[file_id]
		  ,F.[data_space_id]
		  ,F.[name]
		  ,F.[filegroup_name]
		  ,F.[physical_name]
		  ,F.[type]
		  ,F.[size]
		  ,F.[space_used]
		  ,F.[max_size]
		  ,F.[growth]
		  ,F.[is_percent_growth]
		  ,F.[is_read_only]
		  ,F.state
	FROM @DBFiles F 
	JOIN dbo.Databases D ON F.database_id = D.database_id
	WHERE D.IsActive=1
	AND D.InstanceID = @InstanceID
	AND F.file_id IS NOT NULL

	SET @DBFileCount = @@ROWCOUNT

	BEGIN TRAN

	UPDATE F WITH (ROWLOCK)
		SET F.data_space_id = T.data_space_id,
			F.name = T.name,
			F.filegroup_name = ISNULL(T.filegroup_name, F.filegroup_name),
			F.physical_name = T.physical_name,
			F.type = T.type,
			F.size = T.size,
			F.space_used = T.space_used,
			F.max_size = T.max_size,
			F.growth = T.growth,
			F.is_percent_growth = T.is_percent_growth,
			F.is_read_only = T.is_read_only,
			F.IsActive = 1,
			F.state = T.state
	FROM dbo.DBFiles F
	JOIN #DBFiles T ON F.file_id = T.file_id
						AND F.DatabaseID = T.DatabaseID
	WHERE F.InstanceID = @InstanceID;

	SET @UpdateCount = @@ROWCOUNT

	/* If there are more rows in temp table than were updated, then there are new rows to insert */
	IF @DBFileCount > @UpdateCount 
	BEGIN
		INSERT INTO dbo.DBFiles WITH(ROWLOCK)(
			InstanceID,
			DatabaseID,
			file_id,
			data_space_id,
			name,
			filegroup_name,
			physical_name,
			type,
			size,
			space_used,
			max_size,
			growth,
			is_percent_growth,
			is_read_only,
			IsActive,
			state
		)
		SELECT @InstanceID AS InstanceID,
			   T.DatabaseID,
			   T.file_id,
			   T.data_space_id,
			   T.name,
			   T.filegroup_name,
			   T.physical_name,
			   T.type,
			   T.size,
			   T.space_used,
			   T.max_size,
			   T.growth,
			   T.is_percent_growth,
			   T.is_read_only,
			   CAST(1 AS BIT) AS IsActive,
			   T.state
		FROM #DBFiles T
		WHERE NOT EXISTS
		(
			SELECT 1
			FROM dbo.DBFiles F WITH (UPDLOCK, ROWLOCK)
			WHERE F.file_id = T.file_id
			AND F.DatabaseID = T.DatabaseID
			AND F.InstanceID = @InstanceID
		);
	END

	UPDATE F WITH (ROWLOCK)
	SET F.IsActive=0
	FROM dbo.DBFiles F
	WHERE NOT EXISTS(	SELECT 1
						FROM #DBFiles T
						WHERE T.DatabaseID = F.DatabaseID
						AND T.file_id = F.file_id
					)
	AND F.InstanceID = @InstanceID

	INSERT INTO dbo.DBFileSnapshot WITH(ROWLOCK) (SnapshotDate,FileID,Size,space_used)
	SELECT @SnapshotDate,
		  F.FileID,
		  T.size,
		  T.space_used
	FROM #DBFiles T 
	JOIN dbo.DBFiles F WITH(ROWLOCK) ON T.file_id = F.file_id AND T.DatabaseID = F.DatabaseID
	WHERE F.IsActive=1
	AND F.InstanceID = @InstanceID

	COMMIT

	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										 @Reference = @Ref,
										 @SnapshotDate = @SnapshotDate

END
GO
PRINT N'Creating Procedure [dbo].[DBFileSnapshot_Del]...';


GO
CREATE PROC dbo.DBFileSnapshot_Del(
	@InstanceID INT,
	@DaysToKeep INT,
	@BatchSize INT=500000
)
AS
/* 
	Partitioning switching is used to efficiently remove data from this table for all instances.  
	This proc provides an alternative way to remove data associated with a specific instance.
*/
SET NOCOUNT ON
DECLARE @MaxDate DATETIME2(2)
SELECT @MaxDate = CASE WHEN @DaysToKeep  = 0 THEN '30000101' ELSE DATEADD(d,-@DaysToKeep,GETUTCDATE()) END

CREATE TABLE #Files(
	FileID INT PRIMARY KEY
)

INSERT INTO #Files
(
    FileID
)
SELECT F.FileID
FROM dbo.Databases D 
JOIN dbo.DBFiles F ON F.DatabaseID = D.DatabaseID
WHERE D.InstanceID = @InstanceID 

WHILE 1=1
BEGIN
	DELETE TOP(@BatchSize) FSS
	FROM dbo.DBFileSnapshot FSS
	WHERE EXISTS(SELECT 1 
				FROM #Files F 
				WHERE F.FileID = FSS.FileID
				)
	AND SnapshotDate < @MaxDate
	OPTION(RECOMPILE)

	IF @@ROWCOUNT < @BatchSize
		BREAK
END
GO
PRINT N'Creating Procedure [dbo].[DBFileSnapshot_Get]...';


GO
CREATE PROC dbo.DBFileSnapshot_Get(
		@DatabaseID INT=NULL,
		@FG SYSNAME=NULL,
		@DataSpaceID INT=NULL,
		@FromDate DATETIME2(2),
		@ToDate DATETIME2(2),
		@InstanceGroupName SYSNAME=NULL,
		@DBName SYSNAME=NULL,
		@InstanceID INT=NULL,
		@FileName SYSNAME=NULL,
		@Debug BIT=0,
		@DateGroupingMins INT=1440
)
AS
IF @DatabaseID IS NULL AND @DBName IS NOT NULL
BEGIN
	SELECT @DatabaseID=D.DatabaseID
	FROM dbo.Databases D 
	JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
	WHERE D.name = @DBName
	AND I.InstanceGroupName = @InstanceGroupName
	AND I.IsActive=1
	AND D.IsActive=1
END

DECLARE @GroupDatabaseID UNIQUEIDENTIFIER
SELECT @GroupDatabaseID= group_database_id
FROM dbo.DatabasesHADR
WHERE DatabaseID=@DatabaseID 
IF @GroupDatabaseID IS NOT NULL
BEGIN 
	SET @DatabaseID=NULL
	SET @InstanceID=NULL
	SET @InstanceGroupName=NULL
	SET @DBName=NULL
END

DECLARE @SQL NVARCHAR(MAX)
SET @SQL = N'
WITH ss AS (
	SELECT	F.DatabaseID,
			SS.SnapshotDate,
			SUM(SS.size)/128.0 AS SizeMB,
			SUM(SS.space_used) /128.0 AS UsedMB
	FROM dbo.DBFileSnapshot SS
	JOIN dbo.DBFiles F ON F.FileID = SS.FileID
	JOIN dbo.Databases D ON D.DatabaseID = F.DatabaseID
	JOIN dbo.Instances I ON D.InstanceID = I.InstanceID
	WHERE SS.SnapshotDate>=@FromDate
	AND SS.SnapshotDate<@ToDate
	AND D.source_database_id IS NULL
	' + CASE WHEN @GroupDatabaseID IS NULL THEN '' ELSE 'AND EXISTS(SELECT 1 FROM dbo.DatabasesHADR hadr WHERE hadr.DatabaseID = F.DatabaseID AND hadr.group_database_id = @GroupDatabaseID)' END + '
	' + CASE WHEN @DatabaseID IS NULL THEN '' ELSE 'AND F.DatabaseID = @DatabaseID' END + '
	' + CASE WHEN @FG IS NULL THEN '' ELSE 'AND F.filegroup_name = @FG' END + '
	' + CASE WHEN @DataSpaceID IS NULL THEN '' ELSE 'AND F.data_space_id = @DataSpaceID' END + '
	' + CASE WHEN @InstanceGroupName IS NULL THEN '' ELSE 'AND I.InstanceGroupName = @InstanceGroupName' END + '
	' + CASE WHEN @DBName IS NULL THEN '' ELSE 'AND D.name = @DBName' END + '
	' + CASE WHEN @InstanceID IS NULL THEN '' ELSE 'AND I.InstanceID = @InstanceID' END + '
	' + CASE WHEN @FileName IS NULL THEN '' ELSE ' AND F.name = @FileName' END + '
	GROUP BY SS.SnapshotDate,F.DatabaseID
)
, db as (
	SELECT ' + CASE WHEN @GroupDatabaseID IS NULL THEN 'DatabaseID,' ELSE '' END + '
			DG.DateGroup SnapshotDate,
			MAX(SS.SizeMB) AS SizeMB,
			MAX(SS.UsedMB) AS UsedMB
	FROM ss
	CROSS APPLY dbo.DateGroupingMins(ss.SnapshotDate,@DateGroupingMins) DG
	GROUP BY DG.DateGroup' + CASE WHEN @GroupDatabaseID IS NULL THEN ',DatabaseID' ELSE '' END + '
)
SELECT	SnapshotDate,
		SUM(SizeMB) AS SizeMB,
		SUM(UsedMB) AS UsedMB
FROM db
GROUP BY SnapshotDate
ORDER BY SnapshotDate'

IF @Debug=1
BEGIN
	PRINT @SQL
END

EXEC sp_executesql @SQL,N'@DatabaseID INT,@FromDate DATETIME2(2),@ToDate DATETIME2(2),@FG SYSNAME,@GroupDatabaseID UNIQUEIDENTIFIER,@DataSpaceID INT,@InstanceGroupName SYSNAME,@DBName SYSNAME,@FileName SYSNAME,@InstanceID INT,@DateGroupingMins INT',
						@DatabaseID,@FromDate,@ToDate,@FG,@GroupDatabaseID,@DataSpaceID,@InstanceGroupName,@DBName,@FileName,@InstanceID,@DateGroupingMins
GO
