GO
CREATE PROC dbo.DBSpace_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@DatabaseID INT=NULL,
	@DBName SYSNAME=NULL,
	@InstanceGroupName NVARCHAR(128)=NULL,
	@ShowHidden BIT=1
)
AS
DECLARE @SQL NVARCHAR(MAX)
DECLARE @Grp NVARCHAR(MAX) 
SET @Grp = CASE WHEN @DatabaseID IS NOT NULL OR @DBName IS NOT NULL THEN 'F.Name' 
			WHEN @InstanceIDs NOT LIKE '%,%' OR @InstanceGroupName IS NOT NULL THEN 'D.Name'
			ELSE 'I.InstanceGroupName' END 

SET @SQL = N'
SELECT ' + @Grp + ' as Grp,
	SUM(F.size*8)/1024.0 AS AllocatedMB,
	SUM(F.space_used*8)/1024.0 AS UsedMB,
	SUM(F.size*8)/POWER(1024.0,2) AS AllocatedGB,
	SUM(F.space_used*8)/POWER(1024.0,2) AS UsedGB,
	SUM(F.size*8)/POWER(1024.0,3) AS AllocatedTB,
	SUM(F.space_used*8)/POWER(1024.0,3) AS UsedTB,
	SUM(size)/SUM(SUM(size*1.0)) OVER() Pct
FROM dbo.Instances I 
JOIN dbo.Databases D ON D.InstanceID = I.InstanceID
JOIN dbo.DBFiles F ON F.DatabaseID = D.DatabaseID
WHERE I.IsActive=1
AND D.IsActive=1
AND F.IsActive=1
AND D.source_database_id IS NULL
' + CASE WHEN @InstanceIDs IS NULL THEN '' ELSE 'AND EXISTS (SELECT 1
			FROM STRING_SPLIT(@InstanceIDs,'','') ss
			WHERE ss.value = I.InstanceID
			)' END + '
' + CASE WHEN @DatabaseID IS NULL THEN '' ELSE 'AND F.DatabaseID = @DatabaseID' END + '
' + CASE WHEN @InstanceGroupName IS NULL THEN '' ELSE 'AND I.InstanceGroupName = @InstanceGroupName' END + '
' + CASE WHEN @DBName IS NULL THEN '' ELSE 'AND D.Name = @DBName' END + '
' + CASE WHEN @ShowHidden=1 THEN '' ELSE 'AND I.ShowInSummary=1' END + '
GROUP BY ' + @Grp + '
ORDER BY AllocatedGB DESC'

EXEC sp_executesql @SQL,N'@InstanceIDs VARCHAR(MAX),@DatabaseID INT,@DBName SYSNAME,@InstanceGroupName NVARCHAR(128)',@InstanceIDs,@DatabaseID,@DBName,@InstanceGroupName
GO
PRINT N'Creating Procedure [dbo].[DBSummary_Get]...';


GO
CREATE PROC dbo.DBSummary_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@ShowHidden BIT=1
)
AS
SELECT I.InstanceGroupName AS Instance, 
	CASE WHEN COUNT(DISTINCT D.InstanceID) = 1 THEN MAX(D.InstanceID) ELSE NULL END AS InstanceID,
	SUM(CASE WHEN D.page_verify_option<>2 THEN 1 ELSE 0 END) as [Page Verify Not Optimal],
	SUM(CASE WHEN D.is_auto_close_on =1 THEN 1 ELSE 0 END) as [Auto Close],
	SUM(CASE WHEN D.is_auto_shrink_on =1 THEN 1 ELSE 0 END) as [Auto Shrink],
	SUM(CASE WHEN D.is_auto_create_stats_on=0 THEN 1 ELSE 0 END) as [Auto Create Stats Disabled],
	SUM(CASE WHEN D.is_auto_update_stats_on=0 THEN 1 ELSE 0 END) as [Auto Update Stats Disabled],
	SUM(CASE WHEN D.compatibility_level < I.MaxSupportedCompatibilityLevel THEN 1 ELSE 0 END) AS [Old Compat Level],
	SUM(CASE WHEN D.is_trustworthy_on=1 AND D.name<>'msdb' THEN 1 ELSE 0 END) AS [Trustworthy],
	SUM(CASE WHEN D.state=0 THEN 1 ELSE 0 END) AS [Online],
	SUM(CASE WHEN D.state=1 THEN 1 ELSE 0 END) AS Restoring,
	SUM(CASE WHEN D.state=2 THEN 1 ELSE 0 END) AS Recovering,
	SUM(CASE WHEN D.state=3 THEN 1 ELSE 0 END) AS [Recovery Pending],
	SUM(CASE WHEN D.state=4 THEN 1 ELSE 0 END) AS Suspect,
	SUM(CASE WHEN D.state=5 THEN 1 ELSE 0 END) AS Emergency,
	SUM(CASE WHEN D.state IN(6,10) THEN 1 ELSE 0 END) AS Offline,
	SUM(CASE WHEN D.state =7  THEN 1 ELSE 0 END) AS Copying,
	SUM(CASE WHEN D.is_in_standby =1 THEN 1 ELSE 0 END) AS [Standby],
	SUM(CASE WHEN D.database_id >4 THEN 1 ELSE 0 END) AS [User Database Count],
	MAX(D.VLFCount) AS [Max VLF Count],
	SUM(CASE WHEN D.target_recovery_time_in_seconds IS NULL THEN NULL WHEN D.target_recovery_time_in_seconds = 0 AND D.database_id > 4 THEN 1 ELSE 0 END) AS [Not Using Indirect Checkpoints],
	SUM(CASE WHEN D.target_recovery_time_in_seconds IS NULL OR D.target_recovery_time_in_seconds IN(0,60) THEN 0 ELSE 1 END) AS [None-Default Target Recovery Time],
	MAX(I.MaxSupportedCompatibilityLevel) AS [Max Supported Compatibility Level],
	SUM(CASE WHEN D.database_id >4  AND D.is_read_committed_snapshot_on = 1 THEN 1 ELSE 0 END) AS [RCSI Count],
	SUM(CASE WHEN D.is_accelerated_database_recovery_on=1 THEN 1 ELSE 0 END) AS ADR,
	SUM(CASE WHEN D.is_optimized_locking_on=1 THEN 1 ELSE 0 END) AS [Optimized Locking]
FROM dbo.InstanceInfo I 
JOIN dbo.Databases D ON I.InstanceID = D.InstanceID
WHERE I.IsActive=1
AND D.IsActive=1
AND (
	EXISTS	(
			SELECT 1 
			FROM STRING_SPLIT(@InstanceIDs,',') ss 
			WHERE ss.value = I.InstanceID
			)
		OR @InstanceIDs IS NULL
	)
AND (I.ShowInSummary=1 OR @ShowHidden=1)
GROUP BY I.InstanceGroupName
GO
PRINT N'Creating Procedure [dbo].[DBTuningOptions_Upd]...';


GO

CREATE PROC [dbo].[DBTuningOptions_Upd](@DBTuningOptions dbo.DBTuningOptions READONLY,@InstanceID INT,@SnapshotDate DATETIME2(2))
AS
DECLARE @Ref VARCHAR(30)='DBTuningOptions'
IF NOT EXISTS(SELECT 1 FROM dbo.CollectionDates WHERE SnapshotDate>=@SnapshotDate AND InstanceID = @InstanceID AND Reference=@Ref)
BEGIN;
	WITH T AS (
		SELECT InstanceID,
               DatabaseID,
               name,
               desired_state_desc,
               actual_state_desc,
               reason_desc,
               ValidFrom 
		FROM dbo.DBTuningOptions T
		WHERE InstanceID = @InstanceID
		AND EXISTS(SELECT 1 FROM dbo.Databases D WHERE d.DatabaseID = t.DatabaseID AND D.IsActive=1 AND D.InstanceID  = @InstanceID)
	)
	MERGE T
	USING(
		SELECT d.DatabaseID, d.InstanceID, t.database_id,
                            t.name,
                            t.desired_state_desc,
                            t.actual_state_desc,
                            t.reason_desc 
		FROM @DBTuningOptions t
		JOIN dbo.Databases d ON t.database_id = d.database_id AND d.InstanceID = @InstanceID AND d.IsActive=1
		) AS S
		ON S.DatabaseID = T.DatabaseID AND S.name = t.name
	WHEN MATCHED AND (EXISTS(SELECT S.desired_state_desc EXCEPT SELECT T.desired_state_desc)
				OR EXISTS(SELECT S.actual_state_desc EXCEPT SELECT T.actual_state_desc)
				OR EXISTS(SELECT S.reason_desc EXCEPT SELECT T.reason_desc)
				)
	THEN UPDATE SET T.actual_state_desc = S.actual_state_desc,
			T.desired_state_desc = S.desired_state_desc,
			T.reason_desc = T.reason_desc,
			T.ValidFrom=@SnapshotDate
	WHEN NOT MATCHED BY SOURCE
	 THEN DELETE
	WHEN NOT MATCHED BY TARGET THEN INSERT(InstanceID,DatabaseID,name,desired_state_desc,actual_state_desc,reason_desc,ValidFrom)
		VALUES(S.InstanceID,S.DatabaseID,s.name,S.desired_state_desc,s.actual_state_desc,s.reason_desc,@SnapshotDate)
	OUTPUT ISNULL(Deleted.InstanceID,Inserted.InstanceID),
           ISNULL(Deleted.DatabaseID,Inserted.DatabaseID),
           ISNULL(Deleted.name,Inserted.name),
           Deleted.desired_state_desc,
           Deleted.actual_state_desc,
           Deleted.reason_desc,
           ISNULL(Deleted.ValidFrom,'19000101') ,
		   @SnapshotDate,
		   Inserted.actual_state_desc,
		   Inserted.desired_state_desc,
		   Inserted.reason_desc
		   INTO dbo.DBTuningOptionsHistory(InstanceID,DatabaseID,name,desired_state_desc,actual_state_desc,reason_desc,ValidFrom,ValidTo,new_actual_state_desc,new_desired_state_desc,new_reason_desc);

	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										 @Reference = @Ref,
										 @SnapshotDate = @SnapshotDate
END
GO
