CREATE PROC [dbo].[Drivers_Upd](@Drivers dbo.Drivers READONLY,@InstanceID INT,@SnapshotDate DATETIME2(2))
AS
INSERT INTO dbo.Drivers
(
    InstanceID,
    ClassGuid,
    DeviceClass,
    DeviceID,
    DeviceName,
    DriverDate,
    DriverProviderName,
    DriverVersion,
    FriendlyName,
    HardWareID,
    Manufacturer,
    PDO,
	ValidFrom
)
SELECT  @InstanceID,
    ClassGuid,
    DeviceClass,
    DeviceID,
    DeviceName,
    DriverDate,
    DriverProviderName,
    DriverVersion,
    FriendlyName,
    HardWareID,
    Manufacturer,
    PDO,
	@SnapshotDate
FROM @Drivers t
WHERE NOT EXISTS(SELECT 1 FROM dbo.Drivers D WHERE D.DeviceID = t.DeviceID AND D.InstanceID = @InstanceID)
AND (ClassGuid NOT IN ('4D36E96B-E325-11CE-BFC1-08002BE10318','4D36E96F-E325-11CE-BFC1-08002BE10318','1ED2BBF9-11F0-4084-B21F-AD83A8E6DCDC') OR ClassGuid IS NULL); -- ignore KEYBOARD,MOUSE,PRINTQUEUE

WITH S AS(
	SELECT ClassGuid,
		DeviceClass,
		DeviceID,
		DeviceName,
		DriverDate,
		DriverProviderName,
		DriverVersion,
		FriendlyName,
		HardWareID,
		Manufacturer,
		PDO
	FROM @Drivers
	WHERE (ClassGuid NOT IN ('4D36E96B-E325-11CE-BFC1-08002BE10318','4D36E96F-E325-11CE-BFC1-08002BE10318','1ED2BBF9-11F0-4084-B21F-AD83A8E6DCDC') OR ClassGuid IS NULL) -- ignore KEYBOARD,MOUSE,PRINTQUEUE
	EXCEPT 
	SELECT ClassGuid,
		DeviceClass,
		DeviceID,
		DeviceName,
		DriverDate,
		DriverProviderName,
		DriverVersion,
		FriendlyName,
		HardWareID,
		Manufacturer,
		PDO
	FROM dbo.Drivers D 
	WHERE D.InstanceID = @InstanceID
)
UPDATE T
SET T.ClassGuid = S.ClassGuid,
    T.DeviceClass=S.DeviceClass,
    T.DeviceName=S.DeviceName,
    T.DriverDate=S.DriverDate,
    T.DriverProviderName=S.DriverProviderName,
    T.DriverVersion=S.DriverVersion,
    T.FriendlyName=S.FriendlyName,
    T.HardWareID=S.HardWareID,
    T.Manufacturer=S.Manufacturer,
    T.PDO=S.PDO,
	T.ValidFrom=@SnapshotDate
OUTPUT DELETED.InstanceID,
    DELETED.ClassGuid,
    DELETED.DeviceClass,
    DELETED.DeviceID,
    DELETED.DeviceName,
    DELETED.DriverDate,
    DELETED.DriverProviderName,
    DELETED.DriverVersion,
    DELETED.FriendlyName,
    DELETED.HardWareID,
    DELETED.Manufacturer,
    DELETED.PDO,
	DELETED.ValidFrom,
	@SnapshotDate INTO dbo.DriversHistory(    InstanceID,
    ClassGuid,
    DeviceClass,
    DeviceID,
    DeviceName,
    DriverDate,
    DriverProviderName,
    DriverVersion,
    FriendlyName,
    HardWareID,
    Manufacturer,
    PDO,
	ValidFrom,
	ValidTo)
FROM dbo.Drivers T
JOIN S ON T.DeviceID = S.DeviceID AND T.InstanceID = @InstanceID


DELETE D 
OUTPUT DELETED.InstanceID,
    DELETED.ClassGuid,
    DELETED.DeviceClass,
    DELETED.DeviceID,
    DELETED.DeviceName,
    DELETED.DriverDate,
    DELETED.DriverProviderName,
    DELETED.DriverVersion,
    DELETED.FriendlyName,
    DELETED.HardWareID,
    DELETED.Manufacturer,
    DELETED.PDO,
	DELETED.ValidFrom,
	@SnapshotDate INTO dbo.DriversHistory(    InstanceID,
    ClassGuid,
    DeviceClass,
    DeviceID,
    DeviceName,
    DriverDate,
    DriverProviderName,
    DriverVersion,
    FriendlyName,
    HardWareID,
    Manufacturer,
    PDO,
	ValidFrom,
	ValidTo)
FROM dbo.Drivers D
WHERE NOT EXISTS(SELECT 1 FROM @Drivers t WHERE d.DeviceID = t.DeviceID)
AND D.InstanceID = @InstanceID

EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,
                             @Reference = 'Drivers',
                             @SnapshotDate = @SnapshotDate
GO
PRINT N'Creating Procedure [dbo].[Drives_Get]...';


GO
CREATE PROC dbo.Drives_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@IncludeCritical BIT=1,
	@IncludeWarning BIT=1,
	@IncludeNA BIT=0,
	@IncludeOK BIT=0,
	@IncludeMetrics BIT=0,
	@ShowHidden BIT=1,
	@DriveName NVARCHAR(256)=NULL,
	@HasMetrics BIT=0
)
AS
DECLARE @StatusSQL NVARCHAR(MAX)

SELECT @StatusSQL = CASE WHEN @IncludeCritical=1 THEN ',1' ELSE '' END
	+ CASE WHEN @IncludeWarning=1 THEN ',2' ELSE '' END
	+ CASE WHEN @IncludeNA=1 THEN ',3' ELSE '' END
	+ CASE WHEN @IncludeOK=1 THEN ',4' ELSE '' END

SELECT @StatusSQL = CASE WHEN @StatusSQL='' THEN 'AND 1=2'
		ELSE 'AND D.Status IN(' + STUFF(@StatusSQL,1,1,'') + ')' END

DECLARE @SQL NVARCHAR(MAX)
SET @SQL = N'
SELECT D.DriveID,
		D.Name,
		D.InstanceID,
		D.Label,
		D.TotalGB,
		D.FreeGB,
		D.DriveCheckType,
		D.Status,
		D.DriveWarningThreshold,
		D.DriveCriticalThreshold,
		D.IsInheritedThreshold,
		D.Instance,
		D.InstanceDisplayName,
		D.PctFreeSpace,
		D.DriveCheckType,
		D.DriveCheckConfiguredLevel,
		D.SnapshotDate,
		D.SnapshotAgeMins,
		D.SnapshotStatus' + CASE WHEN  @IncludeMetrics=1 THEN ',
		(D.UsedGB-PreviousDay.UsedGB) AS ChangeUsedGB24Hrs,
		(D.TotalGB-PreviousDay.TotalGB) AS ChangeDriveSize24Hrs,
		(D.UsedGB-SevenDay.UsedGB) AS ChangeUsedGB7Days,
		(D.TotalGB-SevenDay.TotalGB) AS ChangeDriveSize7Days,
		(D.UsedGB-ThirtyDay.UsedGB) ChangeUsedGB30Days,
		(D.TotalGB-ThirtyDay.TotalGB) AS ChangeDriveSize30Days,
		(D.UsedGB-NinetyDay.UsedGB) AS ChangeUsedGB90Days,
		(D.TotalGB-NinetyDay.TotalGB) AS ChangeDriveSize90Days' ELSE '' END + '
FROM dbo.DriveStatus D ' + CASE WHEN @IncludeMetrics=1 THEN '
OUTER APPLY (SELECT TOP(1) DSS.Capacity / POWER(1024.0,3) as TotalGB,
                    DSS.UsedSpace / POWER(1024.0,3)as UsedGB
		FROM dbo.DriveSnapshot DSS 
		WHERE DSS.SnapshotDate < DATEADD(HH,-24,GETUTCDATE())
		AND DSS.DriveID=D.DriveID
		ORDER BY DSS.SnapshotDate DESC
		) PreviousDay
OUTER APPLY (SELECT TOP(1) DSS.Capacity / POWER(1024.0,3) as TotalGB,
                    DSS.UsedSpace / POWER(1024.0,3) as UsedGB
		FROM dbo.DriveSnapshot DSS 
		WHERE DSS.SnapshotDate >= DATEADD(d,-7,GETUTCDATE())
		AND DSS.DriveID=D.DriveID
		ORDER BY DSS.SnapshotDate
		) SevenDay
OUTER APPLY (SELECT TOP(1) DSS.Capacity / POWER(1024.0,3) as TotalGB,
                    DSS.UsedSpace / POWER(1024.0,3)as UsedGB
		FROM dbo.DriveSnapshot DSS 
		WHERE DSS.SnapshotDate >= DATEADD(d,-30,GETUTCDATE())
		AND DSS.DriveID=D.DriveID
		ORDER BY DSS.SnapshotDate
		) ThirtyDay
OUTER APPLY (SELECT TOP(1) DSS.Capacity / POWER(1024.0,3) as TotalGB,
                    DSS.UsedSpace / POWER(1024.0,3)as UsedGB
		FROM dbo.DriveSnapshot DSS 
		WHERE DSS.SnapshotDate >= DATEADD(d,-90,GETUTCDATE())
		AND DSS.DriveID=D.DriveID
		ORDER BY DSS.SnapshotDate
		) NinetyDay' ELSE '' END + '
WHERE ' + CASE WHEN @InstanceIDs IS NULL OR @InstanceIDs = '' 
			THEN '1=1' 
			ELSE 'EXISTS(SELECT 1 
						FROM STRING_SPLIT(@InstanceIDs,'','') ss
						WHERE ss.value = D.InstanceID)' END + '
' + @StatusSQL + '
' + CASE WHEN @ShowHidden=1 THEN '' ELSE 'AND D.ShowInSummary=1' END + '
' + CASE WHEN @DriveName IS NULL THEN '' ELSE 'AND D.Name = @DriveName' END + '
' + CASE WHEN @HasMetrics = 1 THEN 'AND EXISTS(
										SELECT 1 
										FROM dbo.DBIOStats IOS 
										WHERE IOS.InstanceID = D.InstanceID 
										AND IOS.DatabaseID=-1 
										AND IOS.FileID = -1
										AND IOS.Drive = CAST(LEFT(D.Name,1) AS CHAR(1))
										) ' ELSE '' END + '
ORDER BY Status DESC, PctFreeSpace DESC;'

EXEC sp_executesql @SQL,N'@InstanceIDs VARCHAR(MAX),@DriveName NVARCHAR(256)',@InstanceIDs,@DriveName
GO
PRINT N'Creating Procedure [dbo].[Drives_Upd]...';


GO
CREATE PROC [dbo].[Drives_Upd](@Drives Drives READONLY,@InstanceID INT,@SnapshotDate DATETIME2(2))
AS
DECLARE @Ref VARCHAR(30)='Drives'
INSERT INTO dbo.DriveSnapshot(DriveID,Capacity,FreeSpace, SnapshotDate)
SELECT D.DriveID,T.Capacity,T.FreeSpace,@SnapshotDate
FROM @Drives T
JOIN dbo.Drives D ON T.Name = D.Name AND D.InstanceID = @InstanceID
WHERE NOT EXISTS(SELECT 1 
				FROM dbo.DriveSnapshot DSS 
				WHERE DSS.DriveID = D.DriveID 
				AND DSS.SnapshotDate = @SnapshotDate
				)

IF NOT EXISTS(SELECT 1 FROM dbo.CollectionDates WHERE SnapshotDate>=@SnapshotDate AND InstanceID = @InstanceID AND Reference=@Ref)
BEGIN
	WITH  T AS (
		SELECT * 
		FROM dbo.Drives 
		WHERE InstanceID = @InstanceID
	)
	MERGE T
	USING (SELECT * FROM @Drives) as S
		ON S.Name = T.Name 

	WHEN MATCHED THEN
	UPDATE SET T.Capacity=S.Capacity,
	T.FreeSpace = S.FreeSpace,
	T.Label = S.Label,
	T.IsActive=1
	WHEN NOT MATCHED BY TARGET THEN 
	INSERT(InstanceID,
		Name,
		Capacity,
		FreeSpace,
		Label,
		IsActive)
	VALUES(@InstanceID,
		Name,
		Capacity,
		FreeSpace,
		Label,
		1)
	WHEN NOT MATCHED BY SOURCE THEN 
	UPDATE SET T.IsActive=0;

	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										 @Reference = @Ref,
										 @SnapshotDate = @SnapshotDate
END
GO
PRINT N'Creating Procedure [dbo].[DriveSnapshot_Del]...';


GO
CREATE PROC dbo.DriveSnapshot_Del(
	@InstanceID INT,
	@DaysToKeep INT,
	@BatchSize INT=500000
)
AS
/* 
	Partitioning switching is used to efficiently remove data from this table for all instances.  
	This proc provides an alternative way to remove data associated with a specific instance.
*/
SET NOCOUNT ON
DECLARE @MaxDate DATETIME2(2)
SELECT @MaxDate = CASE WHEN @DaysToKeep  = 0 THEN '30000101' ELSE DATEADD(d,-@DaysToKeep,GETUTCDATE()) END

WHILE 1=1
BEGIN
	DELETE TOP(@BatchSize) DSS
	FROM dbo.DriveSnapshot DSS
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Drives D 
				WHERE D.InstanceID = @InstanceID 
				AND D.DriveID = DSS.DriveID
				)
	AND DSS.SnapshotDate < @MaxDate
	OPTION(RECOMPILE)

	IF @@ROWCOUNT < @BatchSize
		BREAK
END
GO
PRINT N'Creating Procedure [dbo].[DriveSnapshot_Get]...';


GO
CREATE PROC dbo.DriveSnapshot_Get(
	@DriveID INT,
	@FromDate DATETIME2(2),
	@ToDate DATETIME2(2),
	@DateGroupingMins INT=1440
)
AS
SELECT	DG.DateGroup AS SnapshotDate,
		MAX(DSS.Capacity)/POWER(1024.0,3) AS SizeGB,
		MAX(DSS.UsedSpace)/POWER(1024.0,3) AS UsedGB,
		MIN(DSS.FreeSpace)/POWER(1024.0,3) AS FreeGB,
		MIN(DSS.FreeSpace*1.0)/MAX(DSS.Capacity) AS FreePct,
		COUNT(*) AS Samples
FROM dbo.DriveSnapshot DSS
CROSS APPLY dbo.DateGroupingMins(DSS.SnapshotDate,@DateGroupingMins) DG
WHERE DSS.DriveID=@DriveID
AND DSS.SnapshotDate>= @FromDate
AND DSS.SnapshotDate<@ToDate
GROUP BY DG.DateGroup
ORDER BY SnapshotDate
GO
