CREATE PROC dbo.InstanceMetadata_Get(
	@InstanceIDs IDs READONLY
)
AS
SELECT	I.InstanceDisplayName,
		M.InstanceID, 
		M.Provider, 
		M.Metadata, 
		P.Name,
		P.VMSize,
		P.SKU,
		P.ResourceGroup,
		P.PrivateIPs,
		P.PublicIPs,
		P.IPAddresses,
		P.Tags,
		P.AccountID,
		P.SubscriptionID,
		P.Location,
		P.AvailabilityZone,
		P.ImageID,
		P.AWSInstanceID,
		P.VMHostName,
		P.IAMRole,
		P.SecurityGroups,
		P.LocalHostname,
		P.BillingProducts,
		P.ClusterIP,
		P.ClusterName,
		M.SnapshotDate,
		CD.SnapshotDate AS LastSnapshotDate,
		M.ValidFrom, 
		M.ValidTo
FROM dbo.Instances I 
JOIN dbo.InstanceMetadata M ON I.InstanceID = M.InstanceID
LEFT JOIN dbo.CollectionDates CD ON CD.InstanceID = M.InstanceID AND CD.Reference = 'InstanceMetadata'
OUTER APPLY dbo.ParseInstanceMetadata(M.Metadata) P
WHERE EXISTS(SELECT 1 
			FROM @InstanceIDs IDs 
			WHERE IDs.ID = M.InstanceID
			)
AND I.IsActive=1
GO
PRINT N'Creating Procedure [dbo].[InstanceMetadata_Upd]...';


GO
CREATE PROC dbo.InstanceMetadata_Upd(
	@InstanceID INT,
	@Provider VARCHAR(50),
	@Metadata NVARCHAR(MAX),
	@SnapshotDate DATETIME2 = NULL
)
AS
SET NOCOUNT ON;
DECLARE @Ref VARCHAR(30)='InstanceMetadata'
DECLARE @OldMetadata NVARCHAR(MAX);
DECLARE @LastSnapshotDate DATETIME2;

SELECT @LastSnapshotDate = SnapshotDate
FROM dbo.CollectionDates 
WHERE InstanceID = @InstanceID 
AND Reference=@Ref

IF @LastSnapshotDate >= @SnapshotDate
BEGIN
	RETURN
END

SELECT @OldMetadata = Metadata
FROM dbo.InstanceMetadata
WHERE InstanceID = @InstanceID

IF @OldMetadata IS NULL
BEGIN
	INSERT INTO dbo.InstanceMetadata (InstanceID, Provider, Metadata,SnapshotDate,PreviousVersionLastSnapshotDate)
	VALUES (@InstanceID, @Provider, @Metadata, @SnapshotDate,@LastSnapshotDate);
END

IF @OldMetadata <> @Metadata
BEGIN
	UPDATE dbo.InstanceMetadata
	SET Provider = @Provider,
		Metadata = @Metadata,
		SnapshotDate = @SnapshotDate,
		PreviousVersionLastSnapshotDate = @LastSnapshotDate
	WHERE InstanceID = @InstanceID;
END

EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										@Reference = @Ref,
										@SnapshotDate = @SnapshotDate
GO
