CREATE PROC dbo.InstanceUptimeThresholds_Upd(
	@InstanceID INT,
	@WarningThreshold INT=NULL,
	@CriticalThreshold INT=NULL,
	@Inherit BIT=0
)
AS
SET XACT_ABORT ON
IF @Inherit=1 AND @InstanceID=-1
BEGIN
	RAISERROR('Root level can''t inherit',11,1)
	RETURN
END
BEGIN TRAN

DELETE dbo.InstanceUptimeThresholds
WHERE InstanceID = @InstanceID

IF @Inherit=0
BEGIN
	INSERT INTO dbo.InstanceUptimeThresholds
	(
		InstanceID,
		WarningThreshold,
		CriticalThreshold
	)
	VALUES
	(   @InstanceID,
		@WarningThreshold,
		@CriticalThreshold
		)

END
COMMIT
GO
PRINT N'Creating Procedure [dbo].[InstanceVersionInfo_Get]...';


GO
CREATE PROC dbo.InstanceVersionInfo_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@ShowHidden BIT=1
)
AS
DECLARE @Instances TABLE(
	InstanceID INT PRIMARY KEY
)
IF @InstanceIDs IS NULL
BEGIN
	INSERT INTO @Instances
	(
	    InstanceID
	)
	SELECT InstanceID 
	FROM dbo.Instances 
	WHERE IsActive=1
END 
ELSE 
BEGIN
	INSERT INTO @Instances
	(
		InstanceID
	)
	SELECT value
	FROM STRING_SPLIT(@InstanceIDs,',')
END;
SELECT	I.ConnectionID,
		I.InstanceDisplayName,
		I.SQLVersion,
		I.ProductVersion,
		I.ProductMajorVersion,
		I.ProductMinorVersion,
		I.ProductBuild,
		I.ProductRevision,
		I.Edition,
		I.EngineEdition,
		I.EditionID,
		I.ProductLevel,
		I.ProductUpdateLevel,
		I.ProductUpdateReference,
		I.ProductBuildType,
		I.ResourceVersion,
		I.ResourceLastUpdateDateTime,
		I.LicenseType,
		I.NumLicenses,
		I.WindowsCaption,
		I.WindowsRelease,
		I.WindowsSKU,
		H.ChangedDate AS PatchDate,
		BR.SupportedUntil,
		BR.KBList,
		CASE WHEN BR.IsCurrentBuild=1 THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS IsUpdateAvailable,
		BR.SPBehind,
		BR.CUBehind,
		BR.LatestVersion,
		BR.LatestVersionPatchLevel,
		BR.BuildReferenceVersion,
		BR.BuildReferenceUpdated,
		BR.MainstreamEndDate,
		BR.LifecycleUrl,
		DATEDIFF(d,GETUTCDATE(),SupportedUntil) AS DaysUntilSupportExpires,
        DATEDIFF(d,GETUTCDATE(),MainstreamEndDate) AS DaysUntilMainstreamSupportExpires,
		I.IsWindowsUpdate
FROM dbo.InstanceInfo I
OUTER APPLY(SELECT TOP(1) H.ChangedDate 
			FROM dbo.SQLPatchingHistory H 
			WHERE H.InstanceID = I.InstanceID 
			ORDER BY H.ChangedDate DESC
			) H
OUTER APPLY (SELECT TOP(1) 	
						BR.SPBehind,
						BR.CUBehind,
						BR.LatestVersion,
						BR.KBList,
						BR.IsCurrentBuild,
						BR.LatestVersionPatchLevel,
						BR.SupportedUntil,
						BR.BuildReferenceVersion,
						BR.BuildReferenceUpdated,
						BR.MainstreamEndDate,
						BR.LifecycleUrl
			FROM dbo.BuildReference BR 
			WHERE I.ProductMajorVersion = BR.Major
			AND I.ProductMinorVersion = BR.Minor
			AND I.ProductBuild = BR.Build
			AND I.EngineEdition <=4 /* Exclude Azure */
			ORDER BY CASE WHEN  I.ProductRevision = BR.Revision THEN 0 ELSE 1 END) BR
WHERE EXISTS(SELECT 1 
			FROM @Instances t 
			WHERE t.InstanceID = I.InstanceID
			)
AND I.IsActive=1
AND (I.ShowInSummary=1 OR @ShowHidden=1)
GO
PRINT N'Creating Procedure [dbo].[IOStats_Get]...';


GO
CREATE PROC dbo.IOStats_Get(
	@InstanceID INT,
	@FromDate DATETIME2(2)=NULL, /* UTC */
	@ToDate DATETIME2(2)=NULL, /* UTC */
	@DatabaseID INT=NULL,
	@Drive CHAR(1)=NULL,
	@DateGroupingMin INT=NULL,
	@FileGroup SYSNAME=NULL,
	@UTCOffset INT=0, /* Used for Hours filter */
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY,/* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
	@Debug BIT = 0
)
AS
SET DATEFIRST 1 /* Start week on Monday */
SET NOCOUNT ON
IF @FromDate IS NULL
	SET @FromDate = DATEADD(mi,-60,GETUTCDATE())
IF @ToDate IS NULL
	SET @ToDate = GETUTCDATE()
DECLARE @SQL NVARCHAR(MAX)
DECLARE @DateGroupingSQL NVARCHAR(MAX)

SELECT @DatabaseID=ISNULL(@DatabaseID,-1),@Drive=ISNULL(@Drive,'*')

IF EXISTS(SELECT 1 
		FROM dbo.Databases d 
		JOIN dbo.Instances I ON d.InstanceID = I.InstanceID 
		WHERE I.EngineEdition=5 -- Azure DB
		AND d.DatabaseID = @DatabaseID
		)
BEGIN
	SET @DatabaseID=-1
END
IF @DatabaseID=-1 AND @FileGroup IS NOT NULL
BEGIN
	RAISERROR('Database must be specifed when filtering on filegroup',11,1)
END
IF @FileGroup IS NOT NULL AND @Drive <>'*'
BEGIN
	RAISERROR('Can''t filter on drive when filtering on filegroup',11,1)
END

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')


SELECT @DateGroupingSQL= CASE WHEN @DateGroupingMin IS NULL OR @DateGroupingMin =0 THEN 'IOS.SnapshotDate'
			ELSE 'DG.DateGroup' END

DECLARE @TableName SYSNAME
SELECT @TableName = CASE WHEN @FileGroup IS NULL THEN 'dbo.DBIOStats' ELSE 'dbo.FGIOStats' END + CASE WHEN @DateGroupingMin>=60 THEN '_60MIN' ELSE '' END

SET @SQL = N'
SELECT	' + @DateGroupingSQL + ' as SnapshotDate,
			SUM(IOS.num_of_reads+IOS.num_of_writes)/(SUM(IOS.sample_ms_diff)/1000.0) AS IOPs,
			SUM(IOS.num_of_reads)/(SUM(IOS.sample_ms_diff)/1000.0) AS ReadIOPs,
			SUM(IOS.num_of_writes)/(SUM(IOS.sample_ms_diff)/1000.0) AS WriteIOPs,
			SUM(IOS.num_of_bytes_read+IOS.num_of_bytes_written)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) MBsec,
			SUM(IOS.num_of_bytes_read)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) ReadMBsec,
			SUM(IOS.num_of_bytes_written)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) WriteMBsec,
			ISNULL(SUM(IOS.io_stall_read_ms)/(NULLIF(SUM(IOS.num_of_reads),0)*1.0),0) AS ReadLatency,
			ISNULL(SUM(IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes),0)*1.0),0) AS WriteLatency,
			ISNULL(SUM(IOS.io_stall_read_ms+IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes+IOS.num_of_reads),0)*1.0),0) AS Latency,
			MAX(MaxIOPs) AS MaxIOPs,
			MAX(MaxReadIOPs)  AS MaxReadIOPs,
			MAX(MaxWriteIOPs)  AS MaxWriteIOPs,
			MAX(MaxMBsec) MaxMBsec,
			MAX(MaxReadMBsec) MaxReadMBsec,
			MAX(MaxWriteMBsec) MaxWriteMBsec,
			MAX(MaxReadLatency) AS MaxReadLatency,
			MAX(MaxWriteLatency) AS MaxWriteLatency,
			MAX(MaxLatency) AS MaxLatency
	FROM ' + @TableName + ' AS IOS
	' + CASE WHEN @DateGroupingMin IS NULL OR @DateGroupingMin =0 THEN '' ELSE 'CROSS APPLY dbo.DateGroupingMins(IOS.SnapshotDate,@DateGroupingMin) DG' END + '
	WHERE IOS.InstanceID = @InstanceID
	AND IOS.DatabaseID = @DatabaseID
	AND IOS.SnapshotDate >= @FromDate
	AND IOS.SnapshotDate < @ToDate
	' + CASE WHEN @FileGroup IS NULL THEN 'AND IOS.Drive = @Drive
		AND IOS.FileID = -1'
		ELSE 'AND IOS.filegroup_name = @FileGroup' END + '
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, IOS.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, IOS.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
	GROUP BY ' + @DateGroupingSQL  + '
ORDER BY SnapshotDate'

IF @Debug =1
BEGIN
	PRINT @SQL
END

EXEC sp_executesql @SQL,
				N'@InstanceID INT,
				@FromDate DATETIME2(2),
				@ToDate DATETIME2(2),
				@DatabaseID INT,
				@Drive CHAR(3),
				@DateGroupingMin INT,
				@FileGroup SYSNAME,
				@UTCOffset INT',
				@InstanceID,
				@FromDate,
				@ToDate,
				@DatabaseID,
				@Drive,
				@DateGroupingMin,
				@FileGroup,
				@UTCOffset
GO
PRINT N'Creating Procedure [dbo].[IOStats_Upd]...';


GO
CREATE PROC dbo.IOStats_Upd(
		@IOStats dbo.IOStats READONLY,
		@InstanceID INT,
		@SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON
DECLARE @Ref VARCHAR(30)='IOStats'
DECLARE @EngineEdition INT 
SELECT @EngineEdition = EngineEdition
FROM dbo.Instances 
WHERE InstanceID = @InstanceID

CREATE TABLE #DBIOStatsTemp(
	InstanceID INT NOT NULL,
	DatabaseID INT NOT NULL,
	Drive CHAR(1) COLLATE DATABASE_DEFAULT NOT NULL ,
	FileID INT NOT NULL,
	SnapshotDate DATETIME2(2) NOT NULL,
	SnapshotDate60 DATETIME2(2) NOT NULL,
	num_of_reads BIGINT NOT NULL,
	num_of_writes BIGINT NOT NULL,
	num_of_bytes_read BIGINT NOT NULL,
	num_of_bytes_written BIGINT NOT NULL,
	io_stall_read_ms BIGINT NOT NULL,
	io_stall_write_ms BIGINT NOT NULL,
	sample_ms_diff BIGINT NOT NULL,
	size_on_disk_bytes BIGINT NOT NULL,
	MaxReadLatency AS ISNULL(io_stall_read_ms/NULLIF(num_of_reads*1.0,0),0),
	MaxWriteLatency AS ISNULL(io_stall_write_ms/NULLIF(num_of_writes*1.0,0),0),
	MaxLatency AS ISNULL((io_stall_read_ms+io_stall_write_ms)/NULLIF(num_of_writes+num_of_reads*1.0,0),0),
	MaxReadIOPs AS num_of_reads/(sample_ms_diff/1000.0),
	MaxWriteIOPs AS num_of_writes/(sample_ms_diff/1000.0),
	MaxIOPs AS  (num_of_reads+num_of_writes)/(sample_ms_diff/1000.0),
	MaxReadMBsec AS	 num_of_bytes_read/(sample_ms_diff/1000.0)/POWER(1024.0,2),
	MaxWriteMBsec AS num_of_bytes_written/(sample_ms_diff/1000.0)/POWER(1024.0,2),
	MaxMBsec AS	 (num_of_bytes_written+num_of_bytes_read)/(sample_ms_diff/1000.0)/POWER(1024.0,2), 	
	PRIMARY KEY(InstanceID,DatabaseID,Drive,FileID,	SnapshotDate)
)
DECLARE @IOStorageBitMask TINYINT
DECLARE @Grp NVARCHAR(MAX)
/*	
	Configuration setting to control what level we store IO stats. 
	1 = Instance
	2 = File level
	4 = DB
	8 = DB, Drive
	16 = Drive
	31 = Everything
*/
SELECT @IOStorageBitMask = CAST(SettingValue AS TINYINT)
FROM dbo.InstanceSettings
WHERE InstanceID = @InstanceID
AND SettingName = 'IOStorageBitMask'

/* Azure DB = Instance and file level */
SELECT @IOStorageBitMask = ISNULL(@IOStorageBitMask,31) & CASE WHEN @EngineEdition IN(1,2,3,4) THEN 31 ELSE 3 END

IF @IOStorageBitMask = 0
BEGIN
	RETURN;
END

SELECT @Grp = STUFF((SELECT REPLICATE(CHAR(9),3) + ',' + Grp + CHAR(13) + CHAR(10)
FROM (VALUES('(x.InstanceID)',1),
		('(x.DatabaseID,x.FileID,x.Drive)',2),
		('(x.DatabaseID)',4),
		('(x.DatabaseID,x.Drive)',8),
		('(x.Drive)',16)
		) T(Grp,BitMask)
WHERE BitMask & @IOStorageBitMask > 0
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,4,REPLICATE(CHAR(9),3))

DECLARE @SQL NVARCHAR(MAX)
SET @SQL = N'SELECT @InstanceID,
			A.SnapshotDate,
			DG.DateGroup AS SnapshotDate60,
			' + CASE WHEN @IOStorageBitMask & 14 > 0 THEN 'ISNULL(x.DatabaseID,-1)' ELSE '-1' END + ' AS DatabaseID,
			' + CASE WHEN @IOStorageBitMask & 26 > 0 THEN 'COALESCE(x.Drive,''*'')' ELSE '''*''' END + ' AS Drive,
			' + CASE WHEN @IOStorageBitMask & 2 > 0 THEN 'ISNULL(x.FileID,-1)' ELSE '-1' END + ' AS FileID,
			MAX(A.sample_ms-B.sample_ms) AS sample_ms_diff,
			SUM(A.num_of_reads-B.num_of_reads),
			SUM(A.num_of_bytes_read-B.num_of_bytes_read),
			SUM(A.io_stall_read_ms-B.io_stall_read_ms),
			SUM(A.num_of_writes-B.num_of_writes),
			SUM(A.num_of_bytes_written-B.num_of_bytes_written),
			SUM(A.io_stall_write_ms-B.io_stall_write_ms),
			SUM(A.size_on_disk_bytes)
FROM @IOStats a
JOIN Staging.IOStats b ON b.database_id = a.database_id AND b.file_id = a.file_id AND a.drive = b.drive AND b.InstanceID=@InstanceID
LEFT JOIN dbo.Databases D ON D.database_id = a.database_id AND d.InstanceID=@InstanceID AND D.IsActive=1
LEFT JOIN dbo.DBFiles F ON F.file_id = a.file_id AND F.DatabaseID = D.DatabaseID AND F.IsActive=1 
CROSS APPLY dbo.DateGroupingMins(A.SnapshotDate,60) DG
CROSS APPLY(SELECT ISNULL(D.DatabaseID,-999) AS DatabaseID,
					ISNULL(F.FileID,-999) AS FileID,
					CASE WHEN a.drive LIKE ''[A-Z,-]'' THEN a.drive WHEN F.physical_name LIKE ''_:\%'' THEN LEFT(F.physical_name,1) ELSE ''?'' END AS Drive,
					@InstanceID AS InstanceID
					) x
WHERE A.sample_ms > b.sample_ms
			AND A.SnapshotDate > B.SnapshotDate
			AND A.num_of_bytes_read>=B.num_of_bytes_read
			AND A.num_of_reads>=B.num_of_reads
			AND A.num_of_writes>=B.num_of_writes
			AND A.num_of_bytes_written>= B.num_of_bytes_written
GROUP BY GROUPING SETS(
			' + @Grp + '
			)
		,a.SnapshotDate,DG.DateGroup
HAVING(
		SUM(A.num_of_writes-B.num_of_writes)>0 
		OR SUM(A.num_of_reads-B.num_of_reads)>0
	   )'

INSERT INTO #DBIOStatsTemp
(
	InstanceID,
	SnapshotDate,
	SnapshotDate60,
	DatabaseID,
	Drive,
	FileID,
	sample_ms_diff,
	num_of_reads,
	num_of_bytes_read,
	io_stall_read_ms,
	num_of_writes,
	num_of_bytes_written,
	io_stall_write_ms,
	size_on_disk_bytes
)
EXEC sp_executesql @SQL,N'@IOStats IOStats READONLY,@InstanceID INT',@IOStats,@InstanceID

/* 
	Depending on the IO Collection Level, the database_id & file_id could be set to -1 and Drive could be set to "-".  
	These won't join to an existing DB/file in the repository DB so DatabaseID and FileID get set to -999 in this case.
	We just want to keep the aggregates produced by GROUPING SETS in this case.
*/
DELETE #DBIOStatsTemp 
WHERE InstanceID = @InstanceID 
AND (DatabaseID = -999 OR FileID=-999 OR Drive = '-')



BEGIN TRAN

IF NOT EXISTS(
	/* Check data hasn't been imported already */
	SELECT 1
	FROM #DBIOStatsTemp t
	WHERE EXISTS(SELECT 1 
				FROM dbo.DBIOStats IOS 
				WHERE t.InstanceID = IOS.InstanceID
				AND t.DatabaseID = IOS.DatabaseID
				AND t.Drive = IOS.Drive
				AND t.FileID = IOS.FileID
				AND t.SnapshotDate = IOS.SnapshotDate			
				)
	)
BEGIN

	/* Insert granular IO metrics */
	INSERT INTO dbo.DBIOStats
	(
		InstanceID,
		SnapshotDate,
		DatabaseID,
		Drive,
		FileID,
		sample_ms_diff,
		num_of_reads,
		num_of_bytes_read,
		io_stall_read_ms,
		num_of_writes,
		num_of_bytes_written,
		io_stall_write_ms,
		size_on_disk_bytes
	)
	SELECT 	InstanceID,
		SnapshotDate,
		DatabaseID,
		Drive,
		FileID,
		sample_ms_diff,
		num_of_reads,
		num_of_bytes_read,
		io_stall_read_ms,
		num_of_writes,
		num_of_bytes_written,
		io_stall_write_ms,
		size_on_disk_bytes
	FROM #DBIOStatsTemp t

	/* Update 60min aggregation */
	UPDATE T 
			SET T.num_of_reads += s.num_of_reads,
				T.num_of_writes += S.num_of_writes,
				T.num_of_bytes_read += S.num_of_bytes_read,
				T.num_of_bytes_written += S.num_of_bytes_written,
				T.io_stall_read_ms += S.io_stall_read_ms,
				T.io_stall_write_ms += S.io_stall_write_ms,
				T.sample_ms_diff += S.sample_ms_diff,
				T.MaxReadLatency = CASE WHEN S.MaxReadLatency > t.MaxReadLatency THEN S.MaxReadLatency ELSE T.MaxReadLatency END,
				T.MaxWriteLatency = CASE WHEN S.MaxWriteLatency > t.MaxWriteLatency THEN S.MaxReadLatency ELSE T.MaxReadLatency END,
				T.MaxLatency = CASE WHEN S.MaxLatency > t.MaxLatency THEN S.MaxLatency ELSE T.MaxLatency END,
				T.MaxReadIOPs = CASE WHEN S.MaxReadIOPs > t.MaxReadIOPs THEN S.MaxReadIOPs ELSE T.MaxReadIOPs END,
				T.MaxWriteIOPs = CASE WHEN S.MaxWriteIOPs > t.MaxWriteIOPs THEN S.MaxWriteIOPs ELSE T.MaxWriteIOPs END,
				T.MaxIOPs = CASE WHEN S.MaxIOPs > t.MaxIOPs THEN S.MaxIOPs ELSE T.MaxIOPs END,
				T.MaxReadMBsec = CASE WHEN S.MaxReadMBsec > t.MaxReadMBsec THEN S.MaxReadMBsec ELSE T.MaxReadMBsec END,
				T.MaxWriteMBsec = CASE WHEN S.MaxWriteMBsec > t.MaxWriteMBsec THEN S.MaxWriteMBsec ELSE T.MaxWriteMBsec END,
				T.MaxMBsec =CASE WHEN S.MaxMBsec > t.MaxMBsec THEN S.MaxMBsec ELSE T.MaxMBsec END
	FROM dbo.DBIOStats_60MIN T 
	JOIN #DBIOStatsTemp S ON T.InstanceID = S.InstanceID
			AND S.DatabaseID = T.DatabaseID
			AND S.Drive = T.Drive
			AND S.FileID = T.FileID
			AND S.SnapshotDate60 = T.SnapshotDate

	INSERT INTO dbo.DBIOStats_60MIN(
		InstanceID,
		DatabaseID,
		Drive,
		FileID,
		SnapshotDate,
		num_of_reads,
		num_of_writes,
		num_of_bytes_read,
		num_of_bytes_written,
		io_stall_read_ms,
		io_stall_write_ms,
		sample_ms_diff,
		MaxReadLatency,
		MaxWriteLatency,
		MaxLatency,
		MaxReadIOPs,
		MaxWriteIOPs,
		MaxIOPs,
		MaxReadMBsec,
		MaxWriteMBsec,
		MaxMBsec
	)
	SELECT  InstanceID,
			DatabaseID,
			Drive,
			FileID,
			SnapshotDate60,
			num_of_reads,
			num_of_writes,
			num_of_bytes_read,
			num_of_bytes_written,
			io_stall_read_ms,
			io_stall_write_ms,
			sample_ms_diff,
			MaxReadLatency,
			MaxWriteLatency,
			MaxLatency,
			MaxReadIOPs,
			MaxWriteIOPs,
			MaxIOPs,
			MaxReadMBsec,
			MaxWriteMBsec,
		MaxMBsec
	FROM #DBIOStatsTemp S
	WHERE NOT EXISTS(
				SELECT 1 
				FROM dbo.DBIOStats_60MIN T
				WHERE T.InstanceID = S.InstanceID
				AND S.DatabaseID = T.DatabaseID
				AND S.Drive = T.Drive
				AND S.FileID = T.FileID
				AND S.SnapshotDate60 = T.SnapshotDate
				)

END
/* Replace data in staging table */
DELETE Staging.IOStats
WHERE InstanceID=@InstanceID

INSERT INTO Staging.IOStats
(
    InstanceID,
    SnapshotDate,
    database_id,
    file_id,
    sample_ms,
    num_of_reads,
    num_of_bytes_read,
    io_stall_read_ms,
    num_of_writes,
    num_of_bytes_written,
    io_stall_write_ms,
    io_stall,
    size_on_disk_bytes,
	drive
)
SELECT @InstanceID InstanceID,
    SnapshotDate,
    database_id,
    file_id,
    sample_ms,
    num_of_reads,
    num_of_bytes_read,
    io_stall_read_ms,
    num_of_writes,
    num_of_bytes_written,
    io_stall_write_ms,
    io_stall,
    size_on_disk_bytes,
	drive
FROM @IOStats

COMMIT

EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										@Reference = @Ref,
										@SnapshotDate = @SnapshotDate
GO
PRINT N'Creating Procedure [dbo].[IOSummary_Get]...';


GO
CREATE PROC dbo.IOSummary_Get(
	@InstanceID INT,
	@FromDate DATETIME2(2), /* UTC */
	@ToDate DATETIME2(2), /* UTC */
	@GroupBy VARCHAR(50)='Database',
	@DatabaseID INT=NULL,
	@Debug BIT =0,
	@Use60MIN BIT=NULL,
	@Instance NVARCHAR(128)=NULL OUT,
	@DatabaseName NVARCHAR(128)=NULL OUT,
	@UTCOffset INT=0, /* Used for Hours filter */
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY/* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
)
AS
SET DATEFIRST 1 /* Start week on Monday */
SET NOCOUNT ON
IF @DatabaseID=-1
	SET @DatabaseID=NULL

DECLARE @EditionID INT

SELECT @Instance = I.Instance, 
		@EditionID = I.EditionID
FROM dbo.Instances I
WHERE I.InstanceID = @InstanceID

SELECT @DatabaseName = D.name 
FROM dbo.Databases D 
WHERE D.InstanceID = @InstanceID
AND D.DatabaseID = @DatabaseID

-- For Azure DB, instance level stats are the DB level stats.  DatabaseID will be -1 in table.
IF @GroupBy='Database' AND @EditionID=1674378470 
	SET @DatabaseID=NULL

IF @Use60MIN IS NULL
BEGIN
	SELECT @Use60MIN = CASE WHEN DATEDIFF(hh,@FromDate,@ToDate)>24 THEN 1
						WHEN DATEPART(mi,@FromDate)+DATEPART(s,@FromDate)+DATEPART(ms,@FromDate)=0 
							AND (DATEPART(mi,@ToDate)+DATEPART(s,@ToDate)+DATEPART(ms,@ToDate)=0 
									OR @ToDate>=DATEADD(s,-2,GETUTCDATE())
								)
						THEN 1
						ELSE 0 END
END
DECLARE @TableName SYSNAME
SELECT @TableName = CASE WHEN @GroupBy ='Filegroup' THEN 'dbo.FGIOStats' ELSE 'dbo.DBIOStats' END + CASE WHEN @Use60MIN=1 THEN '_60MIN' ELSE '' END

DECLARE @GroupBySQL NVARCHAR(MAX) 
SELECT @GroupBySQL= CASE @GroupBy WHEN 'Database' THEN 'CASE WHEN IOS.DatabaseID =-1 AND IOS.FileID = -1 AND IOS.Drive=''*'' THEN ''{All}'' ELSE D.name END' 
					WHEN 'Filegroup' THEN 'D.name + '' | '' + IOS.filegroup_name' 
					WHEN 'File' THEN 'CASE WHEN IOS.DatabaseID =-1 AND IOS.FileID = -1 AND IOS.Drive=''*'' THEN ''{All}'' ELSE D.name + '' | '' + F.name + '' | ('' + IOS.Drive + '':\)'' END' 
					WHEN 'Drive' THEN 'REPLACE(IOS.Drive + '':\'',''*'',''{All}'') + ISNULL('' ('' + DRV.Label + '')'','''')' END
IF @GroupBySQL IS NULL
BEGIN
	RAISERROR('Invalid @GroupBy.  Valid values: Database,Filegroup,File,Drive',11,1)
END

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @SQL NVARCHAR(MAX)
SET @SQL =N'
SELECT ' + @GroupBySQL + N' AS Grp,
		SUM(IOS.num_of_reads+IOS.num_of_writes)/(MAX(SUM(IOS.sample_ms_diff)) OVER()/1000.0) AS IOPs,
		SUM(IOS.num_of_reads)/(MAX(SUM(IOS.sample_ms_diff)) OVER()/1000.0) AS ReadIOPs,
		SUM(IOS.num_of_writes)/(MAX(SUM(IOS.sample_ms_diff)) OVER()/1000.0)  AS WriteIOPs,
		SUM(IOS.num_of_bytes_read+IOS.num_of_bytes_written)/POWER(1024.0,2)/(MAX(SUM(IOS.sample_ms_diff)) OVER()/1000.0) AS MBsec,
		SUM(IOS.num_of_bytes_read)/POWER(1024.0,2)/(MAX(SUM(IOS.sample_ms_diff)) OVER()/1000.0) AS ReadMBsec,
		SUM(IOS.num_of_bytes_written)/POWER(1024.0,2)/(MAX(SUM(IOS.sample_ms_diff)) OVER()/1000.0) AS WriteMBsec,
		ISNULL(SUM(IOS.io_stall_read_ms)/(NULLIF(SUM(IOS.num_of_reads),0)*1.0),0) AS ReadLatency,
		ISNULL(SUM(IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes),0)*1.0),0) AS WriteLatency,
		ISNULL(SUM(IOS.io_stall_read_ms+IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes+IOS.num_of_reads),0)*1.0),0) AS Latency,
		MAX(MaxIOPs) AS MaxIOPs,
		MAX(MaxReadIOPs) AS MaxReadIOPs,
		MAX(MaxWriteIOPs) AS MaxWriteIOPs,
		MAX(MaxMBsec) MaxMBsec,
		MAX(MaxReadMBsec) MaxReadMBsec,
		MAX(MaxWriteMBsec) MaxWriteMBsec,
		MAX(MaxReadLatency) AS MaxReadLatency,
		MAX(MaxWriteLatency) AS MaxWriteLatency,
		MAX(MaxLatency) AS MaxLatency
FROM ' + @TableName + ' IOS
' + CASE WHEN @GroupBy IN('Filegroup','File','Database') AND @EditionID=1674378470 THEN 'LEFT JOIN dbo.Databases D ON D.InstanceID = IOS.InstanceID AND D.IsActive=1 ' ELSE '' END + '
' + CASE WHEN @GroupBy IN('Filegroup','File','Database') AND @EditionID<>1674378470 THEN 'LEFT JOIN dbo.Databases D ON D.DatabaseID = IOS.DatabaseID AND D.IsActive=1' ELSE '' END + '
' + CASE WHEN @GroupBy IN('File') THEN 'LEFT JOIN dbo.DBFiles F ON D.DatabaseID = F.DatabaseID AND IOS.FileID = F.FileID' ELSE '' END + '
' + CASE WHEN @GroupBy ='Drive' THEN 'LEFT JOIN dbo.Drives DRV ON IOS.InstanceID = DRV.InstanceID AND DRV.Name = IOS.Drive + '':\'' AND DRV.IsActive=1' ELSE '' END + '
WHERE IOS.InstanceID = @InstanceID
AND IOS.SnapshotDate >= @FromDate
AND IOS.SnapshotDate < @ToDate
' + CASE WHEN @DatabaseID IS NULL THEN '' ELSE 'AND IOS.DatabaseID = @DatabaseID' END + '
' + CASE WHEN @GroupBy IN('Drive','Database') THEN 'AND IOS.FileID = -1' ELSE '' END + '
' + CASE WHEN @GroupBy ='Database' THEN 'AND IOS.Drive=''*''' ELSE '' END + '
' + CASE WHEN @GroupBy ='Drive' AND @DatabaseID IS NULL THEN 'AND IOS.DatabaseID = -1' ELSE '' END + '
' + CASE WHEN @GroupBy = 'File' THEN 'AND (IOS.FileID>0 OR (IOS.FileID=-1 AND IOS.DatabaseID = -1 AND IOS.Drive=''*''))' ELSE '' END + '
' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, IOS.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, IOS.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
GROUP BY ' + @GroupBySQL + '
ORDER BY Grp'

IF @Debug=1
	PRINT @SQL

EXEC sp_executesql @SQL,
					N'@InstanceID INT,
					@FromDate DATETIME2(2),
					@ToDate DATETIME2(2),
					@DatabaseID INT,
					@UTCOffset INT',
					@InstanceID,
					@FromDate,
					@ToDate,
					@DatabaseID,
					@UTCOffset
GO
PRINT N'Creating Procedure [dbo].[Job_Diff]...';


GO
CREATE PROC dbo.Job_Diff(
	@InstanceID_A INT,
	@InstanceID_B INT
)
AS
WITH A AS(
	SELECT I.ConnectionID,
		J.name,
		J.description,
		J.category,
		J.date_modified,
		J.DDLID,
		J.SnapshotUpdatedDate
	FROM dbo.Jobs J
	JOIN dbo.Instances I ON J.InstanceID = I.InstanceID
	WHERE J.InstanceID = @InstanceID_A
	AND J.IsActive=1
)
,B as (
	SELECT I.ConnectionID,
		J.name,
		J.description,
		J.category,
		J.date_modified,
		J.DDLID,
		J.SnapshotUpdatedDate
	FROM dbo.Jobs J 
	JOIN dbo.Instances I ON J.InstanceID = I.InstanceID
	WHERE J.InstanceID = @InstanceID_B
	AND J.IsActive=1
)
SELECT CASE WHEN A.ConnectionID IS NULL THEN B.ConnectionID + ' Only'  
			WHEN B.ConnectionID IS NULL THEN A.ConnectionID + ' Only'
			WHEN A.DDLID = B.DDLID THEN '=' ELSE '<>' END as Diff,
		ISNULL(A.name,B.name) as name,
		A.description as description_A,
		B.description as description_B, 
		A.category as category_A,
		B.category as category_B, 
		A.date_modified as date_modified_A,
		b.date_modified as date_modified_B,
		A.SnapshotUpdatedDate as SnapshotUpdated_A,
		B.SnapshotUpdatedDate as SnapshotUpdated_B,
		A.DDLID as DDLID_A,
		B.DDLID as DDLID_B
FROM A 
FULL JOIN B ON A.name = B.name
GO
