CREATE PROC dbo.Jobs_Upd(
	@InstanceID INT,
	@Jobs dbo.Jobs READONLY,
	@SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON
DECLARE @Ref VARCHAR(30)='Jobs'
IF NOT EXISTS(SELECT 1 FROM dbo.CollectionDates WHERE SnapshotDate>=@SnapshotDate AND InstanceID = @InstanceID AND Reference=@Ref)
BEGIN

	INSERT INTO dbo.DDL	(
		DDLHash,
		DDL
	)
	SELECT DISTINCT DDLHash,
			DDL
	FROM @Jobs T
	WHERE NOT EXISTS(SELECT 1 FROM dbo.DDL WHERE DDL.DDLHash = T.DDLHash)
	AND DDL IS NOT NULL

	BEGIN TRAN

	INSERT INTO dbo.JobDDLHistory(
		InstanceID,
		job_id,
		version_number,
		SnapshotDate,
		date_modified,
		DDLID
	)
	SELECT @InstanceID,T.job_id,T.version_number,@SnapshotDate,T.date_modified,DDL.DDLID 
	FROM @Jobs T
	JOIN dbo.DDL ON T.DDLHash = DDL.DDLHash
	WHERE NOT EXISTS(SELECT 1 FROM dbo.Jobs J WHERE J.InstanceID = @InstanceID AND J.job_id = T.job_id AND DDL.DDLID = J.DDLID)

	INSERT INTO dbo.Jobs(
		InstanceID,
		job_id,
		originating_server,
		name,
		enabled,
		description,
		start_step_id,
		category_id,
		category,
		owner,
		notify_level_eventlog,
		notify_level_email,
		notify_level_netsend,
		notify_level_page,
		notify_email_operator,
		notify_netsend_operator,
		notify_page_operator,
		delete_level,
		date_created,
		date_modified,
		version_number,
		has_schedule,
		has_server,
		has_step,
		DDLID,
		IsActive,
		SnapshotCreatedDate,
		SnapshotUpdatedDate
		)
		SELECT @InstanceID,
		job_id,
		originating_server,
		name,
		enabled,
		description,
		start_step_id,
		category_id,
		category,
		owner,
		notify_level_eventlog,
		notify_level_email,
		notify_level_netsend,
		notify_level_page,
		notify_email_operator,
		notify_netsend_operator,
		notify_page_operator,
		delete_level,
		date_created,
		date_modified,
		version_number,
		has_schedule,
		has_server,
		has_step,
		DDLID,
		1,
		@SnapshotDate,
		@SnapshotDate
	FROM @Jobs T
	LEFT JOIN dbo.DDL ON T.DDLHash = DDL.DDLHash
	WHERE NOT EXISTS(SELECT 1 FROM dbo.Jobs J WHERE T.job_id = J.job_id AND J.InstanceID = @InstanceID)

	UPDATE J 
		SET IsActive = 0,
		SnapshotUpdatedDate = @SnapshotDate
	FROM dbo.Jobs J
	WHERE NOT EXISTS(SELECT 1 FROM @Jobs T WHERE T.job_id = J.job_id)
	AND J.InstanceID = @InstanceID

	UPDATE dbo.Jobs
		SET originating_server=T.originating_server,
		name=T.name,
		enabled=T.enabled,
		description=T.description,
		start_step_id=T.start_step_id,
		category_id=T.category_id,
		category=T.category,
		owner=T.owner,
		notify_level_eventlog=T.notify_level_eventlog,
		notify_level_email=T.notify_level_email,
		notify_level_netsend=T.notify_level_netsend,
		notify_level_page=T.notify_level_page,
		notify_email_operator=T.notify_email_operator,
		notify_netsend_operator=T.notify_netsend_operator,
		notify_page_operator = T.notify_page_operator,
		delete_level=T.delete_level,
		date_created = T.date_created,
		date_modified = T.date_modified,
		version_number = T.version_number,
		has_schedule = T.has_schedule,
		has_server = T.has_server,
		has_step = T.has_step,
		DDLID = DDL.DDLID,
		Isactive=1,
		SnapshotCreatedDate = ISNULL(J.SnapshotCreatedDate,@SnapshotDate),
		SnapshotUpdatedDate = @SnapshotDate
	FROM dbo.Jobs J
	JOIN @Jobs T ON T.job_id = J.job_id
	LEFT JOIN dbo.DDL ON T.DDLHash = DDL.DDLHash
	WHERE J.InstanceID = @InstanceID
	AND NOT EXISTS(SELECT J.job_id,
							J.originating_server,
							J.name,
							J.enabled,
							J.description,
							J.start_step_id,
							J.category_id,
							J.category,
							J.owner,
							J.notify_level_eventlog,
							J.notify_level_email,
							J.notify_level_netsend,
							J.notify_level_page,
							J.notify_email_operator,
							J.notify_netsend_operator,
							J.notify_page_operator,
							J.delete_level,
							J.date_created,
							J.date_modified,
							J.version_number,
							J.has_schedule,
							J.has_server,
							J.has_step,
							J.DDLID
			INTERSECT 
					SELECT T.job_id,
							T.originating_server,
							T.name,
							T.enabled,
							T.description,
							T.start_step_id,
							T.category_id,
							T.category,
							T.owner,
							T.notify_level_eventlog,
							T.notify_level_email,
							T.notify_level_netsend,
							T.notify_level_page,
							T.notify_email_operator,
							T.notify_netsend_operator,
							T.notify_page_operator,
							T.delete_level,
							T.date_created,
							T.date_modified,
							T.version_number,
							T.has_schedule,
							T.has_server,
							T.has_step,
							DDL.DDLID
				)

	COMMIT
	
	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
	                             @Reference = @Ref,
	                             @SnapshotDate = @SnapshotDate
END
GO
PRINT N'Creating Procedure [dbo].[JobStats_60MIN_Del]...';


GO
CREATE PROC dbo.JobStats_60MIN_Del(
	@InstanceID INT,
	@DaysToKeep INT,
	@BatchSize INT=500000
)
AS
/* 
	Partitioning switching is used to efficiently remove data from this table for all instances.  
	This proc provides an alternative way to remove data associated with a specific instance.
*/
SET NOCOUNT ON
DECLARE @MaxDate DATETIME2(2)
SELECT @MaxDate = CASE WHEN @DaysToKeep  = 0 THEN '30000101' ELSE DATEADD(d,-@DaysToKeep,GETUTCDATE()) END

WHILE 1=1
BEGIN
	DELETE TOP(@BatchSize)  
	FROM dbo.JobStats_60MIN
	WHERE InstanceID = @InstanceID
	AND RunDateTime < @MaxDate
	OPTION(RECOMPILE)

	IF @@ROWCOUNT < @BatchSize
		BREAK
END
GO
PRINT N'Creating Procedure [dbo].[JobStats_Get]...';


GO
CREATE PROC dbo.JobStats_Get(
	@InstanceID INT,
	@JobID UNIQUEIDENTIFIER,
	@StepID INT,
	@FromDate DATETIME2(2),
	@ToDate DATETIME2(2),
	@DateGroupingMin INT OUT,
	@Debug BIT =0
)
AS

SELECT @DateGroupingMin= CASE WHEN EXISTS(SELECT 1 
											FROM dbo.DataRetention
											WHERE TableName='JobHistory'
											AND @FromDate < DATEADD(d,-RetentionDays,GETUTCDATE())
											AND @DateGroupingMin<60
											) THEN 60
									ELSE @DateGroupingMin END
DECLARE @DateCol NVARCHAR(MAX) = CASE WHEN @DateGroupingMin=0 THEN 'JS.RunDateTime' ELSE 'G.DateGroup' END


DECLARE @SQL NVARCHAR(MAX)

SET @SQL =N'
SELECT ' + @DateCol + ' AS DateGroup,
		SUM(FailedCount) AS FailedCount,
		SUM(SucceededCount) AS SucceededCount,
		SUM(RetryCount) AS RetryCount,
		SUM(RunDurationSec)/NULLIF(SUM(SucceededCount+FailedCount),0) AS AvgDurationSec,
		MAX(JS.MaxRunDurationSec) AS MaxDurationSec,
		MIN(JS.MinRunDurationSec) AS MinDurationSec,
		SUM(RunDurationSec) AS TotalDurationSec
FROM ' + CASE WHEN @DateGroupingMin <60 THEN 'dbo.JobStats_RAW' ELSE 'dbo.JobStats_60MIN' END + ' AS JS
' + CASE WHEN @DateGroupingMin=0 THEN '' ELSE 'CROSS APPLY dbo.DateGroupingMins(JS.RunDateTime,@DateGroupingMin) G' END + '
WHERE JS.InstanceID=@InstanceID
AND JS.job_id=@JobID
AND JS.step_id=@StepID
AND JS.RunDateTime>=@FromDate
AND JS.RunDateTime < @ToDate
GROUP BY ' + @DateCol + '
ORDER BY ' + @DateCol 

IF @Debug=1
BEGIN
	PRINT @SQL
END

EXEC sp_executesql @SQL,N'@InstanceID INT,@JobID UNIQUEIDENTIFIER,@StepID INT,@FromDate DATETIME2(2),@ToDate DATETIME2(2),@DateGroupingMin INT',@InstanceID,@JobID,@StepID,@FromDate,@ToDate,@DateGroupingMin
GO
PRINT N'Creating Procedure [dbo].[JobStatsSummary_Get]...';


GO
CREATE PROC dbo.JobStatsSummary_Get(
	@InstanceID INT,
	@JobID UNIQUEIDENTIFIER=NULL,
	@StepID INT=NULL,
	@FromDate DATETIME2(2),
	@ToDate DATETIME2(2),
	@Debug BIT =0,
	@Use60MIN BIT=NULL
)
AS
DECLARE @SQL NVARCHAR(MAX)
IF @Use60MIN IS NULL
BEGIN
	SELECT @Use60MIN = CASE WHEN DATEDIFF(hh,@FromDate,@ToDate)>24 THEN 1
						WHEN DATEPART(mi,@FromDate)+DATEPART(s,@FromDate)+DATEPART(ms,@FromDate)=0 
							AND (DATEPART(mi,@ToDate)+DATEPART(s,@ToDate)+DATEPART(ms,@ToDate)=0 
									OR @ToDate>=DATEADD(s,-2,GETUTCDATE())
								)
						THEN 1
						ELSE 0 END
END

SET @SQL = N'
WITH T AS (
	SELECT JS.job_id,
			JS.step_id,
			ISNULL(J.name,CAST(JS.job_id AS NVARCHAR(128))) JobName,
			CASE WHEN JS.step_id=0 THEN ''{outcome}'' ELSE step.step_name END as JobStep,
			SUM(JS.FailedCount) AS FailedCount,
			SUM(JS.SucceededCount) AS SucceededCount,
			SUM(JS.RetryCount) AS RetryCount,
			SUM(JS.RunDurationSec)/NULLIF(SUM(JS.SucceededCount+JS.FailedCount),0) AS AvgDurationSec,
			MAX(JS.MaxRunDurationSec) AS MaxDurationSec,
			MIN(JS.MinRunDurationSec) AS MinDurationSec,
			SUM(JS.RunDurationSec) AS TotalDurationSec
	FROM ' + CASE WHEN @Use60MIN=0 THEN 'dbo.JobStats_RAW' ELSE 'dbo.JobStats_60MIN' END + ' AS JS
	LEFT JOIN dbo.Jobs J ON J.job_id = JS.job_id AND J.InstanceID = JS.InstanceID
	LEFT JOIN dbo.JobSteps step ON JS.job_id = step.job_id AND JS.InstanceID = step.InstanceID AND JS.step_id = step.step_id
	WHERE JS.InstanceID=@InstanceID
	' + CASE WHEN @JobID IS NULL OR @JobID = '00000000-0000-0000-0000-000000000000' THEN '' ELSE 'AND JS.job_id=@JobID' END + '
	' + CASE WHEN @StepID IS NULL THEN '' ELSE 'AND JS.step_id=@StepID' END + '
	AND JS.RunDateTime>=@FromDate
	AND JS.RunDateTime < @ToDate
	GROUP BY JS.job_id, J.name, JS.step_id,step.step_name
)
SELECT  T.job_id,
		T.step_id,
		T.JobName,
		T.JobStep,
		T.FailedCount,
		T.SucceededCount,
		T.RetryCount,
		T.AvgDurationSec,		
		T.MaxDurationSec,		
		T.MinDurationSec,		
		T.TotalDurationSec,
		HDAvg.HumanDuration AS AvgDuration,
		HDMax.HumanDuration AS MaxDuration,
		HDMin.HumanDuration AS MinDuration,
		HDTotal.HumanDuration AS TotalDuration,
		@InstanceID InstanceID
FROM T
CROSS APPLY dbo.SecondsToHumanDuration(T.AvgDurationSec) HDAvg
CROSS APPLY dbo.SecondsToHumanDuration(T.MaxDurationSec) HDMax
CROSS APPLY dbo.SecondsToHumanDuration(T.MinDurationSec) HDMin
CROSS APPLY dbo.SecondsToHumanDuration(T.TotalDurationSec) HDTotal'

IF @Debug=1
BEGIN
	PRINT @SQL
END

EXEC sp_executesql @SQL,N'@InstanceID INT,@JobID UNIQUEIDENTIFIER,@StepID INT,@FromDate DATETIME2(2),@ToDate DATETIME2(2)',@InstanceID,@JobID,@StepID,@FromDate,@ToDate
