CREATE PROC dbo.OSLoadedModuleSummary_Get(
	@InstanceIDs IDs READONLY,
	@ShowHidden BIT=1
)
AS
SELECT I.InstanceID,
	I.EngineEdition,
	I.InstanceDisplayName,
	ISNULL(Status,3) AS Status,
	CASE Status WHEN 1 THEN 'Critical' WHEN 2 THEN 'Warning' WHEN 4 THEN 'OK' ELSE 'N/A' END AS StatusDescription,
	STUFF((SELECT ', ' + Notes 
			FROM dbo.OSLoadedModules OSLM 
			WHERE OSLM.InstanceID = I.InstanceID 
			AND OSLM.Status IN(1,2)
			AND OSLM.Notes IS NOT NULL
			GROUP BY Notes
			ORDER BY MIN(Status)
			FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,2,'') AS Notes
FROM dbo.Instances I 
OUTER APPLY(SELECT TOP(1) Status,
						Notes
			FROM dbo.OSLoadedModules OSLM
			WHERE OSLM.InstanceID = I.InstanceID
			AND Status <> 3
			ORDER BY Status 
			) Loaded
WHERE I.IsActive=1
AND I.EngineEdition NOT IN(5,6,8,9,11)
AND EXISTS(	SELECT * 
			FROM @InstanceIDs IDs
			WHERE IDs.ID = I.InstanceID
			)
AND (I.ShowInSummary=1 OR @ShowHidden=1)
ORDER BY Loaded.Status
GO
PRINT N'Creating Procedure [dbo].[Partitions_Create]...';


GO
CREATE PROC dbo.Partitions_Create(
	@TableName SYSNAME,
	@SchemaName SYSNAME='dbo',
	@PeriodCount INT,
	/* Valid values : m (Month)
					  d (Day)
	*/
	@PeriodType CHAR(1)
)
AS
/* 
	Generic proc to handle adding new partitions to the partitioned tables.
	Creates daily or monthly partitions a specified number of periods into the future.
*/
DECLARE @PartitionFunction SYSNAME
DECLARE @PartitionScheme SYSNAME
DECLARE @Boundary DATETIME2

SELECT TOP(1)	@Boundary= PH.LowerBound, 
				@PartitionScheme= PH.PartitionSchemeName, 
				@PartitionFunction = PH.PartitionFunctionName
FROM dbo.PartitionHelper PH
WHERE PH.TableName = @TableName
AND PH.SchemaName = @SchemaName
ORDER BY PH.partition_number DESC

IF (@PartitionFunction IS NULL)
BEGIN
	RAISERROR('Invalid table %s',11,1,@TableName)
	RETURN
END
IF @PeriodType NOT IN('d','m') OR @PeriodType IS NULL
BEGIN
	RAISERROR('Invalid parameter value for @PeriodType.  Valid Values: d (Day), m (Month)',11,1)
	RETURN
END

DECLARE @SQL NVARCHAR(MAX)
SET @SQL = N'
SELECT @Boundary = CASE WHEN @Boundary IS NULL THEN DATEADD(' + @PeriodType + ', DATEDIFF(' + @PeriodType + ', 0, GETUTCDATE())-1, 0) 
					WHEN @Boundary < GETUTCDATE() THEN DATEADD(' + @PeriodType + ', DATEDIFF(' + @PeriodType + ', 0, GETUTCDATE()), 0) 
					ELSE @Boundary END

-- Repeat until we are specified periods in the future
WHILE DATEDIFF(' + @PeriodType + ', GETUTCDATE(), @Boundary) < @PeriodCount
BEGIN;
   -- Increase by 1 period and split partition
   SET @Boundary = DATEADD(' + @PeriodType + ', 1, @Boundary);

   ALTER PARTITION SCHEME ' + QUOTENAME(@PartitionScheme) + '
   NEXT USED [PRIMARY]

   ALTER PARTITION FUNCTION ' + QUOTENAME(@PartitionFunction) + '()
         SPLIT RANGE (@Boundary);
END;'

DECLARE @applock INT

SET XACT_ABORT ON
BEGIN TRAN
EXEC @applock = sp_getapplock @Resource = 'Partitioning',
                                 @LockMode = 'Exclusive',
                                 @LockOwner = 'Transaction',
                                 @LockTimeout = 5000;
IF NOT @applock IN(0,1)
BEGIN;
	THROW 50000,'sp_getapplock error',1;
	RETURN;
END

EXEC sp_executesql @SQL,N'@PeriodCount INT,@Boundary DATETIME2',@PeriodCount,@Boundary

COMMIT
GO
PRINT N'Creating Procedure [dbo].[PartitionTable_Cleanup]...';


GO
CREATE PROC dbo.PartitionTable_Cleanup(
		@TableName SYSNAME,
		@SchemaName SYSNAME='dbo',
		@DaysToKeep INT
)
AS
SET NOCOUNT ON

DECLARE @QualifiedTableName SYSNAME = QUOTENAME(@SchemaName) + '.' + QUOTENAME(@TableName)
DECLARE @DeleteOlderThanDate DATETIME2
SET @DeleteOlderThanDate = DATEADD(d,-@DaysToKeep,GETUTCDATE())

IF NOT EXISTS(	SELECT 1
				FROM dbo.PartitionHelper PH 
				WHERE PH.TableName = @TableName
				AND PH.SchemaName = @SchemaName
)
BEGIN
	RAISERROR('Invalid table',11,1)
	RETURN
END

DECLARE @PartitionFunction SYSNAME
DECLARE @MaxPartition INT

/* Find oldest partition we can remove */
SELECT TOP(1) @MaxPartition=PH.partition_number,
		@PartitionFunction=PH.PartitionFunctionName
FROM dbo.PartitionHelper PH 
WHERE PH.TableName = @TableName
AND PH.SchemaName = @SchemaName
AND PH.UpperBound < @DeleteOlderThanDate
AND PH.UpperBound < DATEADD(d,-1,GETUTCDATE())
ORDER BY PH.partition_number DESC

IF @MaxPartition IS NULL
BEGIN
	PRINT 'Nothing to cleanup'
	RETURN
END

/* Truncate partitions */
DECLARE @SQL NVARCHAR(MAX)
SET @SQL = CONCAT('TRUNCATE TABLE ',@QualifiedTableName,' WITH(PARTITIONS (1 TO ', @MaxPartition, '))')

PRINT @SQL
EXEC sp_executesql @SQL

/* Remove partitions previously truncated */
DECLARE @lb DATETIME2
DECLARE @rows BIGINT
DECLARE cMerge CURSOR LOCAL FAST_FORWARD FOR 
	SELECT	LowerBound,
			rows
	FROM dbo.PartitionHelper PH 
	WHERE PH.TableName = @TableName
	AND PH.SchemaName = @SchemaName
	AND UpperBound < @DeleteOlderThanDate
	AND UpperBound < DATEADD(d,-1,GETUTCDATE())
	AND partition_number>1

OPEN cMerge
WHILE 1=1
BEGIN
	FETCH NEXT FROM cMerge INTO @lb,@rows
	IF @@FETCH_STATUS<> 0
		BREAK
	IF @rows >0
	BEGIN
		RAISERROR('Partition management error. Expected row count 0 before MERGE',11,1)
		RETURN
	END
	SET @SQL = CONCAT('ALTER PARTITION FUNCTION ',QUOTENAME(@PartitionFunction),'() MERGE RANGE (@lb);')
	EXEC sp_executesql @SQL,N'@lb DATETIME2',@lb
END

CLOSE cMerge
DEALLOCATE cMerge
GO
PRINT N'Creating Procedure [dbo].[PerformanceCounter_Get]...';


GO
CREATE PROC dbo.PerformanceCounter_Get(
	@InstanceID INT,
	@CounterID INT=NULL, /* Filter for a single CounterID. Overrides @CounterIDs if both provided. */
	@CounterIDs IDs READONLY, /* Filter for multiple CounterIDs. Leave @CounterID set to default value (NULL). */
	@FromDate DATETIME2(2),
	@ToDate DATETIME2(2),
	@DateGroupingMin INT=NULL,
	@Use60Min BIT=NULL,
	@DaysOfWeek IDs READONLY, /* e.g. exclude weekends:  Monday,Tuesday,Wednesday,Thursday,Friday. Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY, /* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)  */
	@UTCOffset INT=0 /* Used for filtering on hours & weekday in current timezone */
)
AS
SET DATEFIRST 1 /* Start week on Monday */
DECLARE @DateGroupingSQL NVARCHAR(MAX)
DECLARE @SQL NVARCHAR(MAX)
SELECT @DateGroupingSQL= CASE WHEN @DateGroupingMin = 0 OR @DateGroupingMin IS NULL THEN 'PC.SnapshotDate'
			ELSE 'DG.DateGroup' END

SELECT @Use60Min = CASE WHEN @DateGroupingMin>=60 THEN 1 ELSE 0 END

DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

SET @SQL = N'SELECT PC.CounterID,
       ' + @DateGroupingSQL + ' AS SnapshotDate,
       ' + CASE WHEN @Use60Min=1 THEN 'SUM(PC.Value_Total) AS Value_Total,
										MIN(PC.Value_Min) AS Value_Min,
										MAX(PC.Value_Max) AS Value_Max,
										SUM(PC.Value_Total)/SUM(PC.SampleCount*1.0) AS Value_Avg,
										SUM(PC.SampleCount) AS Value_SampleCount'
		ELSE  'SUM(PC.Value) AS Value_Total,
					MIN(PC.Value) AS Value_Min,
					MAX(PC.Value) AS Value_Max,
					AVG(PC.Value) AS Value_Avg,
					COUNT(*) AS Value_SampleCount'
	END + '
FROM ' + CASE WHEN @CounterID IS NOT NULL THEN '(SELECT @CounterID AS ID) T' ELSE '@CounterIDs T' END + '
INNER JOIN dbo.Counters C ON T.ID = C.CounterID
CROSS APPLY dbo.PerformanceCountersBetweenDates' + CASE WHEN @Use60Min=1 THEN '_60MIN' ELSE '' END + '(@FromDate,@ToDate,@InstanceID,C.CounterID,C.CounterType) PC
' + CASE WHEN @DateGroupingMin = 0 OR @DateGroupingMin IS NULL THEN '' ELSE 'CROSS APPLY dbo.DateGroupingMins(PC.SnapshotDate,@DateGroupingMin) DG' END + '
WHERE 1=1
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, PC.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, PC.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
GROUP BY ' + @DateGroupingSQL + ',PC.CounterID
ORDER BY SnapshotDate'

EXEC sp_executesql @SQL,
					N'@FromDate DATETIME2(2),
					@ToDate DATETIME2(2),
					@InstanceID INT,
					@CounterID INT,
					@DateGroupingMin INT,
					@UTCOffset INT,
					@CounterIDs IDs READONLY',
					@FromDate,
					@ToDate,
					@InstanceID,
					@CounterID,
					@DateGroupingMin,
					@UTCOffset,
					@CounterIDs
GO
PRINT N'Creating Procedure [dbo].[PerformanceCounters_60MIN_Del]...';


GO
CREATE PROC dbo.PerformanceCounters_60MIN_Del(
	@InstanceID INT,
	@DaysToKeep INT,
	@BatchSize INT=500000
)
AS
/* 
	Partitioning switching is used to efficiently remove data from this table for all instances.  
	This proc provides an alternative way to remove data associated with a specific instance.
*/
SET NOCOUNT ON
DECLARE @MaxDate DATETIME2(2)
SELECT @MaxDate = CASE WHEN @DaysToKeep  = 0 THEN '30000101' ELSE DATEADD(d,-@DaysToKeep,GETUTCDATE()) END

WHILE 1=1
BEGIN
	DELETE TOP(@BatchSize)  
	FROM dbo.PerformanceCounters_60MIN
	WHERE InstanceID = @InstanceID
	AND SnapshotDate < @MaxDate
	OPTION(RECOMPILE)

	IF @@ROWCOUNT < @BatchSize
		BREAK
END
GO
