PRINT N'Creating Procedure [dbo].[PerformanceCounters_Upd]...';


GO
CREATE   PROC dbo.PerformanceCounters_Upd(
	@InstanceID INT,
	@SnapshotDate DATETIME2(7),
	@PerformanceCounters dbo.PerformanceCounters READONLY,
	@Internal BIT=0
)
AS
SET XACT_ABORT ON
DECLARE @Ref NVARCHAR(128)='PerformanceCounters'

/* Insert any new performance counters into dbo.Counters table */
INSERT INTO dbo.Counters
(
    object_name,
    counter_name,
    instance_name
)
SELECT	RTRIM(object_name),
		RTRIM(counter_name),
		RTRIM(instance_name) 
FROM @PerformanceCounters
WHERE cntr_type <> 1073939712 /* PERF_LARGE_RAW_BASE.  Excluding this counter as it's just used in calculations for another counter */
EXCEPT 
SELECT	object_name,
		counter_name,
		instance_name 
FROM dbo.Counters WITH(UPDLOCK);

/* Associate performance counters collected with this SQL Instance */
INSERT INTO dbo.InstanceCounters(InstanceID,CounterID)
SELECT	@InstanceID,
		C.CounterID
FROM @PerformanceCounters pc 
JOIN dbo.Counters C ON C.counter_name = pc.counter_name 
					AND C.instance_name = pc.instance_name
					AND C.object_name = pc.object_name
EXCEPT 
SELECT	InstanceID,
		CounterID 
FROM dbo.InstanceCounters
WHERE InstanceID =@InstanceID;

/* Update the date of counter last collection for this SQL Instance */
UPDATE IC 
SET IC.UpdatedDate = @SnapshotDate
FROM dbo.InstanceCounters IC 
WHERE InstanceID = @InstanceID
AND EXISTS(	SELECT 1 
			FROM @PerformanceCounters pc 
			JOIN dbo.Counters C ON C.counter_name = pc.counter_name 
								AND C.instance_name = pc.instance_name 
								AND C.object_name = pc.object_name
			WHERE C.CounterID= IC.CounterID
			AND pc.cntr_type <> 1073939712 /* PERF_LARGE_RAW_BASE. Excluding this counter as it's just used in calculations for another counter  */
		)

DECLARE @PC TABLE(
	InstanceID INT NOT NULL,
	CounterID INT NOT NULL,
	SnapshotDate DATETIME2(2) NOT NULL,
	SnapshotDate60 DATETIME2(2) NOT NULL,
	Value DECIMAL (28, 9) NULL,
	PRIMARY KEY(InstanceID,CounterID,SnapshotDate)
) 

/* 
	Performance counter values require some calculation from the raw values collected based on the counter type.
	PERF_COUNTER_LARGE_RAWCOUNT can be used directly.
	PERF_LARGE_RAW_FRACTION needs to be divided by it's associated base counter.
	PERF_COUNTER_BULK_COUNT is a rate metric.  It needs to be subtracted from the previous collected value and divided by the number of seconds since the last collection.
	PERF_AVERAGE_BULK has an associated base counter.  The values of both counters are cumulative so you need to subtract the current value from the previous collected value.  The difference for PERF_AVERAGE_BULK is divided by the difference for it's associated base value.
	
	More details can be found here:
	https://techcommunity.microsoft.com/t5/sql-server-support-blog/interpreting-the-counter-values-from-sys-dm-os-performance/ba-p/317824
	
	Note: There is a CounterMapping table that associates the PERF_LARGE_RAW_FRACTION & PERF_AVERAGE_BULK counter types with the associated PERF_LARGE_RAW_BASE.  The naming of the base counter usually has the same name with " Base" appended, but this isn't consistent.
	Staging.PerformanceCounters holds the previous collected values
*/
INSERT INTO @PC
(
    InstanceID,
    CounterID,
    SnapshotDate,
	SnapshotDate60,
    Value
)
SELECT @InstanceID AS InstanceID,
	C.CounterID,
	B.SnapshotDate,
	DG.DateGroup, /* 60Min Date Grouping */
	CASE WHEN B.cntr_type = 65792  /* PERF_COUNTER_LARGE_RAWCOUNT - specific handling for Batch Resp Statistics.  This gives is number of batches by duration.  We don't want the total number - it's better to show the difference between the last collection */
			  AND B.object_name='Batch Resp Statistics' 
			  AND B.cntr_value >= A.cntr_value 
			  THEN B.cntr_value - A.cntr_value 
		WHEN B.cntr_type = 65792  /* PERF_COUNTER_LARGE_RAWCOUNT */
			AND B.object_name<>'Batch Resp Statistics' 
			THEN B.cntr_value 
		WHEN B.cntr_type = 272696576 /* PERF_COUNTER_BULK_COUNT */
			AND B.cntr_value>=A.cntr_value /* Sanity check: Current value should be larger than the previous value collected */
			THEN (B.cntr_value-A.cntr_value) / (DATEDIFF(ms,A.SnapshotDate,B.SnapshotDate)/1000.0)
		WHEN B.cntr_type=537003264 /* PERF_LARGE_RAW_FRACTION */
			THEN B.cntr_value*100.0 / NULLIF(Bbase.cntr_value,0)
		WHEN B.cntr_type=1073874176 /* PERF_AVERAGE_BULK */
			AND Bbase.cntr_value>=Abase.cntr_value /* Sanity check: Current value should be larger than the previous value collected */
			AND B.cntr_value>=A.cntr_value
			THEN ISNULL((B.cntr_value-A.cntr_value*1.0) / NULLIF(Bbase.cntr_value-Abase.cntr_value,0),0)
	ELSE NULL END AS Value
FROM @PerformanceCounters B /* B = Current Collection */
CROSS APPLY dbo.DateGroupingMins(B.SnapshotDate,60) DG /* Date groups of 60min intervals to be used for 60Min aggregate table insert later */
JOIN dbo.Counters C ON C.counter_name = B.counter_name AND C.object_name = B.object_name AND C.instance_name = B.instance_name
/* Map counters to the associated base counter */
LEFT JOIN dbo.CounterMapping M 	ON B.object_name = M.object_name 
								AND B.counter_name = M.counter_name 
								AND B.cntr_type IN(1073874176,	/* PERF_AVERAGE_BULK		*/
													537003264	/* PERF_LARGE_RAW_FRACTION	*/
													)  
/* Bbase = Current collection base counter */
LEFT JOIN @PerformanceCounters Bbase ON Bbase.object_name = M.object_name 
										AND Bbase.counter_name = M.base_counter_name 
										AND Bbase.instance_name = B.instance_name 
										AND Bbase.cntr_type=1073939712	/* PERF_LARGE_RAW_BASE		*/
										AND B.cntr_type IN(1073874176,	/* PERF_AVERAGE_BULK		*/
															537003264	/* PERF_LARGE_RAW_FRACTION	*/
															) 
/* A = Previous collection */
LEFT JOIN Staging.PerformanceCounters A ON A.object_name = b.object_name 
											AND A.counter_name = B.counter_name 
											AND A.instance_name = B.instance_name 
											AND B.cntr_type = A.cntr_type 
											AND A.InstanceID = @InstanceID
											AND A.SnapshotDate< B.SnapshotDate
/* ABase = Previous collection base counter */
LEFT JOIN Staging.PerformanceCounters Abase ON Abase.object_name = M.object_name 
											AND Abase.counter_name = M.base_counter_name 
											AND Abase.instance_name = B.instance_name 
											AND A.cntr_type = 1073874176	/* PERF_AVERAGE_BULK */
											AND Abase.InstanceID = @InstanceID 
											AND Abase.cntr_type=1073939712	/* PERF_LARGE_RAW_BASE */
											AND ABase.SnapshotDate <B.SnapshotDate
WHERE B.cntr_type IN(65792,		/*	PERF_COUNTER_LARGE_RAWCOUNT */
					272696576,	/*  PERF_COUNTER_BULK_COUNT		*/
					537003264,	/*  PERF_LARGE_RAW_FRACTION		*/
					1073874176	/*	PERF_LARGE_RAW_BASE			*/
					) 
AND NOT EXISTS(SELECT 1 
				FROM dbo.PerformanceCounters PC 
				WHERE PC.SnapshotDate = CAST(B.SnapshotDate as DATETIME2(2)) 
				AND PC.InstanceID = @InstanceID 
				AND PC.CounterID=C.CounterID
				)
AND (DATEDIFF(mi,A.SnapshotDate,B.SnapshotDate)< 1440 /* Don't insert if the time between collections is more than 1 day */
		OR A.SnapshotDate IS NULL /* OK to insert if there is no previous collection. e.g. PERF_COUNTER_LARGE_RAWCOUNT which doesn't require calculation */
		)
		
BEGIN TRAN

INSERT INTO dbo.PerformanceCounters
(
    InstanceID,
    CounterID,
    SnapshotDate,
    Value
)
SELECT PC.InstanceID,
       PC.CounterID,
	   PC.SnapshotDate,
       PC.Value	
FROM @PC PC
WHERE Value IS NOT NULL;

WITH T AS (
	SELECT PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate60,
		SUM(PC.Value) as Value_Total,
		MIN(PC.Value) as Value_Min,
		MAX(PC.Value) as Value_Max,
		COUNT(*) as SampleCount  
	FROM @PC PC
	WHERE PC.Value IS NOT NULL
	GROUP BY PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate60
)
UPDATE PC60
	SET PC60.Value_Total += T.Value_Total,
		PC60.Value_Min = CASE WHEN T.Value_Min < PC60.Value_Min THEN T.Value_Min ELSE PC60.Value_Min END,
		PC60.Value_Max = CASE WHEN T.Value_Max > PC60.Value_Max THEN T.Value_Max ELSE PC60.Value_Max END,
		PC60.SampleCount += T.SampleCount
FROM dbo.PerformanceCounters_60MIN PC60
JOIN T ON	T.InstanceID = PC60.InstanceID 
			AND T.CounterID = PC60.CounterID 
			AND T.SnapshotDate60 = PC60.SnapshotDate

INSERT INTO dbo.PerformanceCounters_60MIN
(
    InstanceID,
    CounterID,
    SnapshotDate,
    Value_Total,
    Value_Min,
    Value_Max,
    SampleCount
)
SELECT PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate60,
		SUM(PC.Value),
		MIN(PC.Value),
		MAX(PC.Value),
		COUNT(*)  
FROM @PC PC
WHERE Value IS NOT NULL
AND NOT EXISTS(	SELECT 1 
				FROM dbo.PerformanceCounters_60MIN PC60 
				WHERE PC60.InstanceID = PC.InstanceID 
				AND PC60.CounterID = PC.CounterID 
				AND PC60.SnapshotDate = PC.SnapshotDate60
				)
GROUP BY PC.InstanceID,
		PC.CounterID,
		PC.SnapshotDate60

IF @Internal=0
BEGIN

	DELETE Staging.PerformanceCounters 
	WHERE InstanceID = @InstanceID
	
	INSERT INTO Staging.PerformanceCounters(
		   InstanceID,
		   SnapshotDate,
		   object_name,
		   counter_name,
		   instance_name,
		   cntr_value,
		   cntr_type
		   )
	SELECT @InstanceID,
		   SnapshotDate,
		   object_name,
		   counter_name,
		   instance_name,
		   cntr_value,
		   cntr_type
	FROM @PerformanceCounters
	WHERE (cntr_type <> 65792 /* PERF_COUNTER_LARGE_RAWCOUNT.  Value used as is without any calculation required */
			OR object_name='Batch Resp Statistics' /* Batch Resp Statistics is a special case for PERF_COUNTER_LARGE_RAWCOUNT where we want the difference from the previous collection */
			)
END

COMMIT
IF @Internal=0
BEGIN
	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,
								 @Reference = @Ref,
								 @SnapshotDate = @SnapshotDate
END
GO
PRINT N'Creating Procedure [dbo].[PerformanceCounterSummary_Get]...';


GO
CREATE PROC dbo.PerformanceCounterSummary_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@TagIDs VARCHAR(MAX)=NULL,
	@Counters VARCHAR(MAX)=NULL,
	@InstanceID INT=NULL,
	@FromDate DATETIME2(2),
	@ToDate DATETIME2(2),
	@Search NVARCHAR(128)=NULL,
	@Use60Min BIT=NULL,
	@Debug BIT=0,
	@DaysOfWeek IDs READONLY, /* e.g. exclude weekends:  Monday,Tuesday,Wednesday,Thursday,Friday. Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY, /* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)  */
	@UTCOffset INT=0, /* Used for filtering on hours & weekday in current timezone */
	@ShowHidden BIT=1
)
AS
SET DATEFIRST 1 /* Start week on Monday */
IF @Use60Min IS NULL
BEGIN
	SELECT @Use60Min = CASE WHEN DATEDIFF(hh,@FromDate,@ToDate)>24 THEN 1
						WHEN DATEPART(mi,@FromDate)+DATEPART(s,@FromDate)+DATEPART(ms,@FromDate)=0 
							AND (DATEPART(mi,@ToDate)+DATEPART(s,@ToDate)+DATEPART(ms,@ToDate)=0 
									OR @ToDate>=DATEADD(s,-2,GETUTCDATE())
								)
						THEN 1
						ELSE 0 END
END

DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @SQL NVARCHAR(MAX) =N'
WITH T AS (
	SELECT IC.InstanceID,
			C.CounterID,
			C.object_name,
			C.counter_name,
			C.instance_name,
			' + CASE WHEN @Use60Min=1 THEN 'MAX(PC.Value_Max) AS MaxValue,
			MIN(PC.Value_Min) AS MinValue,
			SUM(PC.Value_Total)/SUM(PC.SampleCount*1.0) AS AvgValue,
			SUM(PC.Value_Total) AS TotalValue,
			SUM(SampleCount) as SampleCount,' 
			ELSE '
			MAX(PC.Value) AS MaxValue,
			MIN(PC.Value) AS MinValue,
			AVG(PC.Value) AS AvgValue,
			SUM(PC.Value) as TotalValue,
			COUNT(*) as SampleCount,' END + '
			(SELECT TOP(1) Value FROM dbo.PerformanceCountersBetweenDates(DATEADD(mi,-120,GETUTCDATE()),GETUTCDATE(),IC.InstanceID,C.CounterID,C.CounterType) LV WHERE LV.InstanceID = IC.InstanceID AND LV.CounterID = C.CounterID ORDER BY LV.SnapshotDate DESC) AS CurrentValue,
			COALESCE(IC.CriticalFrom,C.CriticalFrom,C.SystemCriticalFrom) AS CriticalFrom,
			COALESCE(IC.CriticalTo,C.CriticalTo,C.SystemCriticalTo) AS CriticalTo,
			COALESCE(IC.WarningFrom,C.WarningFrom,C.SystemWarningFrom) AS WarningFrom,
			COALESCE(IC.WarningTo,C.WarningTo,C.SystemWarningTo) AS WarningTo,
			COALESCE(IC.GoodFrom,C.GoodFrom,C.SystemGoodFrom) AS GoodFrom,
			COALESCE(IC.GoodTo,C.GoodTo,C.SystemGoodTo) AS GoodTo
	FROM dbo.InstanceCounters IC
	JOIN dbo.Instances I ON I.InstanceID = IC.InstanceID
	JOIN dbo.Counters C ON C.CounterID = IC.CounterID
	CROSS APPLY dbo.PerformanceCountersBetweenDates' + CASE WHEN @Use60Min=1 THEN '_60MIN' ELSE '' END + '(@FromDate,@ToDate,IC.InstanceID,C.CounterID,C.CounterType) PC 
	WHERE 1=1
	' + CASE WHEN @InstanceID IS NULL THEN '' ELSE 'AND IC.InstanceID = @InstanceID' END + '
	' + CASE WHEN @InstanceIDs IS NULL THEN '' ELSE 'AND EXISTS(SELECT * FROM STRING_SPLIT(@InstanceIDs,'','') ss WHERE IC.InstanceID = ss.Value)' END + '
	' + CASE WHEN @Counters IS NULL THEN '' ELSE 'AND EXISTS(SELECT * FROM STRING_SPLIT(@Counters,'','') ss WHERE IC.CounterID = ss.Value)' END + '
	' + CASE WHEN @TagIDs IS NULL THEN '' ELSE 'AND EXISTS(SELECT 1 FROM dbo.InstancesMatchingTags(@TagIDs) tg WHERE tg.InstanceID = IC.InstanceID)' END + '
	' + CASE WHEN @Search IS NULL THEN '' ELSE 'AND (C.object_name LIKE @Search
		OR C.instance_name LIKE @Search
		OR C.counter_name LIKE @Search
		)' END + '
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, PC.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, PC.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
	' + CASE WHEN @ShowHidden=1 THEN '' ELSE 'AND I.ShowInSummary=1' END + '
GROUP BY	C.CounterID,
			C.object_name,
			C.counter_name,
			C.instance_name,
			IC.InstanceID,
			C.CriticalFrom,
			C.CriticalTo,
			C.WarningFrom,
			C.WarningTo,
			C.GoodFrom,
			C.GoodTo,
			IC.CriticalFrom,
			IC.CriticalTo,
			IC.WarningFrom,
			IC.WarningTo,
			IC.GoodFrom,
			IC.GoodTo,
			C.SystemCriticalFrom,
			C.SystemCriticalTo,
			C.SystemWarningFrom,
			C.SystemWarningTo,
			C.SystemGoodFrom,
			C.SystemGoodTo,
			C.CounterType
)
SELECT *,
		CASE	WHEN MinValueStatus =1 OR MaxValueStatus =1 OR AvgValueStatus=1 OR CurrentValueStatus=1 THEN 1
				WHEN MinValueStatus =2 OR MaxValueStatus =2 OR AvgValueStatus=2 OR CurrentValueStatus=2 THEN 2
				WHEN MinValueStatus =4 OR MaxValueStatus =4 OR AvgValueStatus=4 OR CurrentValueStatus=4 THEN 4
				ELSE 3 END AS Status,
		CASE	WHEN MinValueStatus =1 OR MaxValueStatus =1 OR AvgValueStatus=1 OR CurrentValueStatus=1 THEN 1
				WHEN MinValueStatus =2 OR MaxValueStatus =2 OR AvgValueStatus=2 OR CurrentValueStatus=2 THEN 2
				WHEN MinValueStatus =4 OR MaxValueStatus =4 OR AvgValueStatus=4 OR CurrentValueStatus=4 THEN 4
				WHEN CriticalFrom IS NULL AND CriticalTo IS NULL
					AND WarningFrom IS NULL AND WarningTo IS NULL
					AND GoodFrom IS NULL AND GoodTo IS NULL THEN 6
				ELSE 5 END AS StatusSort
FROM T
OUTER APPLY (SELECT	CASE	WHEN T.MinValue >= T.CriticalFrom AND T.MinValue <= T.CriticalTo THEN 1 
							WHEN T.MinValue >= T.WarningFrom AND T.MinValue <= T.WarningTo THEN 2
							WHEN T.MinValue >= T.GoodFrom AND T.MinValue <= T.GoodTo THEN 4
							ELSE 3 END AS MinValueStatus,
					CASE	WHEN T.MaxValue >= T.CriticalFrom AND T.MaxValue <= T.CriticalTo THEN 1
							WHEN T.MaxValue >= T.WarningFrom AND T.MaxValue <= T.WarningTo THEN 2
							WHEN T.MaxValue >= T.GoodFrom AND T.MaxValue <= T.GoodTo THEN 4
							ELSE 3 END AS MaxValueStatus,
					CASE	WHEN T.AvgValue >= T.CriticalFrom AND T.AvgValue <= T.CriticalTo THEN 1
							WHEN T.AvgValue >= T.WarningFrom AND T.AvgValue <= T.WarningTo THEN 2
							WHEN T.AvgValue >= T.GoodFrom AND T.AvgValue <= T.GoodTo THEN 4
							ELSE 3 END AS AvgValueStatus,
					CASE	WHEN T.CurrentValue >= T.CriticalFrom AND T.CurrentValue <= T.CriticalTo THEN 1
							WHEN T.CurrentValue >= T.WarningFrom AND T.CurrentValue <= T.WarningTo THEN 2
							WHEN T.CurrentValue >= T.GoodFrom AND T.CurrentValue <= T.GoodTo THEN 4
							ELSE 3 END AS CurrentValueStatus
							) AS Calc
ORDER BY StatusSort,
		T.InstanceID,
		T.object_name,
		T.counter_name,
		T.instance_name;'


IF @Debug=1
BEGIN
	PRINT @SQL
END

EXEC sp_executesql @SQL,N'@InstanceID INT,
						@FromDate DATETIME2(2),
						@ToDate DATETIME2(2),
						@Search NVARCHAR(128)=NULL,
						@InstanceIDs VARCHAR(MAX),
						@Counters VARCHAR(MAX),
						@TagIDs VARCHAR(MAX),
						@UTCOffset INT',
						@InstanceID, 
						@FromDate, 
						@ToDate, 
						@Search,
						@InstanceIDs,
						@Counters,
						@TagIDs,
						@UTCOffset
GO
