PRINT N'Creating Procedure [dbo].[ResourceGovernorResourcePools_Get]...';


GO
CREATE PROC dbo.ResourceGovernorResourcePools_Get(
    @InstanceID INT,
    @FromDate  DATETIME,
    @ToDate    DATETIME
)
AS
WITH Metrics AS (
	SELECT  M.ResourcePoolID,
			SUM(M.diff_cpu_usage_ms*1.0) AS period_cpu_usage_ms,
			SUM(M.diff_cpu_usage_ms*1.0)/SUM(M.PeriodTimeMs) AS period_cpu_cores,
			SUM(M.diff_cpu_usage_ms*1.0/M.cpu_count)/SUM(M.PeriodTimeMs) AS period_cpu_percent,
			SUM(M.diff_cpu_usage_ms*1.0)/SUM(SUM(M.diff_cpu_usage_ms)) OVER() AS period_cpu_share_percent,      
			(SUM(M.diff_cpu_usage_ms*1.0/M.cpu_count)/SUM(M.PeriodTimeMs)) * 100.0 / NULLIF(MAX(M.cap_cpu_percent),0) AS cpu_cap_utilization_percent,
			-- Percentage of time CPU usage was at or above 95% of the cap (throttling indicator)
			SUM(CASE 
				WHEN (M.diff_cpu_usage_ms*1.0/M.cpu_count)/M.PeriodTimeMs * 100.0 >= (M.cap_cpu_percent * 0.95) 
				THEN M.PeriodTimeMs 
				ELSE 0 
			END) / NULLIF(SUM(M.PeriodTimeMs)*1.0, 0) AS cpu_cap_near_threshold_percent,
			SUM(M.diff_memgrant_count)/SUM(M.PeriodTimeMs/60000.0) AS period_memgrant_count_per_min,
			SUM(M.diff_memgrant_timeout_count)/SUM(M.PeriodTimeMs/60000.0) AS period_memgrant_timeout_count_per_min,
			SUM(M.diff_out_of_memory_count)/SUM(M.PeriodTimeMs/60000.0) AS period_out_of_memory_count_per_min,
			SUM(M.diff_read_io_queued)/SUM(M.PeriodTimeMs/60000.0) AS period_read_io_queued_per_min,
			SUM(M.diff_read_io_issued)/SUM(M.PeriodTimeMs/60000.0) AS period_read_io_issued_per_min,
			SUM(M.diff_read_io_completed)/SUM(M.PeriodTimeMs/60000.0) AS period_read_io_completed_per_min,
			SUM(M.diff_read_io_throttled)/SUM(M.PeriodTimeMs/60000.0) AS period_read_io_throttled_per_min,
			SUM(M.diff_read_bytes/POWER(1024.0,2))/SUM(M.PeriodTimeMs/1000.0) AS period_read_mb_per_sec,
			SUM(M.diff_read_io_stall_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_read_io_stall_ms_per_min,
			SUM(M.diff_read_io_stall_queued_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_read_io_stall_queued_ms_per_min,
			SUM(M.diff_write_io_queued)/SUM(M.PeriodTimeMs/60000.0) AS period_write_io_queued_per_min,
			SUM(M.diff_write_io_issued)/SUM(M.PeriodTimeMs/60000.0) AS period_write_io_issued_per_min,
			SUM(M.diff_write_io_completed)/SUM(M.PeriodTimeMs/60000.0) AS period_write_io_completed_per_min,
			SUM(M.diff_write_io_throttled)/SUM(M.PeriodTimeMs/60000.0) AS period_write_io_throttled_per_min,
			SUM(M.diff_write_bytes/POWER(1024.0,2))/SUM(M.PeriodTimeMs/1000.0) AS period_write_mb_per_sec,
			SUM(M.diff_write_io_stall_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_write_io_stall_ms_per_min,
			SUM(M.diff_write_io_stall_queued_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_write_io_stall_queued_ms_per_min,
			SUM(M.diff_io_issue_delay_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_io_issue_delay_ms_per_min,
			SUM(M.diff_io_issue_delay_non_throttled_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_io_issue_delay_non_throttled_ms_per_min,
			SUM(M.diff_cpu_delayed_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_cpu_delayed_ms_per_min,
			SUM(M.diff_cpu_active_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_cpu_active_ms_per_min,
			SUM(M.diff_cpu_violation_delay_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_cpu_violation_delay_ms_per_min,
			SUM(M.diff_cpu_violation_sec)/SUM(M.PeriodTimeMs/60000.0) AS period_cpu_violation_sec_per_min,
			SUM(M.diff_cpu_usage_preemptive_ms)/SUM(M.PeriodTimeMs/60000.0) AS period_cpu_usage_preemptive_ms_per_min
	FROM dbo.ResourceGovernorResourcePoolsMetrics M
	WHERE M.InstanceID = @InstanceID
	AND M.SnapshotDate >= @FromDate
	AND M.SnapshotDate < @ToDate
	GROUP BY M.ResourcePoolID
)
SELECT  RP.ResourcePoolID,
        RP.InstanceID,
        RP.SnapshotDate,
        RP.pool_id,
        RP.name,
        M.period_cpu_usage_ms,
        M.period_cpu_cores,
        M.period_cpu_percent,
        M.period_cpu_share_percent,
        M.cpu_cap_near_threshold_percent,
        M.period_memgrant_count_per_min,
        M.period_memgrant_timeout_count_per_min,
        M.period_out_of_memory_count_per_min,
        M.period_read_io_queued_per_min,
        M.period_read_io_issued_per_min,
        M.period_read_io_completed_per_min,
        M.period_read_io_throttled_per_min,
        M.period_read_mb_per_sec,
        M.period_read_io_stall_ms_per_min,
        M.period_read_io_stall_queued_ms_per_min,
        M.period_write_io_queued_per_min,
        M.period_write_io_issued_per_min,
        M.period_write_io_completed_per_min,
        M.period_write_io_throttled_per_min,
        M.period_write_mb_per_sec,
        M.period_write_io_stall_ms_per_min,
        M.period_write_io_stall_queued_ms_per_min,
        M.period_io_issue_delay_ms_per_min,
        M.period_io_issue_delay_non_throttled_ms_per_min,
        M.period_cpu_delayed_ms_per_min,
        M.period_cpu_active_ms_per_min,
        M.period_cpu_violation_delay_ms_per_min,
        M.period_cpu_violation_sec_per_min,
        M.period_cpu_usage_preemptive_ms_per_min,
        RP.statistics_start_time,
        RP.total_cpu_usage_ms,
        RP.cache_memory_kb,
        RP.compile_memory_kb,
        RP.used_memgrant_kb,
        RP.total_memgrant_count,
        RP.total_memgrant_timeout_count,
        RP.active_memgrant_count,
        RP.active_memgrant_kb,
        RP.memgrant_waiter_count,
        RP.max_memory_kb,
        RP.used_memory_kb,
        RP.target_memory_kb,
        RP.out_of_memory_count,
        RP.min_cpu_percent,
        RP.max_cpu_percent,
        RP.min_memory_percent,
        RP.max_memory_percent,
        RP.cap_cpu_percent,
        RP.min_iops_per_volume,
        RP.max_iops_per_volume,
        RP.read_io_queued_total,
        RP.read_io_issued_total,
        RP.read_io_completed_total,
        RP.read_io_throttled_total,
        RP.read_bytes_total,
        RP.read_io_stall_total_ms,
        RP.read_io_stall_queued_ms,
        RP.write_io_queued_total,
        RP.write_io_issued_total,
        RP.write_io_completed_total,
        RP.write_io_throttled_total,
        RP.write_bytes_total,
        RP.write_io_stall_total_ms,
        RP.write_io_stall_queued_ms,
        RP.io_issue_violations_total,
        RP.io_issue_delay_total_ms,
        RP.io_issue_delay_non_throttled_total_ms,
        RP.total_cpu_delayed_ms,
        RP.total_cpu_active_ms,
        RP.total_cpu_violation_delay_ms,
        RP.total_cpu_violation_sec,
        RP.total_cpu_usage_preemptive_ms
FROM dbo.ResourceGovernorResourcePools RP
LEFT JOIN Metrics M ON RP.ResourcePoolID = M.ResourcePoolID
WHERE RP.InstanceID = @InstanceID
GO
PRINT N'Creating Procedure [dbo].[ResourceGovernorResourcePools_Upd]...';


GO
CREATE PROC dbo.ResourceGovernorResourcePools_Upd(
	@ResourceGovernorResourcePools dbo.ResourceGovernorResourcePools READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(2)
)
AS
/*
	Note: matching is done on name rather than pool_id. The pool_id could change if the resource pool is dropped and recreated or if the instance associated with the ConnectionID changes (migrations, failover etc).
*/
SET NOCOUNT ON;
SET XACT_ABORT ON;
DECLARE @Ref VARCHAR(30) = 'ResourceGovernorResourcePools';
DECLARE @IntWrapValue BIGINT = 4294967296; /* 2^32: Used to handle INT counter wraparound when counters exceed max INT value */

IF NOT EXISTS (
	SELECT 1
	FROM dbo.CollectionDates
	WHERE SnapshotDate >= CAST(@SnapshotDate AS DATETIME2(2))
	  AND InstanceID = @InstanceID
	  AND Reference = @Ref
)
BEGIN
	/* Insert new records into the Metrics table based on the difference between the current snapshot and the previous snapshot. */
	INSERT INTO dbo.ResourceGovernorResourcePoolsMetrics (
			InstanceID,
			ResourcePoolID,
			SnapshotDate,
			PeriodTimeMs,
			diff_cpu_usage_ms,
			diff_memgrant_count,
			diff_memgrant_timeout_count,
			diff_out_of_memory_count,
			diff_read_io_queued,
			diff_read_io_issued,
			diff_read_io_completed,
			diff_read_io_throttled,
			diff_read_bytes,
			diff_read_io_stall_ms,
			diff_read_io_stall_queued_ms,
			diff_write_io_queued,
			diff_write_io_issued,
			diff_write_io_completed,
			diff_write_io_throttled,
			diff_write_bytes,
			diff_write_io_stall_ms,
			diff_write_io_stall_queued_ms,
			diff_io_issue_violations,
			diff_io_issue_delay_ms,
			diff_io_issue_delay_non_throttled_ms,
			diff_cpu_delayed_ms,
			diff_cpu_active_ms,
			diff_cpu_violation_delay_ms,
			diff_cpu_violation_sec,
			diff_cpu_usage_preemptive_ms,
			cache_memory_kb,
			compile_memory_kb,
			used_memgrant_kb,	
			active_memgrant_count,
			active_memgrant_kb,
			memgrant_waiter_count,
			max_memory_kb,
			used_memory_kb,
			target_memory_kb,
			cpu_count,
			max_cpu_percent,
			cap_cpu_percent
	)
	SELECT	@InstanceID,
			RP.ResourcePoolID,
			T.SnapshotDate,
			DATEDIFF_BIG(ms,RP.SnapshotDate,T.SnapshotDate) AS PeriodTimeMs,
			T.total_cpu_usage_ms - RP.total_cpu_usage_ms AS diff_cpu_usage_ms,
			T.total_memgrant_count - RP.total_memgrant_count AS  diff_memgrant_count,
			T.total_memgrant_timeout_count - RP.total_memgrant_timeout_count AS  diff_memgrant_timeout_count,
			T.out_of_memory_count - RP.out_of_memory_count AS diff_out_of_memory_count,
			CASE WHEN T.read_io_queued_total >= RP.read_io_queued_total THEN T.read_io_queued_total - RP.read_io_queued_total ELSE CAST(T.read_io_queued_total AS BIGINT) - CAST(RP.read_io_queued_total AS BIGINT) + @IntWrapValue END AS diff_read_io_queued,
			CASE WHEN T.read_io_issued_total >= RP.read_io_issued_total THEN T.read_io_issued_total - RP.read_io_issued_total ELSE CAST(T.read_io_issued_total AS BIGINT) - CAST(RP.read_io_issued_total AS BIGINT) + @IntWrapValue END AS diff_read_io_issued,
			CASE WHEN T.read_io_completed_total >= RP.read_io_completed_total THEN T.read_io_completed_total - RP.read_io_completed_total ELSE CAST(T.read_io_completed_total AS BIGINT) - CAST(RP.read_io_completed_total AS BIGINT) + @IntWrapValue END AS diff_read_io_completed,
			CASE WHEN T.read_io_throttled_total >= RP.read_io_throttled_total THEN T.read_io_throttled_total - RP.read_io_throttled_total ELSE CAST(T.read_io_throttled_total AS BIGINT) - CAST(RP.read_io_throttled_total AS BIGINT) + @IntWrapValue END AS diff_read_io_throttled,
			T.read_bytes_total - RP.read_bytes_total AS diff_read_bytes,
			T.read_io_stall_total_ms - RP.read_io_stall_total_ms AS diff_read_io_stall_ms,
			T.read_io_stall_queued_ms - RP.read_io_stall_queued_ms AS diff_read_io_stall_queued_ms,
			CASE WHEN T.write_io_queued_total >= RP.write_io_queued_total THEN T.write_io_queued_total - RP.write_io_queued_total ELSE CAST(T.write_io_queued_total AS BIGINT) - CAST(RP.write_io_queued_total AS BIGINT) + @IntWrapValue END AS diff_write_io_queued,
			CASE WHEN T.write_io_issued_total >= RP.write_io_issued_total THEN T.write_io_issued_total - RP.write_io_issued_total ELSE CAST(T.write_io_issued_total AS BIGINT) - CAST(RP.write_io_issued_total AS BIGINT) + @IntWrapValue END AS diff_write_io_issued,
			CASE WHEN T.write_io_completed_total >= RP.write_io_completed_total THEN T.write_io_completed_total - RP.write_io_completed_total ELSE CAST(T.write_io_completed_total AS BIGINT) - CAST(RP.write_io_completed_total AS BIGINT) + @IntWrapValue END AS diff_write_io_completed,
			CASE WHEN T.write_io_throttled_total >= RP.write_io_throttled_total THEN T.write_io_throttled_total - RP.write_io_throttled_total ELSE CAST(T.write_io_throttled_total AS BIGINT) - CAST(RP.write_io_throttled_total AS BIGINT) + @IntWrapValue END AS diff_write_io_throttled,
			T.write_bytes_total - RP.write_bytes_total AS diff_write_bytes,
			T.write_io_stall_total_ms - RP.write_io_stall_total_ms AS diff_write_io_stall_ms,
			T.write_io_stall_queued_ms - RP.write_io_stall_queued_ms AS diff_write_io_stall_queued_ms,
			CASE WHEN T.io_issue_violations_total >= RP.io_issue_violations_total THEN T.io_issue_violations_total - RP.io_issue_violations_total ELSE CAST(T.io_issue_violations_total AS BIGINT) - CAST(RP.io_issue_violations_total AS BIGINT) + @IntWrapValue END AS diff_io_issue_violations,
			T.io_issue_delay_total_ms - RP.io_issue_delay_total_ms AS diff_io_issue_delay_ms,
			T.io_issue_delay_non_throttled_total_ms - RP.io_issue_delay_non_throttled_total_ms AS diff_io_issue_delay_non_throttled_ms,
			T.total_cpu_delayed_ms - RP.total_cpu_delayed_ms AS diff_cpu_delayed_ms,
			T.total_cpu_active_ms - RP.total_cpu_active_ms AS diff_cpu_active_ms,
			T.total_cpu_violation_delay_ms - RP.total_cpu_violation_delay_ms AS diff_cpu_violation_delay_ms,
			T.total_cpu_violation_sec - RP.total_cpu_violation_sec AS diff_cpu_violation_sec,
			T.total_cpu_usage_preemptive_ms - RP.total_cpu_usage_preemptive_ms AS diff_cpu_usage_preemptive_ms,
			T.cache_memory_kb,
			T.compile_memory_kb,
			T.used_memgrant_kb,	
			T.active_memgrant_count,
			T.active_memgrant_kb,
			T.memgrant_waiter_count,
			T.max_memory_kb,
			T.used_memory_kb,
			T.target_memory_kb,
			I.cpu_count,
			T.max_cpu_percent,
			T.cap_cpu_percent
	FROM dbo.ResourceGovernorResourcePools RP
	JOIN @ResourceGovernorResourcePools T ON RP.name = T.name
	JOIN dbo.Instances I ON RP.InstanceID = I.InstanceID
	WHERE DATEDIFF_BIG(ms, RP.SnapshotDate, T.SnapshotDate) BETWEEN 0 AND 14400000 /* 4 hours in ms.  Skip recording if the gap between collections is too large. */
	AND RP.InstanceID = @InstanceID
	AND RP.statistics_start_time = T.statistics_start_time;

	/* Mark pools that no longer exist for the instance as deleted */
	UPDATE RP
		SET RP.IsActive = CAST(0 AS BIT)
	FROM  dbo.ResourceGovernorResourcePools RP
	WHERE RP.InstanceID = @InstanceID
	AND NOT EXISTS(SELECT 1 
					FROM  @ResourceGovernorResourcePools T 
					WHERE RP.name = T.name 
					)

	/* Update the current snapshot in the main table. */
	UPDATE RP
	SET		RP.SnapshotDate  = T.SnapshotDate,
			RP.pool_id = T.pool_id,
			RP.name = T.name,
			RP.statistics_start_time = T.statistics_start_time,
			RP.total_cpu_usage_ms = T.total_cpu_usage_ms,
			RP.cache_memory_kb = T.cache_memory_kb,
			RP.compile_memory_kb = T.compile_memory_kb,
			RP.used_memgrant_kb = T.used_memgrant_kb,
			RP.total_memgrant_count = T.total_memgrant_count,
			RP.total_memgrant_timeout_count = T.total_memgrant_timeout_count,
			RP.active_memgrant_count = T.active_memgrant_count,
			RP.active_memgrant_kb = T.active_memgrant_kb,
			RP.memgrant_waiter_count = T.memgrant_waiter_count,
			RP.max_memory_kb = T.max_memory_kb,
			RP.used_memory_kb = T.used_memory_kb,
			RP.target_memory_kb = T.target_memory_kb,
			RP.out_of_memory_count = T.out_of_memory_count,
			RP.min_cpu_percent = T.min_cpu_percent,
			RP.max_cpu_percent = T.max_cpu_percent,
			RP.min_memory_percent = T.min_memory_percent,
			RP.max_memory_percent = T.max_memory_percent,
			RP.cap_cpu_percent = T.cap_cpu_percent,
			RP.min_iops_per_volume = T.min_iops_per_volume,
			RP.max_iops_per_volume = T.max_iops_per_volume,
			RP.read_io_queued_total = T.read_io_queued_total,
			RP.read_io_issued_total = T.read_io_issued_total,
			RP.read_io_completed_total = T.read_io_completed_total,
			RP.read_io_throttled_total = T.read_io_throttled_total,
			RP.read_bytes_total = T.read_bytes_total,
			RP.read_io_stall_total_ms = T.read_io_stall_total_ms,
			RP.read_io_stall_queued_ms = T.read_io_stall_queued_ms,
			RP.write_io_queued_total = T.write_io_queued_total,
			RP.write_io_issued_total = T.write_io_issued_total,
			RP.write_io_completed_total = T.write_io_completed_total,
			RP.write_io_throttled_total = T.write_io_throttled_total,
			RP.write_bytes_total = T.write_bytes_total,
			RP.write_io_stall_total_ms = T.write_io_stall_total_ms,
			RP.write_io_stall_queued_ms = T.write_io_stall_queued_ms,
			RP.io_issue_violations_total = T.io_issue_violations_total,
			RP.io_issue_delay_total_ms = T.io_issue_delay_total_ms,
			RP.io_issue_delay_non_throttled_total_ms = T.io_issue_delay_non_throttled_total_ms,
			RP.total_cpu_delayed_ms = T.total_cpu_delayed_ms,
			RP.total_cpu_active_ms = T.total_cpu_active_ms,
			RP.total_cpu_violation_delay_ms = T.total_cpu_violation_delay_ms,
			RP.total_cpu_violation_sec = T.total_cpu_violation_sec,
			RP.total_cpu_usage_preemptive_ms = T.total_cpu_usage_preemptive_ms,
			RP.IsActive = CAST(1 AS BIT)
	FROM dbo.ResourceGovernorResourcePools RP
	JOIN @ResourceGovernorResourcePools T ON RP.name = T.name AND RP.InstanceID = @InstanceID;

	/* Insert new records for any resource pools that don't have a match in the main table. */
	INSERT INTO dbo.ResourceGovernorResourcePools (
			InstanceID,
			SnapshotDate,
			pool_id,
			name,
			statistics_start_time,
			total_cpu_usage_ms,
			cache_memory_kb,
			compile_memory_kb,
			used_memgrant_kb,
			total_memgrant_count,
			total_memgrant_timeout_count,
			active_memgrant_count,
			active_memgrant_kb,
			memgrant_waiter_count,
			max_memory_kb,
			used_memory_kb,
			target_memory_kb,
			out_of_memory_count,
			min_cpu_percent,
			max_cpu_percent,
			min_memory_percent,
			max_memory_percent,
			cap_cpu_percent,
			min_iops_per_volume,
			max_iops_per_volume,
			read_io_queued_total,
			read_io_issued_total,
			read_io_completed_total,
			read_io_throttled_total,
			read_bytes_total,
			read_io_stall_total_ms,
			read_io_stall_queued_ms,
			write_io_queued_total,
			write_io_issued_total,
			write_io_completed_total,
			write_io_throttled_total,
			write_bytes_total,
			write_io_stall_total_ms,
			write_io_stall_queued_ms,
			io_issue_violations_total,
			io_issue_delay_total_ms,
			io_issue_delay_non_throttled_total_ms,
			total_cpu_delayed_ms,
			total_cpu_active_ms,
			total_cpu_violation_delay_ms,
			total_cpu_violation_sec,
			total_cpu_usage_preemptive_ms,
			IsActive
	)
	SELECT	@InstanceID,
			SnapshotDate,
			pool_id,
			name,
			statistics_start_time,
			total_cpu_usage_ms,
			cache_memory_kb,
			compile_memory_kb,
			used_memgrant_kb,
			total_memgrant_count,
			total_memgrant_timeout_count,
			active_memgrant_count,
			active_memgrant_kb,
			memgrant_waiter_count,
			max_memory_kb,
			used_memory_kb,
			target_memory_kb,
			out_of_memory_count,
			min_cpu_percent,
			max_cpu_percent,
			min_memory_percent,
			max_memory_percent,
			cap_cpu_percent,
			min_iops_per_volume,
			max_iops_per_volume,
			read_io_queued_total,
			read_io_issued_total,
			read_io_completed_total,
			read_io_throttled_total,
			read_bytes_total,
			read_io_stall_total_ms,
			read_io_stall_queued_ms,
			write_io_queued_total,
			write_io_issued_total,
			write_io_completed_total,
			write_io_throttled_total,
			write_bytes_total,
			write_io_stall_total_ms,
			write_io_stall_queued_ms,
			io_issue_violations_total,
			io_issue_delay_total_ms,
			io_issue_delay_non_throttled_total_ms,
			total_cpu_delayed_ms,
			total_cpu_active_ms,
			total_cpu_violation_delay_ms,
			total_cpu_violation_sec,
			total_cpu_usage_preemptive_ms,
			CAST(1 AS BIT)
	FROM @ResourceGovernorResourcePools T
	WHERE NOT EXISTS (
		SELECT 1
		FROM dbo.ResourceGovernorResourcePools RP
		WHERE RP.name = T.name
		  AND RP.InstanceID = @InstanceID
	);

	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,
							   @Reference = @Ref,
							   @SnapshotDate = @SnapshotDate;
END;
GO
PRINT N'Creating Procedure [dbo].[ResourceGovernorResourcePoolsMetrics_Del]...';


GO
CREATE PROC dbo.ResourceGovernorResourcePoolsMetrics_Del(
	@InstanceID INT,
	@DaysToKeep INT,
	@BatchSize INT=50000
)
AS
/* 
	Partitioning switching is used to efficiently remove data from this table for all instances.  
	This proc provides an alternative way to remove data associated with a specific instance.
*/
SET NOCOUNT ON
DECLARE @MaxDate DATETIME2(2)
SELECT @MaxDate = CASE WHEN @DaysToKeep  = 0 THEN '30000101' ELSE DATEADD(d,-@DaysToKeep,GETUTCDATE()) END

WHILE 1=1
BEGIN
	DELETE TOP(@BatchSize)  
	FROM dbo.ResourceGovernorResourcePoolsMetrics
	WHERE InstanceID = @InstanceID
	AND SnapshotDate < @MaxDate
	OPTION(RECOMPILE)

	IF @@ROWCOUNT < @BatchSize
		BREAK
END
GO
PRINT N'Creating Procedure [dbo].[ResourceGovernorResourcePoolsMetrics_Get]...';


GO
CREATE PROC dbo.ResourceGovernorResourcePoolsMetrics_Get(
	@InstanceID INT,
	@FromDate DATETIME2(3)=NULL, /* UTC */
	@ToDate DATETIME2(3)=NULL, /* UTC */
	@DateGroupingMin INT=NULL, /* How many minutes to group by.  */
	@UTCOffset INT=0, /* Used for Hours filter */
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY, /* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
	@Debug BIT=0
)
AS
SET DATEFIRST 1 /* Start week on Monday */
IF @FromDate IS NULL
	SET @FromDate = DATEADD(mi,-60,GETUTCDATE())
IF @ToDate IS NULL
	SET @ToDate = GETUTCDATE()
DECLARE @SQL NVARCHAR(MAX)
DECLARE @DateGroupingSQL NVARCHAR(MAX)
SELECT @DateGroupingSQL= CASE WHEN @DateGroupingMin = 0 OR @DateGroupingMin IS NULL THEN 'M.SnapshotDate'
			ELSE 'DG.DateGroup' END

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

SET @SQL = N'
SELECT ' + @DateGroupingSQL + ' AS SnapshotDate,
		RP.name,
		SUM(M.diff_cpu_usage_ms*1.0) AS cpu_usage_ms,
		SUM(M.diff_cpu_usage_ms*1.0)/SUM(M.PeriodTimeMs) AS cpu_cores,
		SUM(M.diff_cpu_usage_ms*1.0/M.cpu_count)/SUM(M.PeriodTimeMs) AS cpu_percent,
		SUM(M.diff_cpu_usage_ms*1.0)/SUM(SUM(M.diff_cpu_usage_ms)) OVER(PARTITION BY ' + @DateGroupingSQL + ') AS cpu_share_percent,
		(SUM(M.diff_cpu_usage_ms*1.0/M.cpu_count)/SUM(M.PeriodTimeMs)) * 100.0 / NULLIF(MAX(M.cap_cpu_percent),0) AS cpu_cap_utilization_percent,
		SUM(CASE WHEN (M.diff_cpu_usage_ms*1.0/M.cpu_count)/M.PeriodTimeMs * 100.0 >= (M.cap_cpu_percent * 0.95) THEN M.PeriodTimeMs ELSE 0 END) / NULLIF(SUM(M.PeriodTimeMs)*1.0, 0) AS cpu_cap_near_threshold_percent,
		SUM(M.diff_memgrant_count)/SUM(M.PeriodTimeMs/60000.0) AS memgrant_count_per_min,
		SUM(M.diff_memgrant_timeout_count)/SUM(M.PeriodTimeMs/60000.0) AS memgrant_timeout_count_per_min,
		SUM(M.diff_out_of_memory_count)/SUM(M.PeriodTimeMs/60000.0) AS out_of_memory_count_per_min,
		SUM(M.diff_read_io_queued)/SUM(M.PeriodTimeMs/60000.0) AS read_io_queued_per_min,
		SUM(M.diff_read_io_issued)/SUM(M.PeriodTimeMs/60000.0) AS read_io_issued_per_min,
		SUM(M.diff_read_io_completed)/SUM(M.PeriodTimeMs/60000.0) AS read_io_completed_per_min,
		SUM(M.diff_read_io_throttled)/SUM(M.PeriodTimeMs/60000.0) AS read_io_throttled_per_min,
		SUM(M.diff_read_bytes/POWER(1024.0,2))/SUM(M.PeriodTimeMs/1000.0) AS read_mb_per_sec,
		SUM(M.diff_read_io_stall_ms)/SUM(M.PeriodTimeMs/60000.0) AS read_io_stall_ms_per_min,
		SUM(M.diff_read_io_stall_queued_ms)/SUM(M.PeriodTimeMs/60000.0) AS read_io_stall_queued_ms_per_min,
		SUM(M.diff_write_io_queued)/SUM(M.PeriodTimeMs/60000.0) AS write_io_queued_per_min,
		SUM(M.diff_write_io_issued)/SUM(M.PeriodTimeMs/60000.0) AS write_io_issued_per_min,
		SUM(M.diff_write_io_completed)/SUM(M.PeriodTimeMs/60000.0) AS write_io_completed_per_min,
		SUM(M.diff_write_io_throttled)/SUM(M.PeriodTimeMs/60000.0) AS write_io_throttled_per_min,
		SUM(M.diff_write_bytes/POWER(1024.0,2))/SUM(M.PeriodTimeMs/1000.0) AS write_mb_per_sec,
		SUM(M.diff_write_io_stall_ms)/SUM(M.PeriodTimeMs/60000.0) AS write_io_stall_ms_per_min,
		SUM(M.diff_write_io_stall_queued_ms)/SUM(M.PeriodTimeMs/60000.0) AS write_io_stall_queued_ms_per_min,
		SUM(M.diff_io_issue_delay_ms)/SUM(M.PeriodTimeMs/60000.0) AS io_issue_delay_ms_per_min,
		SUM(M.diff_io_issue_delay_non_throttled_ms)/SUM(M.PeriodTimeMs/60000.0) AS io_issue_delay_non_throttled_ms_per_min,
		SUM(M.diff_cpu_delayed_ms)/SUM(M.PeriodTimeMs/60000.0) AS cpu_delayed_ms_per_min,
		SUM(M.diff_cpu_active_ms)/SUM(M.PeriodTimeMs/60000.0) AS cpu_active_ms_per_min,
		SUM(M.diff_cpu_violation_delay_ms)/SUM(M.PeriodTimeMs/60000.0) AS cpu_violation_delay_ms_per_min,
		SUM(M.diff_cpu_violation_sec)/SUM(M.PeriodTimeMs/60000.0) AS cpu_violation_sec_per_min,
		SUM(M.diff_cpu_usage_preemptive_ms)/SUM(M.PeriodTimeMs/60000.0) AS cpu_usage_preemptive_ms_per_min
FROM dbo.ResourceGovernorResourcePoolsMetrics M 
JOIN dbo.ResourceGovernorResourcePools RP ON M.ResourcePoolID = RP.ResourcePoolID AND M.InstanceID = RP.InstanceID
' + CASE WHEN @DateGroupingMin IS NULL OR @DateGroupingMin= 0 THEN '' ELSE 'CROSS APPLY dbo.DateGroupingMins(M.SnapshotDate,@DateGroupingMin) DG' END + '
WHERE M.InstanceID = @InstanceID
AND M.SnapshotDate >= @FromDate
AND M.SnapshotDate < @ToDate
' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, M.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, M.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
GROUP BY ' + @DateGroupingSQL + ', RP.name
ORDER BY SnapshotDate'

IF @Debug = 1
BEGIN
	PRINT @SQL
END

EXEC sp_executesql @SQL,
				N'@InstanceID INT,
				@FromDate DATETIME2,
				@ToDate DATETIME2,
				@DateGroupingMin INT,
				@UTCOffset INT',
				@InstanceID,
				@FromDate,
				@ToDate,
				@DateGroupingMin,
				@UTCOffset
GO
PRINT N'Creating Procedure [dbo].[ResourceGovernorWorkloadGroups_Get]...';


