CREATE PROC dbo.SessionWaits_Del(
	@InstanceID INT,
	@DaysToKeep INT,
	@BatchSize INT=500000
)
AS
/* 
	Partitioning switching is used to efficiently remove data from this table for all instances.  
	This proc provides an alternative way to remove data associated with a specific instance.
*/
SET NOCOUNT ON
DECLARE @MaxDate DATETIME2(7)
SELECT @MaxDate = CASE WHEN @DaysToKeep  = 0 THEN '30000101' ELSE DATEADD(d,-@DaysToKeep,GETUTCDATE()) END

WHILE 1=1
BEGIN
	DELETE TOP(@BatchSize)  
	FROM dbo.SessionWaits
	WHERE InstanceID = @InstanceID
	AND SnapshotDateUTC < @MaxDate
	OPTION(RECOMPILE)

	IF @@ROWCOUNT < @BatchSize
		BREAK
END
GO
PRINT N'Creating Procedure [dbo].[SessionWaits_Get]...';


GO
CREATE PROC dbo.SessionWaits_Get(
	@InstanceID INT,
	@SnapshotDateUTC DATETIME2(7),
	@LoginTimeUTC DATETIME=NULL,
	@SessionID SMALLINT=NULL
)
AS
SELECT SW.session_id,
		WT.WaitType, 
		SW.waiting_tasks_count,
        SW.wait_time_ms,
        SW.max_wait_time_ms,
        SW.signal_wait_time_ms,
		SW.signal_wait_time_ms*1.0/ NULLIF(SW.wait_time_ms,0) AS signal_wait_pct,
        wait_time_ms*1.0/NULLIF(SUM(SW.wait_time_ms)OVER(),0) AS wait_pct
FROM dbo.SessionWaits SW
JOIN dbo.WaitType WT ON SW.WaitTypeID = WT.WaitTypeID
WHERE (SW.session_id=@SessionID OR @SessionID IS NULL)
AND SW.SnapshotDateUTC=@SnapshotDateUTC
AND (SW.login_time_utc = @LoginTimeUTC OR @LoginTimeUTC IS NULL)
AND SW.InstanceID = @InstanceID
AND EXISTS(SELECT 1 
		FROM dbo.RunningQueries Q 
		WHERE Q.SnapshotDateUTC = SW.SnapshotDateUTC 
		AND Q.session_id = SW.session_id
		AND Q.login_time_utc = SW.login_time_utc
		AND Q.InstanceID = SW.InstanceID
		)
ORDER BY SW.wait_time_ms DESC
GO
PRINT N'Creating Procedure [dbo].[SessionWaits_Upd]...';


GO
CREATE PROC dbo.SessionWaits_Upd(
	@SessionWaits dbo.SessionWaits READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(7)
)
AS
SET XACT_ABORT ON
DECLARE @Ref VARCHAR(30)='SessionWaits'
IF NOT EXISTS(SELECT 1 FROM dbo.CollectionDates WHERE SnapshotDate>=CAST(@SnapshotDate AS DATETIME2(2)) AND InstanceID = @InstanceID AND Reference=@Ref)
BEGIN
   IF EXISTS(  SELECT wait_type
			   FROM @SessionWaits
			   EXCEPT
			   SELECT WaitType 
			   FROM dbo.WaitType
			   )
   BEGIN
	   INSERT INTO dbo.WaitType
	   (
		   WaitType
	   )
	   SELECT wait_type
	   FROM @SessionWaits
	   EXCEPT
	   SELECT WaitType 
	   FROM dbo.WaitType WITH(UPDLOCK,HOLDLOCK)
   END

   INSERT INTO dbo.SessionWaits
   (
       SnapshotDateUTC,
       InstanceID,
       session_id,
       WaitTypeID,
       waiting_tasks_count,
       wait_time_ms,
       max_wait_time_ms,
       signal_wait_time_ms,
       login_time_utc
   )
   SELECT SW.SnapshotDateUTC,
		  @InstanceID,
          SW.session_id,
          WT.WaitTypeID,
          SW.waiting_tasks_count,
          SW.wait_time_ms,
          SW.max_wait_time_ms,
          SW.signal_wait_time_ms,
          SW.login_time_utc 
	FROM @SessionWaits SW
	JOIN dbo.WaitType WT ON SW.wait_type = WT.WaitType


	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										 @Reference = @Ref,
										 @SnapshotDate = @SnapshotDate;

END
GO
PRINT N'Creating Procedure [dbo].[SessionWaitsSummary_Get]...';


GO
CREATE PROC dbo.SessionWaitsSummary_Get(
	@InstanceID INT,
	@SnapshotDateUTC DATETIME2(7)
)
AS
SELECT WT.WaitType, 
		SUM(SW.waiting_tasks_count) AS waiting_tasks_count,
        SUM(SW.wait_time_ms) AS wait_time_ms,
        MAX(SW.max_wait_time_ms) AS max_wait_time_ms,
        SUM(SW.signal_wait_time_ms) AS signal_wait_time_ms,
		SUM(SW.signal_wait_time_ms*1.0)/ NULLIF(SUM(SW.wait_time_ms),0) AS signal_wait_pct,
        SUM(wait_time_ms)*1.0/NULLIF(SUM(SUM(SW.wait_time_ms)) OVER(),0) AS wait_pct
FROM dbo.SessionWaits SW
JOIN dbo.WaitType WT ON SW.WaitTypeID = WT.WaitTypeID
WHERE SW.SnapshotDateUTC=@SnapshotDateUTC
AND SW.InstanceID = @InstanceID
AND EXISTS(SELECT 1 
		FROM dbo.RunningQueries Q 
		WHERE Q.SnapshotDateUTC = SW.SnapshotDateUTC 
		AND Q.session_id = SW.session_id
		AND Q.login_time_utc = SW.login_time_utc
		AND Q.InstanceID = SW.InstanceID
		)
GROUP BY WT.WaitType
ORDER BY wait_time_ms DESC
GO
PRINT N'Creating Procedure [dbo].[Settings_Add]...';


GO
CREATE PROC Settings_Add(
	@Reset BIT = 0
)
AS
DECLARE @Defaults TABLE(
	SettingName VARCHAR(100) PRIMARY KEY,
	SettingValue SQL_VARIANT
)

INSERT INTO @Defaults(SettingName,SettingValue)
VALUES	('MemoryDumpCriticalThresholdHrs',48),
		('MemoryDumpWarningThresholdHrs',168),
		('CPUCriticalThreshold',90),
		('CPUWarningThreshold',75),
		('CPULowThreshold',50),
		('ReadLatencyCriticalThreshold',50),
		('ReadLatencyWarningThreshold',10),
		('ReadLatencyGoodThreshold',10),
		('WriteLatencyCriticalThreshold',50),
		('WriteLatencyWarningThreshold',10),
		('WriteLatencyGoodThreshold',10),
		('MinIOPsThreshold',100),
		('CriticalWaitCriticalThreshold',1000),
		('CriticalWaitWarningThreshold',10),
		('SummaryCacheDurationSec',300),
		('HardDeleteThresholdDays',NULL),
		('GUISummaryCacheDuration',NULL),
		('GUIDefaultCommandTimeout',NULL),
		('GUISummaryCommandTimeout',NULL),
		('GUIDrivePerformanceMaxDrives',NULL),
		('IdleWarningThresholdForSleepingSessionWithOpenTran',NULL),
		('IdleCriticalThresholdForSleepingSessionWithOpenTran',NULL),
		('GUICellToolTipMaxLength',NULL),
		('ExcludeClosedAlertsWithNotesFromPurge',CAST(1 AS BIT)),
		('InstanceMetadataTags','')

/* If reset, remove any customized settings to be re-inserted with defaults */
IF @Reset=1
BEGIN
	DELETE S 
	FROM dbo.Settings S
	WHERE EXISTS(SELECT 1 
				FROM @Defaults D 
				WHERE D.SettingName=S.SettingName
				)
END

INSERT INTO dbo.Settings(SettingName,SettingValue)
SELECT T.SettingName,T.SettingValue 
FROM @Defaults T
WHERE NOT EXISTS(
	SELECT 1 
	FROM dbo.Settings S 
	WHERE S.SettingName = T.SettingName
	)
AND T.SettingValue IS NOT NULL;

/* Other 'settings' that we just want to initialize to a date */
INSERT INTO dbo.Settings(SettingName,SettingValue)
SELECT SettingName,CAST('19000101' AS DATETIME) 
FROM (VALUES('PurgeCollectionErrorLog_StartDate'),
			('PurgeCollectionErrorLog_CompletedDate'),
			('PurgeQueryText_StartDate'),
			('PurgeQueryText_CompletedDate'),
			('PurgeQueryPlans_StartDate'),
			('PurgeQueryPlans_CompletedDate'),
			('PurgePartitions_StartDate'),
			('PurgePartitions_CompletedDate'),
			('MemoryDumpAckDate'),
			('PurgeBlockingSnapshotSummary_CompletedDate'),
			('PurgeBlockingSnapshotSummary_StartDate'),
			('PurgeClosedAlerts_StartDate'),
			('PurgeClosedAlerts_CompletedDate'),
			('PurgeOfflineInstances_StartDate'),
			('PurgeOfflineInstances_CompletedDate')
	  ) T(SettingName)
WHERE NOT EXISTS(SELECT 1 
				FROM dbo.Settings S
				WHERE S.SettingName=T.SettingName);
GO
