CREATE PROC dbo.SlowQueriesSummary_Get(
	@FromDate DATETIME2(3)=NULL,
	@ToDate DATETIME2(3)=NULL,
	@ObjectName SYSNAME=NULL,
	@ClientHostName NVARCHAR(128)=NULL,
	@ConnectionID SYSNAME=NULL,
	@ClientAppName SYSNAME=NULL,
	@InstanceIDs VARCHAR(MAX)=NULL,
	@DurationFromSec BIGINT=NULL,
	@DurationToSec BIGINT=NULL,
	@DurationFromMs BIGINT=NULL,
	@DurationToMs BIGINT=NULL,
	@GroupBy VARCHAR(50)='InstanceDisplayName',
	@Text NVARCHAR(MAX)=NULL,
	@DatabaseName SYSNAME=NULL,
	@UserName SYSNAME=NULL,
	@Result SYSNAME=NULL,
	@Top INT=20,
	@SessionID VARCHAR(MAX)=NULL, /* Comma-separated list supported */
	@InstanceDisplayName NVARCHAR(128)=NULL,
	@ExcludeClientAppName SYSNAME=NULL,
	@ExcludeClientHostName SYSNAME=NULL,
	@ExcludeDatabaseName SYSNAME=NULL,
	@ExcludeInstanceDisplayName NVARCHAR(128)=NULL,
	@ExcludeObjectName SYSNAME=NULL,
	@ExcludeResult SYSNAME=NULL,
	@ExcludeSessionID VARCHAR(MAX)=NULL, /* Comma-separated list supported */
	@ExcludeText NVARCHAR(MAX)=NULL,
	@ExcludeUserName SYSNAME=NULL,
	@CPUFromMs BIGINT=NULL,
	@CPUToMs BIGINT=NULL,
	@PhysicalReadsFrom BIGINT=NULL,
	@PhysicalReadsTo BIGINT=NULL,
	@LogicalReadsFrom BIGINT=NULL,
	@LogicalReadsTo BIGINT=NULL,
	@WritesFrom BIGINT=NULL,
	@WritesTo BIGINT=NULL,
	@EventType SYSNAME=NULL,
	@Debug BIT=0,
	@ShowHidden BIT=1,
	@Metric VARCHAR(50)='duration', /* duration or cpu_time */
	@ContextInfo VARBINARY(128)=NULL,
	@ExcludeContextInfo VARBINARY(128)=NULL,
	@WorkloadGroup NVARCHAR(128)=NULL,
	@ExcludeWorkloadGroup NVARCHAR(128)=NULL,
	@ResourcePool NVARCHAR(128)=NULL,
	@ExcludeResourcePool NVARCHAR(128)=NULL
)
AS
DECLARE @DurationFromUS BIGINT 
DECLARE @DurationToUS BIGINT
SELECT @DurationFromUS = (SELECT MAX(value) FROM (VALUES(@DurationFromSec*1000000),(@DurationFromMs*1000)) AS T(value)), 
	   @DurationToUS= (SELECT MIN(value) FROM (VALUES(@DurationToSec*1000000),(@DurationToMs*1000)) AS T(value))

IF @Metric NOT IN('duration','cpu_time')
BEGIN
	RAISERROR('Invalid @Metric value.  Valid options: duration, cpu_time',11,1);
	RETURN;
END

IF @FromDate IS NULL	
	SET @FromDate = DATEADD(mi,-60,GETUTCDATE())
IF @ToDate IS NULL	
	SET @ToDate = GETUTCDATE()
DECLARE @Instances IDs
IF @InstanceIDs IS NOT NULL
BEGIN
	INSERT INTO @Instances
	(
		ID
	)
	SELECT value
	FROM STRING_SPLIT(@InstanceIDs,',')
END;
SET @ExcludeSessionID = REPLACE(@ExcludeSessionID,' ','')
SET @SessionID = REPLACE(@SessionID,' ','')
SET @Text = REPLACE(REPLACE(REPLACE(@Text,'[','[[]'),'_','[_]'),'%','[%]') -- Like encode input

DECLARE @TimestampMins INT
DECLARE @TimestampOffset INT
IF @GroupBy LIKE 'timestamp%'
BEGIN
	SELECT	@TimestampMins = PARSENAME(@GroupBy,2), 
			@TimestampOffset = PARSENAME(@GroupBy,1),
			@GroupBy = 'timestamp'
END


DECLARE @GroupSQL NVARCHAR(MAX) = CASE @GroupBy WHEN 'ConnectionID' THEN 'I.ConnectionID' 
												WHEN 'client_hostname' THEN 'SQ.client_hostname'  
												WHEN 'username' THEN 'SQ.username'
												WHEN 'object_name' THEN 'SQ.object_name'
												WHEN 'client_app_name' THEN 'SQ.client_app_name'
												WHEN 'DatabaseName' THEN 'D.name'
												WHEN 'Result' THEN 'SQ.Result'
												WHEN 'text' THEN 'LEFT(SQ.text,1000)'
												WHEN 'session_id' THEN 'SQ.session_id'
												WHEN 'InstanceDisplayName' THEN 'I.InstanceDisplayName' 
												WHEN 'EventType' THEN 'SQ.event_type'
												WHEN 'timestamp' THEN 'DATEADD(MINUTE, (DATEDIFF(MINUTE, 0, DATEADD(mi,@TimestampOffset,SQ.timestamp)) / @TimeStampMins) * @TimeStampMins, 0)'
												WHEN 'context_info' THEN 'CONVERT(VARCHAR(258),SQ.context_info,1)'
												WHEN 'workload_group' THEN 'WG.name'
												WHEN 'resource_pool' THEN 'RP.name'
												ELSE 'InstanceDisplayName' END
IF @Top<=0
BEGIN
	SET @Top=NULL;
END
DECLARE @SQL NVARCHAR(MAX)
SET @SQL = 
N'SELECT ' + CASE WHEN @Top IS NOT NULL THEN 'TOP(@Top) ' ELSE '' END + @GroupSQL + ' as Grp,
		SUM(CASE WHEN {Metric}<5000000 THEN 1 ELSE 0 END) AS [<5 seconds], 
		SUM(CASE WHEN {Metric}>=5000000 AND {Metric} < 10000000 THEN 1 ELSE 0 END) AS [5-10 seconds], 
		SUM(CASE WHEN {Metric}>=10000000 AND {Metric} < 20000000 THEN 1 ELSE 0 END) AS [10-20 seconds], 
		SUM(CASE WHEN {Metric}>=20000000 AND {Metric} < 30000000 THEN 1 ELSE 0 END) AS [20-30 seconds], 
		SUM(CASE WHEN {Metric}>=30000000 AND {Metric}< 60000000 THEN 1 ELSE 0 END) AS [30-60 seconds], 
		SUM(CASE WHEN {Metric}>=60000000 AND {Metric} < 300000000 THEN 1 ELSE 0 END) AS [1-5 minutes], 
		SUM(CASE WHEN {Metric}>=300000000 AND {Metric} < 600000000 THEN 1 ELSE 0 END) AS [5-10 minutes], 
		SUM(CASE WHEN {Metric}>=600000000 AND {Metric} < 1800000000 THEN 1 ELSE 0 END) AS [10-30 minutes], 
		SUM(CASE WHEN {Metric}>=1800000000 AND {Metric} < 3600000000 THEN 1 ELSE 0 END) AS [30-60 minutes], 
		SUM(CASE WHEN {Metric}>=3600000000 THEN 1 ELSE 0 END) AS [1hr+], 
		COUNT(*) Total,
		SUM(CASE WHEN result <> ''0 - OK'' THEN 1 ELSE 0 END) AS FailedCount,
		SUM(Duration) as TotalDuration,
		SUM(cpu_time) as TotalCPU,
		SUM(logical_reads+Writes) as TotalIO,
		SUM(physical_reads+writes) as TotalPhysicalIO
FROM dbo.SlowQueries SQ
JOIN dbo.Instances I ON I.InstanceID = SQ.InstanceID
LEFT JOIN dbo.Databases D ON D.DatabaseID = SQ.DatabaseID
LEFT JOIN dbo.ResourceGovernorWorkloadGroups WG ON WG.WorkloadGroupID = SQ.WorkloadGroupID AND WG.InstanceID = SQ.InstanceID
LEFT JOIN dbo.ResourceGovernorResourcePools RP ON RP.ResourcePoolID = SQ.ResourcePoolID AND RP.InstanceID = SQ.InstanceID
WHERE timestamp>= @FromDate
AND timestamp< @ToDate
' + CASE WHEN @InstanceIDs IS NULL THEN '' ELSE 'AND EXISTS(SELECT 1 FROM @Instances IDs WHERE IDs.ID = SQ.InstanceID)' END + '
' + CASE WHEN @ObjectName IS NULL THEN '' WHEN @ObjectName LIKE '%[%]%' THEN 'AND SQ.object_name LIKE @ObjectName' ELSE 'AND SQ.object_name = @ObjectName' END +'
' + CASE WHEN @ClientHostName IS NULL THEN '' WHEN @ClientHostName LIKE '%[%]%' THEN 'AND SQ.client_hostname LIKE @ClientHostName' ELSE 'AND SQ.client_hostname = @ClientHostName' END +'
' + CASE WHEN @ConnectionID IS NULL THEN '' ELSE 'AND I.ConnectionID = @ConnectionID' END + '
' + CASE WHEN @InstanceDisplayName IS NULL THEN '' WHEN @InstanceDisplayName LIKE '%[%]%' THEN 'AND I.InstanceDisplayName LIKE @InstanceDisplayName'  ELSE 'AND I.InstanceDisplayName = @InstanceDisplayName' END + '
' + CASE WHEN @ClientAppName IS NULL THEN '' WHEN @ClientAppName LIKE '%[%]%' THEN 'AND SQ.client_app_name LIKE @ClientAppName' ELSE 'AND SQ.client_app_name = @ClientAppName' END + '
' + CASE WHEN @DurationFromUS IS NULL THEN '' ELSE 'AND SQ.Duration >= @DurationFrom' END + '
' + CASE WHEN @DurationToUS IS NULL THEN '' ELSE 'AND SQ.Duration < @DurationTo' END + '
' + CASE WHEN @Text IS NULL THEN '' ELSE 'AND SQ.Text LIKE ''%'' + @Text + ''%''' END + '
' + CASE WHEN @DatabaseName IS NULL THEN '' WHEN @DatabaseName LIKE '%[%]%' THEN 'AND D.name LIKE @DatabaseName' ELSE 'AND D.name = @DatabaseName' END + '
' + CASE WHEN @UserName IS NULL THEN '' WHEN @UserName LIKE '%[%]%'  THEN 'AND SQ.username LIKE @UserName' ELSE 'AND SQ.username = @UserName' END + '
' + CASE WHEN @Result IS NULL THEN '' WHEN @Result LIKE '%[%]%' THEN 'AND SQ.Result LIKE @Result' ELSE 'AND SQ.Result = @Result' END + '
' + CASE WHEN @SessionID IS NULL THEN '' WHEN @SessionID LIKE '%,%' THEN 'AND EXISTS(SELECT 1 FROM STRING_SPLIT(@SessionID,'','') SS WHERE CAST(SS.value AS INT) = SQ.session_id)' ELSE 'AND SQ.session_id = CAST(@SessionID AS INT)' END + '
' + CASE WHEN @ExcludeClientAppName IS NULL THEN '' WHEN @ExcludeClientAppName LIKE '%[%]%' THEN 'AND SQ.client_app_name NOT LIKE @ExcludeClientAppName' ELSE 'AND SQ.client_app_name <> @ExcludeClientAppName' END + '
' + CASE WHEN @ExcludeClientHostName IS NULL THEN '' WHEN @ExcludeClientHostName LIKE '%[%]%' THEN 'AND SQ.client_hostname NOT LIKE @ExcludeClientHostName'  ELSE 'AND SQ.client_hostname <> @ExcludeClientHostName' END + '
' + CASE WHEN @ExcludeDatabaseName IS NULL THEN '' WHEN @ExcludeDatabaseName LIKE '%[%]%' THEN 'AND D.name NOT LIKE @ExcludeDatabaseName' ELSE 'AND D.name <> @ExcludeDatabaseName' END + '
' + CASE WHEN @ExcludeInstanceDisplayName IS NULL THEN '' WHEN @ExcludeInstanceDisplayName LIKE '%[%]%' THEN 'AND I.InstanceDisplayName NOT LIKE @ExcludeInstanceDisplayName' ELSE 'AND I.InstanceDisplayName <> @ExcludeInstanceDisplayName' END + '
' + CASE WHEN @ExcludeObjectName IS NULL THEN '' WHEN @ExcludeObjectName LIKE '%[%]%' THEN 'AND SQ.object_name NOT LIKE @ExcludeObjectName' ELSE 'AND SQ.object_name <> @ExcludeObjectName' END + '
' + CASE WHEN @ExcludeResult IS NULL THEN '' WHEN @ExcludeResult LIKE '%[%]%' THEN 'AND SQ.Result NOT LIKE @ExcludeResult' ELSE 'AND SQ.Result <> @ExcludeResult' END + '
' + CASE WHEN @ExcludeSessionID IS NULL THEN '' WHEN @ExcludeSessionID LIKE '%,%' THEN 'AND NOT EXISTS(SELECT 1 FROM STRING_SPLIT(@ExcludeSessionID,'','') SS WHERE CAST(SS.value AS INT) = SQ.session_id)' ELSE 'AND SQ.session_id <> CAST(@ExcludeSessionID AS INT)' END + '
' + CASE WHEN @ExcludeText IS NULL THEN '' ELSE 'AND SQ.Text NOT LIKE ''%'' + @ExcludeText + ''%''' END + '
' + CASE WHEN @ExcludeUserName IS NULL THEN '' WHEN @ExcludeUserName LIKE '%[%]%' THEN 'AND SQ.username NOT LIKE @ExcludeUserName' ELSE 'AND SQ.username <> @ExcludeUserName' END + '
' + CASE WHEN @CPUFromMs IS NULL THEN '' ELSE 'AND SQ.cpu_time >= (@CPUFromMs*1000)' END + '
' + CASE WHEN @CPUToMs IS NULL THEN '' ELSE 'AND SQ.cpu_time < (@CPUToMs*1000)' END + '
' + CASE WHEN @PhysicalReadsFrom IS NULL THEN '' ELSE 'AND SQ.physical_reads >= @PhysicalReadsFrom' END + '
' + CASE WHEN @PhysicalReadsTo IS NULL THEN '' ELSE 'AND SQ.physical_reads < @PhysicalReadsTo' END + '
' + CASE WHEN @LogicalReadsFrom IS NULL THEN '' ELSE 'AND SQ.logical_reads >= @LogicalReadsFrom' END + '
' + CASE WHEN @LogicalReadsTo IS NULL THEN '' ELSE 'AND SQ.logical_reads < @LogicalReadsTo' END + '
' + CASE WHEN @WritesFrom IS NULL THEN '' ELSE 'AND SQ.writes >= @WritesFrom' END + '
' + CASE WHEN @WritesTo IS NULL THEN '' ELSE 'AND SQ.writes < @WritesTo' END + '
' + CASE WHEN @EventType IS NULL THEN '' ELSE 'AND SQ.event_type = @EventType' END + '
' + CASE WHEN @ShowHidden=1 THEN '' ELSE 'AND I.ShowInSummary=1' END + '
' + CASE WHEN @ContextInfo IS NULL THEN '' ELSE 'AND SQ.context_info = @ContextInfo' END + '
' + CASE WHEN @ExcludeContextInfo IS NULL THEN '' ELSE 'AND (SQ.context_info <> @ExcludeContextInfo OR SQ.context_info IS NULL)' END + '
' + CASE WHEN @WorkloadGroup IS NULL THEN '' ELSE 'AND WG.name = @WorkloadGroup' END + '
' + CASE WHEN @ExcludeWorkloadGroup IS NULL THEN '' ELSE 'AND WG.name <> @ExcludeWorkloadGroup' END + '
' + CASE WHEN @ResourcePool IS NULL THEN '' ELSE 'AND RP.name = @ResourcePool' END + '
' + CASE WHEN @ExcludeResourcePool IS NULL THEN '' ELSE 'AND RP.name <> @ExcludeResourcePool' END + '
GROUP BY ' + @GroupSQL +'
ORDER BY ' + CASE WHEN @GroupBy ='timestamp' THEN 'Grp DESC' ELSE 'SUM(Duration) DESC' END

SET @SQL = REPLACE(@SQL,'{Metric}',CASE WHEN @Metric = 'cpu_time' THEN 'cpu_time' ELSE 'Duration' END)

IF @Debug=1
	PRINT @SQL

EXEC sp_executesql @SQL,N'@Instances IDs READONLY,
						@ObjectName SYSNAME,
						@ClientHostName SYSNAME,
						@ConnectionID SYSNAME,
						@ClientAppName SYSNAME,
						@DurationFrom BIGINT,
						@DurationTo BIGINT,
						@Text NVARCHAR(MAX),
						@DatabaseName SYSNAME,
						@FromDate DATETIME2(3),
						@ToDate DATETIME2(3),
						@UserName SYSNAME,
						@Result SYSNAME,@Top INT,
						@SessionID VARCHAR(MAX),
						@InstanceDisplayName NVARCHAR(128),
						@ExcludeClientAppName SYSNAME,
						@ExcludeClientHostName SYSNAME,
						@ExcludeDatabaseName SYSNAME,
						@ExcludeInstanceDisplayName NVARCHAR(128),
						@ExcludeObjectName SYSNAME,
						@ExcludeResult SYSNAME,
						@ExcludeSessionID VARCHAR(MAX),
						@ExcludeText NVARCHAR(MAX),
						@ExcludeUserName SYSNAME,
						@CPUFromMs BIGINT,
						@CPUToMs BIGINT,
						@PhysicalReadsFrom BIGINT,
						@PhysicalReadsTo BIGINT,
						@LogicalReadsFrom BIGINT,
						@LogicalReadsTo BIGINT,
						@WritesFrom BIGINT,
						@WritesTo BIGINT,
						@EventType SYSNAME,
						@TimestampMins INT,
						@TimestampOffset INT,
						@ContextInfo VARBINARY(128),
						@ExcludeContextInfo VARBINARY(128),
						@WorkloadGroup NVARCHAR(128),
						@ExcludeWorkloadGroup NVARCHAR(128),
						@ResourcePool NVARCHAR(128),
						@ExcludeResourcePool NVARCHAR(128)',
						@Instances,
						@ObjectName,
						@ClientHostName,
						@ConnectionID,
						@ClientAppName,
						@DurationFromUS,
						@DurationToUS,
						@Text,
						@DatabaseName,
						@FromDate,
						@ToDate,
						@UserName,
						@Result,
						@Top,
						@SessionID,
						@InstanceDisplayName,
						@ExcludeClientAppName,
						@ExcludeClientHostName,
						@ExcludeDatabaseName,
						@ExcludeInstanceDisplayName,
						@ExcludeObjectName,
						@ExcludeResult,
						@ExcludeSessionID,
						@ExcludeText,
						@ExcludeUserName,
						@CPUFromMs,
						@CPUToMs,
						@PhysicalReadsFrom,
						@PhysicalReadsTo,
						@LogicalReadsFrom,
						@LogicalReadsTo,
						@WritesFrom,
						@WritesTo,
						@EventType,
						@TimestampMins,
						@TimestampOffset,
						@ContextInfo,
						@ExcludeContextInfo,
						@WorkloadGroup,
						@ExcludeWorkloadGroup,
						@ResourcePool,
						@ExcludeResourcePool
GO
PRINT N'Creating Procedure [dbo].[SQLPatching_Get]...';


GO
CREATE PROC dbo.SQLPatching_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@ShowHidden BIT=1
)
AS
DECLARE @Instances TABLE(
	InstanceID INT PRIMARY KEY
)
IF @InstanceIDs IS NULL
BEGIN
	INSERT INTO @Instances
	(
	    InstanceID
	)
	SELECT InstanceID 
	FROM dbo.Instances 
	WHERE IsActive=1
END 
ELSE 
BEGIN
	INSERT INTO @Instances
	(
		InstanceID
	)
	SELECT value
	FROM STRING_SPLIT(@InstanceIDs,',')
END;

SELECT	I.Instance,
		I.InstanceDisplayName,
		P.ChangedDate,
		P.OldVersion,
		NULLIF(P.NewVersion,P.OldVersion) NewVersion,
		P.OldProductLevel,
		NULLIF(P.NewProductLevel,P.OldProductLevel) NewProductLevel,
		P.OldProductUpdateLevel,
		NULLIF(P.NewProductUpdateLevel,P.OldProductUpdateLevel) NewProductUpdateLevel,
		P.OldEdition,
		NULLIF(P.NewEdition,P.OldEdition) NewEdition
FROM dbo.SQLPatchingHistory P
JOIN dbo.Instances I ON I.InstanceID = P.InstanceID
WHERE EXISTS(SELECT 1 FROM @Instances I WHERE I.InstanceID = P.InstanceID)
AND (I.ShowInSummary=1 OR @ShowHidden=1)
ORDER BY P.ChangedDate DESC
GO
PRINT N'Creating Procedure [dbo].[Summary_Upd]...';


GO
CREATE PROC dbo.Summary_Upd
AS
/* 
	Updates dbo.Summary table used by Summary_Get
*/
SET NOCOUNT ON
SET XACT_ABORT ON

DECLARE @ErrorsFrom DATETIME
DECLARE @MemoryDumpWarningThresholdHrs INT 
DECLARE @MemoryDumpCriticalThresholdHrs INT
DECLARE @MemoryDumpAckDate DATETIME

SELECT @ErrorsFrom=CONVERT(DATETIME,SettingValue)
FROM dbo.Settings 
WHERE SettingName = 'ErrorAckDate';

EXEC dbo.MemoryDumpThresholds_Get @MemoryDumpWarningThresholdHrs=@MemoryDumpWarningThresholdHrs OUT,
									@MemoryDumpCriticalThresholdHrs =@MemoryDumpCriticalThresholdHrs OUT,
									@MemoryDumpAckDate=@MemoryDumpAckDate OUT

SET @ErrorsFrom = CASE WHEN @ErrorsFrom > DATEADD(d,-1,GETUTCDATE()) THEN @ErrorsFrom ELSE DATEADD(d,-1,GETUTCDATE())  END;

SELECT	InstanceID,
		MIN(Status) AS LogShippingStatus
INTO #LogShippingStatus
FROM dbo.LogShippingStatus L
WHERE Status<>3
GROUP BY InstanceID

SELECT InstanceID,
		MIN(NULLIF(FullBackupStatus,3)) AS FullBackupStatus,
		MIN(NULLIF(LogBackupStatus,3)) AS LogBackupStatus,
		MIN(NULLIF(DiffBackupStatus,3)) AS DiffBackupStatus
INTO #BackupStatus
FROM dbo.BackupStatus BS
GROUP BY InstanceID

SELECT	InstanceID, 
		MIN(Status) AS DriveStatus
INTO #DriveStatus 
FROM dbo.DriveStatus D
WHERE Status<>3
GROUP BY InstanceID

SELECT InstanceID,
	MIN(CASE WHEN data_space_id <> 0 THEN NULLIF(FreeSpaceStatus,3) ELSE NULL END) AS FileFreeSpaceStatus,
	MIN(CASE WHEN data_space_id = 0 THEN NULLIF(FreeSpaceStatus,3) ELSE NULL END) AS LogFreeSpaceStatus,
	MIN(NULLIF(PctMaxSizeStatus,3)) AS PctMaxSizeStatus
INTO #FileGroupStatus
FROM dbo.FilegroupStatus F
GROUP BY InstanceID

SELECT InstanceID,
	MIN(JobStatus) AS JobStatus
INTO #JobStatus
FROM dbo.AgentJobStatus J
WHERE JobStatus<>3
AND enabled=1
GROUP BY InstanceID

SELECT D.InstanceID, 
	MIN(hadr.synchronization_health) AS synchronization_health
INTO #AGStatus
FROM dbo.DatabasesHADR hadr
JOIN dbo.Databases D ON D.DatabaseID = hadr.DatabaseID
GROUP BY D.InstanceID

SELECT I.InstanceID,
	MAX(DATEADD(mi,I.UTCOffset,c.UpdateDate)) AS DetectedCorruptionDateUtc,
	MIN(CASE WHEN c.CountOfRows>=1000 AND c.SourceTable=1 THEN 1 
			WHEN c.AckDate >=DATEADD(mi,I.UTCOffset,c.UpdateDate) THEN 5 ELSE 1 END) AS CorruptionStatus
INTO #CorruptionStatus
FROM dbo.Instances I
JOIN dbo.Databases D ON D.InstanceID = I.InstanceID
JOIN dbo.Corruption c ON D.DatabaseID = c.DatabaseID
WHERE I.IsActive=1
AND D.IsActive=1
GROUP BY I.InstanceID;

WITH err AS (
	SELECT InstanceID,
		ErrorSource,
		COUNT(*) cnt,
		MAX(ErrorDate) AS LastError
	FROM dbo.CollectionErrorLog E
	WHERE ErrorDate>=@ErrorsFrom
	AND ErrorContext NOT LIKE '%[[]Retry%]'
	AND NOT (ErrorSource='TableSize' AND ErrorMessage LIKE 'Warning%')
	GROUP BY InstanceID,ErrorSource
)
SELECT err.InstanceID, 
	SUM(err.cnt) CollectionErrorCount,
	MIN(x.SucceedAfterErrorCount) AS SucceedAfterErrorCount
INTO #CollectionErrorStatus
FROM err
CROSS APPLY(SELECT COUNT(*) SucceedAfterErrorCount
			FROM dbo.CollectionDates CD 
			WHERE CD.InstanceID = err.InstanceID 
			AND CD.Reference = err.ErrorSource
			AND CD.SnapshotDate>err.LastError
			) x
GROUP BY err.InstanceID

SELECT InstanceID,
	MIN(Status) AS CollectionDatesStatus,
	MAX(SnapshotAge) AS SnapshotAgeMax,
	MIN(SnapshotAge) AS SnapshotAgeMin,
	MIN(SnapshotDate) AS OldestSnapshot
INTO #CollectionStatus
FROM dbo.CollectionDatesStatus C
WHERE Status<>3
GROUP BY InstanceID

SELECT InstanceID,
	MIN(CASE WHEN Status = 3 THEN NULL ELSE Status END) AS LastGoodCheckDBStatus,
	SUM(CASE WHEN Status=1 THEN 1 ELSE 0 END) AS LastGoodCheckDBCriticalCount,
	SUM(CASE WHEN Status=2 THEN 1 ELSE 0 END) AS LastGoodCheckDBWarningCount,
	SUM(CASE WHEN Status=4 THEN 1 ELSE 0 END) AS LastGoodCheckDBHealthyCount,
	SUM(CASE WHEN Status=3 OR Status IS NULL THEN 1 ELSE 0 END) AS LastGoodCheckDBNACount,
	MIN(CASE WHEN Status=3 THEN NULL ELSE LastGoodCheckDbTime END) AS OldestLastGoodCheckDBTime,
	DATEDIFF(d,NULLIF(MIN(CASE WHEN Status <> 3 THEN LastGoodCheckDbTime ELSE NULL END),'1900-01-01'),GETUTCDATE()) AS DaysSinceLastGoodCheckDB
INTO #DBCCStatus
FROM dbo.LastGoodCheckDB LG
GROUP BY InstanceID

SELECT InstanceID,
	MAX(last_occurrence_utc) AS LastAlert,
	SUM(occurrence_count) AS TotalAlerts,
	MAX(CASE WHEN IsCriticalAlert=1 THEN last_occurrence_utc ELSE NULL END) AS LastCritical,
	COUNT(*) ConfiguredAlertCount,
	ISNULL(MIN(NULLIF(AlertStatus,3)),3) AS AlertStatus
INTO #AlertStatus
FROM dbo.SysAlerts A
GROUP BY InstanceID

SELECT cc.InstanceID, 
	MIN(cc.Status) AS Status
INTO #CustomChecksStatus
FROM dbo.CustomChecks cc
WHERE Status <> 3
GROUP BY cc.InstanceID

SELECT	DM.InstanceID,
	MIN(CASE WHEN DM.mirroring_state IN(4,6) AND DM.mirroring_witness_state IN(0,1) THEN 4 WHEN DM.mirroring_state IN(2,4,6) THEN 2 ELSE 1 END) AS MirroringStatus
INTO #MirroringStatus
FROM dbo.DatabaseMirroring DM 
GROUP BY DM.InstanceID

SELECT D.InstanceID,
	MIN(CASE WHEN QS.actual_state=3 THEN 1 
			WHEN QS.readonly_reason NOT IN(0,1,8) THEN 2
			WHEN QS.actual_state=2 THEN 4
			ELSE NULL END) AS QueryStoreStatus
INTO #QueryStoreStatus
FROM dbo.DatabaseQueryStoreOptions QS
JOIN dbo.Databases D ON QS.DatabaseID = D.DatabaseID
GROUP BY D.InstanceID

/* Get max % used for each instance */
SELECT	InstanceID,
		MIN(NULLIF(IdentityStatus,3)) AS IdentityStatus,
		MAX(pct_used) AS MaxIdentityPctUsed,
		MIN(estimated_days) AS MinIdentityEstimatedDays
INTO #IdentityStatus
FROM dbo.IdentityColumnsInfo I
GROUP BY InstanceID
UNION ALL
/* Show status 4 (OK) if we have collected data for a instance but we don't have rows in IdentityColumns table.  (No identity columns have hit the collection threshold) */
SELECT InstanceID,
		4 AS IdentityStatus,
		NULL AS MaxIdentityPctUsed,
		NULL AS MinIdentityEstimatedDays
FROM dbo.CollectionDatesStatus CD
WHERE Reference='IdentityColumns'
AND Status=4
AND NOT EXISTS(SELECT 1 
				FROM dbo.IdentityColumns IC
				WHERE IC.InstanceID=CD.InstanceID
				)

SELECT	InstanceID, 
		1 AS DatabaseStateStatus 
INTO #DatabaseStateStatus
FROM dbo.Databases D
WHERE IsActive = 1
AND state IN(3,4,5) /* Recovery Pending, Suspect, Emergency */
GROUP BY InstanceID

SELECT	EPS.InstanceID,
		MIN(NULLIF(EPS.ElasticPoolStorageStatus,3)) ElasticPoolStorageStatus
INTO #ElasticPoolStatus
FROM dbo.AzureDBElasticPoolStorageStatus EPS
GROUP BY EPS.InstanceID

SELECT I.InstanceID,
	I.Instance,
	I.InstanceGroupName,
	ISNULL(LS.LogShippingStatus,3) AS LogShippingStatus,
	ISNULL(B.FullBackupStatus,3) AS FullBackupStatus,
	ISNULL(B.LogBackupStatus,3) AS LogBackupStatus,
	ISNULL(B.DiffBackupStatus,3) AS DiffBackupStatus,
	ISNULL(D.DriveStatus,3) AS DriveStatus,
	ISNULL(F.FileFreeSpaceStatus,3) AS FileFreeSpaceStatus,
	ISNULL(F.LogFreeSpaceStatus,3) AS LogFreeSpaceStatus,
	ISNULL(J.JobStatus,3) AS JobStatus,
	CASE ag.synchronization_health WHEN 0 THEN 1 WHEN 1 THEN 2 WHEN 2 THEN 4 ELSE 3 END AS AGStatus,
	dc.DetectedCorruptionDateUtc,
	ISNULL(CorruptionStatus,4) AS CorruptionStatus,
	CASE WHEN  errSummary.SucceedAfterErrorCount=0 THEN 1 WHEN errSummary.CollectionErrorCount>0 THEN 2 ELSE 4 END AS CollectionErrorStatus,
	ISNULL(errSummary.CollectionErrorCount,0) AS CollectionErrorCount, 
	SSD.SnapshotAgeMin,
	SSD.SnapshotAgeMax,
	ISNULL(SSD.CollectionDatesStatus,3) AS SnapshotAgeStatus,
	DATEADD(mi,I.UTCOffset,I.sqlserver_start_time) AS sqlserver_start_time_utc,
	I.UTCOffset,
	DATEDIFF(mi,DATEADD(mi,I.UTCOffset,I.sqlserver_start_time),OSInfoCD.SnapshotDate) AS sqlserver_uptime,
	CASE WHEN UTT.UptimeWarningThreshold IS NULL AND UTT.UptimeCriticalThreshold IS NULL THEN 3
		WHEN I.UptimeAckDate > DATEADD(mi,I.UTCOffset,I.sqlserver_start_time) AND I.UptimeAckDate > ISNULL(LastOffline.LastFail,'19000101') THEN 4
		WHEN DATEDIFF(mi,DATEADD(mi,I.UTCOffset,I.sqlserver_start_time),OSInfoCD.SnapshotDate)<UTT.UptimeCriticalThreshold THEN 1
		WHEN DATEDIFF(mi,LastOffline.LastFail,GETUTCDATE()) < UTT.UptimeCriticalThreshold THEN 1
		WHEN DATEDIFF(mi,DATEADD(mi,I.UTCOffset,I.sqlserver_start_time),OSInfoCD.SnapshotDate)<UTT.UptimeWarningThreshold THEN 2
		WHEN DATEDIFF(mi,LastOffline.LastFail,GETUTCDATE()) <UTT.UptimeWarningThreshold THEN 2		
		ELSE 4 END AS UptimeStatus,
	UTT.UptimeWarningThreshold,
	UTT.UptimeCriticalThreshold,
	UTT.UptimeConfiguredLevel,
	DATEDIFF(mi,OSInfoCD.SnapshotDate,GETUTCDATE()) AS AdditionalUptime,
	I.ms_ticks/60000 AS host_uptime,
	DATEADD(s,-I.ms_ticks/1000,OSInfoCD.SnapshotDate) AS host_start_time_utc,
	I.MemoryDumpCount,
	I.LastMemoryDump,
	I.LastMemoryDumpUTC,
	CASE WHEN I.MemoryDumpCount=0 THEN 4 
		WHEN I.MemoryDumpCount IS NULL THEN 3 
		WHEN I.LastMemoryDump < @MemoryDumpAckDate THEN 4
		WHEN DATEDIFF(hh,I.LastMemoryDump,GETUTCDATE()) < @MemoryDumpCriticalThresholdHrs THEN 1 
		WHEN DATEDIFF(hh,I.LastMemoryDump,GETUTCDATE()) < @MemoryDumpWarningThresholdHrs THEN 2
		ELSE 4 END AS MemoryDumpStatus,
    ISNULL(dbc.LastGoodCheckDBStatus,3) LastGoodCheckDBStatus,
    dbc.LastGoodCheckDBCriticalCount,
    dbc.LastGoodCheckDBWarningCount,
    dbc.LastGoodCheckDBHealthyCount,
    dbc.LastGoodCheckDBNACount,
	dbc.OldestLastGoodCheckDBTime,
	dbc.DaysSinceLastGoodCheckDB,
	a.LastAlert,
	a.LastCritical,
	a.TotalAlerts,
	a.AlertStatus,
	AlertCD.SnapshotDate AS AlertSnapshotDate,
	CASE WHEN I.EngineEdition = 4 THEN NULL ELSE I.IsAgentRunning END AS IsAgentRunning,
	CASE WHEN AJT.AgentIsRunningCheck=0 THEN 3 WHEN I.EngineEdition = 4 THEN 3 WHEN I.IsAgentRunning = 1 THEN 4 ELSE 1 END AS IsAgentRunningStatus,
	ISNULL(cus.Status,3) AS CustomCheckStatus,
	ISNULL(dbm.MirroringStatus,3) AS MirroringStatus,
	3 AS ElasticPoolStorageStatus,
	ISNULL(F.PctMaxSizeStatus,3) AS PctMaxSizeStatus,
	ISNULL(QS.QueryStoreStatus,3) AS QueryStoreStatus,
	CASE I.DBMailStatus WHEN 'STARTED' THEN 4 WHEN 'STOPPED' THEN 1 ELSE 3 END AS DBMailStatus,
	I.DBMailStatus as DBMailStatusDescription,
	ISNULL(Ident.IdentityStatus,3) AS IdentityStatus,
	Ident.MaxIdentityPctUsed,
	I.ShowInSummary,
	~I.ShowInSummary IsHidden,
	ISNULL(DBState.DatabaseStateStatus,4) AS DatabaseStateStatus,
	GETUTCDATE() AS RefreshDate,
	CAST(0 AS BIT) AS IsAzure,
	Ident.MinIdentityEstimatedDays,
	CASE WHEN LastOffline.Iscurrent=1 THEN LastOffline.FirstFail ELSE NULL END AS OfflineSince,
	LastOffline.LastFail,
	OSInfoCD.SnapshotDate AS OSInfoSnapshotDate
INTO #Summary
FROM dbo.Instances I 
OUTER APPLY(
			SELECT ISNULL(
							(
							SELECT AJT.AgentIsRunningCheck
							FROM dbo.AgentJobThresholds AJT 
							WHERE AJT.InstanceID = I.InstanceID
							AND AJT.job_id = '00000000-0000-0000-0000-000000000000'
							),
							(
							SELECT AJT.AgentIsRunningCheck
							FROM dbo.AgentJobThresholds AJT 
							WHERE AJT.InstanceID = -1
							AND AJT.job_id = '00000000-0000-0000-0000-000000000000'
							)
						) AS AgentIsRunningCheck
			) AJT	
LEFT JOIN #LogShippingStatus LS ON I.InstanceID = LS.InstanceID
LEFT JOIN #BackupStatus B ON I.InstanceID = B.InstanceID
LEFT JOIN #DriveStatus D ON I.InstanceID = D.InstanceID
LEFT JOIN #FileGroupStatus F ON I.InstanceID = F.InstanceID
LEFT JOIN #JobStatus J ON I.InstanceID = J.InstanceID
LEFT JOIN #AGStatus ag ON I.InstanceID= ag.InstanceID
LEFT JOIN #CorruptionStatus dc ON I.InstanceID = dc.InstanceID
LEFT JOIN #CollectionErrorStatus errSummary ON I.InstanceID = errSummary.InstanceID
LEFT JOIN #CollectionStatus SSD ON I.InstanceID = SSD.InstanceID
LEFT JOIN #DBCCStatus dbc ON I.InstanceID = dbc.InstanceID
LEFT JOIN #AlertStatus a ON I.InstanceID = a.InstanceID 
LEFT JOIN dbo.CollectionDates OSInfoCD ON OSInfoCD.InstanceID = I.InstanceID AND OSInfoCD.Reference='OSInfo'
LEFT JOIN dbo.CollectionDates AlertCD ON AlertCD.InstanceID = I.InstanceID AND AlertCD.Reference='Alerts'
OUTER APPLY(SELECT TOP(1) IUT.WarningThreshold AS UptimeWarningThreshold,
                          IUT.CriticalThreshold AS UptimeCriticalThreshold,
						  CASE WHEN IUT.InstanceID =-1 THEN 'Root' ELSE 'Instance' END AS UptimeConfiguredLevel
			FROM dbo.InstanceUptimeThresholds IUT
			WHERE (IUT.InstanceID = I.InstanceID OR IUT.InstanceID=-1) 
			ORDER BY IUT.InstanceID DESC) UTT		
LEFT JOIN #CustomChecksStatus cus ON cus.InstanceID = I.InstanceID
LEFT JOIN #MirroringStatus dbm ON dbm.InstanceID = I.InstanceID
LEFT JOIN #QueryStoreStatus QS ON QS.InstanceID = I.InstanceID
LEFT JOIN #IdentityStatus Ident ON Ident.InstanceID = I.InstanceID
LEFT JOIN #DatabaseStateStatus DBState ON I.InstanceID = DBState.InstanceID
OUTER APPLY(
			SELECT TOP(1)	FirstFail,
							LastFail,
							IsCurrent
			FROM dbo.OfflineInstances OI
			WHERE OI.InstanceID = I.InstanceID
			ORDER BY OI.FirstFail DESC
) AS LastOffline
WHERE I.IsActive=1
AND I.EngineEdition<> 5 -- not azure
UNION ALL
SELECT I.InstanceID,
	I.Instance,
	I.InstanceGroupName,
	3 AS LogShippingStatus,
	3 AS FullBackupStatus,
	3 AS LogBackupStatus,
	3 AS DiffBackupStatus,
	3 AS DriveStatus,
	ISNULL(F.FileFreeSpaceStatus,3) AS FileFreeSpaceStatus,
	ISNULL(F.LogFreeSpaceStatus,3) AS LogFreeSpaceStatus,
	3 AS JobStatus,
	3 AS AGStatus,
	NULL AS DetectedCorruptionDateUtc,
	3 AS CorruptionStatus,
	CASE WHEN  errSummary.SucceedAfterErrorCount=0 THEN 1 WHEN errSummary.CollectionErrorCount>0 THEN 2 ELSE 4 END AS CollectionErrorStatus,
	ISNULL(errSummary.CollectionErrorCount,0) AS CollectionErrorCount,
	SSD.SnapshotAgeMin AS SnapshotAgeMin,
	SSD.SnapshotAgeMax AS SnapshotAgeMax,
	ISNULL(SSD.CollectionDatesStatus,3) AS SnapshotAgeStatus,
	NULL AS sqlserver_start_time_utc,
	0 AS UTCOffset,
	NULL AS sqlserver_uptime,
	3 AS UptimeStatus,
	NULL AS UptimeWarningThreshold,
	NULL AS UptimeCriticalThreshold,
	NULL AS UptimeConfiguredLevel,
	NULL AS AdditionalUptime,
	NULL AS host_uptime,
	NULL AS	host_start_time_utc,
	NULL AS MemoryDumpCount,
	NULL AS LastMemoryDump,
	NULL AS LastMemoryDumpUTC,
	3 AS MemoryDumpStatus,
    3 AS  LastGoodCheckDBStatus,
    NULL AS LastGoodCheckDBCriticalCount,
    NULL AS LastGoodCheckDBWarningCount,
    NULL AS LastGoodCheckDBHealthyCount,
    NULL AS LastGoodCheckDBNACount,
	NULL AS OldestLastGoodCheckDBTime,
	NULL AS DaysSinceLastGoodCheckDB,
	NULL AS LastAlert,
	NULL AS LastCritical,
	NULL AS TotalAlerts,
	3 AlertStatus,
	NULL AS AlertSnapshotDate,
	NULL AS IsAgentRunning,
	3 AS IsAgentRunningStatus,
	ISNULL(cus.Status,3) AS CustomCheckStatus,
	3 AS MirroringStatus,
	ISNULL(EPS.ElasticPoolStorageStatus,3) AS ElasticPoolStorageStatus,
	ISNULL(F.PctMaxSizeStatus,3) AS PctMaxSizeStatus,
	ISNULL(QS.QueryStoreStatus,3) AS QueryStoreStatus,
	3 AS DBMailStatus,
	NULL AS DBMailStatusDescription,
	ISNULL(Ident.IdentityStatus,3) IdentityStatus,
	Ident.MaxIdentityPctUsed AS MaxIdentityPctUsed,
	I.ShowInSummary,
	~I.ShowInSummary AS IsHidden,
	ISNULL(DBState.DatabaseStateStatus,4) AS DatabaseStateStatus,
	GETUTCDATE() AS RefreshDate,
	CAST(1 AS BIT) AS IsAzure,
	Ident.MinIdentityEstimatedDays,
	CASE WHEN LastOffline.Iscurrent=1 THEN LastOffline.FirstFail ELSE NULL END AS OfflineSince,
	LastOffline.FirstFail,
	CAST(NULL AS DATETIME2) AS OSInfoSnapshotDate 
FROM dbo.Instances I
LEFT JOIN #CollectionErrorStatus errSummary  ON I.InstanceID = errSummary.InstanceID
LEFT JOIN #FileGroupStatus F ON I.InstanceID = F.InstanceID
