GO
CREATE PROC dbo.TableSize_Get(
	@InstanceIDs IDs READONLY,
	@GrowthDays INT=30,
	@Top INT = 1000,
	@DatabaseID INT
)
AS
DECLARE @MinSnapshotDate DATETIME2
SELECT @MinSnapshotDate = DATEADD(d,-@GrowthDays,SYSUTCDATETIME());

WITH T AS (
	SELECT	TS.InstanceID,		
			TS.[SnapshotDate],
			TS.DatabaseID,
			TS.ObjectID,
			TS.[row_count],
			TS.[reserved_pages],
			TS.[used_pages],
			TS.[data_pages],
			TS.index_pages,
			RANK() OVER(PARTITION BY TS.ObjectID ORDER BY TS.SnapshotDate DESC) Latest,
			RANK() OVER(PARTITION BY TS.ObjectID ORDER BY TS.SnapshotDate ASC) Oldest
	FROM dbo.TableSize TS	
	WHERE EXISTS(SELECT 1
				FROM @InstanceIDs T
				WHERE T.ID = TS.InstanceID
				)
	AND TS.SnapshotDate>=@MinSnapshotDate
	AND (TS.DatabaseID = @DatabaseID OR @DatabaseID IS NULL)
	
)
SELECT TOP(@Top) 
	Latest.ObjectID,
	Latest.InstanceID,
	I.InstanceDisplayName AS Instance,
	Latest.[SnapshotDate],
	ISNULL(SSD.Status,3) AS SnapshotStatus,
	D.name AS [DB],
	O.SchemaName,
	O.ObjectName,
	Latest.row_count AS [Rows],
	Latest.reserved_pages*8 AS Reserved_KB,
	Latest.used_pages*8 as Used_KB,
	Latest.data_pages*8 Data_KB,
	(Latest.index_pages)*8 aS Index_KB,
	(Latest.row_count - Oldest.row_count)*1440.0 / NULLIF(DATEDIFF(mi,Oldest.SnapshotDate,Latest.SnapshotDate),0) AS Avg_Rows_Per_Day,
	(Latest.used_pages - Oldest.used_pages)*8*1440.0 / NULLIF(DATEDIFF(mi,Oldest.SnapshotDate,Latest.SnapshotDate),0) AS Avg_KB_Per_Day,
	NULLIF(DATEDIFF(mi,Oldest.SnapshotDate,Latest.SnapshotDate),0)/1440.0 AS CalcDays	
FROM T Latest
JOIN dbo.Instances I ON I.InstanceID = Latest.InstanceID
JOIN dbo.Databases D ON D.DatabaseID = Latest.DatabaseID
JOIN dbo.DBObjects O ON Latest.ObjectID = O.ObjectID AND O.DatabaseID = Latest.DatabaseID
LEFT HASH JOIN T Oldest ON Latest.InstanceID = Oldest.InstanceID AND Latest.DatabaseID = Oldest.DatabaseID AND Latest.ObjectID = Oldest.ObjectID AND Oldest.Oldest = 1
LEFT JOIN dbo.CollectionDatesStatus SSD ON SSD.InstanceID = Latest.InstanceID AND SSD.Reference='TableSize'
WHERE Latest.Latest = 1
AND D.IsActive=1
AND O.IsActive=1
AND I.IsActive=1
AND EXISTS(SELECT 1
				FROM @InstanceIDs T
				WHERE T.ID = I.InstanceID
				)
ORDER BY Latest.reserved_pages DESC
OPTION(RECOMPILE)
GO
PRINT N'Creating Procedure [dbo].[TableSize_Upd]...';


GO
CREATE PROCEDURE dbo.TableSize_Upd
(
	@InstanceID INT,
	@SnapshotDate DATETIME2,
	@TableSize TableSize READONLY
)
AS
SET XACT_ABORT ON
SET NOCOUNT ON
DECLARE @Ref VARCHAR(30)='TableSize'

UPDATE O
	SET O.IsActive = CAST(1 AS BIT)
FROM @TableSize t
JOIN dbo.Databases d ON t.DB = d.name AND D.InstanceID=@InstanceID
JOIN dbo.DBObjects O ON O.DatabaseID = d.DatabaseID 
						AND O.ObjectName = t.object_name 
						AND O.SchemaName = t.schema_name
						AND O.ObjectType = t.type
WHERE O.IsActive = CAST(0 AS BIT);

INSERT INTO dbo.DBObjects
(
    DatabaseID,
	ObjectName,
    object_id,
	ObjectType,
    SchemaName,
    IsActive
)
SELECT d.DatabaseID,
	t.object_name,
	t.object_id,
	t.type,
	t.schema_name,
	CAST(1 AS BIT)
FROM @TableSize t
JOIN dbo.Databases d ON t.DB = d.name AND D.InstanceID=@InstanceID
WHERE D.IsActive=1
AND NOT EXISTS(
				SELECT 1 
				FROM dbo.DBObjects O 
				WHERE O.DatabaseID = d.DatabaseID 
				AND O.ObjectName = t.object_name 
				AND O.SchemaName = t.schema_name
				AND O.ObjectType = t.type
			)
AND t.schema_name <> '{DBADashError}'
GROUP BY d.DatabaseID,
	t.object_name,
	t.type,
	t.schema_name,
	t.object_id;

INSERT INTO dbo.TableSize
(
	InstanceID,
	SnapshotDate,
	DatabaseID,
	ObjectID,
	row_count,
	reserved_pages,
	used_pages,
	data_pages
)
SELECT
	@InstanceID AS InstanceID,
	t.SnapshotDate,
	D.DatabaseID,
	O.ObjectID,
	t.row_count,
	t.reserved_pages,
	t.used_pages,
	t.data_pages
FROM @TableSize t
JOIN dbo.Databases D ON t.DB = D.name AND D.InstanceID = @InstanceID
JOIN dbo.DBObjects O ON O.SchemaName = t.schema_name 
					AND O.ObjectName = t.object_name 
					AND O.DatabaseID = D.DatabaseID 
					AND t.type = O.ObjectType
WHERE t.schema_name <> '{DBADashError}'
AND O.IsActive = CAST(1 AS BIT);

DECLARE @ExcludedDBs NVARCHAR(MAX)

SET @ExcludedDBs = STUFF(
	(
	SELECT ', ' + QUOTENAME(t.DB)
	FROM @TableSize t
	WHERE schema_name = '{DBADashError}'
	AND object_name = '{TableCountExceededThreshold}'
	ORDER BY t.DB
	FOR XML PATH(''),TYPE
	).value('.','NVARCHAR(MAX)'),
	1,2,'')

IF @ExcludedDBs IS NOT NULL
BEGIN
	INSERT INTO dbo.CollectionErrorLog(ErrorDate,InstanceID, ErrorSource, ErrorMessage, ErrorContext)
	SELECT @SnapshotDate,@InstanceID,'TableSize',CONCAT('Warning: ',@ExcludedDBs,' were excluded from TableSize collection due to table count threshold'),'Collect'
END

/* Log the data collection */
EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,
		@Reference = @Ref,
		@SnapshotDate = @SnapshotDate
GO
