GO
CREATE PROC dbo.Waits_Get(
	@InstanceID INT,
	@FromDate DATETIME2(2)=NULL, /* UTC */
	@ToDate DATETIME2(2)=NULL, /* UTC */
	@DateGroupingMin INT=NULL,
	@Top INT=10,
	@WaitType NVARCHAR(60)=NULL,
	@CriticalWaitsOnly BIT=0,
	@Use60MIN BIT=NULL,
	@WaitTypeID INT=NULL,
	@UTCOffset INT=0, /* Used for Hours filter */
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY/* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
)
AS
SET DATEFIRST 1 /* Start week on Monday */
SET NOCOUNT ON
IF @FromDate IS NULL
	SET @FromDate = DATEADD(mi,-60,GETUTCDATE())
IF @ToDate IS NULL
	SET @ToDate = GETUTCDATE()
DECLARE @SQL NVARCHAR(MAX)
DECLARE @DateGroupingSQL NVARCHAR(MAX)
DECLARE @DateGroupingJoin NVARCHAR(MAX)
DECLARE @SchedulerCount INT 

SELECT @SchedulerCount = I.scheduler_count
FROM dbo.Instances I WHERE I.InstanceID = @InstanceID

SELECT @DateGroupingSQL= CASE WHEN @DateGroupingMin IS NULL OR @DateGroupingMin=0 THEN 'W.SnapshotDate'
			ELSE 'DG.DateGroup' END,
		 @DateGroupingJoin = CASE WHEN @DateGroupingMin IS NULL OR @DateGroupingMin=0 THEN ''
			ELSE 'CROSS APPLY dbo.DateGroupingMins(W.SnapshotDate,@DateGroupingMin) DG' END 

IF @Use60MIN IS NULL
BEGIN
	SELECT @Use60MIN = CASE WHEN @DateGroupingMin<60 THEN 0
						WHEN DATEDIFF(hh,@FromDate,@ToDate)>24 THEN 1
						WHEN DATEPART(mi,@FromDate)+DATEPART(s,@FromDate)+DATEPART(ms,@FromDate)=0 
							AND (DATEPART(mi,@ToDate)+DATEPART(s,@ToDate)+DATEPART(ms,@ToDate)=0 
									OR @ToDate>=DATEADD(s,-2,GETUTCDATE())
								)
						THEN 1
						ELSE 0 END
END
IF @WaitType IS NOT NULL AND @WaitType NOT LIKE '%[%]%' AND @WaitTypeID IS NULL /* Filtering for a specific wait type - get the WaitTypeID */
BEGIN
	SELECT @WaitTypeID = WaitTypeID
	FROM dbo.WaitType 
	WHERE WaitType = @WaitType
END
IF @WaitTypeID IS NOT NULL /* Ignore @WaitType if we have @WaitTypeID */
BEGIN
	SET @WaitType = NULL
END

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

CREATE TABLE #WaitGrp(
	[Time] DATETIME2(2) NOT NULL,
	WaitTypeID SMALLINT NOT NULL,
	TotalWaitMs BIGINT NOT NULL,
	SignalWaitMs BIGINT NOT NULL,
	WaitingTasksCount BIGINT NOT NULL
)
CREATE TABLE #Time(
	[Time] DATETIME2(2) NOT NULL,
	SampleDurationMs BIGINT NULL
)
/* 
	Wait types with zero wait are not recorded so we use the max of the sample_ms_diff for each wait type/time, then sum for the date grouping.
*/
SET @SQL = '
WITH W AS (
	SELECT W.SnapshotDate,
			MAX(W.sample_ms_diff) AS sample_ms_diff
	FROM dbo.Waits' + CASE WHEN @Use60MIN =1 THEN '_60MIN' ELSE '' END + ' W 	
	WHERE W.SnapshotDate>= @FromDate
	AND W.SnapshotDate < @ToDate
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
	AND W.InstanceID=@InstanceID
	GROUP BY W.SnapshotDate
)
SELECT ' + @DateGroupingSQL + ' AS [Time],
			SUM(W.sample_ms_diff) AS SampleDurationMs
FROM W
' + @DateGroupingJoin + '
GROUP BY ' + @DateGroupingSQL 

INSERT INTO #Time
(
    Time,
    SampleDurationMs
)
EXEC sp_executesql @SQL,
				N'@FromDate DATETIME2(2),
				@ToDate DATETIME2(2),
				@InstanceID INT,
				@Top INT,
				@DateGroupingMin INT,
				@UTCOffset INT',
				@FromDate,
				@ToDate,
				@InstanceID,
				@Top,
				@DateGroupingMin,
				@UTCOffset;

DECLARE @TotalSampleDurationMs BIGINT 
SELECT @TotalSampleDurationMs = SUM(SampleDurationMs)
FROM #Time

SET @SQL = N'
SELECT ' + @DateGroupingSQL + ' AS [Time],
			W.WaitTypeID,
			SUM(W.wait_time_ms) AS TotalWaitMs,
			SUM(W.signal_wait_time_ms) AS SignalWaitMs,
			SUM(W.waiting_tasks_count) AS WaitingTasksCount
FROM dbo.Waits' + CASE WHEN @Use60MIN =1 THEN '_60MIN' ELSE '' END + ' W 
' + @DateGroupingJoin + '
JOIN dbo.WaitType WT ON WT.WaitTypeID = W.WaitTypeID
WHERE W.SnapshotDate>= @FromDate
AND W.SnapshotDate < @ToDate
AND W.InstanceID=@InstanceID
' + CASE WHEN @CriticalWaitsOnly=1 THEN 'AND WT.IsCriticalWait=1' ELSE '' END + '
' + CASE WHEN @WaitType IS NULL THEN '' ELSE 'AND WT.WaitType LIKE @WaitType' END + '
' + CASE WHEN @WaitTypeID IS NULL THEN '' ELSE 'AND WT.WaitTypeID = @WaitTypeID' END + '
' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
AND WT.IsExcluded = 0
GROUP BY W.WaitTypeID, ' + @DateGroupingSQL 

INSERT INTO #WaitGrp([Time],WaitTypeID,TotalWaitMs,SignalWaitMs,WaitingTasksCount)
EXEC sp_executesql @SQL,
					N'@FromDate DATETIME2(2),
					@ToDate DATETIME2(2),
					@InstanceID INT,
					@Top INT,
					@DateGroupingMin INT,
					@WaitType NVARCHAR(60),
					@WaitTypeID INT,
					@UTCOffset INT',
					@FromDate,
					@ToDate,
					@InstanceID,
					@Top,
					@DateGroupingMin,
					@WaitType,
					@WaitTypeID,
					@UTCOffset;

IF @WaitTypeID IS NOT NULL -- Filtering for a specific wait type
BEGIN
	/*	If a wait doesn't accumulate for a time period it won't be present.  
		This query will fill in the blanks with zeros when we are filtering for a specific wait type - otherwise the charts can look misleading.
	*/
	SELECT T.Time,
			WT.WaitType,
			ISNULL(W.TotalWaitMs/1000.0,0) AS TotalWaitSec,
			ISNULL(W.SignalWaitMs/1000.0,0) AS SignalWaitSec,
			ISNULL(W.SignalWaitMs*100.0/NULLIF(W.TotalWaitMs,0),0) AS SignalWaitPct,
			ISNULL(W.TotalWaitMs / (T.SampleDurationMs/1000.0),0) AS WaitTimeMsPerSec,
			ISNULL(W.SignalWaitMs / (T.SampleDurationMs/1000.0),0) AS SignalWaitMsPerSec,
			ISNULL(W.TotalWaitMs / (T.SampleDurationMs/1000.0) / @SchedulerCount,0) AS WaitTimeMsPerCorePerSec,
			ISNULL(W.SignalWaitMs / (T.SampleDurationMs/1000.0) / @SchedulerCount,0) AS SignalWaitMsPerCorePerSec,
			T.SampleDurationMs /1000 SampleDurationSec,
			W.TotalWaitMs*1.0 /ISNULL(NULLIF(W.WaitingTasksCount,0),1)  AS AvgWaitTimeMs,
			ISNULL(W.WaitingTasksCount,0) AS WaitingTasksCount,
			@SchedulerCount AS SchedulerCount,
			@TotalSampleDurationMs/1000.0 TotalSampleDurationSec,
			0 AS rnk
	FROM #Time T
	CROSS JOIN dbo.WaitType WT 
	LEFT JOIN #WaitGrp W ON W.Time = T.Time AND WT.WaitTypeID = W.WaitTypeID
	WHERE		WT.WaitTypeID = @WaitTypeID
	ORDER BY	WT.WaitType,
				T.Time
END;
ELSE
BEGIN
	/* 
		Show the top waits and group other waits as "{Other}"
		Previously calculated as top N waits for each time period.  Changed to calculate top waits overall for better consistency.  
		e.g. If a wait type is included - you see all waits for that wait type.  It won't sometimes be included in {Other}
		App based calculations can then match WaitsSummary_Get
	*/
	WITH G AS ( /* Calculate total wait for each wait type */
		SELECT *,SUM(T1.TotalWaitMs) OVER(PARTITION BY T1.WaitTypeID) AS Summary_TotalWaitMs
		FROM #WaitGrp T1
	)
	, W AS ( /* Rank the wait types by total wait for entire period.  */
		SELECT *,DENSE_RANK() OVER(ORDER BY G.Summary_TotalWaitMs DESC) rnk
		FROM G
	)
	SELECT	T.[Time],
			CASE WHEN W.rnk> @Top THEN '{Other}' WHEN WT.IsCriticalWait=1 THEN '!!'  + WT.WaitType ELSE WT.WaitType END as WaitType,
			CAST(MAX(CASE WHEN W.rnk> @Top THEN 0 ELSE CAST(WT.IsCriticalWait AS INT) END) AS BIT) AS IsCriticalWait,
			SUM(W.TotalWaitMs)/1000.0 AS TotalWaitSec,
			SUM(W.SignalWaitMs)/1000.0 AS SignalWaitSec,
			SUM(W.SignalWaitMs)*100.0 / NULLIF(SUM(W.TotalWaitMs),0) AS SignalWaitPct,
			SUM(W.TotalWaitMs) / MAX(T.SampleDurationMs/1000.0) AS WaitTimeMsPerSec,
			SUM(W.SignalWaitMs) / MAX(T.SampleDurationMs/1000.0) AS SignalWaitMsPerSec,
			SUM(W.TotalWaitMs) / MAX(T.SampleDurationMs/1000.0) / @SchedulerCount AS WaitTimeMsPerCorePerSec,
			SUM(W.SignalWaitMs) / MAX(T.SampleDurationMs/1000.0) / @SchedulerCount AS SignalWaitMsPerCorePerSec,
			MAX(T.SampleDurationMs) /1000.0 SampleDurationSec,
			SUM(W.TotalWaitMs*1.0) /ISNULL(NULLIF(SUM(W.WaitingTasksCount),0),1)  AS AvgWaitTimeMs,
			SUM(W.WaitingTasksCount) AS WaitingTasksCount,
			@SchedulerCount AS SchedulerCount,
			@TotalSampleDurationMs/1000.0 TotalSampleDurationSec,
			MIN(rnk) rnk
	FROM W 
	JOIN #Time T ON T.Time = W.Time
	JOIN dbo.WaitType WT ON WT.WaitTypeID = W.WaitTypeID
	GROUP BY	T.[Time],
				CASE WHEN W.rnk> @Top THEN '{Other}' WHEN WT.IsCriticalWait=1 THEN '!!'  + WT.WaitType ELSE WT.WaitType END
	ORDER BY	MIN(rnk),
				WaitType,
				T.Time
END

DROP TABLE #WaitGrp
GO
PRINT N'Creating Procedure [dbo].[Waits_Upd]...';


GO
CREATE PROC dbo.Waits_Upd(
    @Waits dbo.Waits READONLY,
    @InstanceID INT,
    @SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON
SET NOCOUNT ON
IF EXISTS(SELECT wait_type 
        FROM @Waits
        EXCEPT 
        SELECT WaitType 
        FROM dbo.WaitType
        )
BEGIN
    INSERT INTO dbo.WaitType(WaitType)
    SELECT wait_type 
    FROM @Waits
    EXCEPT 
    SELECT WaitType 
    FROM dbo.WaitType WITH(UPDLOCK,HOLDLOCK)
END

BEGIN TRAN

INSERT INTO dbo.Waits(InstanceID,SnapshotDate,WaitTypeID,waiting_tasks_count,wait_time_ms,signal_wait_time_ms,sample_ms_diff)
SELECT @InstanceID,
       @SnapshotDate,
       WT.WaitTypeID,
       W2.waiting_tasks_count - W1.waiting_tasks_count,
       W2.wait_time_ms - W1.wait_time_ms,
	   W2.signal_wait_time_ms-W1.signal_wait_time_ms,
	   DATEDIFF(ms,W1.SnapshotDate,@SnapshotDate)
FROM @Waits W2
    JOIN dbo.WaitType WT ON WT.WaitType = W2.wait_type
    JOIN Staging.Waits W1 ON  W1.InstanceID = @InstanceID
                          AND W1.wait_type = W2.wait_type
WHERE W2.waiting_tasks_count>=W1.waiting_tasks_count
AND W2.wait_time_ms>=w1.wait_time_ms
AND W2.signal_wait_time_ms>=W2.signal_wait_time_ms
AND (W2.waiting_tasks_count>W1.waiting_tasks_count OR W2.wait_time_ms>w1.wait_time_ms OR W2.signal_wait_time_ms>W2.signal_wait_time_ms)
AND W1.SnapshotDate<@SnapshotDate
AND DATEDIFF(mi,W1.SnapshotDate,@SnapshotDate)<2160
AND NOT EXISTS(SELECT 1 FROM dbo.Waits w WHERE w.InstanceID = @InstanceID AND w.SnapshotDate = @SnapshotDate);

DELETE Staging.Waits WHERE InstanceID=@InstanceID;

INSERT INTO Staging.Waits
(
    InstanceID,
	SnapshotDate,
    wait_type,
    waiting_tasks_count,
    wait_time_ms,
    signal_wait_time_ms
)
SELECT @InstanceID,
	   @SnapshotDate,
       wait_type,
       waiting_tasks_count,
       wait_time_ms,
       signal_wait_time_ms
FROM @Waits;

COMMIT

/* Update 60min aggregation */
BEGIN TRAN

DECLARE @Tomorrow DATETIME2(2) = CAST(DATEADD(d,1,GETUTCDATE()) AS DATE)
DECLARE @MaxDate DATETIME2(2)
SELECT @MaxDate = ISNULL(MAX(SnapshotDate),'19000101') 
FROM dbo.Waits_60MIN 
WHERE InstanceID = @InstanceID

DELETE dbo.Waits_60MIN
WHERE InstanceID=@InstanceID
AND SnapshotDate=@MaxDate

INSERT INTO dbo.Waits_60MIN
(
    InstanceID,
    SnapshotDate,
    WaitTypeID,
    waiting_tasks_count,
    wait_time_ms,
    signal_wait_time_ms,
    sample_ms_diff
)
SELECT w.InstanceID,
	DG.DateGroup AS SnapshotDate,
	w.WaitTypeID,
	SUM(w.waiting_tasks_count) waiting_tasks_count,
	SUM(w.wait_time_ms) wait_time_ms,
	SUM(w.signal_wait_time_ms) signal_wait_ms,
	MAX(SUM(w.sample_ms_diff)) OVER(PARTITION BY w.InstanceID,DG.DateGroup) sample_ms_diff
FROM dbo.Waits w
CROSS APPLY dbo.DateGroupingMins(SnapshotDate,60) DG
WHERE w.InstanceID=@InstanceID
AND w.SnapshotDate >= @MaxDate
AND w.SnapshotDate < @Tomorrow
AND w.sample_ms_diff < 86400000
GROUP BY w.InstanceID,
	DG.DateGroup,
	w.WaitTypeID
 OPTION(OPTIMIZE FOR(@MaxDate='99991231'))

COMMIT
/* **************** */

EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,
                             @Reference = 'Waits', 
                             @SnapshotDate = @SnapshotDate
GO
PRINT N'Creating Procedure [dbo].[WaitsSummary_Get]...';


GO
CREATE PROC dbo.WaitsSummary_Get(
	@InstanceID INT,
	@FromDate DATETIME2(2), /* UTC */
	@ToDate DATETIME2(2), /* UTC */
	@Use60MIN BIT=NULL,
	@UTCOffset INT=0, /* Used for Hours filter */
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY/* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
)
AS
SET DATEFIRST 1 /* Start week on Monday */
SET NOCOUNT ON

IF @Use60MIN IS NULL
BEGIN
	SELECT @Use60MIN = CASE WHEN DATEDIFF(hh,@FromDate,@ToDate)>24 THEN 1
						WHEN DATEPART(mi,@FromDate)+DATEPART(s,@FromDate)+DATEPART(ms,@FromDate)=0 
							AND (DATEPART(mi,@ToDate)+DATEPART(s,@ToDate)+DATEPART(ms,@ToDate)=0 
									OR @ToDate>=DATEADD(s,-2,GETUTCDATE())
								)
						THEN 1
						ELSE 0 END
END

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @SQL NVARCHAR(MAX)
SET @SQL = N'
SELECT  WT.WaitType,
		WT.Description,
		SUM(W.wait_time_ms)/1000.0 AS TotalWaitSec,
		SUM(W.signal_wait_time_ms)/1000.0 AS SignalWaitSec,
		SUM(W.signal_wait_time_ms*1.0)/NULLIF(SUM(W.wait_time_ms),0) AS SignalWaitPct,
		SUM(W.wait_time_ms)/NULLIF(MAX(SUM(W.sample_ms_diff/1000.0)) OVER(),0) WaitTimeMsPerSec,
		SUM(W.wait_time_ms)/NULLIF(MAX(SUM(W.sample_ms_diff/1000.0)) OVER(),0)/I.scheduler_count WaitTimeMsPerCorePerSec,
		SUM(W.waiting_tasks_count) as WaitingTasksCount,
		SUM(W.wait_time_ms)/ISNULL(NULLIF(SUM(W.waiting_tasks_count),0.0),1.0) AS AvgWaitTimeMs,
		MAX(SUM(CAST(W.sample_ms_diff AS BIGINT))/1000) OVER() SampleDurationSec,
		MAX(CAST(WT.IsCriticalWait AS INT)) CriticalWait,
		I.scheduler_count
FROM dbo.Waits' + CASE WHEN @Use60MIN=1 THEN '_60MIN' ELSE '' END  + ' W
JOIN dbo.WaitType WT ON WT.WaitTypeID = W.WaitTypeID
JOIN dbo.Instances I ON I.InstanceID = W.InstanceID
WHERE W.InstanceID=@InstanceID
AND W.SnapshotDate>=@FromDate
AND W.SnapshotDate<@ToDate
AND WT.IsExcluded=0
' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
GROUP BY WT.WaitType,
		I.scheduler_count,
		WT.Description
ORDER BY WaitTimeMsPerSec DESC'

EXEC sp_executesql @SQL,
					N'@InstanceID INT,
					@FromDate DATETIME2(2),
					@ToDate DATETIME2(2),
					@UTCOffset INT',
					@InstanceID,
					@FromDate,
					@ToDate,
					@UTCOffset
GO
PRINT N'Creating Procedure [Alert].[AGAlert_Upd]...';


GO
CREATE PROC Alert.AGAlert_Upd
AS
/* 
	Get instances that fail the AGHealth alert rule & update the active alerts
*/
SET NOCOUNT ON
DECLARE @Type VARCHAR(50)='AGHealth';

/* Check if we have any rules to process */
IF NOT EXISTS(
	SELECT 1 
	FROM Alert.Rules
	WHERE Type = @Type
)
BEGIN
	PRINT CONCAT('No rules of type ',@Type,' to process')
	RETURN;
END
PRINT CONCAT('Processing alerts of type ',@Type)

DECLARE @AlertDetails Alert.AlertDetails;
DECLARE @MaxDBs INT=10;
CREATE TABLE #Unhealthy(
	InstanceID INT NOT NULL,
	DB NVARCHAR(128) COLLATE DATABASE_DEFAULT NOT NULL,
	synchronization_state_desc NVARCHAR(60) COLLATE DATABASE_DEFAULT NULL,
	synchronization_health_desc NVARCHAR(60) COLLATE DATABASE_DEFAULT NULL,
	Priority TINYINT NOT NULL,
	AlertKey NVARCHAR(256) COLLATE DATABASE_DEFAULT NOT NULL,
	RuleID INT NOT NULL,
	GroupID INT NOT NULL DEFAULT(0)
)
CREATE TABLE #Instances(
	InstanceID INT NOT NULL,
	AlertKey NVARCHAR(256) COLLATE DATABASE_DEFAULT NOT NULL,
	Priority INT NOT NULL,
	RuleID INT NOT NULL,
	GroupID INT NOT NULL DEFAULT(0),
	PRIMARY KEY(InstanceID,GroupID)
);
/* Get the AG rules that apply to each instance, ensuring we have a single rule per instance and group. */
WITH DeDupe AS (
	SELECT I.InstanceID,
			R.AlertKey,
			R.Priority,
			R.RuleID,
			R.GroupID,
			ROW_NUMBER() OVER(PARTITION BY I.InstanceID,R.GroupID ORDER BY R.Priority, R.RuleID) rnum
	FROM Alert.Rules R
	CROSS APPLY Alert.ApplicableInstances_Get(R.ApplyToTagID,R.ApplyToInstanceID,R.AlertKey,R.ApplyToHidden) I
	WHERE R.Type = @Type
	AND R.IsActive=1
)
INSERT INTO #Instances(
	InstanceID,
	AlertKey,
	Priority,
	RuleID,
	GroupID
)
SELECT	InstanceID,
		AlertKey,
		Priority,
		RuleID,
		GroupID
FROM DeDupe
WHERE rnum=1

INSERT INTO #Unhealthy(
	InstanceID,
	DB,
	synchronization_state_desc,
	synchronization_health_desc,
	Priority,
	AlertKey,
	RuleID,
	GroupID
)
SELECT	I.InstanceID, 
		D.name,
		HADR.synchronization_state_desc,
		HADR.synchronization_health_desc,
		CASE WHEN HADR.synchronization_health_desc='NOT_HEALTHY' THEN T.Priority ELSE T.Priority+1 END AS Priority,
		T.AlertKey,
		T.RuleID,
		T.GroupID
FROM dbo.DatabasesHADR HADR
JOIN dbo.Databases D ON D.DatabaseID = HADR.DatabaseID
JOIN dbo.Instances I ON I.InstanceID = D.InstanceID
JOIN #Instances T ON I.InstanceID = T.InstanceID
WHERE (
		HADR.synchronization_state NOT IN(1,2)
		OR HADR.synchronization_health <> 2
		);

/* Convert the per database AG health data into a single row per instance */
INSERT INTO @AlertDetails
(
	InstanceID,
	Priority,
	AlertKey,
	Message,
	RuleID,
	GroupID
)
SELECT I.InstanceID,
		MIN(I.Priority),
		MIN(I.AlertKey),
		CONCAT(COUNT(*),' Databases are not in a healthy state:
',
		STUFF((SELECT TOP(@MaxDBs) CONCAT('
Database ',U.DB,' status is ',U.synchronization_health_desc,' with synchronization state ',U.synchronization_state_desc)
				FROM #Unhealthy U 
				WHERE U.InstanceID =  I.InstanceID
				AND U.GroupID = I.GroupID
				ORDER BY U.Priority,U.DB
				FOR XML PATH,TYPE).value('.','NVARCHAR(MAX)'),1,2,''),
		IIF(COUNT(*)>@MaxDBs,'
...','')) AS Message,
		MIN(I.RuleID),
		I.GroupID
FROM #Unhealthy I
GROUP BY I.InstanceID,I.GroupID

EXEC Alert.ActiveAlerts_Upd @AlertDetails=@AlertDetails,@AlertType=@Type
GO
