GO
CREATE PROC Alert.CPUAlert_Upd
AS
/* 
	Get instances that fail the CPU alert rule & update the active alerts
*/
DECLARE @Type VARCHAR(50)='CPU';

/* Check if we have any rules to process */
IF NOT EXISTS(
	SELECT 1 
	FROM Alert.Rules
	WHERE Type = @Type
)
BEGIN
	PRINT CONCAT('No rules of type ',@Type,' to process')
	RETURN;
END
PRINT CONCAT('Processing alerts of type ',@Type)

CREATE TABLE #EffectiveThresholds(
	RuleID INT NOT NULL,
	AlertKey NVARCHAR(256) COLLATE DATABASE_DEFAULT NOT NULL,	
	InstanceID INT NOT NULL,
	Priority TINYINT NOT NULL,
	EvaluationPeriodMins TINYINT NOT NULL,
	Threshold TINYINT NOT NULL,
	GroupID INT NOT NULL DEFAULT(0)
)
CREATE TABLE #CPUAlert(
	InstanceID INT NOT NULL PRIMARY KEY,
	Priority TINYINT NOT NULL,
	Message NVARCHAR(MAX) COLLATE DATABASE_DEFAULT NOT NULL
);

/* Get thresholds that apply to each instance. If multiple thresholds apply with the same evaluation period & priority, take the lowest threshold*/
WITH T AS (
	SELECT 	R.RuleID,
		R.AlertKey,
		I.InstanceID,
		R.Priority,
		R.EvaluationPeriodMins,
		TRY_CAST(R.Threshold AS TINYINT) AS Threshold,
		R.GroupID,
		ROW_NUMBER() OVER(PARTITION BY I.InstanceID,R.GroupID,R.EvaluationPeriodMins,R.Priority ORDER BY R.Threshold,R.RuleID) rnum
	FROM Alert.Rules R
	CROSS APPLY Alert.ApplicableInstances_Get(R.ApplyToTagID,R.ApplyToInstanceID,R.AlertKey,R.ApplyToHidden) I
	WHERE R.Type = @Type
	AND R.Threshold<=100
	AND R.IsActive=1
)
INSERT INTO #EffectiveThresholds(
	RuleID,
	AlertKey,
	InstanceID,
	Priority,
	EvaluationPeriodMins,
	Threshold,
	GroupID
)
SELECT T.RuleID,
	T.AlertKey,
	T.InstanceID,
	T.Priority,
	ISNULL(T.EvaluationPeriodMins,5),
	T.Threshold,
	T.GroupID
FROM T 
WHERE rnum=1;

DECLARE @AlertDetails Alert.AlertDetails;

WITH T AS (
	SELECT T.RuleID,
			T.InstanceID,
			T.Priority,
			T.EvaluationPeriodMins,
			T.AlertKey,
			T.GroupID,
			agg.AvgCPU,
			ROW_NUMBER() OVER(PARTITION BY T.InstanceID,T.GroupID ORDER BY T.Priority,T.RuleID) rnum
	FROM #EffectiveThresholds T
	CROSS APPLY(SELECT AVG(TotalCPU) AvgCPU
				FROM dbo.CPU 
				WHERE T.InstanceID = CPU.InstanceID
				AND CPU.EventTime >=CAST(DATEADD(mi,-EvaluationPeriodMins,SYSUTCDATETIME()) AS DATETIME2(3))
				AND CPU.EventTime >=CAST(DATEADD(mi,-60,SYSUTCDATETIME()) AS DATETIME2(3)) /* Hard cap at 60min evaluation period for performance */	
				AND CPU.EventTime <= CAST(SYSUTCDATETIME() AS DATETIME2(3)) 
				) agg
	WHERE agg.AvgCPU >T.Threshold
)
/* Get instances exceeding CPU alert threshold, de-duplicated by instance */
INSERT INTO @AlertDetails(
		InstanceID,
		Priority,
		Message,
		AlertKey,
		RuleID,
		GroupID
)
SELECT	T.InstanceID,
		T.Priority,
		CONCAT(I.ConnectionID,' exceeded CPU threshold, averaging ',T.AvgCPU,'% over ',T.EvaluationPeriodMins,'mins') AS Message,
		T.AlertKey,
		T.RuleID,
		T.GroupID
FROM T 
JOIN dbo.Instances I ON T.InstanceID = I.InstanceID
WHERE T.rnum=1

EXEC Alert.ActiveAlerts_Upd @AlertDetails=@AlertDetails,@AlertType=@Type
GO
PRINT N'Creating Procedure [Alert].[DatabaseStatusAlert_Upd]...';


GO
CREATE PROC Alert.DatabaseStatusAlert_Upd
AS
SET NOCOUNT ON
DECLARE @Type VARCHAR(50) = 'DatabaseStatus'
DECLARE @AlertKeyPrefix NVARCHAR(256) = 'DB:'

/* Check if we have any rules to process */
IF NOT EXISTS(
	SELECT 1
	FROM Alert.Rules
	WHERE Type = @Type
)
BEGIN
	PRINT CONCAT('No rules of type ', @Type, ' to process')
	RETURN;
END
PRINT CONCAT('Processing alerts of type ', @Type)

CREATE TABLE #DatabaseStatusApplicable(
	InstanceID INT NOT NULL,
	Priority TINYINT NOT NULL,
	DatabaseName NVARCHAR(128) COLLATE DATABASE_DEFAULT NULL,
	ExcludedStates NVARCHAR(MAX) COLLATE DATABASE_DEFAULT NULL,
	RuleID INT NOT NULL,
	GroupID INT NOT NULL DEFAULT(0)
)

/* Get a list of rules and the instances they apply to */
INSERT INTO #DatabaseStatusApplicable(
	InstanceID,
	Priority,
	DatabaseName,
	ExcludedStates,
	RuleID,
	GroupID
)
SELECT I.InstanceID,
		R.Priority,
		NULLIF(JSON_VALUE(R.Details,'$.DatabaseName'),'') AS DatabaseName,
		CASE
			WHEN JSON_VALUE(R.Details,'$.ExcludedStates[0]') IS NULL THEN '[0,1,7,10]'
			ELSE JSON_QUERY(R.Details,'$.ExcludedStates')
		END AS ExcludedStates,
		R.RuleID,
		R.GroupID
FROM Alert.Rules R
CROSS APPLY Alert.ApplicableInstances_Get(R.ApplyToTagID, R.ApplyToInstanceID, R.AlertKey, R.ApplyToHidden) I
WHERE R.Type = @Type
AND R.IsActive = 1

DECLARE @AlertDetails Alert.AlertDetails

INSERT INTO @AlertDetails(
	InstanceID,
	Priority,
	Message,
	AlertKey,
	RuleID,
	GroupID
)
SELECT D.InstanceID,
		DSA.Priority,
		CONCAT(D.name, ' is ', D.state_desc),
		CONCAT(@AlertKeyPrefix, D.name) AS AlertKey,
		DSA.RuleID,
		DSA.GroupID
FROM dbo.Databases D
JOIN #DatabaseStatusApplicable DSA ON D.InstanceID = DSA.InstanceID
		AND (D.name LIKE DSA.DatabaseName OR DSA.DatabaseName IS NULL)
WHERE D.IsActive = 1
AND NOT EXISTS(SELECT 1 FROM OPENJSON(DSA.ExcludedStates) WHERE CAST(value AS INT) = D.state)

EXEC Alert.ActiveAlerts_Upd @AlertDetails = @AlertDetails, @AlertType = @Type, @ResolveAlertsOfType = 0

/* Resolve alerts when the database is no longer in the triggered set:
   - Database returned to an excluded state (e.g. back ONLINE)
   - Database was dropped (IsActive = 0) or renamed
   - Rule was updated (e.g. ExcludedStates now includes the current state) */
UPDATE AA
		SET ResolvedDate  = SYSUTCDATETIME(),
		IsResolved    = 1,
		LastMessage   = 'Issue resolved',
		UpdateCount  += 1,
		ResolvedCount += 1,
		UpdatedDate   = SYSUTCDATETIME()
FROM Alert.ActiveAlerts AA
WHERE AA.AlertType = @Type
AND NOT EXISTS(
			SELECT 1
			FROM @AlertDetails AD
			WHERE AD.InstanceID = AA.InstanceID
			AND AD.AlertKey = AA.AlertKey
			AND AD.GroupID = AA.GroupID
)
AND AA.IsResolved = 0
GO
PRINT N'Creating Procedure [Alert].[Config_Get]...';


GO
CREATE PROC Alert.Config_Get
AS
SET NOCOUNT ON
SET DATEFIRST 1
EXEC Alert.Rules_Get

SELECT BP.BlackoutPeriodID,
		BP.ApplyToInstanceID,
		CASE WHEN BP.ApplyToInstanceID = -1 THEN '{All}' ELSE I.InstanceDisplayName END AS ApplyToInstance,
		BP.ApplyToTagID,
		T.TagName + ':' + T.TagValue AS ApplyToTag,
		I.ConnectionID,
		BP.AlertKey,
		BP.StartDate,
		BP.EndDate,
		BP.Monday,
		BP.Tuesday,
		BP.Wednesday,
		BP.Thursday,
		BP.Friday,
		BP.Saturday,
		BP.Sunday,
		BP.TimeZone,
		BP.TimeFrom,
		BP.TimeTo,
		CASE WHEN BP.StartDate<=SYSUTCDATETIME() AND BP.EndDate> SYSUTCDATETIME() THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS InEffect,
		CASE	WHEN BP.StartDate>SYSUTCDATETIME() THEN 'Starts in ' + HDStartsIn.HumanDuration
				WHEN BP.EndDate < SYSUTCDATETIME() THEN 'Ended'
				WHEN CHOOSE(DATEPART(dw,TZ.CurrentTime),BP.Monday,BP.Tuesday,BP.Wednesday,BP.Thursday,BP.Friday,BP.Saturday,BP.Sunday) = CAST(0 AS BIT) 
					THEN 'Not scheduled for ' + DATENAME(WEEKDAY,TZ.CurrentTime) + ' (' + BP.TimeZone + ')'
				WHEN (CAST(TZ.CurrentTime AS TIME) < BP.TimeFrom OR CAST(TZ.CurrentTime AS TIME) > BP.TimeTo ) 
						AND NOT (BP.TimeTo < BP.TimeFrom /* Crosses midnight boundary so either >= TimeFrom or < TimeTo */
							AND (CAST(TZ.CurrentTime AS TIME) < BP.TimeTo OR CAST(TZ.CurrentTime AS TIME) >= BP.TimeFrom)
							)
					THEN 'Not scheduled for ' + FORMAT(TZ.CurrentTime,'HH:mm') + ' (' + BP.TimeZone + ')'
		WHEN BP.TimeFrom IS NOT NULL OR BP.TimeTo IS NOT NULL 
			THEN CONCAT(
				'Active between ',
				CONVERT(CHAR(5),ISNULL(BP.TimeFrom,'00:00'),114),
				' and ',CONVERT(CHAR(5),ISNULL(BP.TimeTo,'00:00'),114),' (' + BP.TimeZone + ')',
				IIF(DATEDIFF(d,GETUTCDATE(),BP.EndDate)>365 OR BP.EndDate IS NULL,'',', (Ends in ' + HDEndsIn.HumanDuration + ')')
			)
		ELSE 'Active' + IIF(DATEDIFF(d,GETUTCDATE(),BP.EndDate)>365 OR BP.EndDate IS NULL,'',' (Ends in ' + HDEndsIn.HumanDuration + ')')  END AS CurrentStatus,
		HDStartsIn.HumanDuration AS StartsIn,
		HDEndsIn.HumanDuration AS EndsIn,
		BP.Notes
FROM Alert.BlackoutPeriod BP
OUTER APPLY(SELECT SYSDATETIMEOFFSET() AT TIME ZONE TimeZone AS CurrentTime) AS TZ
LEFT JOIN dbo.Instances I ON I.InstanceID = BP.ApplyToInstanceID
LEFT JOIN dbo.Tags T ON T.TagID = BP.ApplyToTagID
OUTER APPLY dbo.SecondsToHumanDuration(DATEDIFF_BIG(s,GETUTCDATE(),BP.EndDate)) HDEndsIn
OUTER APPLY dbo.SecondsToHumanDuration(DATEDIFF_BIG(s,GETUTCDATE(),BP.StartDate)) HDStartsIn
ORDER BY BP.EndDate DESC

EXEC Alert.NotificationChannel_Get

EXEC Alert.NotificationChannelGroup_Get
GO
PRINT N'Creating Procedure [Alert].[NotificationChannelGroup_Del]...';


GO
CREATE PROC Alert.NotificationChannelGroup_Del(
	@GroupID INT
)
AS
SET XACT_ABORT ON
IF @GroupID = 0
BEGIN
	RAISERROR('The default notification channel group cannot be deleted.',16,1)
	RETURN
END
BEGIN TRAN
/* Channels and rules revert to the default group (0) when their group is deleted */
UPDATE Alert.NotificationChannel SET GroupID = 0 WHERE GroupID = @GroupID

/* 
	Close existing alerts associated with group.  Avoids duplicates in Alert.ActiveAlerts that might be possible if we updated them to default group.
	Closed alerts are not updated as they are historical records.
*/
DECLARE @AlertIDs BigIDs
INSERT INTO @AlertIDs(ID)
SELECT AlertID
FROM Alert.ActiveAlerts
WHERE GroupID = @GroupID

EXEC  Alert.ClosedAlerts_Add @AlertIDs= @AlertIDs

/* Remove rules that would become duplicates in the default group, then revert the rest */
DELETE R
FROM Alert.Rules R
WHERE R.GroupID = @GroupID
AND EXISTS(
	SELECT 1
	FROM Alert.Rules R0
	WHERE R0.GroupID = 0
	AND R0.RuleHash = R.RuleHash
)
UPDATE Alert.Rules SET GroupID = 0 WHERE GroupID = @GroupID


DELETE FROM Alert.NotificationChannelGroup WHERE GroupID = @GroupID

COMMIT
GO
PRINT N'Creating Procedure [Alert].[Alerts_Upd]...';


GO
CREATE PROC Alert.Alerts_Upd
AS
/* 
	Updates all alerts.  Called based on alert polling frequency & startup delay in config tool.  
*/
SET NOCOUNT ON
SET DATEFIRST 1

/* 
	If blackout period is in effect, update any currently active alerts rather than resolving the alert
	Note: new alerts won't be generated during the blackout
*/
UPDATE AA 
	SET LastMessage = IIF(BP.IsBlackout=1,'Blackout Period','Blackout Period Ended.  Pending...'),
	UpdateCount+=1,
	UpdatedDate = SYSUTCDATETIME(),
	IsBlackout = BP.IsBlackout
FROM Alert.ActiveAlerts AA
OUTER APPLY Alert.IsBlackoutPeriod(AA.InstanceID,AA.AlertKey) BP
WHERE AA.IsResolved=0
AND AA.IsBlackout <> BP.IsBlackout

IF EXISTS(
		SELECT 1 
		FROM Alert.IsBlackoutPeriod(DEFAULT,DEFAULT) BP
		WHERE BP.IsBlackout=1
	)
BEGIN
	PRINT 'Blackout period in effect for all instances. No alerts will be processed.'
	RETURN;
END

EXEC Alert.CPUAlert_Upd
EXEC Alert.WaitAlert_Upd
EXEC Alert.CounterAlert_Upd
EXEC Alert.AGAlert_Upd
EXEC Alert.DriveSpaceAlert_Upd
EXEC Alert.CollectionDatesAlert_Upd
EXEC Alert.AgentJobAlert_Upd
EXEC Alert.OfflineAlert_Upd
EXEC Alert.RestartAlert_Upd
EXEC Alert.DatabaseStatusAlert_Upd

/* Close Alerts that have been resolved for a period of time */

DECLARE @AlertAutoCloseThresholdMins INT =1440

SELECT @AlertAutoCloseThresholdMins = ISNULL(TRY_CAST(SettingValue AS INT),@AlertAutoCloseThresholdMins)
FROM dbo.Settings
WHERE SettingName = 'AlertAutoCloseThresholdMins'

DECLARE @AlertIDs BigIDs

INSERT INTO @AlertIDs
SELECT AlertID 
FROM Alert.ActiveAlerts
WHERE (
	(IsResolved=1 AND ResolvedDate < DATEADD(mi,-@AlertAutoCloseThresholdMins,SYSUTCDATETIME()))
	OR UpdatedDate < DATEADD(mi,-@AlertAutoCloseThresholdMins,SYSUTCDATETIME())
	)

EXEC Alert.ClosedAlerts_Add @AlertIDs=@AlertIDs
GO
