CREATE PROC dbo.AvailableProcs_Upd(
	@AvailableProcs dbo.AvailableProcs READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON
DECLARE @Ref VARCHAR(30)='AvailableProcs'

BEGIN TRAN
DELETE dbo.AvailableProcs 
WHERE InstanceID = @InstanceID;

WITH RemoveDupe AS (
	/* Case sensitive collations *could* intruduce duplicates */
	SELECT 	database_name,
			from_master,
			schema_name,
			object_name,
			parameters,
			COUNT(*) OVER(PARTITION BY object_name,schema_name) cnt
	FROM @AvailableProcs
)
INSERT INTO dbo.AvailableProcs(
	InstanceID,
	database_name,
	from_master,
	schema_name,
	object_name,
	parameters
)
SELECT 	@InstanceID,
		database_name,
		from_master,
		schema_name,
		object_name,
		parameters
FROM RemoveDupe
WHERE cnt=1

COMMIT

EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
	                            @Reference = @Ref,
	                            @SnapshotDate = @SnapshotDate
GO
PRINT N'Creating Procedure [dbo].[AzureDBElasticPoolResourceStats_Upd]...';


GO
CREATE PROC dbo.AzureDBElasticPoolResourceStats_Upd(
	@AzureDBElasticPoolResourceStats dbo.AzureDBElasticPoolResourceStats READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(3)
)
AS
SET XACT_ABORT ON
DECLARE @Ref VARCHAR(100)='AzureDBElasticPoolResourceStats'
IF NOT EXISTS(SELECT 1 FROM dbo.CollectionDates WHERE SnapshotDate>=@SnapshotDate AND InstanceID = @InstanceID AND Reference=@Ref)
BEGIN
	CREATE TABLE #Pools(
		elastic_pool_name NVARCHAR(128) PRIMARY KEY,
		elastic_pool_dtu_limit INT,
		elastic_pool_cpu_limit DECIMAL (5, 2),
		first_end_time DATETIME2(7)
	)


	DECLARE @MaxDate DATETIME2(7);
	DECLARE @MinDate DATETIME2(7);
	DECLARE @AggFrom DATETIME2(7);
	DECLARE @PoolUpdates INT=0;

	SELECT @MinDate = MIN(end_time)
	FROM @AzureDBElasticPoolResourceStats S

	SELECT @AggFrom = DG.DateGroup
	FROM dbo.DateGroupingMins(@MinDate,60) DG;

	WITH pools AS (
		SELECT	elastic_pool_name,
				elastic_pool_dtu_limit,
				elastic_pool_cpu_limit,
				FIRST_VALUE(end_time) OVER(PARTITION BY elastic_pool_name,elastic_pool_dtu_limit,elastic_pool_cpu_limit ORDER BY end_time) first_end_time, /* First occurrence of this config */
				ROW_NUMBER() OVER(PARTITION BY elastic_pool_name ORDER BY end_time DESC) rnum
		FROM @AzureDBElasticPoolResourceStats
	)
	INSERT INTO #Pools(elastic_pool_name,elastic_pool_dtu_limit,elastic_pool_cpu_limit,first_end_time)
	SELECT	p.elastic_pool_name,
			p.elastic_pool_dtu_limit,
			p.elastic_pool_cpu_limit,
			p.first_end_time
	FROM pools p
	WHERE p.rnum=1

	/* Update existing pools */
	UPDATE EP
		 SET EP.elastic_pool_dtu_limit = T.elastic_pool_dtu_limit,
			EP.elastic_pool_cpu_limit = T.elastic_pool_cpu_limit,
			EP.ValidFrom = T.first_end_time
	/* Track updates */
	OUTPUT Inserted.PoolID, DELETED.elastic_pool_dtu_limit,DELETED.elastic_pool_cpu_limit,INSERTED.elastic_pool_dtu_limit,Inserted.elastic_pool_cpu_limit,ISNULL(Deleted.ValidFrom,'19000101'),Inserted.ValidFrom
		INTO dbo.AzureDBElasticPoolHistory(PoolID,elastic_pool_dtu_limit_old,elastic_pool_cpu_limit_old,elastic_pool_dtu_limit_new,elastic_pool_cpu_limit_new,ValidFrom,ValidTo)
	FROM dbo.AzureDBElasticPool EP
	JOIN #Pools T ON EP.elastic_pool_name = T.elastic_pool_name
	WHERE EP.InstanceID = @InstanceID
	AND (	
			/* Limits have changed */
			EXISTS(
				SELECT	T.elastic_pool_dtu_limit,
						T.elastic_pool_cpu_limit
				EXCEPT 
				SELECT	EP.elastic_pool_dtu_limit,
						EP.elastic_pool_cpu_limit
				)
		)
	SET @PoolUpdates += @@ROWCOUNT

	/* Insert new pools */
	INSERT INTO dbo.AzureDBElasticPool(InstanceID,elastic_pool_name,elastic_pool_dtu_limit ,elastic_pool_cpu_limit,ValidFrom )
	SELECT	@InstanceID,
			P.elastic_pool_name,
			P.elastic_pool_dtu_limit ,
			P.elastic_pool_cpu_limit,
			P.first_end_time
	FROM #Pools P
	WHERE NOT EXISTS(
					SELECT 1 
					FROM dbo.AzureDBElasticPool EP
					WHERE EP.elastic_pool_name = P.elastic_pool_name
					AND EP.InstanceID = @InstanceID
					)
	SET @PoolUpdates += @@ROWCOUNT

	/* Deactivate pools that no longer exist */
	UPDATE EP
		SET EP.ValidTo = SYSUTCDATETIME()
	FROM dbo.AzureDBElasticPool EP
	WHERE EP.InstanceID = @InstanceID
	AND NOT EXISTS(
					SELECT 1 
					FROM #Pools P
					WHERE EP.elastic_pool_name = P.elastic_pool_name
					)
	AND EP.ValidTo IS NULL

	SET @PoolUpdates += @@ROWCOUNT

	/* Re-activate pools */
	UPDATE EP
		SET EP.ValidTo = NULL
	FROM dbo.AzureDBElasticPool EP
	WHERE EP.InstanceID = @InstanceID
	AND EXISTS(
				SELECT 1 
				FROM #Pools P
				WHERE EP.elastic_pool_name = P.elastic_pool_name
				)
	AND EP.ValidTo IS NOT NULL

	SET @PoolUpdates += @@ROWCOUNT

	IF @PoolUpdates>0
	BEGIN
		EXEC dbo.AzureDBCounters_Upd @InstanceID = @InstanceID
	END

	SELECT @MaxDate=ISNULL(MAX(end_time),'19000101')
	FROM dbo.AzureDBElasticPoolResourceStats RS 
	JOIN dbo.AzureDBElasticPool EP ON EP.PoolID = RS.PoolID
	WHERE EP.InstanceID=@InstanceID
	AND RS.end_time >= @AggFrom

	BEGIN TRAN
	INSERT INTO dbo.AzureDBElasticPoolResourceStats
	(
		PoolID,
	    start_time,
	    end_time,
	    avg_cpu_percent,
	    avg_data_io_percent,
	    avg_log_write_percent,
	    avg_storage_percent,
	    max_worker_percent,
	    max_session_percent,
	    elastic_pool_dtu_limit,
	    elastic_pool_storage_limit_mb,
	    avg_allocated_storage_percent,
	    elastic_pool_cpu_limit
	)
	SELECT  EP.PoolID,
		RS.start_time,
	    RS.end_time,
	    RS.avg_cpu_percent,
	    RS.avg_data_io_percent,
	    RS.avg_log_write_percent,
	    RS.avg_storage_percent,
	    RS.max_worker_percent,
	    RS.max_session_percent,
	    RS.elastic_pool_dtu_limit,
	    RS.elastic_pool_storage_limit_mb,
	    RS.avg_allocated_storage_percent,
		RS.elastic_pool_cpu_limit
	FROM @AzureDBElasticPoolResourceStats RS
	JOIN dbo.AzureDBElasticPool EP ON EP.elastic_pool_name = RS.elastic_pool_name AND EP.InstanceID = @InstanceID
	WHERE RS.end_time>@MaxDate

	IF @@ROWCOUNT>0
	BEGIN

		DELETE agg
		FROM dbo.AzureDBElasticPoolResourceStats_60MIN agg
		WHERE EXISTS(SELECT 1 
					FROM dbo.AzureDBElasticPool P 
					WHERE P.PoolID = agg.PoolID
					AND P.InstanceID= @InstanceID
					)
		AND agg.end_time>=@AggFrom

		INSERT INTO dbo.AzureDBElasticPoolResourceStats_60MIN
		(
			PoolID,
			end_time,
			avg_cpu_percent,
			max_cpu_percent,
			avg_data_io_percent,
			max_data_io_percent,
			avg_log_write_percent,
			max_log_write_percent,
			avg_storage_percent,
			max_storage_percent,
			max_worker_percent,
			max_session_percent,
			elastic_pool_dtu_limit,
			elastic_pool_cpu_limit,
			elastic_pool_storage_limit_mb,
			avg_allocated_storage_percent,
			avg_dtu_percent,
			max_dtu_percent,
			avg_dtu,
			max_dtu,
			DTU10,
			DTU20,
			DTU30,
			DTU40,
			DTU50,
			DTU60,
			DTU70,
			DTU80,
			DTU90,
			DTU100,
			CPU10,
			CPU20,
			CPU30,
			CPU40,
			CPU50,
			CPU60,
			CPU70,
			CPU80,
			CPU90,
			CPU100,
			Data10,
			Data20,
			Data30,
			Data40,
			Data50,
			Data60,
			Data70,
			Data80,
			Data90,
			Data100,
			Log10,
			Log20,
			Log30,
			Log40,
			Log50,
			Log60,
			Log70,
			Log80,
			Log90,
			Log100
		)
		SELECT     PoolID,
			DG.DateGroup,
			AVG(avg_cpu_percent),
			MAX(max_cpu_percent),
			AVG(avg_data_io_percent),
			MAX(max_data_io_percent),
			AVG(avg_log_write_percent),
			MAX(max_log_write_percent),
			AVG(avg_storage_percent),
			MAX(max_storage_percent),
			MAX(max_worker_percent),
			MAX(max_session_percent),
			MAX(elastic_pool_dtu_limit),
			MAX(elastic_pool_cpu_limit),
			MAX(elastic_pool_storage_limit_mb),
			AVG(avg_allocated_storage_percent),
			AVG(avg_dtu_percent),
			MAX(max_dtu_percent),
			AVG(avg_dtu),
			MAX(max_dtu),
			SUM(DTU10),
			SUM(DTU20),
			SUM(DTU30),
			SUM(DTU40),
			SUM(DTU50),
			SUM(DTU60),
			SUM(DTU70),
			SUM(DTU80),
			SUM(DTU90),
			SUM(DTU100),
			SUM(CPU10),
			SUM(CPU20),
			SUM(CPU30),
			SUM(CPU40),
			SUM(CPU50),
			SUM(CPU60),
			SUM(CPU70),
			SUM(CPU80),
			SUM(CPU90),
			SUM(CPU100),
			SUM(Data10),
			SUM(Data20),
			SUM(Data30),
			SUM(Data40),
			SUM(Data50),
			SUM(Data60),
			SUM(Data70),
			SUM(Data80),
			SUM(Data90),
			SUM(Data100),
			SUM(Log10),
			SUM(Log20),
			SUM(Log30),
			SUM(Log40),
			SUM(Log50),
			SUM(Log60),
			SUM(Log70),
			SUM(Log80),
			SUM(Log90),
			SUM(Log100) 
		FROM dbo.AzureDBElasticPoolResourceStats_Raw R
		CROSS APPLY dbo.DateGroupingMins(R.end_time,60) DG
		WHERE R.InstanceID= @InstanceID
		AND R.end_time>=@AggFrom
		GROUP BY DG.DateGroup,R.PoolID

	END
	COMMIT
	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										 @Reference = @Ref,
										 @SnapshotDate = @SnapshotDate
END
GO
PRINT N'Creating Procedure [dbo].[AzureDBPerformanceSummary_Get]...';


GO
CREATE PROC dbo.AzureDBPerformanceSummary_Get(
	@FromDate DATETIME2(3)=NULL,
	@ToDate DATETIME2(3)=NULL,
	@InstanceIDs VARCHAR(MAX)=NULL,
	@DatabaseName SYSNAME=NULL,
	@DTUHist BIT=0,
	@CPUHist BIT=0,
	@DataHist BIT = 0,
	@LogHist BIT=0,
	@Use60MIN BIT=NULL,
	@Debug BIT=0,
	@ShowHidden BIT=1
)
AS
IF @FromDate IS NULL
	SET @FromDate = DATEADD(d,-1,GETUTCDATE())
IF @ToDate IS NULL 
	SET @ToDate = GETUTCDATE()
DECLARE @tInstanceIDs IDs
IF @InstanceIDs IS NULL
BEGIN
	INSERT INTO @tInstanceIDs
	(
	    ID
	)
	SELECT DISTINCT InstanceID
	FROM dbo.Instances I
	WHERE I.IsActive=1
	AND I.EngineEdition=5 --AzureDB
	AND (I.ShowInSummary=1 OR @ShowHidden=1)
END 
ELSE 
BEGIN
	INSERT INTO @tInstanceIDs
	(
		ID
	)
	SELECT value
	FROM dbo.Instances I
	JOIN STRING_SPLIT(@InstanceIDs,',') SS ON SS.Value = I.InstanceID
	WHERE (I.ShowInSummary=1 OR @ShowHidden=1)

END;
IF @Use60MIN IS NULL
BEGIN
	SELECT @Use60MIN = CASE WHEN DATEDIFF(hh,@FromDate,@ToDate)>24 THEN 1
						WHEN DATEPART(mi,@FromDate)+DATEPART(s,@FromDate)+DATEPART(ms,@FromDate)=0 
							AND (DATEPART(mi,@ToDate)+DATEPART(s,@ToDate)+DATEPART(ms,@ToDate)=0 
									OR @ToDate>=DATEADD(s,-2,GETUTCDATE())
								)
						THEN 1
						ELSE 0 END
END

DECLARE @SQL NVARCHAR(MAX)
SET @SQL = CAST(N'' AS NVARCHAR(MAX)) + N'
WITH agg AS(
	SELECT  RS.InstanceID,
		MAX(max_dtu_percent) Max_DTUPercent,
		MAX(max_dtu) AS Max_DTUsUsed,
		MAX(RS.dtu_limit)-MAX(max_dtu) AS UnusedDTU,
		AVG(avg_dtu_percent) AS Avg_DTUPercent,
		AVG(avg_dtu) AS Avg_DTUsUsed,
		MIN(RS.dtu_limit) Min_DTULimit,
		MAX(RS.dtu_limit) MAX_DTULimit,
		MAX(RS.max_cpu_percent) AS MaxCPUPercent,
		MAX(RS.max_data_io_percent) AS MaxDataPercent,
		MAX(RS.max_log_write_percent) MaxLogWritePercent,
		AVG(RS.avg_cpu_percent) AS AvgCPUPercent,
		AVG(RS.avg_data_io_percent) AS AvgDataPercent,
		AVG(RS.avg_log_write_percent) AvgLogWritePercent,
		' + CASE WHEN @DTUHist =1 THEN '
		SUM(DTU10) AS DTU10,
		SUM(DTU20) AS DTU20,
		SUM(DTU30) AS DTU30,
		SUM(DTU40) AS DTU40,
		SUM(DTU50) AS DTU50,
		SUM(DTU60) AS DTU60,
		SUM(DTU70) AS DTU70,
		SUM(DTU80) AS DTU80,
		SUM(DTU90) AS DTU90,
		SUM(DTU100) AS DTU100,
		' ELSE '' END 
		 + CASE WHEN @CPUHist =1 THEN '
		SUM(CPU10) AS CPU10,
		SUM(CPU20) AS CPU20,
		SUM(CPU30) AS CPU30,
		SUM(CPU40) AS CPU40,
		SUM(CPU50) AS CPU50,
		SUM(CPU60) AS CPU60,
		SUM(CPU70) AS CPU70,
		SUM(CPU80) AS CPU80,
		SUM(CPU90) AS CPU90,
		SUM(CPU100) AS CPU100,
		' ELSE '' END + 
		CASE WHEN @DataHist=1 THEN '
		SUM(Data10) AS Data10,
		SUM(Data20) AS Data20,
		SUM(Data30) AS Data30,
		SUM(Data40) AS Data40,
		SUM(Data50) AS Data50,
		SUM(Data60) AS Data60,
		SUM(Data70) AS Data70,
		SUM(Data80) AS Data80,
		SUM(Data90) AS Data90,
		SUM(Data100) AS Data100,
		' ELSE '' END + 
		CASE WHEN @LogHist =1 THEN '
		SUM(Log10) AS Log10,
		SUM(Log20) AS Log20,
		SUM(Log30) AS Log30,
		SUM(Log40) AS Log40,
		SUM(Log50) AS Log50,
		SUM(Log60) AS Log60,
		SUM(Log70) AS Log70,
		SUM(Log80) AS Log80,
		SUM(Log90) AS Log90,
		SUM(Log100) AS Log100,'
		ELSE '' END + '
		SUM(CPU10+CPU20+CPU30+CPU40+CPU50+CPU70+CPU80+CPU90+CPU100) AS TotalSamples
	FROM ' + CASE WHEN @Use60MIN=1 THEN 'dbo.AzureDBResourceStats_60MIN' ELSE 'dbo.AzureDBResourceStats_Raw' END + ' RS
	WHERE RS.end_time>=@FromDate
	AND RS.end_time <@ToDate
	AND EXISTS(SELECT 1 FROM @tInstanceIDs t WHERE RS.InstanceID = t.ID)
	GROUP BY RS.InstanceID
)
SELECT I.InstanceID,
	I.ConnectionID,
	I.Instance,
	I.DB,
	I.edition,
	I.service_objective,
	I.elastic_pool_name,
	I.AllocatedSpaceMB,
	I.UsedSpaceMB,
	I.MaxStorageSizeMB,
	I.AllocatedPctOfMaxSize,
	I.UsedPctOfMaxSize,
	I.ConfiguredLevel,
	I.PctMaxSizeWarningThreshold,
	I.PctMaxSizeCriticalThreshold,
	I.PctMaxSizeStatus,
	I.FileSnapshotDate,
	I.FileSnapshotAge,
	I.FileSnapshotStatus,
	agg.*
FROM agg
JOIN dbo.AzureDBInfo I ON I.InstanceID = agg.InstanceID
AND EXISTS(SELECT 1 FROM @tInstanceIDs t WHERE I.InstanceID = t.ID)
' + CASE WHEN @DatabaseName IS NOT NULL THEN 'AND D.name=@DatabaseName' ELSE '' END + '
ORDER BY UnusedDTU DESC;'

IF @Debug=1
	EXEC dbo.PrintMax @SQL

EXEC sp_executesql @SQL,N'@FromDate DATETIME2(3),@ToDate DATETIME2(3),@tInstanceIDs IDs READONLY,@DatabaseName SYSNAME',@FromDate,@ToDate,@tInstanceIDs,@DatabaseName
GO
