CREATE PROC dbo.Databases_Upd(
	@Databases dbo.Databases READONLY,
	@InstanceID INT,
	@SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON
SET NOCOUNT ON
DECLARE @Ref VARCHAR(30)='Databases'
IF NOT EXISTS(SELECT 1 FROM dbo.CollectionDates WHERE SnapshotDate>=@SnapshotDate AND InstanceID = @InstanceID AND Reference=@Ref)
BEGIN

	DECLARE @Created INT = 0
	DECLARE @Dropped INT = 0
	DECLARE @MetricsInstanceID INT 
	SELECT @MetricsInstanceID = CASE WHEN EXISTS(SELECT 1 FROM dbo.RepositoryMetricsConfig WHERE InstanceID = @InstanceID AND MetricType='Databases') THEN @InstanceID ELSE -1 END

	CREATE TABLE #History(
		DatabaseID INT NOT NULL,
		Setting sysname NOT NULL,
		OldValue SQL_VARIANT NULL,
		NewValue SQL_VARIANT NULL,
		ChangeDate DATETIME2(2) NOT NULL
	);
	DECLARE @OldSettings TABLE(
		DatabaseID INT NOT NULL,
		Setting sysname NOT NULL,
		Value SQL_VARIANT NULL,
		is_in_standby BIT NULL
	);
	/* Capture old settings before update */
	INSERT INTO @OldSettings
	(
	    DatabaseID,
	    Setting,
	    Value,
	    is_in_standby
	)
	SELECT 	DatabaseID,
			Setting,
			Value,
			is_in_standby   
	FROM dbo.DatabaseSettingsUnpivot_Get(@InstanceID)

	BEGIN TRAN;

	/*	Handle database rename 
		Update name where database_id and service_broker_guid match, but name is different and new name doesn't already exist
	*/
	UPDATE D 
		SET D.name = T.name,
		D.UpdatedDate = @SnapshotDate
	OUTPUT INSERTED.DatabaseID, 'name',DELETED.name,INSERTED.name,@SnapshotDate INTO #History(DatabaseID,Setting,OldValue,NewValue,ChangeDate)
	FROM dbo.Databases D 
	JOIN @Databases T ON D.database_id = T.database_id 
			AND D.service_broker_guid = T.service_broker_guid /* Provides some confidence it's the same database.  Note: create_date is updated on rename */
	WHERE D.InstanceID = @InstanceID 
	AND D.service_broker_guid <> '00000000-0000-0000-0000-000000000000'
	AND D.name <> T.name
    AND NOT EXISTS(	SELECT 1 
					FROM dbo.Databases D2 
					WHERE D2.InstanceID = @InstanceID 
					AND D2.name = T.name
					);

	/* Handle dropped databases - set IsActive=0 where database doesn't exist in new data */
	UPDATE D 
		SET D.IsActive = 0,
		D.UpdatedDate = @SnapshotDate
	OUTPUT INSERTED.DatabaseID, 'IsActive',DELETED.IsActive,INSERTED.IsActive,@SnapshotDate INTO #History(DatabaseID,Setting,OldValue,NewValue,ChangeDate)
	FROM dbo.Databases D 
	WHERE InstanceID = @InstanceID
	AND NOT EXISTS(SELECT 1 
			FROM @Databases T 
			WHERE D.name = T.name
			)
	AND D.IsActive=1;
	SET @Dropped = @@ROWCOUNT

	/* Update existing databases where settings have changed */
	UPDATE D SET [database_id] = T.database_id
		  ,[source_database_id] = T.source_database_id
		  ,[owner_sid] = T.owner_sid
		  ,[create_date] = T.create_date
		  ,[compatibility_level] = T.[compatibility_level]
		  ,[collation_name] = T.collation_name
		  ,[user_access] = T.user_access
		  ,[is_read_only] = T.is_read_only
		  ,[is_auto_close_on] = T.is_auto_close_on 
		  ,[is_auto_shrink_on] = T.is_auto_shrink_on
		  ,[state] = T.state
		  ,[is_in_standby] = T.is_in_standby
		  ,[is_cleanly_shutdown] = T.is_cleanly_shutdown
		  ,[is_supplemental_logging_enabled] = T.is_supplemental_logging_enabled
		  ,[snapshot_isolation_state] = T.snapshot_isolation_state
		  ,[is_read_committed_snapshot_on] = T.is_read_committed_snapshot_on
		  ,[recovery_model] = T.recovery_model
		  ,[page_verify_option] = T.page_verify_option
		  ,[is_auto_create_stats_on] = T.is_auto_create_stats_on
		  ,[is_auto_create_stats_incremental_on] = T.is_auto_create_stats_incremental_on
		  ,[is_auto_update_stats_on] = T.is_auto_update_stats_on
		  ,[is_auto_update_stats_async_on] = T.is_auto_update_stats_async_on
		  ,[is_ansi_null_default_on] = T.is_ansi_null_default_on
		  ,[is_ansi_nulls_on] = T.is_ansi_nulls_on
		  ,[is_ansi_padding_on] = T.is_ansi_padding_on
		  ,[is_ansi_warnings_on] = T.is_ansi_warnings_on
		  ,[is_arithabort_on] = T.is_arithabort_on
		  ,[is_concat_null_yields_null_on] = T.is_concat_null_yields_null_on
		  ,[is_numeric_roundabort_on] = T.is_numeric_roundabort_on
		  ,[is_quoted_identifier_on] = T.is_quoted_identifier_on
		  ,[is_recursive_triggers_on] = T.is_recursive_triggers_on
		  ,[is_cursor_close_on_commit_on] = T.is_cursor_close_on_commit_on
		  ,[is_local_cursor_default] = T.is_local_cursor_default
		  ,[is_fulltext_enabled] = T.is_fulltext_enabled
		  ,[is_trustworthy_on] = T.is_trustworthy_on
		  ,[is_db_chaining_on] = T.is_db_chaining_on
		  ,[is_parameterization_forced] = T.is_parameterization_forced
		  ,[is_master_key_encrypted_by_server] = T.is_master_key_encrypted_by_server
		  ,[is_query_store_on] = T.is_query_store_on
		  ,[is_published] = T.is_published
		  ,[is_subscribed] = T.is_subscribed
		  ,[is_merge_published] = T.is_merge_published
		  ,[is_distributor] = T.is_distributor
		  ,[is_sync_with_backup] = T.is_sync_with_backup
		  ,[is_broker_enabled] = T.is_broker_enabled
		  ,[log_reuse_wait] = T.log_reuse_wait
		  ,[is_date_correlation_on] = T.is_date_correlation_on
		  ,[is_cdc_enabled] = T.is_cdc_enabled
		  ,[is_encrypted] = T.is_encrypted
		  ,[is_honor_broker_priority_on] = T.is_honor_broker_priority_on
		  ,[replica_id] = T.replica_id
		  ,[group_database_id] = T.group_database_id
		  ,[resource_pool_id] = T.resource_pool_id
		  ,[default_language_lcid] = T.default_language_lcid
		  ,[default_language_name] = T.default_language_name
		  ,[default_fulltext_language_lcid] = T.default_fulltext_language_lcid
		  ,[default_fulltext_language_name] = T.default_fulltext_language_name
		  ,[is_nested_triggers_on] = T.is_nested_triggers_on
		  ,[is_transform_noise_words_on] = T.is_transform_noise_words_on
		  ,[two_digit_year_cutoff] = T.two_digit_year_cutoff
		  ,[containment] = T.containment
		  ,[target_recovery_time_in_seconds] = T.target_recovery_time_in_seconds
		  ,[delayed_durability] = T.delayed_durability
		  ,[is_memory_optimized_elevate_to_snapshot_on] = T.is_memory_optimized_elevate_to_snapshot_on
		  ,[is_federation_member] = T.is_federation_member
		  ,[is_remote_data_archive_enabled] = T.is_remote_data_archive_enabled
		  ,[is_mixed_page_allocation_on] = T.is_mixed_page_allocation_on
		  ,is_ledger_on = T.is_ledger_on
		  ,catalog_collation_type = T.catalog_collation_type
		  ,is_accelerated_database_recovery_on=T.is_accelerated_database_recovery_on
		  ,is_change_feed_enabled=T.is_change_feed_enabled
		  ,is_event_stream_enabled=T.is_event_stream_enabled
		  ,is_memory_optimized_enabled=T.is_memory_optimized_enabled
		  ,is_temporal_history_retention_enabled=T.is_temporal_history_retention_enabled
		  ,is_optimized_locking_on = T.is_optimized_locking_on
		  ,service_broker_guid = T.service_broker_guid
		  ,UpdatedDate = @SnapshotDate
	FROM dbo.Databases D
	JOIN @Databases T ON D.name = T.name
	WHERE D.InstanceID = @InstanceID
	AND EXISTS(SELECT 	   T.database_id,
						   T.source_database_id,
						   T.owner_sid,
						   T.create_date,
						   T.compatibility_level,
						   T.collation_name,
						   T.user_access,
						   T.is_read_only,
						   T.is_auto_close_on,
						   T.is_auto_shrink_on,
						   T.state,
						   T.is_in_standby,
						   T.is_cleanly_shutdown,
						   T.is_supplemental_logging_enabled,
						   T.snapshot_isolation_state,
						   T.is_read_committed_snapshot_on,
						   T.recovery_model,
						   T.page_verify_option,
						   T.is_auto_create_stats_on,
						   T.is_auto_create_stats_incremental_on,
						   T.is_auto_update_stats_on,
						   T.is_auto_update_stats_async_on,
						   T.is_ansi_null_default_on,
						   T.is_ansi_nulls_on,
						   T.is_ansi_padding_on,
						   T.is_ansi_warnings_on,
						   T.is_arithabort_on,
						   T.is_concat_null_yields_null_on,
						   T.is_numeric_roundabort_on,
						   T.is_quoted_identifier_on,
						   T.is_recursive_triggers_on,
						   T.is_cursor_close_on_commit_on,
						   T.is_local_cursor_default,
						   T.is_fulltext_enabled,
						   T.is_trustworthy_on,
						   T.is_db_chaining_on,
						   T.is_parameterization_forced,
						   T.is_master_key_encrypted_by_server,
						   T.is_query_store_on,
						   T.is_published,
						   T.is_subscribed,
						   T.is_merge_published,
						   T.is_distributor,
						   T.is_sync_with_backup,
						   T.is_broker_enabled,
						   T.log_reuse_wait,
						   T.is_date_correlation_on,
						   T.is_cdc_enabled,
						   T.is_encrypted,
						   T.is_honor_broker_priority_on,
						   T.replica_id,
						   T.group_database_id,
						   T.resource_pool_id,
						   T.default_language_lcid,
						   T.default_language_name,
						   T.default_fulltext_language_lcid,
						   T.default_fulltext_language_name,
						   T.is_nested_triggers_on,
						   T.is_transform_noise_words_on,
						   T.two_digit_year_cutoff,
						   T.containment,
						   T.target_recovery_time_in_seconds,
						   T.delayed_durability,
						   T.is_memory_optimized_elevate_to_snapshot_on,
						   T.is_federation_member,
						   T.is_remote_data_archive_enabled,
						   T.is_mixed_page_allocation_on ,
						   1, -- IsActive
						   T.is_ledger_on,
						   T.catalog_collation_type,
						   T.is_accelerated_database_recovery_on,
						   T.is_change_feed_enabled,
						   T.is_event_stream_enabled,
						   T.is_memory_optimized_enabled,
						   T.is_temporal_history_retention_enabled,
						   T.is_optimized_locking_on,
						   T.service_broker_guid
			EXCEPT
			SELECT 	   D.database_id,
						   D.source_database_id,
						   D.owner_sid,
						   D.create_date,
						   D.compatibility_level,
						   D.collation_name,
						   D.user_access,
						   D.is_read_only,
						   D.is_auto_close_on,
						   D.is_auto_shrink_on,
						   D.state,
						   D.is_in_standby,
						   D.is_cleanly_shutdown,
						   D.is_supplemental_logging_enabled,
						   D.snapshot_isolation_state,
						   D.is_read_committed_snapshot_on,
						   D.recovery_model,
						   D.page_verify_option,
						   D.is_auto_create_stats_on,
						   D.is_auto_create_stats_incremental_on,
						   D.is_auto_update_stats_on,
						   D.is_auto_update_stats_async_on,
						   D.is_ansi_null_default_on,
						   D.is_ansi_nulls_on,
						   D.is_ansi_padding_on,
						   D.is_ansi_warnings_on,
						   D.is_arithabort_on,
						   D.is_concat_null_yields_null_on,
						   D.is_numeric_roundabort_on,
						   D.is_quoted_identifier_on,
						   D.is_recursive_triggers_on,
						   D.is_cursor_close_on_commit_on,
						   D.is_local_cursor_default,
						   D.is_fulltext_enabled,
						   D.is_trustworthy_on,
						   D.is_db_chaining_on,
						   D.is_parameterization_forced,
						   D.is_master_key_encrypted_by_server,
						   D.is_query_store_on,
						   D.is_published,
						   D.is_subscribed,
						   D.is_merge_published,
						   D.is_distributor,
						   D.is_sync_with_backup,
						   D.is_broker_enabled,
						   D.log_reuse_wait,
						   D.is_date_correlation_on,
						   D.is_cdc_enabled,
						   D.is_encrypted,
						   D.is_honor_broker_priority_on,
						   D.replica_id,
						   D.group_database_id,
						   D.resource_pool_id,
						   D.default_language_lcid,
						   D.default_language_name,
						   D.default_fulltext_language_lcid,
						   D.default_fulltext_language_name,
						   D.is_nested_triggers_on,
						   D.is_transform_noise_words_on,
						   D.two_digit_year_cutoff,
						   D.containment,
						   D.target_recovery_time_in_seconds,
						   D.delayed_durability,
						   D.is_memory_optimized_elevate_to_snapshot_on,
						   D.is_federation_member,
						   D.is_remote_data_archive_enabled,
						   D.is_mixed_page_allocation_on ,
						   D.IsActive,
						   D.is_ledger_on,
						   D.catalog_collation_type,
						   D.is_accelerated_database_recovery_on,
						   D.is_change_feed_enabled,
						   D.is_event_stream_enabled,
						   D.is_memory_optimized_enabled,
						   D.is_temporal_history_retention_enabled,
						   D.is_optimized_locking_on,
						   D.service_broker_guid
						   )
	/* Capture history if settings have been updated */
	IF @@ROWCOUNT>0
	BEGIN
		DECLARE @NewSettings TABLE(
			DatabaseID INT NOT NULL,
			Setting sysname NOT NULL,
			Value SQL_VARIANT NULL,
			is_in_standby BIT NULL
		);
		INSERT INTO @NewSettings(
			DatabaseID,
			Setting,
			Value,
			is_in_standby
		)
		SELECT 	DatabaseID,
			Setting,
			Value,
			is_in_standby   
		FROM dbo.DatabaseSettingsUnpivot_Get(@InstanceID)

		INSERT INTO #History(DatabaseID,Setting,OldValue,NewValue,ChangeDate)
		SELECT o.DatabaseID,o.Setting,o.Value,n.Value,@SnapshotDate AS ChangeDate 
		FROM @OldSettings o
		JOIN @NewSettings n ON o.DatabaseID = n.DatabaseID AND o.Setting = n.Setting
		WHERE NOT EXISTS(SELECT o.Value 
						INTERSECT
						SELECT n.Value)
		AND NOT (o.Setting<>'is_read_only' AND n.is_in_standby=1 AND n.Value=1)
		AND NOT (o.Setting<>'is_read_only' AND o.is_in_standby=1 AND o.Value=1)
		AND NOT (o.Setting='state' AND n.Value IN(0,1,2,3) AND o.Value IN(0,1,2,3));
	END

	/* Handle databases being re-created or restored */
	UPDATE D 
		SET D.IsActive = 1,
		D.UpdatedDate = SYSUTCDATETIME()
	OUTPUT INSERTED.DatabaseID, 'IsActive',DELETED.IsActive,INSERTED.IsActive,@SnapshotDate INTO #History(DatabaseID,Setting,OldValue,NewValue,ChangeDate)
	FROM dbo.Databases D
	JOIN @Databases T ON D.name = T.name
	WHERE D.InstanceID = @InstanceID
	AND D.IsActive=0;
	SET @Created = @@ROWCOUNT

	/* Handle new databases */
	INSERT INTO dbo.Databases (
			InstanceID,
			name,
		   database_id,
		   source_database_id,
		   owner_sid,
		   create_date,
		   compatibility_level,
		   collation_name,
		   user_access,
		   is_read_only,
		   is_auto_close_on,
		   is_auto_shrink_on,
		   state,
		   is_in_standby,
		   is_cleanly_shutdown,
		   is_supplemental_logging_enabled,
		   snapshot_isolation_state,
		   is_read_committed_snapshot_on,
		   recovery_model,
		   page_verify_option,
		   is_auto_create_stats_on,
		   is_auto_create_stats_incremental_on,
		   is_auto_update_stats_on,
		   is_auto_update_stats_async_on,
		   is_ansi_null_default_on,
		   is_ansi_nulls_on,
		   is_ansi_padding_on,
		   is_ansi_warnings_on,
		   is_arithabort_on,
		   is_concat_null_yields_null_on,
		   is_numeric_roundabort_on,
		   is_quoted_identifier_on,
		   is_recursive_triggers_on,
		   is_cursor_close_on_commit_on,
		   is_local_cursor_default,
		   is_fulltext_enabled,
		   is_trustworthy_on,
		   is_db_chaining_on,
		   is_parameterization_forced,
		   is_master_key_encrypted_by_server,
		   is_query_store_on,
		   is_published,
		   is_subscribed,
		   is_merge_published,
		   is_distributor,
		   is_sync_with_backup,
		   is_broker_enabled,
		   log_reuse_wait,
		   is_date_correlation_on,
		   is_cdc_enabled,
		   is_encrypted,
		   is_honor_broker_priority_on,
		   replica_id,
		   group_database_id,
		   resource_pool_id,
		   default_language_lcid,
		   default_language_name,
		   default_fulltext_language_lcid,
		   default_fulltext_language_name,
		   is_nested_triggers_on,
		   is_transform_noise_words_on,
		   two_digit_year_cutoff,
		   containment,
		   target_recovery_time_in_seconds,
		   delayed_durability,
		   is_memory_optimized_elevate_to_snapshot_on,
		   is_federation_member,
		   is_remote_data_archive_enabled,
		   is_mixed_page_allocation_on ,
		   IsActive,
		   is_ledger_on,
		   catalog_collation_type,
		   is_accelerated_database_recovery_on,
		   is_change_feed_enabled,
		   is_event_stream_enabled,
		   is_memory_optimized_enabled,
		   is_temporal_history_retention_enabled,
		   is_optimized_locking_on,
		   service_broker_guid
	)
	SELECT  @InstanceID,
			name,
		   database_id,
		   source_database_id,
		   owner_sid,
		   create_date,
		   compatibility_level,
		   collation_name,
		   user_access,
		   is_read_only,
		   is_auto_close_on,
		   is_auto_shrink_on,
		   state,
		   is_in_standby,
		   is_cleanly_shutdown,
		   is_supplemental_logging_enabled,
		   snapshot_isolation_state,
		   is_read_committed_snapshot_on,
		   recovery_model,
		   page_verify_option,
		   is_auto_create_stats_on,
		   is_auto_create_stats_incremental_on,
		   is_auto_update_stats_on,
		   is_auto_update_stats_async_on,
		   is_ansi_null_default_on,
		   is_ansi_nulls_on,
		   is_ansi_padding_on,
		   is_ansi_warnings_on,
		   is_arithabort_on,
		   is_concat_null_yields_null_on,
		   is_numeric_roundabort_on,
		   is_quoted_identifier_on,
		   is_recursive_triggers_on,
		   is_cursor_close_on_commit_on,
		   is_local_cursor_default,
		   is_fulltext_enabled,
		   is_trustworthy_on,
		   is_db_chaining_on,
		   is_parameterization_forced,
		   is_master_key_encrypted_by_server,
		   is_query_store_on,
		   is_published,
		   is_subscribed,
		   is_merge_published,
		   is_distributor,
		   is_sync_with_backup,
		   is_broker_enabled,
		   log_reuse_wait,
		   is_date_correlation_on,
		   is_cdc_enabled,
		   is_encrypted,
		   is_honor_broker_priority_on,
		   replica_id,
		   group_database_id,
		   resource_pool_id,
		   default_language_lcid,
		   default_language_name,
		   default_fulltext_language_lcid,
		   default_fulltext_language_name,
		   is_nested_triggers_on,
		   is_transform_noise_words_on,
		   two_digit_year_cutoff,
		   containment,
		   target_recovery_time_in_seconds,
		   delayed_durability,
		   is_memory_optimized_elevate_to_snapshot_on,
		   is_federation_member,
		   is_remote_data_archive_enabled,
		   is_mixed_page_allocation_on ,
		   CAST(1 as BIT),
		   is_ledger_on,
		   catalog_collation_type,
		   is_accelerated_database_recovery_on,
		   is_change_feed_enabled,
		   is_event_stream_enabled,
		   is_memory_optimized_enabled,
		   is_temporal_history_retention_enabled,
		   is_optimized_locking_on,
		   service_broker_guid
	FROM @Databases T
	WHERE NOT EXISTS(SELECT 1 
					FROM dbo.Databases D 
					WHERE D.InstanceID = @InstanceID 
					AND D.name = T.name
					)

	SET @Created += @@ROWCOUNT

	/* Capture history */
	INSERT INTO dbo.DBOptionsHistory(DatabaseID,Setting,OldValue,NewValue,ChangeDate)
	SELECT DatabaseID,Setting,OldValue,NewValue,ChangeDate
	FROM #History

	/* Capture metrics if enabled */
	IF EXISTS(
		SELECT 1 
		FROM dbo.RepositoryMetricsConfig 
		WHERE InstanceID = @MetricsInstanceID
		AND MetricType='Databases'
		AND IsEnabled=1
	)
	-- Exclude Azure DB
	AND NOT EXISTS(
		SELECT 1 
		FROM dbo.Instances 
		WHERE EngineEdition=5 
		AND InstanceID = @InstanceID
	)
	BEGIN
		/* Log a metric for user database count */
		DECLARE @UserDatabases INT
		SELECT @UserDatabases = COUNT(*) 
		FROM @Databases
		WHERE database_id > 4;

		DECLARE @PC dbo.PerformanceCounters;

		WITH Metrics AS (
			SELECT @SnapshotDate AS SnapshotDate,'sys.databases' AS object_name,'Count of User Databases' AS counter_name,'' AS instance_name,@UserDatabases AS cntr_value,65792 AS cntr_type
			UNION ALL
			SELECT @SnapshotDate,'sys.databases','Databases Created','',@Created,65792
			UNION ALL
			SELECT @SnapshotDate,'sys.databases','Databases Dropped','',@Dropped,65792
		)
		INSERT INTO @PC(SnapshotDate,object_name,counter_name,instance_name,cntr_value,cntr_type)
		SELECT SnapshotDate,object_name,counter_name,instance_name,cntr_value,cntr_type
		FROM Metrics 
		WHERE EXISTS(
				SELECT 1 
				FROM dbo.RepositoryMetricsConfig 
				WHERE InstanceID = @MetricsInstanceID 
				AND MetricType='Databases'
				AND MetricName =Metrics.counter_name
				AND IsEnabled=1
				)

		EXEC dbo.PerformanceCounters_Upd @PerformanceCounters=@PC,
										@InstanceID = @InstanceID,
										@SnapshotDate=@SnapshotDate,
										@Internal=1 /* Don't clear staging table used for other metric types */

	END

	COMMIT

	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
									 @Reference = @Ref,
									 @SnapshotDate = @SnapshotDate
END
GO
PRINT N'Creating Procedure [dbo].[DatabasesHADR_Upd]...';


GO
CREATE PROC dbo.DatabasesHADR_Upd(
		@DatabasesHADR DatabasesHADR READONLY,
		@InstanceID INT,
		@SnapshotDate DATETIME2(2)
)
AS
SET XACT_ABORT ON;
DECLARE @Ref VARCHAR(30)='DatabasesHADR'
IF NOT EXISTS(	SELECT 1 
				FROM dbo.CollectionDates 
				WHERE SnapshotDate>=@SnapshotDate 
				AND InstanceID = @InstanceID 
				AND Reference=@Ref
			 )
BEGIN
	BEGIN TRAN;

	DELETE hadr
	FROM dbo.DatabasesHADR hadr
	WHERE InstanceID = @InstanceID

	INSERT INTO dbo.DatabasesHADR
	(
		InstanceID,
		DatabaseID,
		group_database_id,
		is_primary_replica,
		synchronization_state,
		synchronization_health,
		is_suspended,
		suspend_reason,
		replica_id,
		group_id,
		is_commit_participant,
		database_state,
		is_local,
		secondary_lag_seconds,
		last_sent_time,
		last_received_time,
		last_hardened_time,
		last_redone_time,
		log_send_queue_size,
		log_send_rate,
		redo_queue_size,
		redo_rate,	
		filestream_send_rate,
		last_commit_time
	)
	SELECT @InstanceID,
		   d.DatabaseID,
		   hadr.group_database_id,
		   hadr.is_primary_replica,
		   hadr.synchronization_state,
		   hadr.synchronization_health,
		   hadr.is_suspended,
		   hadr.suspend_reason,
		   ISNULL(hadr.replica_id,'00000000-0000-0000-0000-000000000000'),
		   hadr.group_id,
		   hadr.is_commit_participant,
		   hadr.database_state,
		   hadr.is_local,
		   hadr.secondary_lag_seconds,
		   hadr.last_sent_time,
		   hadr.last_received_time,
		   hadr.last_hardened_time,
		   hadr.last_redone_time,
		   hadr.log_send_queue_size,
		   hadr.log_send_rate,
		   hadr.redo_queue_size,
		   hadr.redo_rate,	
		   hadr.filestream_send_rate,
		   hadr.last_commit_time
	FROM @DatabasesHADR hadr
		JOIN dbo.Databases d ON hadr.database_id = d.database_id
	WHERE d.InstanceID = @InstanceID
	AND d.IsActive=1;

	EXEC dbo.CollectionDates_Upd @InstanceID = @InstanceID,  
										 @Reference = @Ref,
										 @SnapshotDate = @SnapshotDate
	COMMIT;

	DECLARE @MetricsInstanceID INT 
	SELECT @MetricsInstanceID = CASE WHEN EXISTS(SELECT 1 FROM dbo.RepositoryMetricsConfig WHERE InstanceID = @InstanceID AND MetricType='AG') THEN @InstanceID ELSE -1 END

	DECLARE @PerformanceCounters dbo.PerformanceCounters
	IF EXISTS(SELECT 1 
			FROM dbo.RepositoryMetricsConfig 
			WHERE IsEnabled = 1
			AND IsAggregate = 1
			AND InstanceID = @MetricsInstanceID
			)
	BEGIN
		INSERT INTO @PerformanceCounters(
			SnapshotDate,
			object_name,
			counter_name,
			instance_name,
			cntr_value,
			cntr_type
		)
		SELECT	@SnapshotDate,
				'Availability Group Metrics',
				UNPVT.counter_name,
				'',
				UNPVT.cntr_value,
				65792 AS cntr_type
		FROM (	SELECT	CAST(MAX(CASE WHEN HADR.is_primary_replica = 1 THEN -1 WHEN HADR.synchronization_state=2 THEN 0 ELSE ISNULL(DATEDIFF(ss, HADR.last_commit_time, PrimaryHADR.last_commit_time), -2) END) AS DECIMAL(28,9)) [Max Estimated Data Loss (sec)],
						CAST(MAX(CASE WHEN HADR.is_primary_replica = 1 THEN -1 WHEN HADR.redo_queue_size IS NULL THEN -2 WHEN HADR.redo_queue_size = 0 THEN 0 WHEN HADR.redo_rate IS NULL OR HADR.redo_rate = 0 THEN -2 ELSE CAST(HADR.redo_queue_size AS DECIMAL(28,9)) / HADR.redo_rate END) AS DECIMAL(28,9)) AS [Max Estimated Recovery Time (sec)],
						CAST(MAX(HADR.secondary_lag_seconds) AS DECIMAL(28,9)) AS [Max Secondary Lag (sec)],
						CAST(SUM(HADR.redo_queue_size) AS DECIMAL(28,9)) AS [Total Redo Queue Size (KB)],
						CAST(AVG(HADR.redo_queue_size) AS DECIMAL(28,9)) AS [Avg Redo Queue Size (KB)],
						CAST(SUM(HADR.log_send_queue_size) AS DECIMAL(28,9)) AS [Total Log Send Queue Size (KB)],
						CAST(AVG(HADR.log_send_queue_size) AS DECIMAL(28,9)) AS [Avg Log Send Queue Size (KB)]
				FROM @DatabasesHADR HADR
				LEFT JOIN @DatabasesHADR PrimaryHADR ON PrimaryHADR.group_database_id = HADR.group_database_id 
											 AND PrimaryHADR.is_primary_replica = 1
											 AND PrimaryHADR.is_local = 1     
				) HA
		UNPIVOT(cntr_value
				FOR counter_name IN([Max Estimated Data Loss (sec)],
									[Max Estimated Recovery Time (sec)],
									[Max Secondary Lag (sec)],
									[Total Redo Queue Size (KB)],
									[Avg Redo Queue Size (KB)],
									[Total Log Send Queue Size (KB)],
									[Avg Log Send Queue Size (KB)]
									)
		) UNPVT
		WHERE EXISTS(	SELECT 1 
						FROM dbo.RepositoryMetricsConfig M
						WHERE M.MetricName = UNPVT.counter_name
						AND M.IsEnabled = 1
						AND M.IsAggregate = 1
						AND M.InstanceID = @MetricsInstanceID
						AND M.MetricType = 'AG'
					)
	END
	IF EXISTS(SELECT 1 
			FROM dbo.RepositoryMetricsConfig 
			WHERE IsEnabled = 1
			AND IsAggregate = 0
			)
	BEGIN	
		INSERT INTO @PerformanceCounters(
			SnapshotDate,
			object_name,
			counter_name,
			instance_name,
			cntr_value,
			cntr_type
		)
		SELECT	@SnapshotDate,
				'Availability Group Metrics',
				UNPVT.counter_name,
				UNPVT.instance_name,
				UNPVT.cntr_value,
				65792 AS cntr_type
		FROM (	SELECT	CASE WHEN HADR.is_local=1 THEN '' ELSE AR.replica_server_name + ' \ ' END + D.name AS instance_name,
						CAST(CASE WHEN HADR.is_primary_replica = 1 THEN NULL WHEN HADR.synchronization_state=2 THEN 0 ELSE ISNULL(DATEDIFF(ss, HADR.last_commit_time, PrimaryHADR.last_commit_time), -2) END AS DECIMAL(28,9)) [Estimated Data Loss (sec)],
						CAST(CASE WHEN HADR.is_primary_replica = 1 THEN NULL WHEN HADR.redo_queue_size IS NULL THEN -2 WHEN HADR.redo_queue_size = 0 THEN 0 WHEN HADR.redo_rate IS NULL OR HADR.redo_rate = 0 THEN -2 ELSE CAST(HADR.redo_queue_size AS DECIMAL(28,9)) / HADR.redo_rate END AS DECIMAL(28,9)) AS [Estimated Recovery Time (sec)],
						CAST(HADR.secondary_lag_seconds AS DECIMAL(28,9)) AS [Secondary Lag (sec)],
						CAST(HADR.redo_queue_size AS DECIMAL(28,9)) AS [Redo Queue Size (KB)],
						CAST(HADR.log_send_queue_size AS DECIMAL(28,9)) AS [Log Send Queue Size (KB)]
				FROM @DatabasesHADR HADR
				JOIN dbo.Databases D ON HADR.database_id = D.database_id AND D.InstanceID = @InstanceID AND D.IsActive = 1
				JOIN dbo.AvailabilityReplicas AR ON AR.InstanceID = @InstanceID AND AR.replica_id = HADR.replica_id
				LEFT JOIN @DatabasesHADR PrimaryHADR ON PrimaryHADR.group_database_id = HADR.group_database_id 
											 AND PrimaryHADR.is_primary_replica = 1
											 AND PrimaryHADR.is_local = 1     
				) HA
		UNPIVOT(cntr_value
				FOR counter_name IN([Estimated Data Loss (sec)],
									[Estimated Recovery Time (sec)],
									[Secondary Lag (sec)],
									[Redo Queue Size (KB)],
									[Log Send Queue Size (KB)]
									)
		) UNPVT
		WHERE EXISTS(	SELECT 1 
						FROM dbo.RepositoryMetricsConfig M
						WHERE M.MetricName = UNPVT.counter_name
						AND M.IsEnabled = 1
						AND M.IsAggregate = 0
						AND M.InstanceID = @MetricsInstanceID
						AND M.MetricType = 'AG'
					)
	END
	IF EXISTS(SELECT 1 FROM @PerformanceCounters)
	BEGIN
		EXEC dbo.PerformanceCounters_Upd @PerformanceCounters=@PerformanceCounters,
									@InstanceID = @InstanceID,
									@SnapshotDate=@SnapshotDate,
									@Internal=1 /* Don't clear staging table used for other metric types */
	END
END
GO
PRINT N'Creating Procedure [dbo].[Deadlocks_Get]...';


GO
CREATE PROC dbo.Deadlocks_Get(
	@InstanceID INT,
	@FromDate DATETIME2(2),
	@ToDate DATETIME2(2),
	@DateGroupingMin INT=NULL,
	@Use60Min BIT=NULL,
	@Debug BIT=0
)
AS
SET NOCOUNT ON
DECLARE @DateGroupingSQL NVARCHAR(MAX)
DECLARE @SQL NVARCHAR(MAX)
SELECT @DateGroupingSQL= CASE WHEN @DateGroupingMin = 0 OR @DateGroupingMin IS NULL THEN 'Deadlocks.SnapshotDate'
			ELSE 'DG.DateGroup' END
SELECT @Use60Min = CASE WHEN @Use60Min IS NOT NULL THEN @Use60Min WHEN @DateGroupingMin>=60 THEN 1 ELSE 0 END


SET @SQL = N'
WITH Deadlocks AS (
	SELECT  PC.SnapshotDate,
			/* Convert deadlocks/sec to deadlock count */
			CAST(ROUND((' + CASE WHEN @Use60Min=1 THEN '(PC.Value_Total/PC.SampleCount)' ELSE 'PC.value' END + ' * (DATEDIFF(ms,LAG(PC.SnapshotDate) OVER (ORDER BY PC.SnapshotDate),PC.SnapshotDate)/1000.0)),0) AS BIGINT) AS DeadlockCount
	FROM dbo.PerformanceCounters' + CASE WHEN @Use60Min=1 THEN '_60MIN' ELSE '' END + ' PC
	JOIN dbo.Counters C ON PC.CounterID = C.CounterID
	WHERE PC.SnapshotDate >= @FromDate 
	AND PC.SnapshotDate < @ToDate
	AND PC.InstanceID = @InstanceID
	AND C.counter_name = ''Number of Deadlocks/sec''
	AND C.object_name = ''Locks''
	AND C.instance_name = ''_Total''
)
SELECT ' + @DateGroupingSQL + ' AS SnapshotDate,
		SUM(DeadlockCount) AS DeadlockCount
FROM Deadlocks
' + CASE WHEN @DateGroupingMin = 0 OR @DateGroupingMin IS NULL THEN '' ELSE 'CROSS APPLY dbo.DateGroupingMins(Deadlocks.SnapshotDate,@DateGroupingMin) DG' END + '
WHERE DeadlockCount IS NOT NULL
GROUP BY ' + @DateGroupingSQL + '
ORDER BY SnapshotDate DESC'

IF @Debug=1
BEGIN
	EXEC dbo.PrintMax @SQL
END

EXEC sp_executesql @SQL, N'@InstanceID INT, @FromDate DATETIME2(2), @ToDate DATETIME2(2), @DateGroupingMin INT', @InstanceID, @FromDate, @ToDate, @DateGroupingMin
GO
PRINT N'Creating Procedure [dbo].[Instance_Del]...';


GO
CREATE PROC dbo.Instance_Del(
	@InstanceID INT=NULL,
	@ConnectionID NVARCHAR(128)=NULL,
	@IsActive BIT=0,
	@HardDelete BIT=0
)
AS
SET NOCOUNT ON
SET XACT_ABORT ON
IF @InstanceID IS NULL AND @ConnectionID IS NULL
BEGIN
	RAISERROR('InstanceID or ConnectionID must be provided',11,1)
	RETURN
END
ELSE IF @InstanceID IS NULL
BEGIN
	SELECT @InstanceID = InstanceID
	FROM dbo.Instances
	WHERE ConnectionID = @ConnectionID

	IF @InstanceID IS NULL
	BEGIN
		RAISERROR('Instance not found',11,1)
		RETURN
	END
END

IF @HardDelete = 0
BEGIN
	UPDATE dbo.Instances
	SET IsActive=@IsActive
	WHERE InstanceID = @InstanceID
END
ELSE
BEGIN
	IF EXISTS(SELECT 1 FROM dbo.Instances WHERE InstanceID = @InstanceID AND IsActive=1)
	BEGIN
		RAISERROR('Mark Instance IsActive=0 before delete',11,1)
		RETURN
	END
	IF EXISTS(
		SELECT * 
		FROM dbo.CollectionDates 
		WHERE InstanceID=@InstanceID
		AND SnapshotDate>=DATEADD(d,-1,GETUTCDATE())
		)
	BEGIN 
		RAISERROR('The instance can''t be deleted at this time.  Please wait 24hrs after removing the collection.',11,1)
		RETURN
	END

	DELETE dbo.AgentJobThresholds
	WHERE InstanceID = @InstanceID

	DELETE dbo.Alerts
	WHERE InstanceID=@InstanceID

	DELETE dbo.AvailabilityGroups
	WHERE InstanceID = @InstanceID

	DELETE dbo.AvailabilityReplicas
	WHERE InstanceID = @InstanceID

	DELETE dbo.AzureDBDTULimitChange
	WHERE InstanceID = @InstanceID

	DELETE EPH 
	FROM dbo.AzureDBElasticPoolHistory EPH
	WHERE EXISTS(SELECT 1 
				FROM dbo.AzureDBElasticPool EP
				WHERE EP.InstanceID = @InstanceID
				AND EP.PoolID = EPH.PoolID
				)

	DELETE EPT
	FROM dbo.AzureDBElasticPoolStorageThresholds EPT
	WHERE EXISTS(SELECT 1 
				FROM dbo.AzureDBElasticPool EP
				WHERE EP.InstanceID = @InstanceID
				AND EP.PoolID = EPT.PoolID
				)
	EXEC dbo.AzureDBElasticPoolResourceStats_Del @InstanceID =@InstanceID,@DaysToKeep=0
	EXEC dbo.AzureDBElasticPoolResourceStats_60MIN_Del @InstanceID =@InstanceID,@DaysToKeep=0

	DELETE dbo.AzureDBResourceGovernanceHistory
	WHERE InstanceID = @InstanceID

	DELETE dbo.AzureDBElasticPool
	WHERE InstanceID= @InstanceID

	EXEC dbo.AzureDBResourceStats_Del @InstanceID =@InstanceID,@DaysToKeep=0
	EXEC dbo.AzureDBResourceStats_60MIN_Del @InstanceID =@InstanceID,@DaysToKeep=0

	DELETE dbo.AzureDBServiceObjectives 
	WHERE InstanceID = @InstanceID

	DELETE dbo.AzureDBServiceObjectivesHistory 
	WHERE InstanceID = @InstanceID

	DELETE B 
	FROM dbo.Backups B
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = B.DatabaseID
				)

	DELETE dbo.BackupThresholds
	WHERE InstanceID = @InstanceID

	EXEC dbo.BlockingSnapshotSummary_Del @InstanceID =@InstanceID,@DaysToKeep=0

	DELETE dbo.CollectionDates
	WHERE InstanceID = @InstanceID

	DELETE dbo.CollectionDatesThresholds
	WHERE InstanceID = @InstanceID

	DELETE dbo.CollectionErrorLog
	WHERE InstanceID= @InstanceID

	DELETE C 
	FROM dbo.Corruption C
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = C.DatabaseID
				)


	EXEC dbo.CPU_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.CPU_60MIN_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.CustomChecks
	WHERE InstanceID = @InstanceID

	DELETE dbo.CustomChecksHistory
	WHERE InstanceID= @InstanceID

	DELETE dbo.DatabaseMirroring 
	WHERE InstanceID = @InstanceID

	DELETE DP 
	FROM dbo.DatabasePermissions DP
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DP.DatabaseID
				)

	DELETE DP 
	FROM dbo.DatabasePrincipals DP
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DP.DatabaseID
				)

	DELETE DQS
	FROM dbo.DatabaseQueryStoreOptions DQS
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DQS.DatabaseID
				)

	DELETE DRM 
	FROM dbo.DatabaseRoleMembers DRM
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DRM.DatabaseID
				)


	DELETE HADR 
	FROM dbo.DatabasesHADR HADR
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = HADR.DatabaseID
				)

	DELETE DC
	FROM dbo.DBConfig DC
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DC.DatabaseID
				)

	DELETE DCH
	FROM dbo.DBConfigHistory DCH
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DCH.DatabaseID
				)

	EXEC dbo.DBFileSnapshot_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.DBFileThresholds
	WHERE InstanceID = @InstanceID

	DELETE F
	FROM dbo.DBFiles F
	WHERE F.InstanceID = @InstanceID

	DELETE DOH
	FROM dbo.DBOptionsHistory DOH
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DOH.DatabaseID
				)

	DELETE dbo.DBTuningOptions 
	WHERE InstanceID =@InstanceID

	DELETE dbo.DBTuningOptionsHistory
	WHERE InstanceID = @InstanceID


	DELETE DDLH
	FROM dbo.DDLHistory DDLH
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DDLH.DatabaseID
				)

	DELETE DSS 
	FROM dbo.DDLSnapshots DSS
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DSS.DatabaseID
				)

	DELETE DSSL 
	FROM dbo.DDLSnapshotsLog DSSL
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DSSL.DatabaseID
				)

	DELETE dbo.LogRestoreThresholds
	WHERE InstanceID = @InstanceID

	DELETE LR 
	FROM dbo.LogRestores LR
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = LR.DatabaseID
				)

	DELETE dbo.JobSteps
	WHERE InstanceID = @InstanceID

	DELETE dbo.JobHistory 
	WHERE InstanceID = @InstanceID

	DELETE 
	FROM dbo.Jobs
	WHERE InstanceID = @InstanceID

	DELETE dbo.JobDDLHistory
	WHERE InstanceID = @InstanceID

	SELECT DDLID 
	INTO #DDLToDelete
	FROM dbo.DDL 
	WHERE NOT EXISTS(
			SELECT 1 
			FROM dbo.DDLHistory H
			WHERE H.DDLID = DDL.DDLID
			UNION ALL 
			SELECT 1 
			FROM dbo.Jobs J
			WHERE J.DDLID = DDL.DDLID
			UNION ALL 
			SELECT 1
			FROM dbo.JobDDLHistory H
			WHERE H.DDLID = DDL.DDLID
			)

	DELETE D 
	FROM dbo.DDL D
	WHERE EXISTS(
				SELECT 1 
				FROM #DDLToDelete T
				WHERE T.DDLID = D.DDLID
				)


	EXEC dbo.DBIOStats_Del @InstanceID=@InstanceID,@DaysToKeep=0
	EXEC dbo.DBIOStats_60MIN_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.Drivers WHERE InstanceID = @InstanceID

	DELETE dbo.DriversHistory WHERE InstanceID = @InstanceID 

	EXEC dbo.DriveSnapshot_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.DriveThresholds 
	WHERE InstanceID = @InstanceID

	DELETE dbo.Drives 
	WHERE InstanceID = @InstanceID

	DELETE dbo.HostUpgradeHistory 
	WHERE InstanceID = @InstanceID

	DELETE dbo.InstanceCounters
	WHERE InstanceID = @InstanceID

	DECLARE @DeletedTags TABLE(
		TagID INT
	)
	
	BEGIN TRAN
	
	DELETE dbo.InstanceIDsTags
	OUTPUT DELETED.TagID INTO @DeletedTags
	WHERE InstanceID = @InstanceID 

	DELETE T
	FROM dbo.Tags T
	WHERE EXISTS(SELECT 1 
				FROM @DeletedTags D
				WHERE D.TagID = T.TagID
				)
	AND NOT EXISTS(SELECT 1 
				FROM dbo.InstanceIDsTags I
				WHERE I.TagID = T.TagID
				)
	COMMIT

	DELETE dbo.InstanceUptimeThresholds
	WHERE InstanceID = @InstanceID

	EXEC dbo.JobStats_60MIN_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.LastGoodCheckDBThresholds
	WHERE InstanceID = @InstanceID 

	EXEC dbo.MemoryUsage_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.ObjectExecutionStats_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.ObjectExecutionStats_60MIN_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE DO
	FROM dbo.DBObjects DO
	WHERE EXISTS(
				SELECT 1 
				FROM dbo.Databases D
				WHERE D.InstanceID = @InstanceID
				AND D.DatabaseID = DO.DatabaseID
				)


	DELETE dbo.OSLoadedModules 
	WHERE InstanceID = @InstanceID

	EXEC dbo.PerformanceCounters_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.PerformanceCounters_60MIN_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.ResourceGovernorConfigurationHistory
	WHERE InstanceID = @InstanceID

	EXEC dbo.RunningQueries_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.RunningQueriesSummary_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.ServerPermissions
	WHERE InstanceID = @InstanceID

	DELETE dbo.ServerPrincipals
	WHERE InstanceID = @InstanceID 

	DELETE dbo.ServerRoleMembers
	WHERE InstanceID = @InstanceID

	EXEC dbo.SessionWaits_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.SlowQueries_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.SlowQueriesStats_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.SQLPatchingHistory WHERE InstanceID = @InstanceID

	DELETE dbo.SysConfig
	WHERE InstanceID = @InstanceID 

	DELETE dbo.SysConfigHistory
	WHERE InstanceID = @InstanceID 

	DELETE dbo.TraceFlagHistory
	WHERE InstanceID = @InstanceID 

	DELETE dbo.TraceFlags
	WHERE InstanceID = @InstanceID

	EXEC dbo.Waits_Del @InstanceID=@InstanceID,@DaysToKeep=0

	EXEC dbo.Waits_60MIN_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.IdentityColumnsHistory 
	WHERE InstanceID = @InstanceID

	DELETE dbo.IdentityColumns 
	WHERE InstanceID = @InstanceID

	DELETE dbo.Databases 
	WHERE InstanceID = @InstanceID

	DELETE Staging.Waits
	WHERE InstanceID = @InstanceID

	DELETE Staging.ObjectExecutionStats
	WHERE InstanceID = @InstanceID
	
	DELETE Staging.IOStats
	WHERE InstanceID = @InstanceID

	DELETE Staging.PerformanceCounters
	WHERE InstanceID = @InstanceID	

	DELETE dbo.RunningJobs
	WHERE InstanceID = @InstanceID

	DELETE dbo.ServerServices
	WHERE InstanceID = @InstanceID

	DELETE CTK 
	FROM Alert.CustomThreadKey CTK
	WHERE EXISTS(
				SELECT 1 
				FROM Alert.ActiveAlerts AA
				WHERE AA.InstanceID = @InstanceID
				AND AA.AlertID = CTK.AlertID
				)

	DELETE NL 
	FROM Alert.NotificationLog NL
	WHERE EXISTS(
				SELECT 1 
				FROM Alert.ActiveAlerts AA
				WHERE AA.InstanceID = @InstanceID
				AND AA.AlertID = NL.AlertID
				)

	DELETE Alert.ActiveAlerts
	WHERE InstanceID = @InstanceID 

	DELETE Alert.ClosedAlerts 
	WHERE InstanceID = @InstanceID

	DELETE Alert.BlackoutPeriod
	WHERE ApplyToInstanceID = @InstanceID

	DELETE Alert.Rules
	WHERE ApplyToInstanceID = @InstanceID

	DELETE dbo.OfflineInstances
	WHERE InstanceID = @InstanceID

	DELETE dbo.RepositoryMetricsConfig
	WHERE InstanceID = @InstanceID

	DELETE dbo.InstanceMetadata
	WHERE InstanceID = @InstanceID

	EXEC dbo.ResourceGovernorWorkloadGroupsMetrics_Del @InstanceID=@InstanceID,@DaysToKeep=0
	
	EXEC dbo.ResourceGovernorResourcePoolsMetrics_Del @InstanceID=@InstanceID,@DaysToKeep=0

	DELETE dbo.ResourceGovernorWorkloadGroups 
	WHERE InstanceID = @InstanceID

	DELETE dbo.ResourceGovernorResourcePools 
	WHERE InstanceID = @InstanceID

	IF EXISTS(SELECT 1 
			FROM dbo.InstanceMetadataHistory
			WHERE InstanceID = @InstanceID)
	BEGIN
		/* System versioning needs to be turned off on InstanceMetadata to allow us to remove data from InstanceMetadataHistory */
		BEGIN TRAN
		ALTER TABLE dbo.InstanceMetadata
		SET (SYSTEM_VERSIONING = OFF )

		DECLARE @SQL NVARCHAR(MAX) = N'
		DELETE dbo.InstanceMetadataHistory 
		WHERE InstanceID = @InstanceID'
		EXEC sp_executesql @SQL, N'@InstanceID INT', @InstanceID = @InstanceID

		ALTER TABLE dbo.InstanceMetadata 
		SET ( SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.InstanceMetadataHistory))

		COMMIT
	END
	
	DELETE dbo.Instances
	WHERE InstanceID = @InstanceID

END
GO
PRINT N'Creating Procedure [dbo].[Instances_Get]...';


GO
CREATE PROC dbo.Instances_Get(	
	@TagIDs VARCHAR(MAX)=NULL,
	@IsActive BIT=1,
	@IsAzure BIT=NULL,
	@SearchString NVARCHAR(128)=NULL,
	@GroupByTag NVARCHAR(50)=NULL,
	@ConnectionID NVARCHAR(128)=NULL,
	@Debug BIT =0
)
AS
DECLARE @SQL NVARCHAR(MAX)
SET @SQL = N'
SELECT  I.InstanceID,
	I.ConnectionID,
	I.Instance,
	CASE WHEN I.EngineEdition = 5 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsAzure,
	D.DatabaseID AS AzureDatabaseID,
	D.name AS AzureDBName,
	I.IsActive,
	I.EngineEdition,
	I.InstanceDisplayName,
	I.InstanceGroupName,
	I.ShowInSummary,
	~I.ShowInSummary AS IsHidden,
	' + CASE WHEN @GroupByTag IS NULL THEN 'CAST(NULL AS NVARCHAR(128)) as TagGroup' ELSE 'ISNULL(T.TagValue,''[N/A]'') AS TagGroup' END + ',
	SO.elastic_pool_name,
	I.CollectAgentID,
	I.ImportAgentID,
	IA.MessagingEnabled & CA.MessagingEnabled AS MessagingEnabled,
	I.ProductVersion,
	CASE WHEN M.InstanceID IS NULL THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS HasInstanceMetadata,
	FIRST_VALUE(CASE WHEN D.name = ''master'' THEN D.InstanceID ELSE NULL END) OVER(PARTITION BY Instance ORDER BY CASE WHEN D.name = ''master'' THEN 0 ELSE 1 END) AS MasterInstanceID,
	CASE WHEN EXISTS(SELECT 1 FROM dbo.ResourceGovernorWorkloadGroups WG WHERE WG.InstanceID = I.InstanceID) THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS HasResourceGovernorWorkloadGroups,
	I.UTCOffset
FROM dbo.InstancesMatchingTags(@TagIDs) I
LEFT JOIN dbo.Databases D ON D.InstanceID = I.InstanceID AND I.EngineEdition = 5 AND D.IsActive=1
LEFT JOIN dbo.AzureDBServiceObjectives SO ON I.InstanceID = SO.InstanceID
LEFT JOIN dbo.DBADashAgent IA ON I.ImportAgentID = IA.DBADashAgentID
LEFT JOIN dbo.DBADashAgent CA ON I.CollectAgentID = CA.DBADashAgentID
LEFT JOIN dbo.InstanceMetadata M ON I.InstanceID = M.InstanceID
' + CASE WHEN @GroupByTag IS NULL THEN '' ELSE 'OUTER APPLY dbo.TagValue(I.InstanceID,@GroupByTag,I.EngineEdition) T' END + '
WHERE (D.InstanceID IS NOT NULL OR I.EngineEdition <> 5 OR I.EngineEdition IS NULL)
' + CASE WHEN @IsActive IS NULL THEN '' ELSE 'AND I.IsActive=@IsActive' END + '
' + CASE WHEN @IsAzure=1 THEN 'AND I.EngineEdition = 5' WHEN @IsAzure=0 THEN 'AND I.EngineEdition <> 5' ELSE '' END + '
' + CASE WHEN @SearchString IS NULL THEN '' ELSE 'AND (I.ConnectionID LIKE @SearchString OR I.Alias LIKE @SearchString OR I.Instance LIKE @SearchString)' END + '
' + CASE WHEN @ConnectionID IS NULL THEN '' ELSE 'AND I.ConnectionID = @ConnectionID' END + '
ORDER BY TagGroup,I.InstanceDisplayName'

IF @Debug=1
BEGIN
	EXEC dbo.PrintMax @SQL
END

EXEC sp_executesql @SQL,N'@TagIDs VARCHAR(MAX),@IsActive BIT,@SearchString NVARCHAR(128),@GroupByTag NVARCHAR(50),@ConnectionID NVARCHAR(128)',@TagIDs,@IsActive,@SearchString,@GroupByTag,@ConnectionID
GO
PRINT N'Creating Procedure [dbo].[Instances_HardDelete]...';


GO
CREATE PROC dbo.Instances_HardDelete(
	@HardDeleteThresholdDays INT
)
AS
/* 
	Removes SQL instances that have been soft deleted (IsActive=0) after a specified number of days (@HardDeleteThresholdDays)
	The number of days is based on the time since the last collection.
*/
IF (@HardDeleteThresholdDays<1 OR @HardDeleteThresholdDays IS NULL)
BEGIN
	RAISERROR('@HardDeleteThresholdDays must be >=1',11,1)
	RETURN
END
DECLARE @InstanceID INT
DECLARE @ConnectionID NVARCHAR(MAX)
DECLARE c1 CURSOR FAST_FORWARD LOCAL FOR
	SELECT InstanceID,ConnectionID
	FROM dbo.Instances I
	where IsActive=0
	AND NOT EXISTS(SELECT 1 
			FROM dbo.CollectionDates CD 
			WHERE CD.InstanceID = I.InstanceID
			AND CD.SnapshotDate >= DATEADD(d,-@HardDeleteThresholdDays,GETUTCDATE())
			)
OPEN c1
WHILE 1=1
BEGIN
	FETCH NEXT FROM c1 INTO @InstanceID,@ConnectionID
	IF @@FETCH_STATUS<>0
		BREAK
	PRINT CONCAT('Deleting ',@ConnectionID)
	EXEC dbo.Instance_Del @InstanceID=@InstanceID,@HardDelete=1
END
CLOSE c1
DEALLOCATE c1
GO
