GO
CREATE PROC dbo.ObjectExecutionStats_Get(
	@Instance SYSNAME=NULL,
	@InstanceGroupName SYSNAME=NULL,
	@DatabaseID INT=NULL,
	@ObjectName SYSNAME=NULL,
	@SchemaName SYSNAME=NULL,
	@FromDateUTC DATETIME2(3)=NULL,
	@ToDateUTC DATETIME2(3)=NULL,
	@Measure VARCHAR(30)='TotalDuration',
	@UTCOffset INT=0,
	@InstanceID INT=NULL,
	@ObjectID BIGINT=NULL,
	@DateGroupingMin INT=NULL,
	/* 
		ObjectExecutionCounts table doesn't store zero executions counts.  This option will generate zero rows where we have object execution data collected for the instance but not for the specified stored proc.
	*/
	@ZeroFill BIT=1,
	@Debug BIT=0,
	@DaysOfWeek IDs READONLY, /* e.g. 1=Monday. exclude weekends:  1,2,3,4,5.  Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY, /* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)*/
	@Top INT=10,
	@IncludeOther BIT=1
)
AS
SET NOCOUNT ON
SET DATEFIRST 1 /* Start week on Monday */
CREATE TABLE #results(
    SnapshotDate DATETIME,
    DatabaseName NVARCHAR(128),
    DatabaseID INT,
	ObjectID BIGINT,
    object_name NVARCHAR(257),
    TotalCPU DECIMAL(29, 9),
    AvgCPU DECIMAL(29, 9),
	cpu_ms_per_sec DECIMAL(29, 9),
    ExecutionCount BIGINT,
    ExecutionsPerMin DECIMAL(38, 9),
    TotalDuration DECIMAL(29, 9),
    AvgDuration DECIMAL(29, 9),
	duration_ms_per_sec DECIMAL(29, 9),
    TotalLogicalReads BIGINT,
    AvgLogicalReads BIGINT,
    TotalPhysicalReads BIGINT,
    AvgPhysicalReads BIGINT,
    TotalWrites BIGINT,
    AvgWrites BIGINT,
	MaxExecutionsPerMin DECIMAL(29, 9),
    Measure DECIMAL(29, 9),
	TotalMeasure DECIMAL(29, 9),
    ProcRankPeriod BIGINT,
	ProcRankTotal BIGINT
	
);

IF @Instance IS NULL AND @InstanceID IS NULL AND @InstanceGroupName IS NULL
BEGIN
	RAISERROR('Instance not specified',11,1);
	RETURN;
END

IF @FromDateUTC IS NULL
	SET @FromDateUTC = CONVERT(DATETIME,STUFF(CONVERT(VARCHAR,DATEADD(mi,-120,GETUTCDATE()),120),16,4,'0:00'),120) 
IF @ToDateUTC IS NULL
	SET @ToDateUTC = GETUTCDATE()

DECLARE @MeasureString NVARCHAR(MAX) 
SELECT @MeasureString = CASE WHEN @Measure IN('TotalCPU','AvgCPU','TotalDuration','AvgDuration','ExecutionCount','ExecutionsPerMin','AvgLogicalReads','AvgPhysicalReads','AvgWrites','TotalWrites','TotalLogicalReads','TotalPhysicalReads','MaxExecutionsPerMin','cpu_ms_per_sec','duration_ms_per_sec') 
						THEN @Measure ELSE NULL END

DECLARE @SQL NVARCHAR(MAX)

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

/* Generate CSV list from list of integer values (safe from SQL injection compared to passing in a CSV string) */
DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @MeasureCol NVARCHAR(MAX) = CASE WHEN @MeasureString = 'TotalDuration' THEN 'SUM(OES.total_elapsed_time)/1000000.0' 
					WHEN @MeasureString = 'TotalCPU' THEN 'SUM(OES.total_worker_time)/1000000.0 '
					WHEN @MeasureString = 'ExecutionCount' THEN 'SUM(OES.execution_count)'
					WHEN @MeasureString = 'AvgCPU' THEN 'SUM(OES.total_worker_time)/NULLIF(SUM(OES.execution_count),0)/1000000.0'
					WHEN @MeasureString = 'AvgDuration' THEN 'SUM(OES.total_elapsed_time)/NULLIF(SUM(OES.execution_count),0)/1000000.0'
					WHEN @MeasureString = 'ExecutionsPerMin' THEN 'SUM(OES.execution_count) / NULLIF(MAX(SUM(OES.PeriodTime)/60000000.0) OVER(PARTITION BY DateGroup),0)'
					WHEN @MeasureString = 'AvgLogicalReads' THEN 'SUM(OES.total_logical_reads)/NULLIF(SUM(OES.execution_count),0)'
					WHEN @MeasureString = 'AvgPhysicalReads' THEN 'SUM(OES.total_physical_reads)/NULLIF(SUM(OES.execution_count),0) '
					WHEN @MeasureString = 'AvgWrites' THEN 'SUM(OES.total_logical_writes)/NULLIF(SUM(OES.execution_count),0) '
					WHEN @MeasureString = 'TotalWrites' THEN 'SUM(OES.total_logical_writes)'
					WHEN @MeasureString = 'TotalLogicalReads' THEN 'SUM(OES.total_logical_reads)'
					WHEN @MeasureString = 'TotalPhysicalReads' THEN 'SUM(OES.total_physical_reads)'
					WHEN @MeasureString = 'MaxExecutionsPerMin' THEN 'MAX(MaxExecutionsPerMin)'
					WHEN @MeasureString = 'cpu_ms_per_sec' THEN 'SUM(total_worker_time)/1000.0 / NULLIF(MAX(SUM(OES.PeriodTime)/1000000.0) OVER(PARTITION BY DateGroup),0)' 
					WHEN @MeasureString = 'duration_ms_per_sec' THEN 'SUM(OES.total_elapsed_time)/1000.0 / NULLIF(MAX(SUM(OES.PeriodTime)/1000000.0) OVER(PARTITION BY DateGroup),0)' 
		   END + ' AS Measure,'

DECLARE @TotalMeasureCol NVARCHAR(MAX) = CASE WHEN @MeasureString = 'TotalDuration' THEN 'SUM(SUM(OES.total_elapsed_time)) OVER(PARTITION BY OES.ObjectID)/1000000.0 ' 
					WHEN @MeasureString = 'TotalCPU' THEN 'SUM(SUM(OES.total_worker_time)) OVER(PARTITION BY OES.ObjectID) /1000000.0 '
					WHEN @MeasureString = 'ExecutionCount' THEN 'SUM(SUM(OES.execution_count)) OVER(PARTITION BY OES.ObjectID) '
					WHEN @MeasureString = 'AvgCPU' THEN 'SUM(SUM(OES.total_worker_time)) OVER(PARTITION BY OES.ObjectID)/NULLIF(SUM(SUM(OES.execution_count)) OVER(PARTITION BY OES.ObjectID),0)/1000000.0'
					WHEN @MeasureString = 'AvgDuration' THEN 'SUM(SUM(OES.total_elapsed_time)) OVER(PARTITION BY OES.ObjectID)/NULLIF(SUM(SUM(OES.execution_count)) OVER(PARTITION BY OES.ObjectID),0)/1000000.0 '
					WHEN @MeasureString = 'ExecutionsPerMin' THEN 'SUM(SUM(OES.execution_count)) OVER(PARTITION BY OES.ObjectID) * 60.0 / NULLIF(DATEDIFF_BIG(s,MIN(MIN(PeriodStartTime)) OVER(),MAX(MAX(PeriodEndTime)) OVER()),0) '
					WHEN @MeasureString = 'AvgLogicalReads' THEN 'SUM(SUM(OES.total_logical_reads)) OVER(PARTITION BY OES.ObjectID) /NULLIF(SUM(SUM(OES.execution_count)) OVER(PARTITION BY OES.ObjectID),0) '
					WHEN @MeasureString = 'AvgPhysicalReads' THEN 'SUM(SUM(OES.total_physical_reads)) OVER(PARTITION BY OES.ObjectID) /NULLIF(SUM(SUM(OES.execution_count)) OVER(PARTITION BY OES.ObjectID),0) '
					WHEN @MeasureString = 'AvgWrites' THEN 'SUM(SUM(OES.total_logical_writes)) OVER(PARTITION BY OES.ObjectID) /NULLIF(SUM(SUM(OES.execution_count)) OVER(PARTITION BY OES.ObjectID),0) '
					WHEN @MeasureString = 'TotalWrites' THEN 'SUM(SUM(OES.total_logical_writes)) OVER(PARTITION BY OES.ObjectID)'
					WHEN @MeasureString = 'TotalLogicalReads' THEN 'SUM(SUM(OES.total_logical_reads)) OVER(PARTITION BY OES.ObjectID)'
					WHEN @MeasureString = 'TotalPhysicalReads' THEN 'SUM(SUM(OES.total_physical_reads)) OVER(PARTITION BY OES.ObjectID)'
					WHEN @MeasureString = 'MaxExecutionsPerMin' THEN 'MAX(MAX(OES.MaxExecutionsPerMin)) OVER(PARTITION BY OES.ObjectID)'
					WHEN @MeasureString = 'cpu_ms_per_sec' THEN 'SUM(SUM(OES.total_worker_time)) OVER(PARTITION BY OES.ObjectID) /1000.0 / NULLIF(DATEDIFF_BIG(s,MIN(MIN(PeriodStartTime)) OVER(),MAX(MAX(PeriodEndTime)) OVER()),0)' 
					WHEN @MeasureString = 'duration_ms_per_sec' THEN 'SUM(SUM(OES.total_elapsed_time)) OVER(PARTITION BY OES.ObjectID) /1000.0 / NULLIF(DATEDIFF_BIG(s,MIN(MIN(PeriodStartTime)) OVER(),MAX(MAX(PeriodEndTime)) OVER()),0)' 
		   END + ' AS TotalMeasure,'

SET @SQL = CONCAT(N'
WITH agg AS (
	/* Initial Aggregation by time period & object */
	SELECT DG.DateGroup,
		   D.name AS DatabaseName,
		   D.DatabaseID,
		   OES.ObjectID,
		   O.SchemaName + ''.'' + O.objectname as object_name,
		   ', @MeasureCol, '
		   ', @TotalMeasureCol, '
		   SUM(OES.total_elapsed_time) AS total_elapsed_time,
		   SUM(OES.execution_count) AS execution_count,
		   SUM(OES.total_logical_reads) AS total_logical_reads,
		   SUM(OES.total_logical_writes) AS total_logical_writes,
		   SUM(OES.total_physical_reads) AS total_physical_reads,
		   SUM(OES.total_worker_time) AS total_worker_time,
		   SUM(OES.PeriodTime) AS PeriodTime,
		   MAX(MaxExecutionsPerMin) AS MaxExecutionsPerMin,
		   MIN(PeriodStartTime) AS PeriodStartTime,
		   MAX(PeriodEndTime) AS PeriodEndTime
	FROM dbo.ObjectExecutionStats' + CASE WHEN @DateGroupingMin>=60 THEN N'_60MIN' ELSE N'' END + N' OES
		' + CASE WHEN @DateGroupingMin IS NULL OR @DateGroupingMin =0 THEN 'OUTER APPLY(SELECT DATEADD(mi, @UTCOffset, OES.SnapshotDate) AS DateGroup) DG' ELSE 'CROSS APPLY dbo.DateGroupingMins(DATEADD(mi, @UTCOffset, OES.SnapshotDate),@DateGroupingMin) DG' END + '
		JOIN dbo.DBObjects O ON OES.ObjectID = O.ObjectID
		JOIN dbo.Databases D ON D.DatabaseID = O.DatabaseID
		JOIN dbo.Instances I ON D.InstanceID = I.InstanceID AND OES.InstanceID = I.InstanceID
	WHERE D.IsActive=1
	', CASE WHEN @Instance IS NOT NULL THEN N'AND I.Instance = @Instance' ELSE '' END, N'
	', CASE WHEN @InstanceGroupName IS NOT NULL THEN N'AND I.InstanceGroupName = @InstanceGroupName' ELSE '' END, N'
	', CASE WHEN @InstanceID IS NOT NULL THEN N'AND I.InstanceID = @InstanceID' ELSE '' END, N'
	AND OES.SnapshotDate >= @FromDate 
	AND OES.SnapshotDate< @ToDate
	', CASE WHEN @DatabaseID IS NULL THEN N'' ELSE N'AND D.DatabaseID=@DatabaseID' END, N'
	', CASE WHEN @ObjectName IS NULL THEN N'' ELSE N'AND O.objectname=@ObjectName' END, N'
	', CASE WHEN @ObjectID IS NULL THEN N'' ELSE N'AND OES.ObjectID = @ObjectID' END, N'
	', CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, OES.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END, '
	', CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, OES.SnapshotDate)) IN(' + @HoursCsv + ')' END, '
	GROUP BY DG.DateGroup,D.Name,O.objectname,D.DatabaseID,O.SchemaName,OES.ObjectID
)
, Ranking AS (
	/* Get top objects for each period & overall */
	SELECT agg.*,
		ROW_NUMBER() OVER (PARTITION BY DateGroup ORDER BY Measure DESC,ObjectID) ProcRankPeriod,
		DENSE_RANK() OVER (ORDER BY TotalMeasure DESC,ObjectID) ProcRankTotal
	FROM agg
	WHERE TotalMeasure>0
),
ReGrouping AS (
	/* Bucket objects outside top into "Other" category */
	SELECT  DateGroup,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN DatabaseName ELSE '''' END AS DatabaseName,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN DatabaseID ELSE -1 END AS DatabaseID,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN ObjectID ELSE -1 END AS ObjectID,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN object_name ELSE ''{Other}'' END AS object_name,
			SUM(total_elapsed_time) AS total_elapsed_time,
			SUM(execution_count) AS execution_count,
			SUM(total_logical_reads) AS total_logical_reads,
			SUM(total_logical_writes) AS total_logical_writes,
			SUM(total_physical_reads) AS total_physical_reads,
			SUM(total_worker_time) AS total_worker_time,
			MAX(PeriodTime) AS PeriodTime,
			MAX(MaxExecutionsPerMin) AS MaxExecutionsPerMin,
			MIN(PeriodStartTime) AS PeriodStartTime,
			MAX(PeriodEndTime) AS PeriodEndTime,
			MIN(CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN ProcRankPeriod ELSE 2147483647 END) AS ProcRankPeriod,
			MIN(CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN ProcRankTotal ELSE 2147483647 END) AS ProcRankTotal
	FROM Ranking
	GROUP BY  DateGroup,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN DatabaseName ELSE '''' END,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN DatabaseID ELSE -1 END,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN ObjectID ELSE -1 END,
			CASE WHEN ProcRankTotal <=@Top OR ProcRankPeriod<=@Top THEN object_name ELSE ''{Other}'' END
)
SELECT DateGroup AS SnapshotDate,
		DatabaseName,
		DatabaseID,
		ObjectID,
		object_name,
		SUM(OES.total_worker_time)/1000000.0 as TotalCPU,
		SUM(OES.total_worker_time)/NULLIF(SUM(OES.execution_count),0)/1000000.0 as AvgCPU,
		SUM(total_worker_time)/1000.0 / NULLIF(MAX(SUM(OES.PeriodTime)/1000000.0) OVER(PARTITION BY DateGroup),0) cpu_ms_per_sec,
		SUM(OES.execution_count) as ExecutionCount,
		SUM(OES.execution_count)/ NULLIF(MAX(SUM(OES.PeriodTime)/60000000.0) OVER(PARTITION BY DateGroup),0) as ExecutionsPerMin,
		SUM(OES.total_elapsed_time)/1000000.0 AS TotalDuration,
		SUM(OES.total_elapsed_time)/NULLIF(SUM(OES.execution_count),0)/1000000.0 AS AvgDuration,
		SUM(OES.total_elapsed_time)/1000.0 / NULLIF(MAX(SUM(OES.PeriodTime)/1000000.0) OVER(PARTITION BY DateGroup),0) duration_ms_per_sec,
		SUM(OES.total_logical_reads) as TotalLogicalReads,
		SUM(OES.total_logical_reads)/NULLIF(SUM(OES.execution_count),0) as AvgLogicalReads,
		SUM(OES.total_physical_reads) as TotalPhysicalReads,
		SUM(OES.total_physical_reads)/NULLIF(SUM(OES.execution_count),0) as AvgPhysicalReads,
		SUM(OES.total_logical_writes) as TotalWrites,
		SUM(OES.total_logical_writes)/NULLIF(SUM(OES.execution_count),0) as AvgWrites,
		MAX(MaxExecutionsPerMin) as MaxExecutionsPerMin,
		', @MeasureCol,'
		', @TotalMeasureCol,'
		MIN(ProcRankPeriod) AS ProcRankPeriod,
		MIN(ProcRankTotal) AS ProcRankTotal
FROM ReGrouping OES
',CASE WHEN @IncludeOther=1 THEN '' ELSE 'WHERE ProcRankTotal <> 2147483647 ' END,'
GROUP BY DateGroup,
		DatabaseName,
		DatabaseID,
		ObjectID,
		object_name
ORDER BY ProcRankTotal,SnapshotDate')

IF @Debug=1
BEGIN
	EXEC dbo.PrintMax @SQL
END

IF @SQL IS NOT NULL
BEGIN
	INSERT INTO #results
	(
	    SnapshotDate,
	    DatabaseName,
	    DatabaseID,
	    ObjectID,
	    object_name,
	    TotalCPU,
	    AvgCPU,
	    cpu_ms_per_sec,
	    ExecutionCount,
	    ExecutionsPerMin,
	    TotalDuration,
	    AvgDuration,
	    duration_ms_per_sec,
	    TotalLogicalReads,
	    AvgLogicalReads,
	    TotalPhysicalReads,
	    AvgPhysicalReads,
	    TotalWrites,
	    AvgWrites,
	    MaxExecutionsPerMin,
	    Measure,
	    TotalMeasure,
		ProcRankPeriod,
		ProcRankTotal
	)
	EXEC sp_executesql @SQL,N'@Instance SYSNAME,
							@InstanceGroupName SYSNAME,
							@DatabaseID INT,
							@FromDate DATETIME2(3),
							@ToDate DATETIME2(3),
							@ObjectName SYSNAME,
							@SchemaName SYSNAME,
							@UTCOffset INT,
							@InstanceID INT,
							@ObjectID BIGINT,
							@DateGroupingMin INT,
							@Top INT',
							@Instance,
							@InstanceGroupName,
							@DatabaseID,
							@FromDateUTC,
							@ToDateUTC,
							@ObjectName,
							@SchemaName,
							@UTCOffset,
							@InstanceID,
							@ObjectID,
							@DateGroupingMin,
							@Top

END 

IF @ZeroFill=1 AND @ObjectID IS NOT NULL
BEGIN;
	DECLARE @DateGroups TABLE(
		DateGroup DATETIME2(3) NOT NULL PRIMARY KEY
	)
	/*	Get all the date groups where we have data collected for the instance
		We could generate the date groups using a table of numbers which would be more efficient, but this method doesn't generate dates if collections are missing.
		Collections could be missing if @ToDateUTC is a date in the future or the data hasn't been loaded yet. It could also be missing if the agent was stopped or the SQL instance wasn't running.
		It would be wrong to generate zero values in these situations.
	*/
	DECLARE @DateGroupSQL NVARCHAR(MAX)
	SET @DateGroupSQL=N'	
	SELECT ' + CASE WHEN @DateGroupingMin >0 THEN 'DG.DateGroup' ELSE 'DATEADD(mi, @UTCOffset, OES.SnapshotDate)' END + '
	FROM dbo.ObjectExecutionStats' + CASE WHEN @DateGroupingMin>=60 THEN N'_60MIN' ELSE N'' END + N' OES
	' + CASE WHEN @DateGroupingMin >0 THEN 'CROSS APPLY dbo.DateGroupingMins(DATEADD(mi, @UTCOffset, OES.SnapshotDate),@DateGroupingMin) DG' ELSE '' END + '
	WHERE OES.SnapshotDate>=@FromDateUTC
	AND OES.SnapshotDate < @ToDateUTC
	AND OES.InstanceID = @InstanceID
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, OES.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, OES.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
	GROUP BY ' + CASE WHEN @DateGroupingMin >0 THEN 'DG.DateGroup' ELSE 'DATEADD(mi, @UTCOffset, OES.SnapshotDate)' END

	IF @Debug=1
	BEGIN
		PRINT @DateGroupSQL
	END

	INSERT INTO @DateGroups
	(
	    DateGroup
	)
	EXEC sp_executesql @DateGroupSQL,
						N'@Instance SYSNAME,
						@InstanceGroupName SYSNAME,
						@DatabaseID INT,
						@FromDateUTC DATETIME2(3),
						@ToDateUTC DATETIME2(3),
						@ObjectName SYSNAME,
						@SchemaName SYSNAME,
						@UTCOffset INT,
						@InstanceID INT,
						@ObjectID BIGINT,
						@DateGroupingMin INT,
						@Top INT',
						@Instance,
						@InstanceGroupName,
						@DatabaseID,
						@FromDateUTC,
						@ToDateUTC,
						@ObjectName,
						@SchemaName,
						@UTCOffset,
						@InstanceID,
						@ObjectID,
						@DateGroupingMin,
						@Top
	
	INSERT INTO #results
	(
		SnapshotDate,
		DatabaseName,
		DatabaseID,
		ObjectID,
		object_name,
		TotalCPU,
		AvgCPU,
		cpu_ms_per_sec,
		ExecutionCount,
		ExecutionsPerMin,
		TotalDuration,
		AvgDuration,
		duration_ms_per_sec,
		TotalLogicalReads,
		AvgLogicalReads,
		TotalPhysicalReads,
		AvgPhysicalReads,
		TotalWrites,
		AvgWrites,
		MaxExecutionsPerMin,
		Measure,
		TotalMeasure,
		ProcRankPeriod,
		ProcRankTotal
	)
	SELECT DG.DateGroup AS SnapshotDate,
			D.name AS DatabaseName,
			D.DatabaseID,
			O.ObjectID,
			O.SchemaName + '.' + O.ObjectName AS object_name,
			0 AS TotalCPU,
			0 AS AvgCPU,
			0 AS cpu_ms_per_sec,
			0 AS ExecutionCount,
			0 AS ExecutionsPerMin,
			0 AS TotalDuration,
			0 AS AvgDuration,
			0 AS duration_ms_per_sec,
			0 AS TotalLogicalReads,
			0 AS AvgLogicalReads,
			0 AS TotalPhysicalReads,
			0 AS AvgPhysicalReads,
			0 AS TotalWrites,
			0 AS AvgWrites,
			0 AS MaxExecutionsPerMin,
			0 AS Measure,
			0 AS TotalMeasure,
			1 AS ProcRankPeriod,
			1 AS ProcRankTotal
	FROM dbo.DBObjects O
	JOIN dbo.Databases D ON D.DatabaseID = O.DatabaseID
	CROSS JOIN @DateGroups DG
	WHERE O.ObjectID= @ObjectID
	AND NOT EXISTS(SELECT 1 FROM #results R WHERE DG.DateGroup = R.SnapshotDate)
END

SELECT SnapshotDate,
       DatabaseName,
       DatabaseID,
       ObjectID,
       object_name,
       TotalCPU,
       AvgCPU,
       cpu_ms_per_sec,
       ExecutionCount,
       ExecutionsPerMin,
       TotalDuration,
       AvgDuration,
       duration_ms_per_sec,
       TotalLogicalReads,
       AvgLogicalReads,
       TotalPhysicalReads,
       AvgPhysicalReads,
       TotalWrites,
       AvgWrites,
       MaxExecutionsPerMin,
       Measure,
       TotalMeasure,
	   ProcRankPeriod,
	   ProcRankTotal
FROM #results
ORDER BY ProcRankTotal,DatabaseName,object_name,SnapshotDate
GO
PRINT N'Creating Procedure [dbo].[Partitions_Add]...';


GO
CREATE PROC dbo.Partitions_Add
AS
DECLARE @SchemaName SYSNAME
DECLARE @TableName SYSNAME
DECLARE @PeriodType CHAR(1)
DECLARE @PeriodCount INT
DECLARE @ErrorMessages NVARCHAR(MAX)=''

DECLARE cDaily CURSOR FAST_FORWARD LOCAL FOR 
			SELECT	SchemaName,
					TableName,
					PeriodType,
					PeriodCount
			FROM dbo.PartitionConfiguration PC			
			WHERE NOT EXISTS(SELECT 1 
							FROM dbo.PartitionHelper PH
							WHERE (
									( DATEDIFF(d, GETUTCDATE(), PH.LowerBound) >= PC.PeriodCount AND PC.PeriodType='d')
									OR (DATEDIFF(m, GETUTCDATE(), PH.LowerBound) >= PC.PeriodCount AND PC.PeriodType='m')
								)
							AND PH.TableName = PC.TableName
							AND PH.SchemaName = PC.SchemaName
							)
											
			ORDER BY IsSystem DESC, TableName

OPEN cDaily
WHILE 1=1
BEGIN
	FETCH NEXT FROM cDaily INTO @SchemaName, @TableName,@PeriodType,@PeriodCount
	IF @@FETCH_STATUS <> 0 
		BREAK
	PRINT @TableName
	BEGIN TRY
		EXEC dbo.Partitions_Create @SchemaName=@SchemaName, @TableName = @TableName,@PeriodCount=@PeriodCount,@PeriodType=@PeriodType
	END TRY
	BEGIN CATCH
		IF @@TRANCOUNT>0
			ROLLBACK
		SET @ErrorMessages = CONCAT(@ErrorMessages,'Error managing partitions for table "',@TableName,'": ',ERROR_MESSAGE(),CHAR(13)+CHAR(10))
	END CATCH
END
CLOSE cDaily
DEALLOCATE cDaily
IF @ErrorMessages <> ''
BEGIN;
	THROW 509999,@ErrorMessages,1
END
GO
PRINT N'Creating Procedure [dbo].[PerformanceSummary_Get]...';


GO
CREATE PROC dbo.PerformanceSummary_Get(
	@InstanceIDs VARCHAR(MAX)=NULL,
	@FromDate DATETIME2(3)=NULL,
	@ToDate DATETIME2(3)=NULL,
	@TagIDs VARCHAR(MAX)=NULL,
	@Use60MIN BIT=NULL,
	@Debug BIT=0,
	@DaysOfWeek IDs READONLY, /* e.g. exclude weekends:  Monday,Tuesday,Wednesday,Thursday,Friday. Filter applied in local timezone (@UTCOffset) */
	@Hours IDs READONLY, /* e.g. 9 to 5 :  9,10,11,12,13,14,15,16. Filter applied in local timezone (@UTCOffset)  */
	@UTCOffset INT=0, /* Used for filtering on hours & weekday in current timezone */
	@ShowHidden BIT=1
)
AS
SET DATEFIRST 1 /* Start week on Monday */
IF @FromDate IS NULL
	SET @FromDate = DATEADD(mi,-15,GETUTCDATE())
IF @ToDate IS NULL
	SET @ToDate=GETUTCDATE()

IF @Use60MIN IS NULL
BEGIN
	SELECT @Use60MIN = CASE WHEN DATEDIFF(hh,@FromDate,@ToDate)>24 THEN 1
						WHEN DATEPART(mi,@FromDate)+DATEPART(s,@FromDate)+DATEPART(ms,@FromDate)=0 
							AND (DATEPART(mi,@ToDate)+DATEPART(s,@ToDate)+DATEPART(ms,@ToDate)=0 
									OR @ToDate>=DATEADD(s,-2,GETUTCDATE())
								)
						THEN 1
						ELSE 0 END
END
CREATE TABLE #Instances(
	InstanceID INT PRIMARY KEY
)

IF @InstanceIDs IS NULL
BEGIN
	INSERT INTO #Instances
	(
		InstanceID
	)
	SELECT InstanceID
	FROM dbo.InstancesMatchingTags(@TagIDs)
END 
ELSE 
BEGIN
	INSERT INTO #Instances
	(
		InstanceID
	)
	SELECT value
	FROM STRING_SPLIT(@InstanceIDs,',')

END;

DECLARE @DaysOfWeekCsv NVARCHAR(MAX)
SELECT @DaysOfWeekCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @DaysOfWeek
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @HoursCsv NVARCHAR(MAX)
SELECT @HoursCsv =  STUFF((SELECT ',' + CAST(ID AS VARCHAR)
FROM @Hours
FOR XML PATH(''),TYPE).value('.','NVARCHAR(MAX)'),1,1,'')

DECLARE @SQL NVARCHAR(MAX) 
SET @SQL = CAST(N'' AS NVARCHAR(MAX)) + N'
WITH cpuAgg AS (
	SELECT InstanceID,
		SUM(SumTotalCPU*1.0)/SUM(SampleCount*1.0) as AvgCPU,
	    SUM(SumOtherCPU*1.0)/SUM(SampleCount*1.0) as OtherCPU,
	    MAX(MaxTotalCPU*1.0) as MaxCPU,
		SUM(CAST(CPU10 as INT)) AS CPU10,
		SUM(CAST(CPU20 as INT)) AS CPU20,
		SUM(CAST(CPU30 as INT)) AS CPU30,
		SUM(CAST(CPU40 as INT)) AS CPU40,
		SUM(CAST(CPU50 as INT)) AS CPU50,
		SUM(CAST(CPU60 as INT)) AS CPU60,
		SUM(CAST(CPU70 as INT)) AS CPU70,
		SUM(CAST(CPU80 as INT)) AS CPU80,
		SUM(CAST(CPU90 as INT)) AS CPU90,
		SUM(CAST(CPU100 as INT)) AS CPU100
	FROM ' + CASE WHEN @Use60MIN=1 THEN 'dbo.CPU_60MIN' ELSE 'dbo.CPU_Histogram' END + ' as CPU
	WHERE EventTime >=@FromDate
	AND EventTime <@ToDate
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, EventTime)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, EventTime)) IN(' + @HoursCsv + ')' END + '
	AND EXISTS(SELECT 1 FROM #Instances t WHERE CPU.InstanceID = t.InstanceID)
	GROUP BY InstanceID
)
, dbio AS (
	SELECT IOS.InstanceID,
			SUM(IOS.num_of_reads)/(SUM(IOS.sample_ms_diff)/1000.0) AS ReadIOPs,
			SUM(IOS.num_of_writes)/(SUM(IOS.sample_ms_diff)/1000.0) AS WriteIOPs,
			SUM(IOS.num_of_reads+IOS.num_of_writes)/(SUM(IOS.sample_ms_diff)/1000.0) AS IOPs,
			SUM(IOS.num_of_bytes_read)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) ReadMBsec,
			SUM(IOS.num_of_bytes_written)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) WriteMBsec,
			SUM(IOS.num_of_bytes_read+IOS.num_of_bytes_written)/POWER(1024.0,2)/(SUM(IOS.sample_ms_diff)/1000.0) MBsec,
			SUM(IOS.io_stall_read_ms)/(NULLIF(SUM(IOS.num_of_reads),0)*1.0) AS ReadLatency,
			SUM(IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes),0)*1.0) AS WriteLatency,
			SUM(IOS.io_stall_read_ms+IOS.io_stall_write_ms)/(NULLIF(SUM(IOS.num_of_writes+IOS.num_of_reads),0)*1.0) AS Latency,
			MAX(IOS.MaxReadIOPs) AS MaxReadIOPs,
			MAX(IOS.MaxWriteIOPs) AS MaxWriteIOPs,
			MAX(IOS.MaxIOPs) AS MaxIOPs,
			MAX(IOS.MaxReadMBsec) AS MaxReadMBsec,
			MAX(IOS.MaxWriteMBsec) AS MaxWriteMBsec,
			MAX(IOS.MaxMBsec) AS MaxMBsec
	FROM ' + CASE WHEN @Use60MIN = 1 THEN 'dbo.DBIOStats_60MIN' ELSE 'dbo.DBIOStats' END + ' AS IOS
	WHERE IOS.DatabaseID=-1
	AND IOS.Drive=''*''
	AND IOS.FileID=-1
	AND IOS.SnapshotDate>=CAST(@FromDate AS DATETIME2(2))
	AND IOS.SnapshotDate<CAST(@ToDate AS DATETIME2(2))
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, IOS.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, IOS.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
	AND EXISTS(SELECT 1 FROM #Instances t WHERE IOS.InstanceID = t.InstanceID)
	GROUP BY IOS.InstanceID
)
, wait1 AS (
	SELECT W.InstanceID,
		W.WaitTypeID,
		SUM(W.wait_time_ms)*1000.0 / MAX(SUM(W.sample_ms_diff*1.0)) OVER(PARTITION BY InstanceID) WaitMsPerSec,
		SUM(W.wait_time_ms) wait_time_ms,
		SUM(W.signal_wait_time_ms) as signal_wait_time_ms
	FROM ' + CASE WHEN @Use60MIN=1 THEN 'dbo.Waits_60MIN' ELSE 'dbo.Waits' END + ' W 
	WHERE W.SnapshotDate>= CAST(@FromDate AS DATETIME2(2))
	AND W.SnapshotDate < CAST(@ToDate AS DATETIME2(2))
	' + CASE WHEN @DaysOfWeekCsv IS NULL THEN N'' ELSE 'AND DATEPART(dw,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN (' + @DaysOfWeekCsv + ')' END + '
	' + CASE WHEN @HoursCsv IS NULL THEN N'' ELSE 'AND DATEPART(hh,DATEADD(mi, @UTCOffset, W.SnapshotDate)) IN(' + @HoursCsv + ')' END + '
	AND EXISTS(SELECT 1 FROM #Instances t WHERE W.InstanceID = t.InstanceID)
	GROUP BY W.InstanceID,W.WaitTypeID

)
, wait AS (
	SELECT W.InstanceID,	
		SUM(CASE WHEN WT.IsCriticalWait =1 THEN W.WaitMsPerSec ELSE 0 END) CriticalWaitMsPerSec,
		SUM(CASE WHEN WT.WaitType LIKE ''LATCH%'' THEN W.WaitMsPerSec  ELSE 0 END) LatchWaitMsPerSec,
		SUM(CASE WHEN WT.WaitType LIKE ''LCK%'' THEN W.WaitMsPerSec  ELSE 0 END) LockWaitMsPerSec,
		SUM(CASE WHEN WT.WaitType LIKE ''PAGEIO%'' OR WT.WaitType LIKE ''WRITE%'' THEN W.WaitMsPerSec  ELSE 0 END) IOWaitMsPerSec,
		SUM(W.WaitMsPerSec) WaitMsPerSec,
		SUM(signal_wait_time_ms)/NULLIF(SUM(wait_time_ms*1.0),0) as SignalWaitPct
	FROM wait1 w
	JOIN dbo.WaitType WT ON WT.WaitTypeID = W.WaitTypeID
	GROUP BY w.InstanceID
)
SELECT I.InstanceID,
	   I.ConnectionID,
       I.Instance,
	   I.InstanceDisplayName,
	   cpuAgg.AvgCPU,
	   CASE WHEN cpuAgg.AvgCPU > thres.CPUCriticalThreshold THEN 1 WHEN cpuAgg.AvgCPU > thres.CPUWarningThreshold THEN 2 WHEN cpuAgg.AvgCPU < thres.CPULowThreshold THEN 4 ELSE 3 END AS AvgCPUStatus,
	   cpuAgg.MaxCPU,
	   CASE WHEN cpuAgg.MaxCPU > thres.CPUCriticalThreshold  THEN 1 WHEN cpuAgg.MaxCPU > thres.CPUWarningThreshold THEN 2 WHEN cpuAgg.MaxCPU < thres.CPULowThreshold THEN 4 ELSE 3 END AS MaxCPUStatus,
       dbio.ReadIOPs,
       dbio.WriteIOPs,
	   dbio.IOPs,
       dbio.ReadMBsec,
       dbio.WriteMBsec,
	   dbio.MBsec,
       dbio.ReadLatency,
	   CASE WHEN dbio.ReadIOPs < thres.MinIOPsThreshold THEN 3 WHEN dbio.ReadLatency > thres.ReadLatencyCriticalThreshold THEN 1 WHEN dbio.ReadLatency > thres.ReadLatencyWarningThreshold THEN 2 WHEN dbio.ReadLatency <= thres.ReadLatencyGoodThreshold THEN 4 ELSE 3 END AS ReadLatencyStatus,
       dbio.WriteLatency,
	   CASE WHEN dbio.WriteIOPs < thres.MinIOPsThreshold THEN 3 WHEN dbio.WriteLatency > thres.ReadLatencyCriticalThreshold THEN 1 WHEN dbio.WriteLatency > thres.ReadLatencyWarningThreshold THEN 2 WHEN dbio.WriteLatency <= thres.ReadLatencyGoodThreshold THEN 4 ELSE 3 END AS WriteLatencyStatus,
       dbio.Latency,
       dbio.MaxReadIOPs,
       dbio.MaxWriteIOPs,
       dbio.MaxIOPs,
       dbio.MaxReadMBsec,
       dbio.MaxWriteMBsec,
       dbio.MaxMBsec,
       wait.CriticalWaitMsPerSec,
	   CASE WHEN wait.CriticalWaitMsPerSec=0 THEN 4 WHEN wait.CriticalWaitMsPerSec> thres.CriticalWaitCriticalThreshold THEN 1 WHEN wait.CriticalWaitMsPerSec> thres.CriticalWaitWarningThreshold THEN 2 ELSE 3 END AS CriticalWaitStatus, 
       wait.LatchWaitMsPerSec,
       wait.LockWaitMsPerSec,
       wait.IOWaitMsPerSec,
       wait.WaitMsPerSec,
	   wait.SignalWaitPct,
	   CPU10,
	   CPU20,
	   CPU30,
	   CPU40,
	   CPU50,
	   CPU60,
	   CPU70,
	   CPU80,
	   CPU90,
	   CPU100
FROM dbo.Instances I 
LEFT JOIN dbio ON I.InstanceID = dbio.InstanceID
LEFT JOIN cpuAgg ON I.InstanceID = cpuAgg.InstanceID
LEFT JOIN wait ON I.InstanceID = wait.InstanceID
CROSS JOIN dbo.PerformanceThresholds thres
WHERE EXISTS(SELECT 1 FROM #Instances t WHERE I.InstanceID = t.InstanceID)
AND I.IsActive=1
' + CASE WHEN @ShowHidden=1 THEN '' ELSE 'AND I.ShowInSummary=1' END + '
ORDER BY CASE WHEN wait.CriticalWaitMsPerSec > thres.CriticalWaitWarningThreshold THEN wait.CriticalWaitMsPerSec ELSE 0 END DESC, cpuAgg.AvgCPU DESC
OPTION(RECOMPILE)'

IF @Debug=1
BEGIN
	EXEC dbo.PrintMax @SQL 
END

EXEC sp_executesql @SQL,
					N'@FromDate DATETIME2(3),
					@ToDate DATETIME2(3),
					@UTCOffset INT',
					@FromDate,
					@ToDate,
					@UTCOffset
GO
PRINT N'Creating Procedure [dbo].[PurgeData]...';


GO
CREATE PROC dbo.PurgeData(
	@Force BIT=0 /* Option to force purge of non-partitioned tables which usually run once per day */
)
AS
SET NOCOUNT ON
SET XACT_ABORT ON
DECLARE @SchemaName SYSNAME
DECLARE @TableName SYSNAME
DECLARE @RetentionDays INT
DECLARE @Errors VARCHAR(MAX) = ''
DECLARE @Error VARCHAR(MAX)
/*	Prevent simultaneous execution of partition cleanup.
	After 20min, assume previous execution failed.
*/
UPDATE S
	SET SettingValue = GETUTCDATE()
FROM dbo.Settings S
WHERE S.SettingName = 'PurgePartitions_StartDate'
AND (S.SettingValue < DATEADD(mi,-20,GETUTCDATE())
	OR EXISTS(SELECT 1 
			FROM dbo.Settings S2
			WHERE S2.SettingName = 'PurgePartitions_CompletedDate'
			AND S2.SettingValue > S.SettingValue
			)
	)

IF @@ROWCOUNT= 1
BEGIN
	DECLARE cTables CURSOR FAST_FORWARD LOCAL FOR
		SELECT	DR.SchemaName,
				DR.TableName,
				DR.RetentionDays
		FROM dbo.DataRetention DR
		WHERE DR.RetentionDays > 0
		AND EXISTS(	SELECT 1
					FROM dbo.PartitionHelper PH
					WHERE PH.SchemaName = DR.SchemaName
					AND PH.TableName = DR.TableName
					)
		ORDER BY CASE WHEN DR.SchemaName = 'dbo' THEN 1 ELSE 2 END, DR.TableName
	
	OPEN cTables
	WHILE 1=1
	BEGIN
		FETCH NEXT FROM cTables INTO @SchemaName, @TableName, @RetentionDays
		IF @@FETCH_STATUS<>0
			BREAK
		PRINT 'Cleanup ' + @TableName

		BEGIN TRY
			EXEC dbo.PartitionTable_Cleanup @SchemaName = @SchemaName, @TableName=@TableName, @DaysToKeep=@RetentionDays
		END TRY 
		BEGIN CATCH 
			/* Continue processing if there is an issue with partition switching for a particular table and throw error at end */
			SET @Error = 'Error running cleanup for ' + @TableName + ':' + ERROR_MESSAGE()
			PRINT @Error 
			SET @Errors += @Error + CHAR(13) + CHAR(10)
		END CATCH
	END

	CLOSE cTables
	DEALLOCATE cTables

	UPDATE dbo.Settings
		SET SettingValue = GETUTCDATE()
	WHERE SettingName = 'PurgePartitions_CompletedDate'

END
ELSE
BEGIN
	PRINT 'Skipping PartitionTable_Cleanup (Already Running)'
END

/* Remove old data from CollectionErrorLog table.  Run once per day */
UPDATE dbo.Settings
	SET SettingValue = GETUTCDATE()
WHERE SettingName = 'PurgeCollectionErrorLog_StartDate'
AND SettingValue < DATEADD(d,-1,GETUTCDATE())

IF @@ROWCOUNT =1 OR @Force=1
BEGIN
	PRINT 'Cleanup CollectionErrorLog'
	EXEC dbo.PurgeCollectionErrorLog

	UPDATE dbo.Settings
		SET SettingValue = GETUTCDATE()
	WHERE SettingName = 'PurgeCollectionErrorLog_CompletedDate'
END
ELSE
BEGIN
	PRINT 'Skipping CollectionErrorLog (Ran withing last 24hrs)'
END

/* Remove old data from QueryPlans table.  Run once per day */
UPDATE dbo.Settings
	SET SettingValue = GETUTCDATE()
WHERE SettingName = 'PurgeQueryPlans_StartDate'
AND SettingValue < DATEADD(d,-1,GETUTCDATE())

IF @@ROWCOUNT =1 OR @Force=1
BEGIN
	PRINT 'Cleanup QueryPlans'
	EXEC dbo.PurgeQueryPlans

	UPDATE dbo.Settings
		SET SettingValue = GETUTCDATE()
	WHERE SettingName = 'PurgeQueryPlans_CompletedDate'
END
ELSE
BEGIN
	PRINT 'Skipping QueryPlans (Ran withing last 24hrs)'
END

/* Remove old data from QueryText table.  Run once per day */
UPDATE dbo.Settings
	SET SettingValue = GETUTCDATE()
WHERE SettingName = 'PurgeQueryText_StartDate'
AND SettingValue < DATEADD(d,-1,GETUTCDATE())

IF @@ROWCOUNT =1 OR @Force=1
BEGIN
	PRINT 'Cleanup QueryText'
	EXEC dbo.PurgeQueryText

	UPDATE dbo.Settings
		SET SettingValue = GETUTCDATE()
	WHERE SettingName = 'PurgeQueryText_CompletedDate'
END
ELSE
BEGIN
	PRINT 'Skipping QueryText (Ran withing last 24hrs)'
END

/* Remove old data from BlockingSnapshotSummary table.  Run once per day */
UPDATE dbo.Settings
	SET SettingValue = GETUTCDATE()
WHERE SettingName = 'PurgeBlockingSnapshotSummary_StartDate'
AND SettingValue < DATEADD(d,-1,GETUTCDATE())

IF @@ROWCOUNT =1 OR @Force=1
BEGIN
	PRINT 'Cleanup QueryText'
	EXEC dbo.PurgeBlockingSnapshotSummary

	UPDATE dbo.Settings
		SET SettingValue = GETUTCDATE()
	WHERE SettingName = 'PurgeBlockingSnapshotSummary_CompletedDate'
END
ELSE
BEGIN
	PRINT 'Skipping BlockingSnapshotSummary (Ran withing last 24hrs)'
END

/* Remove old data from ClosedAlerts table.  Run once per day */
UPDATE dbo.Settings
	SET SettingValue = GETUTCDATE()
WHERE SettingName = 'PurgeClosedAlerts_StartDate'
AND SettingValue < DATEADD(d,-1,GETUTCDATE())

IF @@ROWCOUNT =1 OR @Force=1
BEGIN
	PRINT 'Cleanup ClosedAlerts'
	DECLARE @KeepNotes BIT = 1
	IF EXISTS(	SELECT 1 
				FROM dbo.Settings 
				WHERE SettingName = 'ExcludeClosedAlertsWithNotesFromPurge' 
				AND SettingValue = CAST(0 AS BIT)
				)
	BEGIN
		PRINT 'ClosedAlerts with notes will be purged'
		SET @KeepNotes=0
	END
	EXEC dbo.PurgeClosedAlerts @KeepNotes=@KeepNotes

	UPDATE dbo.Settings
		SET SettingValue = GETUTCDATE()
	WHERE SettingName = 'PurgeClosedAlerts_CompletedDate'
END
ELSE
BEGIN
	PRINT 'Skipping ClosedAlerts (Ran withing last 24hrs)'
END

/* Remove old data from OfflineInstances table.  Run once per day */
UPDATE dbo.Settings
	SET SettingValue = GETUTCDATE()
WHERE SettingName = 'PurgeOfflineInstances_StartDate'
AND SettingValue < DATEADD(d,-1,GETUTCDATE())

IF @@ROWCOUNT =1 OR @Force=1
BEGIN
	PRINT 'Cleanup OfflineInstances'

	EXEC dbo.PurgeOfflineInstances

	UPDATE dbo.Settings
		SET SettingValue = GETUTCDATE()
	WHERE SettingName = 'PurgeOfflineInstances_CompletedDate'
END
ELSE
BEGIN
	PRINT 'Skipping OfflineInstances (Ran withing last 24hrs)'
END

/* Service Broker Cleanup */
EXEC Messaging.Cleanup

/* Remove instances that have been soft deleted after threshold days if enaabled */
DECLARE @HardDeleteThresholdDays INT
SELECT @HardDeleteThresholdDays = TRY_CAST(SettingValue AS INT)
FROM dbo.Settings
WHERE SettingName = 'HardDeleteThresholdDays'

IF @HardDeleteThresholdDays >= 1
BEGIN
	PRINT CONCAT('Running Instances_HardDelete with threshold ',@HardDeleteThresholdDays,' days')
	EXEC dbo.Instances_HardDelete @HardDeleteThresholdDays=@HardDeleteThresholdDays
END

/* DBADashAgent table cleanup */
DELETE A
FROM dbo.DBADashAgent A
WHERE NOT EXISTS(SELECT 1 
				FROM dbo.Instances I
				WHERE I.CollectAgentID = A.DBADashAgentID
				UNION ALL
				SELECT 1 
				FROM dbo.Instances I
				WHERE I.ImportAgentID = A.DBADashAgentID
				)
AND A.ModifiedDate < DATEADD(d,-14,SYSUTCDATETIME())

IF @Errors <> ''
BEGIN;
	THROW 51000,@Errors,1;
END
GO
