MERGE INTO dbo.ObjectType AS T
USING(
	VALUES( 'P','Stored Procedure'),
	('V','View'),
	('IF','Inline Function'),
	('U','Table'),
	('TF','Table Function'),
	('FN','Scalar Function'),
	('AF','Aggregate Function'),
	('DTR','Database Trigger'),
	('CLR','CLR Assembly'),
	('FT','CLR Table Function'),
	('FS','CLR Scalar Function'),
	('TYP','User Defined Data Type'),
	('TT','User Defined Table Type'),
	('UTY','User Defined Type'),
	('XSC','XML Schema Collection'),
	('SO','Sequence Object'),
	('SCH','Schema'),
	('SN','Synonym'),
	('DB','Database'),
	('PC','CLR Procedure'),
	('ROL','Role'),
	('SBM','Service Broker Message Type'),
	('SBS','Service Broker Service'),
	('SBC','Service Broker Contract'),
	('SBB','Service Broker Binding'),
	('SBP','Service Broker Priorities'),
	('SQ','Service Broker Queue'),
	('SBR','Service Broker Route'),
	('TR','Trigger')
	) AS S (ObjectType,TypeDescription)
ON S.ObjectType = T.ObjectType
WHEN MATCHED 
AND EXISTS (SELECT T.TypeDescription
			EXCEPT
			SELECT S.TypeDescription
			)
THEN UPDATE
SET T.TypeDescription = S.TypeDescription
WHEN NOT MATCHED BY TARGET THEN
INSERT(ObjectType,TypeDescription)
VALUES(S.ObjectType,S.TypeDescription);

