WHEN MATCHED AND (
	NULLIF([Source].[base_counter_name], [Target].[base_counter_name]) IS NOT NULL OR NULLIF([Target].[base_counter_name], [Source].[base_counter_name]) IS NOT NULL) THEN
 UPDATE SET
  [Target].[base_counter_name] = [Source].[base_counter_name]
