IF NOT EXISTS(SELECT * FROM dbo.PerformanceCounters_60MIN)
BEGIN
	INSERT INTO dbo.PerformanceCounters_60MIN
	(
		InstanceID,
		CounterID,
		SnapshotDate,
		Value_Total,
		Value_Min,
		Value_Max,
		SampleCount
	)
	SELECT PC.InstanceID,
			PC.CounterID,
			DG.DateGroup,
			SUM(PC.Value),
			MIN(PC.Value),
			MAX(PC.Value),
