/* 
	ResourceGovernorConfiguration collection no longer run non-enterprise edition engines.
	Remove the row from CollectionDates to prevent warnings about snapshot age for this collection
	where it's no longer applicable.
	#542
*/
DELETE CD
FROM dbo.CollectionDates CD
WHERE Reference = 'ResourceGovernorConfiguration'
AND NOT EXISTS(SELECT 1
	FROM dbo.Instances I
	WHERE I.InstanceID = CD.InstanceID
	AND I.EngineEdition = 3 /* Enterprise */
)

UPDATE dbo.Instances 
	SET ProductMinorVersion = TRY_CAST(PARSENAME(ProductVersion,3) AS INT),
		ProductBuild= TRY_CAST(PARSENAME(ProductVersion,2) AS INT),
		ProductRevision = TRY_CAST(PARSENAME(ProductVersion,1) AS INT)
WHERE (ProductMinorVersion IS NULL OR ProductBuild IS NULL OR ProductRevision IS NULL)

INSERT INTO dbo.Counters(
	object_name,
	counter_name,
	instance_name,
	CounterType
)
SELECT object_name,counter_name,instance_name,CounterType 
FROM (VALUES('Running Queries','Running Query Count','',2),
	('Running Queries','Blocked Query Count','',2),
	('Running Queries','Oldest Transaction (ms)','',2),
	('Running Queries','Blocked Queries Wait (ms)','',2),
	('Running Queries','Max Memory Grant KB','',2),
	('Running Queries','Sum Memory Grant KB','',2),
	('Running Queries','Longest Running Query (ms)','',2),
	('Running Queries','Critical Wait Count','',2),
	('Running Queries','Critical Wait Time (ms)','',2),
	('Running Queries','TempDB Wait Count','',2),
	('Running Queries','TempDB Wait Time (ms)','',2),
	('Running Queries','Sleeping Sessions Count','',2),
	('Running Queries','Sleeping Sessions Max Idle Time (ms)','',2),
	('sys.dm_db_resource_stats', 'avg_cpu_percent','',4),
	('sys.dm_db_resource_stats', 'avg_data_io_percent','',4),
	('sys.dm_db_resource_stats', 'avg_log_write_percent','',4),
	('sys.dm_db_resource_stats', 'avg_memory_usage_percent','',4),
	('sys.dm_db_resource_stats', 'xtp_storage_percent','',4),
	('sys.dm_db_resource_stats', 'max_worker_percent','',4),
	('sys.dm_db_resource_stats', 'max_session_percent','',4),
	('sys.dm_db_resource_stats', 'dtu_limit','',4),
	('sys.dm_db_resource_stats', 'avg_instance_cpu_percent','',4),
	('sys.dm_db_resource_stats', 'avg_instance_memory_percent','',4),
	('sys.dm_db_resource_stats', 'cpu_limit','',4)
	) VirtualCounters(object_name,counter_name,instance_name,CounterType)
WHERE NOT EXISTS(
				SELECT 1 
				FROM dbo.Counters C 
				WHERE C.counter_name = VirtualCounters.counter_name
				AND C.object_name = VirtualCounters.object_name
				AND C.instance_name = VirtualCounters.instance_name
				)

INSERT INTO dbo.RepositoryMetricsConfig(
	InstanceID,
	MetricName,
	IsAggregate,
	IsEnabled,
	Metrictype
)
SELECT -1,MetricName,IsAggregate,IsEnabled,MetricType
FROM (VALUES -- AG aggregate
			('Max Estimated Data Loss (sec)',1,1,'AG'),
			('Max Estimated Recovery Time (sec)',1,1,'AG'),
			('Max Secondary Lag (sec)',1,1,'AG'),
			('Total Redo Queue Size (KB)',1,0,'AG'),
			('Avg Redo Queue Size (KB)',1,1,'AG'),
			('Total Log Send Queue Size (KB)',1,0,'AG'),
			('Avg Log Send Queue Size (KB)',1,1,'AG'),
			-- AG Per database
			('Estimated Data Loss (sec)',0,0,'AG'),
			('Estimated Recovery Time (sec)',0,0,'AG'),
			('Secondary Lag (sec)',0,0,'AG'),
			('Redo Queue Size (KB)',0,0,'AG'),
			('Log Send Queue Size (KB)',0,0,'AG'),
			-- Log Shipping aggregate
			('Max Total Time Behind (min)',1,1,'LogShipping'),
			('Avg Total Time Behind (min)',1,1,'LogShipping'),
			('Min Total Time Behind (min)',1,1,'LogShipping'),
			('Max Latency Of Last (min)',1,0,'LogShipping'),
			('Avg Latency Of Last (min)',1,0,'LogShipping'),
			('Min Latency Of Last (min)',1,0,'LogShipping'),
			('Max Time Since Last (min)',1,0,'LogShipping'),
			('Avg Time Since Last (min)',1,0,'LogShipping'),
			('Min Time Since Last (min)',1,0,'LogShipping'),
			('Log Shipped Database Count',1,0,'LogShipping'),
			('Warning Count',1,0,'LogShipping'),
			('Critical Count',1,0,'LogShipping'),
			-- Slow Queries
			('Abort Count',1,0,'SlowQueries'),
			('Error Count',1,0,'SlowQueries'),
			('Total Queries',1,0,'SlowQueries'),
			-- Databases
			('Count of User Databases',1,0,'Databases'),
			('Databases Created',1,0,'Databases'),
			('Databases Dropped',1,0,'Databases')
		) M(MetricName,IsAggregate,IsEnabled,MetricType)
WHERE NOT EXISTS(
				SELECT 1 
				FROM dbo.RepositoryMetricsConfig AGM
				WHERE M.MetricName = AGM.MetricName
				AND AGM.InstanceID = -1
				)


ALTER DATABASE [$(DatabaseName)] SET AUTO_UPDATE_STATISTICS_ASYNC ON WITH NO_WAIT

/* Cleanup old objects */
IF OBJECT_ID('dbo.PartitionBoundaryHelper') IS NOT NULL
BEGIN
	PRINT 'Drop dbo.PartitionBoundaryHelper'
	DROP FUNCTION dbo.PartitionBoundaryHelper
END
IF OBJECT_ID('dbo.PartitionFunctionName') IS NOT NULL
BEGIN
	PRINT 'Drop dbo.PartitionFunctionName'
	DROP FUNCTION dbo.PartitionFunctionName
END
/* Migrate LogRestores data from old schema */
IF OBJECT_ID('dbo.LogRestoresTemp') IS NOT NULL
BEGIN 

	INSERT INTO dbo.LogRestores(
			InstanceID,
			DatabaseID,
			restore_date,
			backup_start_date,
			last_file,
			backup_time_zone
	)
	SELECT	D.InstanceID,
			T.DatabaseID,
			T.restore_date,
			T.backup_start_date,
			T.last_file,
			T.backup_time_zone	 
	FROM dbo.LogRestoresTemp T
	JOIN dbo.Databases D ON D.DatabaseID = T.DatabaseID
	WHERE NOT EXISTS(SELECT 1 
					FROM dbo.LogRestores LR 
					WHERE LR.InstanceID = D.InstanceID
					AND LR.DatabaseID = T.DatabaseID
					)
	DROP TABLE dbo.LogRestoresTemp
END
EXEC dbo.AzureDBCounters_Upd
IF EXISTS(SELECT 1 FROM dbo.DBFiles WHERE InstanceID=-1)
BEGIN
	UPDATE F
		SET F.InstanceID = D.InstanceID
	FROM dbo.DBFiles F
	JOIN dbo.Databases D ON F.DatabaseID = D.DatabaseID
	WHERE F.InstanceID=-1
END
-- Disable lock escalation to improve concurrency.  In most cases we will be below the lock escalation threshold, but we could be slightly over it in some edge cases.
ALTER TABLE dbo.DBFiles SET (LOCK_ESCALATION = DISABLE);
ALTER TABLE dbo.DBFileSnapshot SET (LOCK_ESCALATION = DISABLE);
/* 
	Update extended property to indicate that a DB deployment is no longer in progress, allowing the GUI to continue loading.
*/
EXECUTE sp_updateextendedproperty
		@name = N'IsDBUpgradeInProgress',
		@value = 'N';
GO

GO
DECLARE @VarDecimalSupported AS BIT;

SELECT @VarDecimalSupported = 0;

IF ((ServerProperty(N'EngineEdition') = 3)
    AND (((@@microsoftversion / power(2, 24) = 9)
          AND (@@microsoftversion & 0xffff >= 3024))
         OR ((@@microsoftversion / power(2, 24) = 10)
             AND (@@microsoftversion & 0xffff >= 1600))))
    SELECT @VarDecimalSupported = 1;

IF (@VarDecimalSupported > 0)
    BEGIN
        EXECUTE sp_db_vardecimal_storage_format N'$(DatabaseName)', 'ON';
    END


GO
PRINT N'Update complete.';


GO
